DELIMITER $$
CREATE PROCEDURE `AccountGroup_Typeahead`
Begin 
 set Group_Name_ = Concat( '%',Group_Name_ ,'%');
 SELECT 
 Account_Group_Id,
Group_Name From Account_Group 
where Group_Name like Group_Name_ and DeleteStatus=false 
 ORDER BY Group_Name Asc ;
 End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Accounts_Typeahead`
Begin 

	DECLARE Account_Group_String_ LONGTEXT DEFAULT '';
    
	set Client_Accounts_Name_ = Concat( "'%",Client_Accounts_Name_ ,"%'");
    
    IF Account_Group_Id_ != "" THEN
		SET Account_Group_String_ = CONCAT( "AND Account_Group_Id IN(",Account_Group_Id_,") ");
	END IF;
    
    
Set @query=CONCAT("	SELECT 	Client_Accounts_Id,	Client_Accounts_Name,Address1,Address2,
Address3,Address4,PinCode,Mobile,GSTNo
	From Client_Accounts 
    where  Client_Accounts_Name like ",  Client_Accounts_Name_," 
    ",Account_Group_String_,"
    and DeleteStatus=false 
    ORDER BY Client_Accounts_Name Asc 
    #Limit 5 
    ");
     PREPARE QUERY FROM @query;EXECUTE QUERY;
     delete from db_logs;
     insert into db_logs values(0,@query,'Accounts_Typeahead','');
   #select @query;
    
 End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Accounts_Typeahead_1`
BEGIN
    DECLARE Account_Group_String_ LONGTEXT DEFAULT '';    
    -- Escape special characters in the input
    SET Client_Accounts_Name_ = REPLACE(Client_Accounts_Name_, '\', '\\');
    SET Client_Accounts_Name_ = REPLACE(Client_Accounts_Name_, '%', '\%');
    SET Client_Accounts_Name_ = REPLACE(Client_Accounts_Name_, '', '\');
    SET Client_Accounts_Name_ = REPLACE(Client_Accounts_Name_, "'", "\'");
    SET Client_Accounts_Name_ = CONCAT("'%", Client_Accounts_Name_, "%'");
    -- Handle Account_Group_Id
    IF Account_Group_Id_ != "" THEN
        SET Account_Group_String_ = CONCAT("AND Account_Group_Id IN(", Account_Group_Id_, ") ");
    END IF;
    -- Dynamic query construction
    SET @query = CONCAT(
        "SELECT Client_Accounts_Id, Client_Accounts_Name, Address1, Address2, ",
        "Address3, Address4, PinCode, Mobile, GSTNo ",
        "FROM Client_Accounts ",
        "WHERE DeleteStatus = FALSE and  Client_Accounts_Name LIKE ", Client_Accounts_Name_,
        Account_Group_String_
    );
    -- Log final query for debugging
    -- Execute query
    PREPARE QUERY FROM @query;
   
    EXECUTE QUERY;
     
    DEALLOCATE PREPARE QUERY;
END
$$
DELIMITER ;

