CREATE PROCEDURE `Customer_Sales_Report`
Begin 
declare Search_Date_ varchar(500);
declare SearchbyName_Value varchar(2000);
set Search_Date_="";
set SearchbyName_Value="";
if Is_Date_Check_=true then
	set Search_Date_=concat( " and Sales_Master.Bill_Date >= '", From_Date_ ,"' and  Sales_Master.Bill_Date <= '", To_Date_,"'");
end if;
if Account_Party_Id_>0 then
	SET SearchbyName_Value =concat(SearchbyName_Value," and Sales_Master.Account_Party_Id =",Account_Party_Id_);
end if;
if Item_Id_>0 then
	SET SearchbyName_Value =concat(SearchbyName_Value," and Sales_Master.Sales_Master_Id in(
	select Sales_Master_Id from Sales_Details where ItemId =",Item_Id_,")");
end if;
SET @query = Concat("select (Date_Format(Bill_Date,'%Y-%m-%d')) as Bill_Date,Client_Accounts_Name,count(Sales_Master_Id)Noofbills,Sum(GrandTotal)Total
	from Sales_Master 
    inner join Client_Accounts on Sales_Master.Account_Party_Id=Client_Accounts.Client_Accounts_Id
	WHERE Sales_Master.DeleteStatus = false", Search_Date_ ,SearchbyName_Value,"
	group by Bill_Date,Client_Accounts_Name");
PREPARE QUERY FROM @query;EXECUTE QUERY;
#select @query;
End
$$
DELIMITER ;

