CREATE PROCEDURE `Delete_AddStock_Master`
BEGIN
declare StockId_ decimal(18,0);declare To_Employee_Id_ decimal(18,0);
declare Quantity_ decimal(18,2);declare fetch_status decimal(18,0);
Declare Cur Cursor for select  stock_add_details.StockId,Quantity
from stock_add_details
inner join stock_add_master on stock_add_details.Stock_Add_Master_Id=stock_add_master.Stock_Add_Master_Id
where stock_add_master.Stock_Add_Master_Id=Stock_Add_Master_Id_;
set fetch_status=(select Count(Stock_Add_Details_Id) from stock_add_details where
Stock_Add_Master_Id=Stock_Add_Master_Id_);
Open Cur;
FETCH Cur INTO StockId_,Quantity_;  
While(fetch_status != 0)do
update Stock set Quantity=Quantity-Quantity_ where Stock.Stock_Id=StockId_ ;
set fetch_status=fetch_status-1;
         if(fetch_status != 0)
then
FETCH Cur INTO StockId_,Quantity_;  
end if;
END WHILE;
Close Cur;
update stock_add_details set DeleteStatus=true where Stock_Add_Master_Id =Stock_Add_Master_Id_ ;
update stock_add_master set DeleteStatus=true where Stock_Add_Master_Id =Stock_Add_Master_Id_ ;
select Stock_Add_Master_Id_;
END
$$
DELIMITER ;

