CREATE PROCEDURE `Delete_currencydetails`
Begin 
declare DeleteStatus_ int;

IF EXISTS (
        SELECT 1 FROM salesquotationmaster WHERE DeleteStatus = FALSE AND CurrencyId = currencydetails_Id_)
    OR EXISTS (SELECT 1 FROM deliveryordermaster WHERE DeleteStatus = FALSE AND CurrencyId = currencydetails_Id_)
        OR EXISTS (SELECT 1 FROM packinglist_master WHERE DeleteStatus = FALSE AND CurrencyId = currencydetails_Id_)
        OR EXISTS (SELECT 1 FROM performainvoicemaster WHERE DeleteStatus = FALSE AND CurrencyId = currencydetails_Id_)
        OR EXISTS (SELECT 1 FROM sales_master WHERE DeleteStatus = FALSE AND CurrencyId = currencydetails_Id_)
        OR EXISTS (SELECT 1 FROM purchaseordermaster WHERE DeleteStatus = FALSE AND CurrencyId = currencydetails_Id_)
        OR EXISTS (SELECT 1 FROM purchase_master WHERE DeleteStatus = FALSE AND Currency_Id = currencydetails_Id_)
        OR EXISTS (SELECT 1 FROM purchase_return_master WHERE DeleteStatus = FALSE AND CurrencyId = currencydetails_Id_)
        OR EXISTS (SELECT 1 FROM sales_return_master WHERE DeleteStatus = FALSE AND CurrencyId = currencydetails_Id_)
		OR EXISTS (SELECT 1 FROM creditnote_master WHERE DeleteStatus = FALSE AND CurrencyId = currencydetails_Id_)
		OR EXISTS (SELECT 1 FROM debitnote_master WHERE DeleteStatus = FALSE AND CurrencyId = currencydetails_Id_)


    THEN
    set DeleteStatus_=-2;

    else
    
update currencydetails set DeleteStatus=True where CurrencyDetails_Id=currencydetails_Id_;
set DeleteStatus_=1;
end if;
select DeleteStatus_;
end
$$
DELIMITER ;

