CREATE PROCEDURE `Delete_HSN`
Begin 
  declare DeleteStatus_ bit;
  
if exists(select HSN_Id from HSN where  DeleteStatus=False and  HSN_Id =HSN_Id_ 
and HSN_Id  not in (select IFNULL(Sales_Details.HSNMasterId,0) HSNMasterId   from Sales_Details where DeleteStatus=False)
and HSN_Id  not in (select IFNULL(Purchase_Details.HSNMasterId,0) HSNMasterId  from Purchase_Details where DeleteStatus=False)
and HSN_Id  not in (select IFNULL(Stock_Add_Details.HSNMasterId,0) HSNMasterId  from Stock_Add_Details where DeleteStatus=False)
and HSN_Id  not in (select IFNULL(Stock.HSNMasterId,0) HSNMasterId from Stock where DeleteStatus=False)
and HSN_Id  not in (select IFNULL(Item.HSNMasterId,0) HSNMasterId from Item where DeleteStatus=False)
)
then
 update HSN set DeleteStatus=true where HSN_Id =HSN_Id_ ;
set DeleteStatus_=1;

else
set DeleteStatus_=0;
  
end if;
select DeleteStatus_;
end
$$
DELIMITER ;

