CREATE PROCEDURE `Delete_payment_term`
Begin 
declare DeleteStatus_ int;

IF EXISTS (
        SELECT 1 FROM salesquotationmaster WHERE DeleteStatus = FALSE AND Payment_Term_Description = payment_Term_ID_)
    OR EXISTS (SELECT 1 FROM deliveryordermaster WHERE DeleteStatus = FALSE AND Payment_Term_Description = payment_Term_ID_)
        OR EXISTS (SELECT 1 FROM packinglist_master WHERE DeleteStatus = FALSE AND Payment_Term_Description = payment_Term_ID_)
        OR EXISTS (SELECT 1 FROM performainvoicemaster WHERE DeleteStatus = FALSE AND Payment_Term_Description = payment_Term_ID_)
        OR EXISTS (SELECT 1 FROM sales_master WHERE DeleteStatus = FALSE AND Payment_Term_Description = payment_Term_ID_)
        OR EXISTS (SELECT 1 FROM purchaseordermaster WHERE DeleteStatus = FALSE AND Payment_Term_Description = payment_Term_ID_)
        OR EXISTS (SELECT 1 FROM purchase_master WHERE DeleteStatus = FALSE AND Payment_Term_Description = payment_Term_ID_)
        OR EXISTS (SELECT 1 FROM purchase_return_master WHERE DeleteStatus = FALSE AND Payment_Term_Description = payment_Term_ID_)
        OR EXISTS (SELECT 1 FROM sales_return_master WHERE DeleteStatus = FALSE AND Payment_Term_Description = payment_Term_ID_)
		OR EXISTS (SELECT 1 FROM creditnote_master WHERE DeleteStatus = FALSE AND Payment_Term_Description = payment_Term_ID_)
		OR EXISTS (SELECT 1 FROM debitnote_master WHERE DeleteStatus = FALSE AND Payment_Term_Description = payment_Term_ID_)


    THEN
    set DeleteStatus_=-2;

    else
update payment_term set DeleteStatus=True where payment_Term_ID=payment_Term_ID_;
set DeleteStatus_=1;
end if;
select DeleteStatus_;
end
