CREATE PROCEDURE `Delete_Prodution_Master`
BEGIN
declare StockId_ decimal(18,0);declare Quantity_ decimal(18,2);declare fetch_status decimal(18,0);
declare StockId_1 decimal(18,0);declare Quantity_1 decimal(18,2);declare fetch_status1 decimal(18,0);
declare DeleteStatus_ bit;
Declare Cur Cursor for select Stock_Id,Quanity from Prodcution_Details 
where Prodution_Master_Id=Prodution_Master_Id_;
Declare Cur1 Cursor for select Stock_Id,Quanity from Production_Materials 
where Prodution_Master_Id=Prodution_Master_Id_;

set fetch_status=(select Count(Prodcution_Details_Id) from Prodcution_Details where 
Prodution_Master_Id=Prodution_Master_Id_);
Open Cur;
FETCH Cur INTO StockId_,Quantity_;  
While(fetch_status != 0)do
	update Stock set Quantity=Quantity-Quantity_ where Stock_Id=StockId_ ;
	set fetch_status=fetch_status-1;
     if(fetch_status != 0)
		then
			FETCH Cur INTO StockId_,Quantity_;  
		end if;
END WHILE;
Close Cur;

set fetch_status1=(select Count(Production_Materials_Id) from Production_Materials where 
Prodution_Master_Id=Prodution_Master_Id_);
Open Cur1;
FETCH Cur1 INTO StockId_1,Quantity_1;  
While(fetch_status1 != 0)do
	update Stock set Quantity=Quantity+Quantity_1 where Stock_Id=StockId_1 ;
	set fetch_status1=fetch_status1-1;
     if(fetch_status1 != 0)
		then
			FETCH Cur1 INTO StockId_1,Quantity_1;  
		end if;
END WHILE;
Close Cur1;
update Prodution_Master set DeleteStatus=true where Prodution_Master_Id=Prodution_Master_Id_;
update Production_Materials set DeleteStatus=true where Prodution_Master_Id=Prodution_Master_Id_;
update Prodcution_Details set DeleteStatus=true where Prodution_Master_Id=Prodution_Master_Id_;
select Prodution_Master_Id_;
END
$$
DELIMITER ;

