CREATE PROCEDURE `Delete_Purchase_Payment`
BEGIN
    DECLARE Purchase_Master_Id_ DECIMAL(18,0);
    DECLARE Paid_Amount_ DECIMAL(18,2);
    DECLARE Voucher_Type_Id_ INT;
    DECLARE fetch_status INT DEFAULT 1; -- Fetch status for loop control

    -- Declare a cursor for the relevant data
    DECLARE Cur CURSOR FOR 
        SELECT Master_Id, COALESCE(Paying_Amount, 0), Voucher_Type_Id
        FROM payment_reference 
        WHERE Payment_Voucher_Id = Payment_Voucher_Id_;

    -- Declare handler to handle when cursor reaches the end
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET fetch_status = 0;

    -- Open the cursor
    OPEN Cur;

    -- Start fetching data from the cursor
    FETCH Cur INTO Purchase_Master_Id_, Paid_Amount_, Voucher_Type_Id_;

    WHILE fetch_status != 0 DO
        -- Check the voucher type and perform the corresponding update
        IF Voucher_Type_Id_ = 1 THEN
            UPDATE purchase_master
            SET PaidAmount = PaidAmount - Paid_Amount_
            WHERE Purchase_Master_Id = Purchase_Master_Id_;
        ELSE
            UPDATE journal_entry
            SET PaidAmount = PaidAmount - Paid_Amount_
            WHERE Journal_Entry_Id = Purchase_Master_Id_;
        END IF;

        -- Fetch the next record
        FETCH Cur INTO Purchase_Master_Id_, Paid_Amount_, Voucher_Type_Id_;
    END WHILE;

    -- Close the cursor
    CLOSE Cur;
 DELETE FROM payment_reference WHERE  Payment_Voucher_Id=Payment_Voucher_Id_; 
    -- Return the Payment Voucher ID as output
    SELECT Payment_Voucher_Id_;
END
$$
DELIMITER ;

