CREATE PROCEDURE `Delete_Receipt_Reference`
BEGIN
    DECLARE Master_Id_ DECIMAL(18,0);
    DECLARE Paid_Amount_ DECIMAL(18,2);
    DECLARE Voucher_Type_Id_ INT;
    DECLARE fetch_status INT DEFAULT 1; -- Fetch status for loop control

    -- Declare a cursor for the relevant data
    DECLARE Cur CURSOR FOR 
        SELECT Master_Id, COALESCE(Receiving_Amount, 0), Voucher_Type_Id
        FROM Receipt_Reference 
        WHERE Receipt_Voucher_Id = Receipt_Voucher_Id_;

    -- Declare handler to handle when cursor reaches the end
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET fetch_status = 0;

    -- Open the cursor
    OPEN Cur;

    -- Start fetching data from the cursor
    FETCH Cur INTO Master_Id_, Paid_Amount_, Voucher_Type_Id_;

    WHILE fetch_status != 0 DO
        -- Check the voucher type and perform the corresponding update
        IF Voucher_Type_Id_ = 5 THEN
            UPDATE sales_master
            SET PaidAmount = PaidAmount - Paid_Amount_
            WHERE Sales_Master_Id = Master_Id_;
        ELSE
            UPDATE journal_entry
            SET PaidAmount = PaidAmount - Paid_Amount_
            WHERE Journal_Entry_Id = Master_Id_;
        END IF;

        -- Fetch the next record
        FETCH Cur INTO Master_Id_, Paid_Amount_, Voucher_Type_Id_;
    END WHILE;

    -- Close the cursor
    CLOSE Cur;

    -- Delete from Receipt_Reference
    DELETE FROM Receipt_Reference WHERE Receipt_Voucher_Id = Receipt_Voucher_Id_;

    -- Return the Receipt Voucher ID as output
    SELECT Receipt_Voucher_Id_;
END
$$
DELIMITER ;

