CREATE PROCEDURE `Delete_SalesReturn_Master`
BEGIN
    DECLARE StockId_ DECIMAL(18,0);
    DECLARE Quantity_ DECIMAL(18,2);
    DECLARE fetch_status DECIMAL(18,0);

    -- Cursor declaration
    DECLARE Cur CURSOR FOR
        SELECT sales_return_details.Stock_Id, Quantity
        FROM sales_return_details
        INNER JOIN sales_return_master
        ON sales_return_details.Sales_Return_Master_Id = sales_return_master.Sales_Return_Master_Id
        WHERE sales_return_master.Sales_Return_Master_Id = Sales_Return_Master_Id_;

    -- Fetch status to control the loop
    SET fetch_status = (SELECT COUNT(Sales_Return_Details_Id)
                        FROM sales_return_details
                        WHERE Sales_Return_Master_Id = Sales_Return_Master_Id_);
                        -- Open the cursor
    OPEN Cur;
   
    -- Start fetching
    FETCH Cur INTO StockId_, Quantity_;

    -- Loop through the results and update stock
    WHILE (fetch_status != 0) DO
        -- Update stock based on StockId_ (assuming Stock_Id is the key column)
        UPDATE Stock
        SET Quantity = Quantity - Quantity_
        WHERE Stock.Stock_Id = StockId_;

        -- Decrement fetch_status and fetch next row if available
        SET fetch_status = fetch_status - 1;
        IF (fetch_status != 0) THEN
            FETCH Cur INTO StockId_, Quantity_;
        END IF;
    END WHILE;

    -- Close the cursor
    CLOSE Cur;

    -- Delete related transactions from the Accounts table
    DELETE FROM Accounts
    WHERE Tran_Type = 'SR' AND Tran_Id = Sales_Return_Master_Id_;

    -- Mark the sales return details as deleted
    UPDATE sales_return_details
    SET DeleteStatus = true
    WHERE sales_return_details.Sales_Return_Master_Id = Sales_Return_Master_Id_;

    -- Mark the sales return master as deleted
    UPDATE sales_return_master
    SET DeleteStatus = true
    WHERE sales_return_master.Sales_Return_Master_Id = Sales_Return_Master_Id_;

    -- Return the Sales_Return_Master_Id_ to confirm the deletion process
    SELECT Sales_Return_Master_Id_;
END
$$
DELIMITER ;

