		where Stock.Stock_Id=StockId_ ;
		set fetch_status=fetch_status-1;
         if(fetch_status != 0)
			then
				FETCH Cur INTO StockId_,Quantity_;  
			end if;
	END WHILE;
Close Cur;
delete from Accounts where Tran_Type='SA' and Tran_Id=Sales_Master_Id_;
update Sales_Details set DeleteStatus=true where Sales_Details.Sales_Master_Id =Sales_Master_Id_ ;
 update Sales_Master set DeleteStatus=true where Sales_Master.Sales_Master_Id =Sales_Master_Id_ ;
 update delivery_salesmaster set DeleteStatus = true where delivery_salesmaster.SalesMaster_Id = Sales_Master_Id_;
 update quotation_salesmaster set DeleteStatus = true where quotation_salesmaster.SalesMaster_Id = Sales_Master_Id_;
  update delivery_salesmaster set DeleteStatus = true where delivery_salesmaster.SalesMaster_Id = Sales_Master_Id_;
    update performa_salesmaster set DeleteStatus = true where performa_salesmaster.SalesMaster_Id = Sales_Master_Id_;


 select Sales_Master_Id_;
 End
$$
DELIMITER ;

