CREATE PROCEDURE `Delete_Sales_Order_Master_Mobile`
BEGIN

    DECLARE StockId_ DECIMAL(18,0);
    DECLARE To_Employee_Id_ DECIMAL(18,0);
    DECLARE Quantity_ DECIMAL(18,2);
    DECLARE fetch_status INT;

    DECLARE Cur CURSOR FOR
        SELECT  sod.Stock_Id,
                som.Employee_Id,
                sod.Quantity
        FROM Sales_Order_Details sod
        INNER JOIN Sales_Order_Master som
            ON sod.Sales_Order_Master_Id = som.Sales_Order_Master_Id
        WHERE som.Sales_Order_Master_Id = Sales_Order_Master_Id_;

    SET fetch_status = (
        SELECT COUNT(Sales_Order_Details_Id)
        FROM Sales_Order_Details
        WHERE Sales_Order_Master_Id = Sales_Order_Master_Id_
    );

    OPEN Cur;

    FETCH Cur INTO StockId_, To_Employee_Id_, Quantity_;

    WHILE (fetch_status <> 0) DO

        UPDATE Stock_Details
        SET Quantity = Quantity + Quantity_
        WHERE Stock_Details.Stock_Id = StockId_
          AND To_Employee_Id = To_Employee_Id_;

        SET fetch_status = fetch_status - 1;

        IF (fetch_status <> 0) THEN
            FETCH Cur INTO StockId_, To_Employee_Id_, Quantity_;
        END IF;

    END WHILE;

    CLOSE Cur;

    DELETE FROM Accounts
    WHERE Tran_Type = 'SO'
      AND Tran_Id = Sales_Order_Master_Id_;

    UPDATE Sales_Order_Details
    SET DeleteStatus = TRUE
    WHERE Sales_Order_Master_Id = Sales_Order_Master_Id_;

    UPDATE Sales_Order_Master
    SET DeleteStatus = TRUE
    WHERE Sales_Order_Master_Id = Sales_Order_Master_Id_;

    SELECT Sales_Order_Master_Id_;

END
$$
DELIMITER ;

