CREATE PROCEDURE `Delete_Sales_Receipt`
Begin
declare Sales_Master_Id_ decimal(18,0);declare Received_Amount_ decimal(18,2);declare Received_Discount_ decimal(18,2);
declare fetch_status decimal(18,0);
Declare Cur Cursor for 
select distinct Sales_Master_Id,COALESCE(sum(Receiving_Amount),0),COALESCE(SUM(Discount),0)
from Sales_Receipt 
where Receipt_Voucher_Id=Receipt_Voucher_Id_ group by Sales_Master_Id;
set fetch_status=(select Count(distinct Sales_Master_Id) from Sales_Receipt where Receipt_Voucher_Id=Receipt_Voucher_Id_);
Open Cur;
FETCH Cur INTO Sales_Master_Id_,Received_Amount_,Received_Discount_;  
While(fetch_status != 0)do
update sales_master set Received_Amount=Received_Amount-Received_Amount_,Received_Discount=Received_Discount-Received_Discount_
        where Sales_Master_Id=Sales_Master_Id_ ;
set fetch_status=fetch_status-1;
         if(fetch_status != 0)
then
FETCH Cur INTO Sales_Master_Id_,Received_Amount_,Received_Discount_;  
end if;
END WHILE;
Close Cur;
 select Receipt_Voucher_Id_;
 End
$$
DELIMITER ;

