CREATE PROCEDURE `Delete_Sale_Unit`
Begin 
  declare DeleteStatus_ bit;
if exists(select Sale_Unit_Id from Sale_Unit where  DeleteStatus=False and 
 Sale_Unit_Id =Sale_Unit_Id_ and Sale_Unit_Id  not in
(select Sales_Return_Details.UnitId  from Sales_Return_Details where DeleteStatus=False)
and Sale_Unit_Id  not in
(select Sales_Details.UnitId  from Sales_Details where DeleteStatus=False)
and Sale_Unit_Id  not in
(select Purchase_Details.UnitId  from Purchase_Details where DeleteStatus=False)
and Sale_Unit_Id  not in
(select Stock_Add_Details.UnitId  from Stock_Add_Details where DeleteStatus=False)
and Sale_Unit_Id  not in
(select Stock.UnitId  from Stock where DeleteStatus=False)
and Sale_Unit_Id  not in
(select Item.Saleunit_Id  from Item where DeleteStatus=False))
then
update Sale_Unit set DeleteStatus=True where Sale_Unit_Id=Sale_Unit_Id_;

set DeleteStatus_=1;

else
set DeleteStatus_=0;
  
end if;
select DeleteStatus_;
end
$$
DELIMITER ;

