	if Account_Name_='Purchase' then
		select Branch_Name,ifnull(Sum(NetTotal),0)Amount from purchase_master
		WHERE DeleteStatus = 0 and purchase_master.Branch_Id=(case when Branch_Id_>0 then  Branch_Id_ else Branch_Id end)
        AND Date_Format(PurchaseDate,'%Y-%m-%d') = Date_Format(Date_,'%Y-%m-%d') 
        group by Branch_Name;
	elseif Account_Name_='Sales' then
	 Select Branch_Name,ifnull(sum(Amount),0)Amount from petty_cash
	where 
       DeleteStatus = 0 and petty_cash.Branch_Id=(case when Branch_Id_>0 then  Branch_Id_ else Branch_Id end)
    and Date_Format(Date,'%Y-%m-%d') = Date_Format(Date_,'%Y-%m-%d') 
     group by Branch_Name;
	elseif Account_Name_='Receipt' then
        Select Branch_Name, ifnull(sum(RecpTotal),0)Amount  from petty_cash
	where
		DeleteStatus = 0 and petty_cash.Branch_Id=(case when Branch_Id_>0 then  Branch_Id_ else Branch_Id end)
    and Date_Format(Date,'%Y-%m-%d') = Date_Format(Date_,'%Y-%m-%d')  
    group by Branch_Name;
    elseif Account_Name_='Payment' then
    Select Branch_Name,ifnull(sum(SumTotal),0)Amount from petty_cash
	where 
		DeleteStatus = 0 and petty_cash.Branch_Id=(case when Branch_Id_>0 then  Branch_Id_ else Branch_Id end)
    and Date_Format(Date,'%Y-%m-%d') = Date_Format(Date_,'%Y-%m-%d')
     group by Branch_Name;
    end if;
END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Get_Dashboard_New_Count`
BEGIN
declare SearchbyName_Value_1 varchar(1000);
declare SearchbyName_Value_2 varchar(1000);
declare yesterday date;
set SearchbyName_Value_1 = '';
set SearchbyName_Value_2 = '';
if Branch_ > 0 then
	SET SearchbyName_Value_1 =concat(SearchbyName_Value_1," and purchase_master.Branch_Id=",Branch_);
	SET SearchbyName_Value_2 =concat(SearchbyName_Value_2," and petty_cash.Branch_Id=",Branch_);
end if;
set yesterday=DATE(Date_ - INTERVAL 1 DAY);   
SET @query = CONCAT(
    "select ifnull(sum(NetTotal),0)Sum,'Purchase' as account_name,1 as Type from purchase_master
    WHERE
        deletestatus = 0
        AND DATE(PurchaseDate) = '", Date_, "'
        ", SearchbyName_Value_1, "
    UNION
    select ifnull(sum(Amount),0)TotalSales,'Sales' as TypeName,2 as Type from petty_cash
    WHERE
        petty_cash.DeleteStatus = 0 
        AND DATE(Date) = '", Date_, "'
        ", SearchbyName_Value_2, "   
    UNION
   select ifnull(sum(RecpTotal),0)TotalReceipt,'Receipt' as TypeName,3 as Type from petty_cash
    WHERE
        petty_cash.DeleteStatus = 0 
        AND DATE(Date) = '", Date_, "'
        ", SearchbyName_Value_2, "
    UNION
   select ifnull(sum(SumTotal),0)TotalPayment,'Payment' as TypeName,4 as Type from petty_cash
    WHERE
        deletestatus = 0
        AND DATE(Date) = '", DATE(Date_), "'
        ", SearchbyName_Value_2
);
  PREPARE QUERY FROM @query;
  EXECUTE QUERY;
#select @Query;

END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Get_Dashboard_New_Count_curr`
BEGIN

declare SearchbyName_Value_1 varchar(1000);
declare SearchbyName_Value_2 varchar(1000);
declare yesterday date;
set SearchbyName_Value_1 = '';
set SearchbyName_Value_2 = '';

delete from db_logs;
insert into db_logs values(0,Branch_,date_,'');

if Branch_ > 0 then

	SET SearchbyName_Value_1 =concat(SearchbyName_Value_1," and stock.Branch_Id=",Branch_);
	SET SearchbyName_Value_2 =concat(SearchbyName_Value_2," and petty_cash.Branch_Id=",Branch_);
end if;

set yesterday=DATE(Date_ - INTERVAL 1 DAY);
   
SET @query = CONCAT(
    "SELECT
        SUM(Close_Stock) AS sum,
        'Opening_Stock' AS account_name
    FROM
        petty_cash
    WHERE
        deletestatus = 0
        AND DATE(Date) = '", yesterday, "'
        ", SearchbyName_Value_2, "

    UNION

    SELECT
        SUM(petty_cash_details.amount) AS sum,
        account_name
    FROM
        petty_cash_details
    INNER JOIN petty_cash ON petty_cash.petty_cash_id = petty_cash_details.petty_cash_id
    WHERE
        petty_cash.DeleteStatus = 0 AND petty_cash_details.DeleteStatus = 0
        AND DATE(Date) = '", Date_, "'
        ", SearchbyName_Value_2, "
    GROUP BY
        petty_cash_details.account_name

    UNION

    SELECT
        SUM(petty_cash_details.amount) AS sum,
        'Balance' AS account_name
    FROM
        petty_cash_details
    INNER JOIN petty_cash ON petty_cash.petty_cash_id = petty_cash_details.petty_cash_id
    WHERE
        petty_cash.DeleteStatus = 0 AND petty_cash_details.DeleteStatus = 0
        AND DATE(Date) = '", Date_, "'
        ", SearchbyName_Value_2, "

    UNION

    SELECT
        SUM(Close_Stock) AS sum,
        'Closing_Stock' AS account_name
    FROM
        petty_cash
    WHERE
        deletestatus = 0
        AND DATE(Date) = '", DATE(Date_), "'
        ", SearchbyName_Value_2
);


  PREPARE QUERY FROM @query;
  EXECUTE QUERY;
  insert into db_logs values(0,'',@query,yesterday);
#select @Query;

END
$$
DELIMITER ;

