CREATE PROCEDURE `Get_Item_Name_Get_With_Code`
Begin 
 #set Item_Code_ = Concat( '%',Item_Code_ ,'%');
SELECT Item_Id ItemId,Item_Name ItemName,Group_Id GroupId,Group_Name GroupName,Saleunit_Id UnitId,
Saleunit_Name UnitName,HSNMasterId,HSNCODE,Sales_Tax SaleTax,CGST,SGST,IGST,'' Barcode,
'' PurchaseRate,''  SaleRate,'' MRP
From Item  
where Item_Code like Item_Code_ and Group_Id=Item_Group_Id_ and DeleteStatus=false
union
SELECT ItemId,ItemName,GroupId,GroupName,UnitId,UnitName,HSNMasterId,HSNCODE,SaleTax ,CGST,
SGST,IGST,Barcode,PurchaseRate,SaleRate,MRP
From Purchase_Details  
