DELIMITER $$
CREATE PROCEDURE `Get_Item_Name_Get_With_Code_App`
BEGIN
    SET Item_Code_ = CONCAT('%', Item_Code_, '%');
    SET Item_Name_ = CONCAT('%', Item_Name_, '%');

    SELECT
        i.Item_Id ItemId,
        i.Item_Code,
        i.Item_Name ItemName,
        i.Group_Id GroupId,
        ig.Item_Group_Name GroupName,
        i.Saleunit_Id UnitId,
        i.Saleunit_Name UnitName,
        i.HSNMasterId,
        i.HSNCODE,
        i.Sales_Tax SaleTax,
        i.CGST,
        i.SGST,
        i.IGST,
        COALESCE(pd.Barcode, '') Barcode,
        COALESCE(pd.PurchaseRate, 0) PurchaseRate,
        COALESCE(pd.SaleRate, 0) SaleRate,
        COALESCE(pd.MRP, 0) MRP
    FROM
        Item i
        LEFT JOIN Purchase_Details pd ON i.Item_Id = pd.ItemId AND pd.DeleteStatus = 0
        LEFT JOIN Item_Group ig ON i.Group_Id = ig.Item_Group_Id
    WHERE
        (Item_Code_ = '' OR i.Item_Code LIKE Item_Code_)
        AND (Item_Group_Id_ = 0 OR i.Group_Id = Item_Group_Id_)
        AND (Item_Name_ = '' OR i.Item_Name LIKE Item_Name_)
        AND i.DeleteStatus = 0
    ORDER BY
        ItemName DESC;
       
       
       

    SELECT DISTINCT
        Item_Group_Name,Item_Group_Id
    FROM
        Item_Group
    WHERE
        DeleteStatus = 0;


END
$$
DELIMITER ;

