DELIMITER $$
CREATE PROCEDURE `Get_Item_Name_Typeahead_For_Purchase_Return`
BEGIN
 
 #SET Item_Name_ = Concat( '%',Item_Name_ ,'%');
  SET Item_Name_ = REPLACE(Item_Name_, '\', '\\');
    SET Item_Name_ = REPLACE(Item_Name_, '%', '\%');
    SET Item_Name_ = REPLACE(Item_Name_, '', '\');
    SET Item_Name_ = CONCAT('%', Item_Name_, '%');
 
 SELECT
	pd.Purchase_Details_Id,
    pd.Purchase_Master_Id,
    pd.ItemId,
    pd.ItemName,
    pd.ItemId AS Item_Id,
    pd.ItemName AS Item_Name,
    pd.Item_Code AS ItemCode,
    pd.Item_Code,
    pd.GroupId,
    pd.GroupId AS Group_Id,
    pd.GroupName,
    pd.GroupName AS Group_Name,
    pd.UnitId,
    pd.UnitName,
    pd.StockId,
    pd.StockId AS Stock_Id,
    pd.SaleRate,
    pd.SaleRate AS Sale_Rate,
    pd.SaleTax,
    pd.SaleTax AS Sale_Tax,
    IFNULL(pd.HSNMasterId,0) HSNMasterId,
    IFNULL(pd.HSNCODE,'') HSNCODE,
	IFNULL(pd.Country_Id,0) Country_Id,
	IFNULL(pd.Country_Name,'') Country_Name

  FROM purchase_details pd
  WHERE 
	pd.DeleteStatus =false 
    AND pd.ItemName like Item_Name_ 
    AND pd.Purchase_Master_Id = Purchase_Master_Id_
  ORDER BY pd.ItemName ASC;
  
 END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Get_Item_Name_Typeahead_For_Sales_Return`
BEGIN
 
# SET Item_Name_ = Concat( '%',Item_Name_ ,'%');

  SET Item_Name_ = REPLACE(Item_Name_, '\', '\\');
    SET Item_Name_ = REPLACE(Item_Name_, '%', '\%');
    SET Item_Name_ = REPLACE(Item_Name_, '', '\');
    SET Item_Name_ = CONCAT('%', Item_Name_, '%');
 SELECT
	pd.Sales_Details_Id,
    pd.Sales_Master_Id,
    pd.ItemId,
    pd.ItemName,
    pd.ItemId AS Item_Id,
    pd.ItemName AS Item_Name,
    pd.ItemCode AS Item_Code,
    pd.ItemCode,
    pd.GroupId,
    pd.GroupId AS Group_Id,
    pd.GroupName,
    pd.GroupName AS Group_Name,
    pd.UnitId,
    pd.UnitName,
    IFNULL(pd.Stock_Id,0) Stock_Id,
    IFNULL(pd.Stock_Id,0) AS StockId,
    pd.UnitPrice AS SaleRate,
    pd.UnitPrice AS Sale_Rate,
    pd.SaleTax,
    pd.SaleTax AS Sale_Tax,
    IFNULL(pd.HSNMasterId,0) HSNMasterId,
    IFNULL(pd.HSNCODE,'') HSNCODE,
	IFNULL(pd.Country_Id,0) Country_Id,
	IFNULL(pd.Country_Name,'') Country_Name

  FROM sales_details pd
  WHERE 
	pd.DeleteStatus =false 
    AND pd.ItemName like Item_Name_ 
    AND pd.Sales_Master_Id = Sales_Master_Id_
  ORDER BY pd.ItemName ASC;
  
 END
$$
DELIMITER ;

