DELIMITER $$
CREATE PROCEDURE `Get_Opening_Balance`
BEGIN
Select
	ifnull(sum(Close_Stock),0)Opening_Balance	
From
	Petty_Cash
Where Petty_Cash_Id = (SELECT max(petty_cash_id) FROM petty_cash WHERE Branch_Id=Branch_Id_ and 
Date_Format(Date,'%Y-%m-%d')< Date_Format(Date_,'%Y-%m-%d')group by Date
order by petty_cash_id asc limit 1);

SELECT
	Master_Category_Id,
    Master_Category_Name,
    SUM(IFNULL(Amount,0)) AS Total_Amount,
    SUM(Quantity) AS Quantity
FROM
	Daybook
WHERE
	DeleteStatus = 0
    AND DATE(Entry_Date) = DATE(Date_)
    AND Client_Accounts_Id = Branch_Id_
GROUP BY
	Master_Category_Id,
    Master_Category_Name
ORDER BY
	CASE WHEN Master_Category_Name = 'Expense' THEN 1 
	 WHEN Master_Category_Name = 'Bank' THEN 2 
	 WHEN Master_Category_Name = 'Ho' THEN 3 
	 WHEN Master_Category_Name = 'Salary' THEN 4 
	 WHEN Master_Category_Name = 'Management' THEN 5 
     ELSE 6
     END;
END
$$
DELIMITER ;

