DELIMITER $$
CREATE PROCEDURE `Get_Payment_Reference`
Begin 
declare Account_Party_Id_ int;
set Account_Party_Id_=(select To_Party_Id from payment_voucher where Payment_Voucher_Id=Payment_Voucher_Id_ and DeleteStatus=0);

Select 1 as Voucher_Type_Id,(case when Check_Box='1'then true else false end)Check_Box,'Purchase' as Voucher_Type_Name,
purchase_master.Purchase_Master_Id,purchase_master.InvoiceNo,(Date_Format(purchase_master.PurchaseDate,'%d-%m-%Y')) As PurchaseDate,
purchase_master.NetTotal as Amount,COALESCE((payment_reference.Paying_Amount),0) as Paying_Amount,
(purchase_master.NetTotal-ifnull(payment_reference.Paying_Amount,0))BalAmt,purchase_master.Account_Party_Id
from purchase_master inner join payment_reference
on purchase_master.Purchase_Master_Id=payment_reference.Master_Id and Voucher_Type_Id=1 
and payment_reference.DeleteStatus=0
where purchase_master.DeleteStatus=0 AND payment_reference.Payment_Voucher_Id=Payment_Voucher_Id_
union
select 2 as Voucher_Type_Id,(case when Check_Box='1'then true else false end)Check_Box,'Expense' as Voucher_Type_Name,
journal_entry.Journal_Entry_Id as Purchase_Master_Id,Voucher_No as InvoiceNo,(Date_Format(journal_entry.Date,'%d-%m-%Y')) As PurchaseDate,
journal_entry.Amount,COALESCE(payment_reference.Paying_Amount,0) as Paying_Amount ,
(journal_entry.Amount-ifnull((payment_reference.Paying_Amount),0))BalAmt,journal_entry.To_Account_Id as Account_Party_Id
from journal_entry inner join payment_reference
on journal_entry.Journal_Entry_Id=payment_reference.Master_Id and Voucher_Type_Id=2 and payment_reference.DeleteStatus=0
where journal_entry.DeleteStatus=0 AND payment_reference.Payment_Voucher_Id = Payment_Voucher_Id_
union
Select distinct 1 as Voucher_Type_Id,0 as Check_Box,'Purchase' as Voucher_Type_Name,purchase_master.Purchase_Master_Id,
purchase_master.InvoiceNo,(Date_Format(purchase_master.PurchaseDate,'%d-%m-%Y')) As PurchaseDate,
purchase_master.NetTotal as Amount,0 as Paying_Amount,
(purchase_master.NetTotal-ifnull(sum(payment_reference.Paying_Amount),0))BalAmt,purchase_master.Account_Party_Id
from purchase_master left join payment_reference
on purchase_master.Purchase_Master_Id=payment_reference.Master_Id and Voucher_Type_Id=1 
and payment_reference.DeleteStatus=0
where purchase_master.DeleteStatus=0 AND purchase_master.Account_Party_Id=Account_Party_Id_
and purchase_master.Purchase_Master_Id not in(select Master_Id from payment_reference 
where payment_reference.DeleteStatus=0 and payment_reference.Payment_Voucher_Id = Payment_Voucher_Id_)
group by purchase_master.Purchase_Master_Id,purchase_master.InvoiceNo,purchase_master.PurchaseDate,
purchase_master.NetTotal,purchase_master.Account_Party_Id
having (COALESCE(purchase_master.NetTotal,0)-(COALESCE(sum(payment_reference.Paying_Amount),0)))>0
union
select 2 as Voucher_Type_Id,0 as Check_Box,'Expense' as Voucher_Type_Name,journal_entry.Journal_Entry_Id as Purchase_Master_Id,
Voucher_No as InvoiceNo,(Date_Format(journal_entry.Date,'%d-%m-%Y')) As PurchaseDate,
journal_entry.Amount,0 as Paying_Amount ,
(journal_entry.Amount-ifnull(sum(payment_reference.Paying_Amount),0))BalAmt,journal_entry.To_Account_Id as Account_Party_Id
from journal_entry left join payment_reference
on journal_entry.Journal_Entry_Id=payment_reference.Master_Id and Voucher_Type_Id=2 and payment_reference.DeleteStatus=0
where journal_entry.DeleteStatus=0 AND journal_entry.To_Account_Id=Account_Party_Id_ 
and journal_entry.Journal_Entry_Id not in(select Master_Id from payment_reference 
where payment_reference.DeleteStatus=0 and payment_reference.Payment_Voucher_Id = Payment_Voucher_Id_)
group by journal_entry.Journal_Entry_Id,Voucher_No,journal_entry.Date,journal_entry.Amount,journal_entry.To_Account_Id
having (COALESCE(journal_entry.Amount,0)-(COALESCE(sum(payment_reference.Paying_Amount),0)))>0;
 End
$$
DELIMITER ;

