DELIMITER $$
CREATE PROCEDURE `Get_Purchase_Item_Code_Typeahead`
BEGIN



    -- Escape special characters for MySQL LIKE queries
    SET ItemName_ = REPLACE(ItemName_, '\', '\\'); -- Escape backslash
    SET ItemName_ = REPLACE(ItemName_, '%', '\%');  -- Escape percentage
    SET ItemName_ = REPLACE(ItemName_, '', '\');  -- Escape underscore

    -- Wrap the input in wildcard characters for partial matching
    SET ItemName_ = CONCAT('%', ItemName_, '%');

    -- Log the escaped input for debugging purposes
   # DELETE FROM db_logs;

    -- Perform the query
    SELECT 
       ifnull(Stock.Stock_Id,0) Stock_Id, 
        ifnull(Stock.Stock_Id,0) AS StockId, 
        ifnull(stock.Quantity,0) as Quantity,
         ifnull(stock.PurchaseRate,0) as PurchaseRate,
         ifnull(stock.PurchaseRate,0)SaleRate,
         ifnull(stock.PurchaseRate,0)UnitPrice,
        item.Item_Id AS ItemId,
        item.Item_Code,
        item.Item_Code AS Item_Code,
        item.Item_Name AS ItemName,
        item.Group_Id AS GroupId,
        item.Group_Name AS GroupName,
        IFNULL(item.Country_Id, 0) AS Country_Id,
        IFNULL(item.Country_Name, '') AS Country_Name,
        item.Saleunit_Id AS UnitId,
        item.Saleunit_Name AS UnitName,
        ifnull(item.Sales_Tax,0)AS SaleTax,
        IFNULL(item.HSNCODE, '') AS HSNCODE,
        IFNULL(item.HSNMasterId, 0) AS HSNMasterId
    FROM item
    LEFT JOIN stock ON item.Item_Id = stock.ItemId
    WHERE item.DeleteStatus = FALSE
      AND item.Item_Code LIKE ItemName_
    ORDER BY item.Item_Name ASC
    LIMIT 25;
END
$$
DELIMITER ;

DELIMITER $$
