and DeleteStatus=0);
select purchase_master.Purchase_Master_Id,InvoiceNo,(Date_Format(purchase_master.PurchaseDate,'%Y-%m-%d')) As Date ,Purchase_Payment.Paying_Amount,NetTotal,
Purchase_Payment.Discount,Account_Party_Id,(COALESCE(NetTotal,0)-(COALESCE(Paid_Amount,0)+COALESCE(Paying_Discount ,0))) as BalAmt,1 as Check_Box
from Purchase_Payment inner join purchase_master
