0 as Paying_Discount,Account_Party_Id,(COALESCE(NetTotal,0)-(COALESCE(Paid_Amount,0)+COALESCE(Paying_Discount,0))) as BalAmt,0 as Check_Box
from purchase_master
where DeleteStatus=0 AND Account_Party_Id=Account_Party_Id_
and (COALESCE(NetTotal,0)-(COALESCE(Paid_Amount,0)+COALESCE(Paying_Discount,0)))>0 
and Purchase_Master_Id not in(select Purchase_Master_Id from Purchase_Payment where DeleteStatus=0 and Payment_Voucher_Id=Payment_Voucher_Id_);
