CREATE PROCEDURE `Get_Receipt_Reference`
Begin 
declare Account_Party_Id_ int;
set Account_Party_Id_=(select Frm_Party_Id from Receipt_Voucher where Receipt_Voucher_Id=Receipt_Voucher_Id_ and DeleteStatus=0);

Select 5 as Voucher_Type_Id,(case when Check_Box='1'then true else false end)Check_Box,'Sales' as Voucher_Type_Name,
sales_master.Sales_Master_Id,sales_master.Invoice_No as InvoiceNo,(Date_Format(sales_master.EntryDate,'%d-%m-%Y')) As Date,
sales_master.NetTotal as Amount,COALESCE((receipt_reference.Receiving_Amount),0) as Receiving_Amount,
(sales_master.NetTotal-ifnull(receipt_reference.Receiving_Amount,0))BalAmt,sales_master.Account_Party_Id
from sales_master inner join receipt_reference
on sales_master.Sales_Master_Id=receipt_reference.Master_Id and Voucher_Type_Id=5 
and receipt_reference.DeleteStatus=0
where sales_master.DeleteStatus=0 AND receipt_reference.Receipt_Voucher_Id=Receipt_Voucher_Id_
union
select 2 as Voucher_Type_Id,(case when Check_Box='1'then true else false end)Check_Box,'Expense' as Voucher_Type_Name,
journal_entry.Journal_Entry_Id as Sales_Master_Id,Voucher_No as InvoiceNo,(Date_Format(journal_entry.Date,'%d-%m-%Y')) As Date,
journal_entry.Amount,COALESCE(receipt_reference.Receiving_Amount,0) as Receiving_Amount ,
(journal_entry.Amount-ifnull((receipt_reference.Receiving_Amount),0))BalAmt,journal_entry.From_Account_Id as Account_Party_Id
from journal_entry inner join receipt_reference
on journal_entry.Journal_Entry_Id=receipt_reference.Master_Id and Voucher_Type_Id=2 and receipt_reference.DeleteStatus=0
where journal_entry.DeleteStatus=0 AND receipt_reference.Receipt_Voucher_Id = Receipt_Voucher_Id_
union
Select 5 as Voucher_Type_Id,0 as Check_Box,'Sales' as Voucher_Type_Name,Sales_Master_Id,Invoice_No as InvoiceNo,
(Date_Format(Sales_Master.EntryDate,'%d-%m-%Y')) As Date,NetTotal as Amount,0 as Receiving_Amount,
(COALESCE(NetTotal,0)-COALESCE(PaidAmount,0)) as BalAmt,Account_Party_Id
from Sales_Master where DeleteStatus=0 AND Account_Party_Id=Account_Party_Id_ and (COALESCE(NetTotal,0)-COALESCE(PaidAmount,0))>0
union
select 2 as Voucher_Type_Id,0 as Check_Box,'Expense' as Voucher_Type_Name,journal_entry.Journal_Entry_Id as Sales_Master_Id,Voucher_No as InvoiceNo,
(Date_Format(journal_entry.Date,'%d-%m-%Y')) As Date,journal_entry.Amount,0 as Receiving_Amount,
(journal_entry.Amount-ifnull(journal_entry.PaidAmount,0))BalAmt,journal_entry.From_Account_Id as Account_Party_Id
from journal_entry where journal_entry.DeleteStatus=0 AND journal_entry.From_Account_Id=Account_Party_Id_ 
and (COALESCE(journal_entry.Amount,0)-(ifnull(journal_entry.PaidAmount,0)))>0;
End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Get_Receipt_Voucher`
BEGIN
declare Account_Party_Id_ int;
set Account_Party_Id_=(select From_Account_Id from Receipt_Voucher where Receipt_Voucher_Id=Receipt_Voucher_Id_
and DeleteStatus=0);
select Sales_Master.Sales_Master_Id,Invoice_No,(Date_Format(Sales_Master.Bill_Date,'%Y-%m-%d')) As Date ,Sales_Receipt.Receiving_Amount,NetTotal,
Sales_Receipt.Discount,Account_Party_Id,(COALESCE(NetTotal,0)-(COALESCE(Received_Amount,0)+COALESCE(Received_Discount ,0))) as BalAmt,1 as Check_Box
from Sales_Receipt 
inner join Sales_Master on Sales_Receipt.Sales_Master_Id=Sales_Master.Sales_Master_Id
where Sales_Receipt.Receipt_Voucher_Id=Receipt_Voucher_Id_
union
Select distinct Sales_Master_Id,Invoice_No,(Date_Format(Sales_Master.Bill_Date,'%Y-%m-%d')) As Date ,0 as Receiving_Amount,NetTotal,
0 as Received_Discount,Account_Party_Id,(COALESCE(NetTotal,0)-(COALESCE(Received_Amount,0)+COALESCE(Received_Discount,0))) as BalAmt,0 as Check_Box
from Sales_Master
where DeleteStatus=0 AND Account_Party_Id=Account_Party_Id_
and (COALESCE(NetTotal,0)-(COALESCE(Received_Amount,0)+COALESCE(Received_Discount,0)))>0 
and Sales_Master_Id not in(select Sales_Master_Id from Sales_Receipt where DeleteStatus=0 and Receipt_Voucher_Id=Receipt_Voucher_Id_);
END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Get_Receipt_Voucher_Mobile`
Begin 

SELECT
	Receipt_Voucher.Receipt_Voucher_Id,Receipt_Voucher.Description,Amount,Concat( Receipt_Voucher.Voucher_No ,'') Voucher_No,
	(Date_Format(Receipt_Voucher.Date,'%Y-%m-%d')) As Date ,Receipt_Voucher.User_Id,Payment_Status,
	Receipt_Voucher.From_Account_Id,FromAcc.Client_Accounts_Name as FromAccount_Name,
	Receipt_Voucher.To_Account_Id,	ToAcc.Client_Accounts_Name as ToAccount_Name,
	Payment_Mode,Payment_Mode_Name,User_Details.Employee_Id
From Receipt_Voucher 
inner join Sales_Receipt on Receipt_Voucher.Receipt_Voucher_Id=Sales_Receipt.Receipt_Voucher_Id
inner join Client_Accounts as FromAcc on FromAcc.Client_Accounts_Id=Receipt_Voucher.From_Account_Id
inner join Client_Accounts as ToAcc on ToAcc.Client_Accounts_Id=Receipt_Voucher.To_Account_Id
left join Payment_Mode on Receipt_Voucher.Payment_Mode=Payment_Mode.Payment_Mode_Id
inner join User_Details on Receipt_Voucher.User_Id=User_Details.User_Details_Id
where Receipt_Voucher.DeleteStatus=false and Sales_Master_Id=Sales_Master_Id_;
 End
$$
DELIMITER ;

