CREATE PROCEDURE `Get_Sales_Details_Report`
Begin 
declare Search_Date_ varchar(500);declare SearchbyName_Value varchar(2000);
set Search_Date_="";set SearchbyName_Value="";
 if Is_Date_Check_=true then
	set Search_Date_=concat( " and Sales_Master.Bill_Date >= '", FromDate_ ,"' and  Sales_Master.Bill_Date <= '", ToDate_,"'");
end if;
if Client_Id_>0 then
	SET SearchbyName_Value =concat(SearchbyName_Value," and Sales_Master.Account_Party_Id =",Client_Id_);
end if;
if VoucherType_>0 then
	SET SearchbyName_Value =concat(SearchbyName_Value," and Concat( Sales_Master.Invoice_No ,'')  =",VoucherType_);
end if;
if ItemId_>0 then
	SET SearchbyName_Value =concat(SearchbyName_Value," and Sales_Details.ItemId =",ItemId_);
end if;
    
SET @query = Concat("SELECT Sales_Details.Sales_Master_Id,(Date_Format(Bill_Date,'%Y-%m-%d')) As Bill_Date,
Invoice_No,Account_Party_Id,Client_Accounts.Client_Accounts_Name as Customer,
UnitName,ItemId,ItemName,Barcode,
GroupId,GroupName,PurchaseRate,SaleRate,MRP,Sales_Details.HSNCODE,Sales_Details.SaleTax,
Sales_Details.CGST,Sales_Details.IGST,Sales_Details.SGST,Sales_Details.Cesspers,
Sales_Details.Quantity,Sales_Details.GrossValue,Sales_Details.Discount,Sales_Details.NetValue,
Sales_Details.CGSTAMT,Sales_Details.SGSTAMT,Sales_Details.IGSTAMT,Sales_Details.CessAMT,
Sales_Details.TotalAmount 

FROM Sales_Details
	 INNER JOIN Sales_Master ON Sales_Details.Sales_Master_Id=Sales_Master.Sales_Master_Id 
	 INNER JOIN Client_Accounts ON Sales_Master.Account_Party_Id=Client_Accounts.Client_Accounts_Id 
	 inner join Item ON Sales_Details.ItemId=Item.Item_Id
	 inner join Item_Group ON Sales_Details.GroupId=Item_Group.Item_Group_Id
	 
WHERE Sales_Master.DeleteStatus =false", Search_Date_ ,SearchbyName_Value,"");

PREPARE QUERY FROM @query; EXECUTE QUERY;
 #select @query;
 End
$$
DELIMITER ;

