CREATE PROCEDURE `Get_Sales_Order_Details`
BEGIN 

    -- Order Details
    SELECT 
        sales_order_details.*,
        (Stock.Quantity + sales_order_details.Quantity) AS Stock,
        IFNULL(sales_order_details.Unit_Discount, 0) AS Unit_Discount
    FROM sales_order_details
    LEFT JOIN sales_order_master
        ON sales_order_master.Sales_Order_Master_Id = sales_order_details.Sales_Order_Master_Id
    LEFT JOIN Stock
        ON Stock.Stock_Id = sales_order_details.Stock_Id
    WHERE sales_order_details.Sales_Order_Master_Id = Sales_Order_Master_Id_
        AND sales_order_details.DeleteStatus = FALSE;


    -- HSN Summary
    SELECT 
        HSNCODE,
        SaleTax,
        SUM(NetValue) AS NetValue,
        SUM(TaxAmount) AS TaxAmount
    FROM sales_order_details
    WHERE Sales_Order_Master_Id = Sales_Order_Master_Id_
        AND DeleteStatus = FALSE
    GROUP BY HSNCODE, SaleTax;


    -- Client Accounts
    SELECT 
        Client_Accounts_Id,
        Client_Accounts_Name,
        Client_Accounts_No,
        Address1,
        Address2
    FROM client_accounts
    WHERE Account_Group_Id IN (4,5)
        AND DeleteStatus = 0;


    -- Company Details
    SELECT 
        Company_Name,
        Company_Id,
        Address1,
        Address2,
        Address3,
        Address4,
        Mobile_Number,
        EMail,
        GSTNO,
        PANNO,
        CINO
    FROM Company
    WHERE DeleteStatus = 0;

END
$$
DELIMITER ;

