        sales_order_details.UnitName,
        sales_order_details.PurchaseRate,
        sales_order_details.SaleRate,
        sales_order_details.MRP,
        sales_order_details.HSNMasterId,
        sales_order_details.HSNCODE,
        sales_order_details.SaleTax,
        sales_order_details.CGST,
        sales_order_details.IGST,
        sales_order_details.SGST,
