DELIMITER $$
CREATE PROCEDURE `Get_Sales_Receipt`
BEGIN
declare Account_Party_Id_ int;
set Account_Party_Id_=(select To_Account_Id from Receipt_Voucher where Receipt_Voucher_Id=Receipt_Voucher_Id_
and DeleteStatus=0);

Select distinct Sales_Master.Sales_Master_Id,Invoice_No,
(Date_Format(Sales_Master.PurchaseDate,'%Y-%m-%d')) As Date ,
COALESCE( (Sales_Master.NetTotal ),0) NetTotal,COALESCE( (Sales_Receipt.Receiving_Amount ),0) Receiving_Amount,
COALESCE( (Sales_Receipt.Discount ),0) Discount,
 COALESCE(NetTotal,0)-(COALESCE(sum(Sales_Receipt.Receiving_Amount),0)+
 COALESCE(SUM(Sales_Receipt.Discount),0)) as BalAmt,Receipt_Voucher_Id,
case when Check_Box>0 then 1 else 0 end as Check_Box
from Sales_Master 
left join Sales_Receipt on Sales_Receipt.Sales_Master_Id=Sales_Master.Sales_Master_Id 
and Sales_Receipt.DeleteStatus=0
where Sales_Master.DeleteStatus=0 AND Sales_Master.Account_Party_Id=Account_Party_Id_

group by Sales_Master.Sales_Master_Id,Date,Invoice_No,NetTotal
having COALESCE(NetTotal,0)-(COALESCE(sum(Sales_Receipt.Receiving_Amount),0)+
COALESCE(SUM(Sales_Receipt.Discount),0))!=0
union
Select distinct Sales_Master.Sales_Master_Id,Invoice_No,
(Date_Format(Sales_Master.PurchaseDate,'%Y-%m-%d')) As Date ,
COALESCE( (Sales_Master.NetTotal ),0) NetTotal,COALESCE( (Sales_Receipt.Receiving_Amount ),0) Receiving_Amount,
COALESCE( (Sales_Receipt.Discount ),0) Discount,
 COALESCE(NetTotal,0)-(COALESCE(sum(Sales_Receipt.Receiving_Amount),0)+
 COALESCE(SUM(Sales_Receipt.Discount),0)) as BalAmt,Receipt_Voucher_Id,
case when Check_Box>0 then 1 else 0 end as Check_Box
from Sales_Master
inner join Sales_Receipt on Sales_Receipt.Sales_Master_Id=Sales_Master.Sales_Master_Id 
 and Sales_Receipt.Receipt_Voucher_Id=Receipt_Voucher_Id_
where Sales_Receipt.DeleteStatus=0 and Sales_Master.Account_Party_Id=Account_Party_Id_ and
Sales_Master.Sales_Master_Id in(select Sales_Receipt.Sales_Master_Id from Sales_Receipt
 where Receipt_Voucher_Id=Receipt_Voucher_Id_);
 
END
$$
DELIMITER ;

