CREATE PROCEDURE `Get_Sales_summary`
Begin 
 declare Search_Date_ varchar(500);
declare SearchbyName_Value varchar(2000);
set Search_Date_="";
set SearchbyName_Value="";
	if Is_Date_Check_=true then
		set Search_Date_=concat( " and Sales_Master.Bill_Date >= '", FromDate_ ,"' and  Sales_Master.Bill_Date <= '", ToDate_,"'");
	end if;
	if Client_Id_>0 then
		SET SearchbyName_Value =concat(SearchbyName_Value," and Sales_Master.Account_Party_Id =",Client_Id_);
	end if;
	if VoucherType_>0 then
		SET SearchbyName_Value =concat(SearchbyName_Value," and Concat( Sales_Master.Invoice_No ,'')  =",VoucherType_);
	end if;
	if Employee_Id_>0 then
		SET SearchbyName_Value =concat(SearchbyName_Value," and Sales_Master.Employee_Id =",Employee_Id_);
	end if;
    
SET @query = Concat("SELECT Sales_Master_Id,(Date_Format(Bill_Date,'%Y-%m-%d')) As Bill_Date,
Invoice_No,GrossTotal,TotalDiscount,NetTotal,TotalAmount,Bill_Type_Name,BillType,Account_Party_Id,
