	inner join Client_Accounts ON Sales_Master.Account_Party_Id=Client_Accounts.Client_Accounts_Id 
	inner join Client_Accounts as Emp ON Sales_Master.Account_Party_Id=Emp.Client_Accounts_Id 
	inner join Bill_Type ON Sales_Master.BillType=Bill_Type.Bill_Type_Id
WHERE Sales_Master.DeleteStatus =false", Search_Date_ ,SearchbyName_Value,"");

PREPARE QUERY FROM @query;
EXECUTE QUERY;
  #select @query;
