 ItemName,GroupId,GroupName,UnitId,UnitName,PurchaseRate,SaleRate,MRP,HSNMasterId,
 HSNCODE,SaleTax,Quantity,Quantity as Availability, Country_Id,Country_Name  From Stock;*/

