CREATE PROCEDURE `Item_Expiry_Report`
BEGIN

declare Search_Date_ varchar(500);
declare SearchbyName_Value varchar(2000);
set Search_Date_='';
set SearchbyName_Value="";
	if Is_Date_Check_=true then
		set Search_Date_=concat( " and Stock.Expiry_Date >= '", From_Date_ ,"' and  Stock.Expiry_Date <= '", To_Date_,"'");
	end if;
	if Barcode_!='' then
		SET SearchbyName_Value =   Concat( " and Stock.Barcode like '%",Barcode_ ,"%'") ;
	end if;
	if GroupId_>0 then
