	if ItemId_>0 then
		SET SearchbyName_Value =concat(SearchbyName_Value," and Stock.ItemId =",ItemId_);
	end if;
	if Employee_Id_>0 then
		SET SearchbyName_Value =concat(SearchbyName_Value," and Stock_Details.To_Employee_Id =",Employee_Id_);
	end if;

	SET @query = Concat("SELECT Stock.Stock_Id,Barcode,ItemId,ItemName,GroupId,GroupName,
	Stock_Details.Quantity,PurchaseRate,Stock.SaleRate,Stock.MRP,Stock.SaleTax,Stock.SGST,
