CREATE PROCEDURE `Ledger_Report`
Begin
declare Sumdr decimal(18,2);
declare Sumcr decimal(18,2);
declare Sum decimal(18,2);
declare curdr decimal(18,2);
declare curcr decimal(18,2);
declare cursum decimal(18,2);
declare cbdr decimal(18,2);
declare cbcr decimal(18,2);
declare bal decimal(18,2);
declare Ac_Opn decimal(18,2);
set Ac_Opn=(select Opening_Balance from Client_Accounts where Client_Accounts.Client_Accounts_Id=Client_Id_);
set Sumdr=(select SUM(Dr) from Accounts where Accounts.Client_Id=Client_Id_ and
Date_Format(Accounts.Entry_Date,'%Y-%m-%d')< Date_Format(FromDate_,'%Y-%m-%d')
and VoucherType= (case when VoucherType_ >0 then VoucherType_ else VoucherType end)); 
set Sumcr=(select SUM(Cr) from Accounts where Accounts.Client_Id=Client_Id_ and
Date_Format(Accounts.Entry_Date,'%Y-%m-%d')< Date_Format(FromDate_,'%Y-%m-%d')
and VoucherType=(case when VoucherType_ >0 then VoucherType_ else VoucherType end ));
 if Sumdr is null then
set Sumdr=0;
end if;
if Sumcr is null then
set Sumcr=0;
end if;
set Sum=(Sumdr-Sumcr)+Ac_Opn;
set curdr=(select SUM(Dr) from Accounts where Accounts.Client_Id=Client_Id_ and
Date_Format(Accounts.Entry_Date,'%Y-%m-%d') between Date_Format(FromDate_,'%Y-%m-%d') and Date_Format(ToDate_,'%Y-%m-%d')
and VoucherType=(case  when VoucherType_ >0 then VoucherType_ else VoucherType end ));
set curcr=(select SUM(Cr) from Accounts where Accounts.Client_Id=Client_Id_ and
Date_Format(Accounts.Entry_Date,'%Y-%m-%d') between Date_Format(FromDate_,'%Y-%m-%d') and Date_Format(ToDate_,'%Y-%m-%d') 
and VoucherType=(case when VoucherType_ >0 then VoucherType_ else VoucherType end ));
if curdr is null then
set curdr=0;
end if;
if curcr is null then
set curcr=0;
end if;
set cursum=(curdr-curcr);
if cursum is null then
set cursum=0;
end if;
if Sum is null then
set Sum=0;
end if;
set bal=Sum+cursum;
if bal is null then
set bal=0;
end if;

Select 1 as SlNo,(Date_Format(FromDate_,'%Y-%m-%d')) As Date,'' as Particular,'' as Narration,
'Opening Balance' VoucherType,'' as VoucherNo,(case when Sum>0 then Sum else 0 end)Dr,
(case when Sum<0 then -1*Sum else 0 end)Cr
union

Select 2 as SlNo, (Date_Format(Accounts.Entry_Date,'%Y-%m-%d')) As Date, SecondAccount.Client_Accounts_Name as Particular,
Accounts.Description1+','+accounts.Status as Narration,Voucher_Type.Voucher_Type_Name VoucherType,Accounts.Voucher_No
 as VoucherNo, Accounts.Dr,Accounts.Cr from Accounts 
 inner join Client_Accounts as FirstAccount  on FirstAccount.Client_Accounts_Id=Accounts.Client_Id 
 inner join Client_Accounts as SecondAccount on SecondAccount.Client_Accounts_Id=Accounts.X_Client_Id 
 inner join Voucher_Type on Accounts.VoucherType=Voucher_Type.Voucher_Type_Id
where Accounts.Client_Id=Client_Id_ and Date_Format(Accounts.Entry_Date,'%Y-%m-%d') 
between Date_Format(FromDate_,'%Y-%m-%d') and Date_Format(ToDate_,'%Y-%m-%d') 
and VoucherType=(case when VoucherType_ >0 then VoucherType_ else VoucherType end )
union

Select 3 as SlNo,(Date_Format(FromDate_,'%Y-%m-%d')) As Date,'' as Particular,'' as Narration,
'Total' VoucherType,'' as VoucherNo,(case when curdr>0 then curdr else -1*curdr end)Dr,
(case when curcr<0 then -1*curcr else curcr end)Cr
union

select 4 as Slno,(Date_Format(ToDate_,'%Y-%m-%d')) As Date,'' Particular,'' as Narration,'Closing Balance' 
as VoucherType,'' as VoucherNo,(case when bal>0 then bal else 0 end)Dr,
(case when bal<0 then -1*bal else 0 end)Cr 
order by SlNo, Date;
End
$$
DELIMITER ;

