CREATE PROCEDURE `Load_B2B_SaleTax_Report`
Begin
declare data_status decimal(18,0);declare MastId_ int;Declare Date_ datetime;Declare Party_ varchar(200);Declare Bilno_ varchar(100);
Declare gstin_ varchar(100);Declare 0net_ decimal(18,2) default 0;declare 5net_ decimal(18,2) default 0;declare 2p5cgst_ decimal(18,2) default 0;
declare 2p5sgst_ decimal(18,2) default 0;declare 12net_ decimal(18,2) default 0;declare 6cgst_ decimal(18,2) default 0;declare 6sgst_ decimal(18,2) default 0;
declare 18net_ decimal(18,2) default 0;declare 9cgst_ decimal(18,2) default 0;declare 9sgst_ decimal(18,2) default 0;declare 28net_ decimal(18,2) default 0;
declare 14cgst_ decimal(18,2) default 0;declare 14sgst_ decimal(18,2) default 0;declare trans_charge_ decimal(18,2) default 0;declare trans_gst_ decimal(18,2) default 0;
declare hand_charge_ decimal(18,2) default 0;declare hand_gst_ decimal(18,2) default 0;declare roundoff_ decimal(18,2) default 0;DECLARE done INT DEFAULT 0;
DECLARE  Cur CURSOR FOR select  Sales_master.Sales_Master_Id, (Date_Format(Bill_Date,'%Y-%m-%d')) Bill_Date,client_accounts.Client_Accounts_Name,Invoice_No,
client_accounts.GSTNo,COALESCE(Transportation_Charge,0),COALESCE(Transportation_Gst,0),COALESCE(Handling_Charge,0),COALESCE(Handling_Gst,0),Roundoff
from Sales_master inner join client_accounts on Sales_master.Account_Party_Id=client_accounts.Client_Accounts_Id
where Sales_Master.Bill_Date >= From_Date_ and Sales_Master.Bill_Date <= To_Date_ and BillType=1 and Sales_master.DeleteStatus=0
order by Sales_master.Sales_Master_Id asc;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;
delete from Sale_Tax;
Open Cur;
read_loop: LOOP
FETCH Cur INTO MastId_,Date_,Party_,Bilno_,gstin_,trans_charge_,trans_gst_,hand_charge_,hand_gst_,roundoff_;
IF done = 1 THEN
LEAVE read_loop;
END IF;
set 0net_=(select COALESCE(sum(Sales_details.NetValue),0) from Sales_details where Sales_details.Sales_Master_Id=MastId_ and Sales_details.DeleteStatus=0
and Sales_details.SaleTax=0.00 group by  Sales_details.SaleTax);
set 5net_=(select COALESCE(sum(Sales_details.NetValue),0) from Sales_details where Sales_details.Sales_Master_Id=MastId_ and Sales_details.DeleteStatus=0
and  Sales_details.SaleTax=5.00 group by  Sales_details.SaleTax);
set 2p5cgst_=(select COALESCE(sum(Sales_details.CGSTAmt),0) from Sales_details where Sales_details.Sales_Master_Id=MastId_ and Sales_details.DeleteStatus=0
and  Sales_details.CGST=2.50 group by  Sales_details.CGST);
set 2p5sgst_=(select COALESCE(sum(Sales_details.SGSTAmt),0) from Sales_details where Sales_details.Sales_Master_Id=MastId_ and Sales_details.DeleteStatus=0
and  Sales_details.SGST=2.50 group by  Sales_details.SGST);
set 12net_=(select COALESCE(sum(Sales_details.NetValue),0) from Sales_details where Sales_details.Sales_Master_Id=MastId_ and Sales_details.DeleteStatus=0
and Sales_details.SaleTax=12.00 group by  Sales_details.SaleTax);
set 6cgst_=(select COALESCE(sum(Sales_details.CGSTAmt),0) from Sales_details where Sales_details.Sales_Master_Id=MastId_ and Sales_details.DeleteStatus=0
and Sales_details.CGST=6.00 group by  Sales_details.CGST);
set 6sgst_=(select COALESCE(sum(Sales_details.SGSTAmt),0) from Sales_details where Sales_details.Sales_Master_Id=MastId_ and Sales_details.DeleteStatus=0
and Sales_details.SGST=6.00 group by  Sales_details.SGST);
set 18net_=(select COALESCE(sum(Sales_details.NetValue),0) from Sales_details where Sales_details.Sales_Master_Id=MastId_ and Sales_details.DeleteStatus=0
and Sales_details.SaleTax=18 group by  Sales_details.SaleTax);
set 9cgst_=(select COALESCE(sum(Sales_details.CGSTAmt),0) from Sales_details where Sales_details.Sales_Master_Id=MastId_ and Sales_details.DeleteStatus=0
and Sales_details.CGST=9 group by  Sales_details.CGST);
set 9sgst_=(select COALESCE(sum(Sales_details.SGSTAmt),0) from Sales_details where Sales_details.Sales_Master_Id=MastId_ and Sales_details.DeleteStatus=0
