CREATE PROCEDURE `Load_Daybook_Report`
BEGIN
select (Date_Format(accounts.Entry_Date,'%Y-%m-%d')) As Entry_Date,Client_Id,Voucher_No,X_Client_Id,VoucherType,
accounts.Description1,Status,To_Party.Client_Accounts_Name  To_Party_Name,
From_Party.Client_Accounts_Name   From_Party_Name,Voucher_Type_Name
from accounts
inner join  client_accounts From_Party on accounts.Client_Id=From_Party.Client_Accounts_Id
inner join  client_accounts To_Party on accounts.X_Client_Id=To_Party.Client_Accounts_Id
inner join  voucher_type on accounts.VoucherType=voucher_type.Voucher_Type_Id
where Date_Format(Accounts.Entry_Date,'%Y-%m-%d') 
between Date_Format(FromDate_,'%Y-%m-%d') and Date_Format(ToDate_,'%Y-%m-%d') and DayBook='Y';
End
$$
