CREATE PROCEDURE `Load_DeliveryOrder`
Begin 
  SELECT DISTINCT
        deliveryordermaster.*,
        DATE_FORMAT(deliveryordermaster.EntryDate, '%d-%m-%Y') AS FormattedEntryDate,
		DATE_FORMAT(deliveryordermaster.EntryDate, '%d-%m-%Y') AS PrintDate,
        deliveryordermaster.DONo as QuotationNo,
        client_accounts.Client_Accounts_Name AS Customer,
        currencydetails.currecnyName AS CurrencyName,
        accounttype.AccountType_Name AS AccountType_Name,
        deliveryordermaster.TypeId AS AccountType_Id,
        deliveryordermaster.CurrencyId AS CurrencyDetails_Id,
        deliveryordermaster.Payment_Term_Value AS payment_Term_Value,
        client_accounts.Address1,
        client_accounts.Address2,
        client_accounts.Address3,
        client_accounts.Address4,
        client_accounts.GSTNo,client_accounts.Phone,client_accounts.Mobile,client_accounts.Email,
        IFNULL(qdo.SalesQuotationMaster_Id,0) SalesQuotationMaster_Id
    FROM deliveryordermaster 
    INNER JOIN deliveryorderdetails ON deliveryordermaster.DeliveryOrderMaster_Id = deliveryorderdetails.DeliveryMaster_Id
    INNER JOIN client_accounts ON deliveryordermaster.Account_Party_Id = client_accounts.Client_Accounts_Id 
    LEFT JOIN currencydetails ON deliveryordermaster.CurrencyId = currencydetails.CurrencyDetails_Id
    LEFT JOIN accounttype ON deliveryordermaster.TypeId = accounttype.AccountType_Id
    LEFT JOIN quotation_delivery_order qdo ON qdo.DeliveryOrderMaster_Id = deliveryordermaster.DeliveryOrderMaster_Id
    WHERE deliveryordermaster.DeleteStatus = FALSE 
    and deliveryordermaster.DeliveryOrderMaster_Id = DeliveryOrderMaster_Id_;
 End
$$
DELIMITER ;

