CREATE PROCEDURE `Load_Delivery_Items_Pending_List_ByQuotation`
BEGIN
	declare tempItem_Id numeric(18,0);	declare tempItem_code  nvarchar(500);	declare tempItem_Name nvarchar(500);	declare tempGroupName varchar(200);
	declare tempUnitPrice decimal(18,2);	declare tempQuantity numeric(18,3);   declare fetch_status decimal(18,0); 
    Declare Cur Cursor for select ItemId,IFNULL(sum(Quantity),0)Quantity from deliveryorderdetails
where DeleteStatus=0 and DeliveryMaster_Id  in(select distinct DeliveryOrderMaster_Id from quotation_delivery_order where DeleteStatus=0
and SalesQuotationMaster_Id =SalesQuotationMaster_Id_)
group by ItemId;#,ItemCode,ItemName,GroupName,UnitPrice;

DROP TEMPORARY TABLE IF EXISTS temp_1;
CREATE TEMPORARY TABLE temp_1(
ItemId numeric(18, 0) ,
ItemCode nvarchar(500) ,
ItemName nvarchar(500),
GroupName varchar(200),
UnitPrice decimal(18,2),
Quantity numeric(18,3)
);
insert into temp_1
select ItemId,ItemCode,ItemName,GroupName,UnitPrice,IFNULL(Quantity,0) from salesquotationdetails
where DeleteStatus=0 and QuotationMaster_Id=SalesQuotationMaster_Id_;
#group by ItemId,ItemCode,ItemName,GroupName,UnitPrice;
Open Cur;
Fetch next from Cur into tempItem_Id, tempQuantity;#, tempItem_code, tempItem_Name, tempGroupName, tempUnitPric;
While(fetch_status!=0) do
begin
	update temp_1 set  Quantity =Quantity-tempQuantity 
	where  ItemId =tempItem_Id;#   and ItemCode =tempItem_code and ItemName =tempItem_Name   and GroupName =tempGroupName   and UnitPrice =tempUnitPrice;	   
    	set fetch_status=fetch_status-1;
         if(fetch_status != 0)
			then
				 Fetch next from Cur into tempItem_Id, tempQuantity;#, tempItem_code, tempItem_Name, tempGroupName, tempUnitPrice, tempQuantity; 
			end if;
End;
END WHILE;
close Cur;
select * from temp_1 where Quantity>0;
DROP TEMPORARY TABLE temp_1;
END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Load_Delivery_Items_Pending_List_ByQuotation_new`
BEGIN
    -- Create temporary table for quotation details
    DROP TEMPORARY TABLE IF EXISTS temp_quotation_items;
    CREATE TEMPORARY TABLE temp_quotation_items (
        ItemId NUMERIC(18, 0),
        ItemCode NVARCHAR(500),
        ItemName NVARCHAR(500),
        GroupName VARCHAR(200),
        UnitPrice DECIMAL(18,3),
        Quantity DECIMAL(18,3)
    );

    -- Insert initial quantities from quotation details
    INSERT INTO temp_quotation_items
    SELECT 
        ItemId, 
        ItemCode, 
        ItemName, 
        GroupName, 
        UnitPrice,
        COALESCE(SUM(Quantity), 0) AS Quantity 
    FROM salesquotationdetails
    WHERE DeleteStatus = 0 
    AND QuotationMaster_Id = SalesQuotationMaster_Id_
    GROUP BY ItemId, ItemCode, ItemName, GroupName, UnitPrice;

    -- Create temporary table for sales details
    DROP TEMPORARY TABLE IF EXISTS temp_sales_items;
    CREATE TEMPORARY TABLE temp_sales_items (
        ItemId NUMERIC(18, 0),
        ItemCode NVARCHAR(500),
        ItemName NVARCHAR(500),
        GroupName VARCHAR(200),
        UnitPrice DECIMAL(18,3),
        Quantity DECIMAL(18,3)
    );

    -- Insert quantities from sales details
    INSERT INTO temp_sales_items
    SELECT 
        ItemId,
        ItemCode,
        ItemName,
        GroupName,
        UnitPrice,
        COALESCE(SUM(Quantity), 0) AS Quantity 
    FROM deliveryorderdetails
    WHERE DeleteStatus = 0 
    AND DeliveryMaster_Id IN (
        SELECT DISTINCT DeliveryOrderMaster_Id 
        FROM quotation_delivery_order 
        WHERE DeleteStatus = 0
        AND SalesQuotationMaster_Id = SalesQuotationMaster_Id_
    )
    GROUP BY ItemId, ItemCode, ItemName, GroupName, UnitPrice;
    


    -- Update quantities in one operation
    UPDATE temp_quotation_items tq
    LEFT JOIN temp_sales_items ts ON 
        ts.ItemId = tq.ItemId AND
        ts.ItemCode = tq.ItemCode AND
        ts.ItemName = tq.ItemName AND
        ts.GroupName = tq.GroupName AND
        ts.UnitPrice = tq.UnitPrice
    SET tq.Quantity = tq.Quantity - coalesce(ts.Quantity,0);
    
    


    -- Return results
    SELECT 
        ItemId,
        ItemCode,
        ItemName,
        GroupName,
        UnitPrice,
        Quantity
    FROM temp_quotation_items 
    WHERE Quantity > 0;
    


    -- Clean up
    DROP TEMPORARY TABLE IF EXISTS temp_quotation_items;
    DROP TEMPORARY TABLE IF EXISTS temp_sales_items;
END
$$
DELIMITER ;

