CREATE PROCEDURE `Load_GRN_Items_Pending_List_ByPO`
BEGIN
    SELECT JSON_ARRAYAGG(
        JSON_OBJECT(
            'ItemId', remaining_items.ItemId,
            'ItemCode', remaining_items.ItemCode,
            'ItemName', remaining_items.ItemName,
            'GroupName', remaining_items.GroupName,
            'UnitPrice', remaining_items.UnitPrice,
            'RemainingQuantity', remaining_items.RemainingQuantity
        )
    ) AS RemainingItems
    FROM (
        SELECT 
            pod.ItemId,
            pod.ItemCode,
            pod.ItemName,
            pod.GroupName,
            pod.UnitPrice,
            (pod.Quantity - COALESCE(SUM(pd.Quantity), 0)) AS RemainingQuantity
        FROM 
            purchaseorderdetails pod
        LEFT JOIN 
            purchaseorder_purchasemaster pom ON pod.PurchaseOrderId = pom.PurchaseOrderMaster_Id
        LEFT JOIN 
            purchase_details pd ON pom.PurchaseMaster_Id = pd.Purchase_Master_Id
            AND pod.ItemId = pd.ItemId
        WHERE 
            pod.PurchaseOrderId = Purchase_OrderMaster_Id_
        GROUP BY 
            pod.ItemId, pod.ItemCode, pod.ItemName, pod.GroupName, pod.UnitPrice, pod.Quantity
        HAVING 
            RemainingQuantity > 0
    ) AS remaining_items;

END
$$
DELIMITER ;

