DELIMITER $$
CREATE PROCEDURE `Load_GRn_Pending_List_ByPurchaseOrder_new`
BEGIN
    -- Create temporary table for quotation details
    DROP TEMPORARY TABLE IF EXISTS temp_quotation_items;
    CREATE TEMPORARY TABLE temp_quotation_items (
        ItemId NUMERIC(18, 0),
        ItemCode NVARCHAR(500),
        ItemName NVARCHAR(500),
        GroupName VARCHAR(200),
        UnitPrice DECIMAL(18,2),
        Quantity NUMERIC(18,3)
    );

    -- Insert initial quantities from quotation details
    INSERT INTO temp_quotation_items
    SELECT 
        ItemId, 
        ItemCode, 
        ItemName, 
        GroupName, 
        UnitPrice,
        IFNULL(SUM(Quantity), 0) AS Quantity 
    FROM purchaseorderdetails
    WHERE DeleteStatus = 0 
    AND PurchaseOrderId = SalesQuotationMaster_Id_
    GROUP BY ItemId, ItemCode, ItemName, GroupName, UnitPrice;

    -- Create temporary table for sales details
    DROP TEMPORARY TABLE IF EXISTS temp_sales_items;
    CREATE TEMPORARY TABLE temp_sales_items (
        ItemId NUMERIC(18, 0),
        ItemCode NVARCHAR(500),
        ItemName NVARCHAR(500),
        GroupName VARCHAR(200),
        UnitPrice DECIMAL(18,2),
        Quantity NUMERIC(18,3)
    );

    -- Insert quantities from sales details
    INSERT INTO temp_sales_items
    SELECT 
        ItemId,
        Item_Code as ItemCode,
        ItemName,
        GroupName,
        UnitPrice,
        COALESCE(SUM(Quantity), 0) AS Quantity 
    FROM purchase_details
    WHERE DeleteStatus = 0 
    AND Purchase_Master_Id IN (
        SELECT DISTINCT PurchaseMaster_Id 
        FROM purchaseorder_purchasemaster 
        WHERE DeleteStatus = 0
        AND PurchaseOrderMaster_Id = SalesQuotationMaster_Id_
    )
    GROUP BY ItemId, ItemCode, ItemName, GroupName, UnitPrice;

    -- Update quantities in one operation
    UPDATE temp_quotation_items tq
    LEFT JOIN temp_sales_items ts ON 
        ts.ItemId = tq.ItemId AND
        ts.ItemCode = tq.ItemCode AND
        ts.ItemName = tq.ItemName AND
        ts.GroupName = tq.GroupName AND
        ts.UnitPrice = tq.UnitPrice
    SET tq.Quantity = tq.Quantity - IFNULL(ts.Quantity, 0);

    -- Return results
    SELECT 
        ItemId,
        ItemCode,
        ItemName,
        GroupName,
        UnitPrice,
        Quantity
    FROM temp_quotation_items 
    WHERE Quantity > 0;

    -- Clean up
    DROP TEMPORARY TABLE IF EXISTS temp_quotation_items;
    DROP TEMPORARY TABLE IF EXISTS temp_sales_items;
END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Load_GRn_Pending_List_ByPurchaseOrder_old`
BEGIN
    SELECT JSON_ARRAYAGG(
        JSON_OBJECT(
            'ItemId', ItemId,
            'ItemCode', ItemCode,
            'ItemName', ItemName,
            'GroupName',GroupName,
            'UnitPrice',UnitPrice,
            'RemainingQuantity', RemainingQuantity
        )
    ) AS RemainingItems
    FROM (
        SELECT 
            sq.ItemId,
            sq.ItemCode,
            sq.ItemName,
            sq.GroupName,
            sq.UnitPrice,
            (sq.Quantity - COALESCE(SUM(pid.Quantity), 0)) AS RemainingQuantity
        FROM 
            purchaseorderdetails sq
        LEFT JOIN 
            purchaseorder_purchasemaster qp ON sq.PurchaseOrderId = qp.PurchaseOrderMaster_Id
        LEFT JOIN 
            purchase_details pid ON qp.PurchaseMaster_Id = pid.Purchase_Master_Id
            AND sq.ItemId = pid.ItemId
        WHERE 
            sq.PurchaseOrderId = Purchase_OrderMaster_Id_
        GROUP BY 
            sq.PurchaseOrderId, sq.ItemId, sq.ItemCode, sq.ItemName, sq.Quantity, sq.GroupName, sq.UnitPrice
        HAVING 
            RemainingQuantity > 0
    ) AS remaining_items;
END
$$
DELIMITER ;

