CREATE PROCEDURE `Load_Hsn_Purchase_Report`
Begin
declare data_status decimal(18,0) ;
select purchase_details.HSNCODE,purchase_details.ItemName,UnitName,purchase_details.PurchaseRate,sum(purchase_details.Quantity)as Quantity,sum(purchase_details.NetValue)as NetValue,
CGST as 'CGST %',sum(purchase_details.CGST_Amt)as CGST,SGST AS 'SGST %',sum(purchase_details.SGST_Amt)as SGST,
IGST AS 'IGST %',sum(purchase_details.IGST_Amt)as IGST,SaleTax AS 'GST %',sum(purchase_details.GST_Amount)as GST,
(sum(purchase_details.NetValue)+sum(purchase_details.CGST_Amt)+sum(purchase_details.SGST_Amt))as Total
from purchase_details inner join purchase_master
on purchase_master.Purchase_Master_Id=purchase_details.Purchase_Master_Id
where  Purchase_Master.PurchaseDate >= From_Date_ and Purchase_Master.PurchaseDate <= To_Date_  
and purchase_master.DeleteStatus=0
Group by HSNCODE,ItemName,UnitName,PurchaseRate,CGST,SGST,IGST
union
select purchase_master.HSNCODE,'' as ItemName,'No' as UnitName,0 as PurchaseRate,1 as Quantity,(sum(Handling_Charge)+sum(Transportation_Charge))as NetValue,
Tax_Pers/2 as 'CGST %' ,(sum(Transportation_Gst)+sum(Handling_Gst))/2 as CGST,Tax_Pers/2 as 'SGST %',(sum(Transportation_Gst)+sum(Handling_Gst))/2 as SGST,
0 as 'IGST %',0 as IGST,Tax_Pers as 'GST %',(sum(Transportation_Gst)+sum(Handling_Gst))as GST,
(sum(Transportation_Total)+sum(Handling_Total))as Total
from Purchase_Master
where Purchase_Master.PurchaseDate >= From_Date_ and Purchase_Master.PurchaseDate <= To_Date_  
and purchase_master.DeleteStatus=0 and Isgst=1;
end
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Load_Hsn_Purchase_Return_Report`
Begin
declare data_status decimal(18,0) ;

select HSNCODE, UnitName, sum(Purchase_Return_details.NetValue) NetValue,sum(Purchase_Return_details.Quantity) Quantity,
CGST,sum(Purchase_Return_details.CGST_Amt) CGST_Amt,SGST,sum(Purchase_Return_details.SGST_Amt) SGST_Amt,
IGST,sum(Purchase_Return_details.IGST_Amt),SaleTax,sum(Purchase_Return_details.GST_Amount) GST_Amount,
(sum(Purchase_Return_details.NetValue)+sum(Purchase_Return_details.CGST_Amt)+sum(Purchase_Return_details.SGST_Amt)) Total
from Purchase_Return_details
inner join Purchase_Return_master on Purchase_Return_master.Purchase_Return_Master_Id=Purchase_Return_details.Purchase_Return_Master_Id
where   Purchase_Return_Master.PurchaseDate >= From_Date_  and  Purchase_Return_Master.PurchaseDate <= To_Date_  
and Purchase_Return_master.DeleteStatus=0
Group by HSNCODE,UnitName,CGST_Amt,SGST_Amt
order by GST_Amount asc;
end
$$
DELIMITER ;

