CREATE PROCEDURE `Load_Hsn_Sales_Report`
Begin
declare data_status decimal(18,0) ;
select Sales_details.HSNCODE,ItemName,UnitName,SaleRate,sum(Sales_details.NetValue)as NetValue,sum(Sales_details.Quantity)as Quantity,
CGST as 'CGST %',sum(Sales_details.CGSTAMT)as CGST,SGST as 'SGST %',sum(Sales_details.SGSTAMT)as SGST,SaleTax as 'GST %',sum(Sales_details.TaxAmount)as GST,
(sum(Sales_details.NetValue)+sum(Sales_details.CGSTAMT)+sum(Sales_details.SGSTAMT)) Total
from Sales_details inner join Sales_master on Sales_master.Sales_Master_Id=Sales_details.Sales_Master_Id
where Sales_Master.Bill_Date >= From_Date_ and Sales_Master.Bill_Date <= To_Date_  
and Sales_master.DeleteStatus=0
group by HSNCODE,ItemName,UnitName,SaleRate,CGST,SGST,SaleTax
union
select Sales_Master.HSNCODE,'' as ItemName,'No' as UnitName,0 as SaleRate,Sum(Transportation_Charge+Handling_Charge)as NetValue,count(Sales_Master_Id)as Quantity,Tax_Pers/2 as 'CGST %',
(sum(Transportation_Gst+Handling_Gst)/2)as CGST,Tax_Pers/2 as 'SGST %',(sum(Transportation_Gst+Handling_Gst)/2)as SGST,
Tax_Pers as 'GST %',sum(Transportation_Gst+Handling_Gst)as GST,SUM(Transportation_Total+Handling_Total)as Total
from Sales_master
where Sales_Master.Bill_Date >= From_Date_ and Sales_Master.Bill_Date <= To_Date_  
and Sales_master.DeleteStatus=0 and Isgst=1;
end
$$
DELIMITER ;

