CREATE PROCEDURE `Load_NewBill`
Begin
 declare  YearFrom datetime;declare  YearTo datetime;declare Voucher_No_ varchar(100);
    set YearFrom=(select Account_Years.YearFrom from Account_Years where  
	Date_Format(Bill_Date_,'%Y-%m-%d') between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') 
    and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));
	set YearTo=(select Account_Years.YearTo from Account_Years where 
	Date_Format(Bill_Date_,'%Y-%m-%d') between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') 
    and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));    
if exists(select distinct Invoice_No from Sales_Master)then
	set Voucher_No_=(SELECT COALESCE( MAX(Invoice_No ),0)+1 FROM Sales_Master
	where BillType=BillType_ and Date_Format(Bill_Date_,'%Y-%m-%d') between Date_Format(YearFrom,'%Y-%m-%d') 
    and Date_Format(YearTo,'%Y-%m-%d'));  
else 
	if exists(select Invoice_No from General_Settings)
	then
		set Voucher_No_=(select COALESCE(Invoice_No,0) from General_Settings);
	else
		set Voucher_No_=1;
	end if;    
end if;
select Bill_Date_,YearFrom,YearTo,Voucher_No_;
 End
$$
DELIMITER ;

