CREATE PROCEDURE `Load_OutStanding_Report`
BEGIN
    -- Declare variables
    DECLARE v_opsalesdr DECIMAL(18,2);
    DECLARE v_oppurcr DECIMAL(18,2);
    DECLARE v_oppaydr DECIMAL(18,2);
    DECLARE v_opreccr DECIMAL(18,2);
    DECLARE v_opjurdr DECIMAL(18,2);
    DECLARE v_opcondr DECIMAL(18,2);
    DECLARE v_opdr DECIMAL(18,2);
    DECLARE v_opcr DECIMAL(18,2);
    DECLARE v_open DECIMAL(18,2);
    DECLARE v_opendr DECIMAL(18,2);
    DECLARE v_opencr DECIMAL(18,2);
    DECLARE v_OpBal DECIMAL(18,2);
    DECLARE v_cursalesdr DECIMAL(18,2);
    DECLARE v_curpurcr DECIMAL(18,2);
    DECLARE v_curpaydr DECIMAL(18,2);
    DECLARE v_curreccr DECIMAL(18,2);
    DECLARE v_curjurdr DECIMAL(18,2);
    DECLARE v_curcondr DECIMAL(18,2);
    DECLARE v_curdr DECIMAL(18,2);
    DECLARE v_curcr DECIMAL(18,2);
    DECLARE v_closebal DECIMAL(18,2);
    DECLARE v_closbaldr DECIMAL(18,2);
    DECLARE v_closbalcr DECIMAL(18,2);

    -- Set opening balance
    SET v_OpBal = IFNULL((SELECT Opening_Balance FROM ClientAccounts WHERE ClientAccounts_Id = Client_Id_), 0);

    -- Calculate opening balances
    SELECT IFNULL(SUM(NetTotal) - IFNULL(SUM(Receipt_Reference.amount), 0), 0) INTO v_opsalesdr
    FROM SalesMaster
    INNER JOIN AccountType ON AccountType.AccountType_Id = SalesMaster.TypeId
    AND DATE(SalesMaster.EntryDate) < DATE(FromDate_)
    INNER JOIN CurrencyDetails ON CurrencyDetails.CurrencyDetails_Id = SalesMaster.CurrencyId
    INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = SalesMaster.Account_Party_Id AND ClientAccounts.ClientAccounts_Id = Client_Id_
    LEFT JOIN Receipt_Reference ON Receipt_Reference.SalesId = SalesMaster.SalesMaster_Id
    AND Receipt_Reference.DeleteStatus = 'False'
    HAVING (SUM(NetTotal) - IFNULL(SUM(Receipt_Reference.amount), 0)) > 0;
   
    SELECT  IFNULL(SUM(NetTotal) - COALESCE(SUM(Payment_Reference.Amount), 0), 0) INTO v_oppurcr
FROM PurchaseMaster
INNER JOIN AccountType ON AccountType.AccountType_Id = PurchaseMaster.TypeId
AND DATE_FORMAT(PurchaseMaster.PurchaseDate, '%Y-%m-%d') < DATE_FORMAT(FromDate_, '%Y-%m-%d')
AND PurchaseMaster.DeleteStatus = 'false'
INNER JOIN CurrencyDetails ON CurrencyDetails.CurrencyDetails_Id = PurchaseMaster.CurrencyId
INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = PurchaseMaster.Account_Party_Id AND ClientAccounts_Id = Client_Id_
LEFT JOIN Payment_Reference ON Payment_Reference.PurchaseMaster_Id = PurchaseMaster.PurchaseMaster_Id
AND Payment_Reference.DeleteStatus = 'false'
HAVING SUM(NetTotal) - COALESCE(SUM(Payment_Reference.Amount), 0) > 0;
   
    SELECT  SUM(Amount) INTO v_oppaydr
FROM PaymentVoucher
INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = PaymentVoucher.To_Party_Id
WHERE ClientAccounts_Id = Client_Id_
AND DATE_FORMAT(PaymentVoucher.Date, '%Y-%m-%d') < DATE_FORMAT(FromDate_, '%Y-%m-%d')
AND PaymentVoucher.PaymentVoucher_Id NOT IN (SELECT Payment_Id FROM Payment_Reference)
AND PaymentVoucher.DeleteStatus = 'false';
   
    select  (sum(Amount)) INTO v_opreccr
from RecieptVoucher inner join ClientAccounts
on ClientAccounts.ClientAccounts_Id = RecieptVoucher.Frm_Party_Id
where ClientAccounts_Id = Client_Id_ and CAST(FLOOR(CAST(RecieptVoucher.Date AS float)) AS DATETIME) < CAST(FLOOR(CAST(FromDate_ AS float)) AS DATETIME)
and RecieptVoucher.DeleteStatus='False' and RecieptVoucher.RecieptVoucher_Id not in(select Receipt_Id from Receipt_Reference);
   
    SELECT  SUM(CASE WHEN Journal_Entry.ToAccount_Id = Client_Id_ THEN Journal_Entry.Amount ELSE 0 END) INTO v_opjurdr
FROM Journal_Entry
INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = Journal_Entry.ToAccount_Id
WHERE ClientAccounts_Id = Client_Id_
AND DATE_FORMAT(Journal_Entry.Date, '%Y-%m-%d') < DATE_FORMAT(FromDate_, '%Y-%m-%d')
AND Journal_Entry.DeleteStatus = 'False';
   
    SELECT  SUM(CASE WHEN ContraEntry.ToAccount_Id = Client_Id_ THEN ContraEntry.Amount ELSE 0 END) INTO v_opcondr
FROM ContraEntry
INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = ContraEntry.ToAccount_Id
WHERE ClientAccounts_Id = Client_Id_
AND DATE_FORMAT(ContraEntry.Date, '%Y-%m-%d') < DATE_FORMAT(FromDate_, '%Y-%m-%d')
AND ContraEntry.DeleteStatus = 'False';

   
    -- Calculate current balances
    SELECT IFNULL(SUM(NetTotal) - IFNULL(SUM(Receipt_Reference.amount), 0), 0) INTO v_cursalesdr
    FROM SalesMaster
    INNER JOIN AccountType ON AccountType.AccountType_Id = SalesMaster.TypeId
    AND DATE(SalesMaster.EntryDate) BETWEEN DATE(FromDate_) AND DATE(ToDate_)
    AND SalesMaster.DeleteStatus = 'false'
    INNER JOIN CurrencyDetails ON CurrencyDetails.CurrencyDetails_Id = SalesMaster.CurrencyId
    INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = SalesMaster.Account_Party_Id AND ClientAccounts.ClientAccounts_Id = Client_Id_
    LEFT JOIN Receipt_Reference ON Receipt_Reference.SalesId = SalesMaster.SalesMaster_Id
    AND Receipt_Reference.DeleteStatus = 'false'
    WHERE SalesMaster.TypeId = IF(TypeId_ > 0, TypeId_, SalesMaster.TypeId)
    HAVING (SUM(NetTotal) - IFNULL(SUM(Receipt_Reference.amount), 0)) > 0;
   
    SELECT  SUM(NetTotal) - COALESCE(SUM(Payment_Reference.Amount), 0) INTO v_curpurcr
FROM PurchaseMaster
INNER JOIN AccountType ON AccountType.AccountType_Id = PurchaseMaster.TypeId
AND DATE_FORMAT(PurchaseMaster.PurchaseDate, '%Y-%m-%d') BETWEEN DATE_FORMAT(FromDate_, '%Y-%m-%d') AND DATE_FORMAT(ToDate_, '%Y-%m-%d')
AND PurchaseMaster.DeleteStatus = 'false'
INNER JOIN CurrencyDetails ON CurrencyDetails.CurrencyDetails_Id = PurchaseMaster.CurrencyId
INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = PurchaseMaster.Account_Party_Id AND ClientAccounts_Id = Client_Id_
LEFT JOIN Payment_Reference ON Payment_Reference.PurchaseMaster_Id = PurchaseMaster.PurchaseMaster_Id
AND Payment_Reference.DeleteStatus = 'false'
HAVING SUM(NetTotal) - COALESCE(SUM(Payment_Reference.Amount), 0) > 0;
   
    SELECT  SUM(Amount) INTO v_curpaydr
FROM PaymentVoucher
INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = PaymentVoucher.To_Party_Id
WHERE ClientAccounts_Id = Client_Id_
AND DATE_FORMAT(PaymentVoucher.Date, '%Y-%m-%d') BETWEEN DATE_FORMAT(FromDate_, '%Y-%m-%d') AND DATE_FORMAT(ToDate_, '%Y-%m-%d')
AND PaymentVoucher.PaymentVoucher_Id NOT IN (SELECT Payment_Id FROM Payment_Reference)
AND PaymentVoucher.DeleteStatus = 'false';
   
    SELECT  SUM(Amount) INTO v_curreccr
FROM RecieptVoucher
INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = RecieptVoucher.Frm_Party_Id
WHERE ClientAccounts_Id = Client_Id_
AND DATE_FORMAT(RecieptVoucher.Date, '%Y-%m-%d') BETWEEN DATE_FORMAT(FromDate_, '%Y-%m-%d') AND DATE_FORMAT(ToDate_, '%Y-%m-%d')
AND RecieptVoucher.DeleteStatus = 'False'
AND RecieptVoucher.RecieptVoucher_Id NOT IN (SELECT Receipt_Id FROM Receipt_Reference);
   
    SELECT  SUM(CASE WHEN Journal_Entry.ToAccount_Id = Client_Id_ THEN Journal_Entry.Amount ELSE 0 END) INTO v_curjurdr
FROM Journal_Entry
INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = Journal_Entry.ToAccount_Id
WHERE ClientAccounts_Id = Client_Id_
AND DATE_FORMAT(Journal_Entry.Date, '%Y-%m-%d') BETWEEN DATE_FORMAT(FromDate_, '%Y-%m-%d') AND DATE_FORMAT(ToDate_, '%Y-%m-%d')
AND Journal_Entry.DeleteStatus = 'False';
   
    SELECT  SUM(CASE WHEN ContraEntry.ToAccount_Id = Client_Id_ THEN ContraEntry.Amount ELSE 0 END) INTO v_curcondr
FROM ContraEntry
INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = ContraEntry.ToAccount_Id
WHERE ClientAccounts_Id = Client_Id_
AND DATE_FORMAT(ContraEntry.Date, '%Y-%m-%d') BETWEEN DATE_FORMAT(FromDate_, '%Y-%m-%d') AND DATE_FORMAT(ToDate_, '%Y-%m-%d')
AND ContraEntry.DeleteStatus = 'False';

   

    -- Main logic based on voucher type
    -- Assuming variables are declared and set before this block
IF Voucher_ = 'All' THEN
    SET v_opdr = IFNULL(v_opsalesdr, 0) + IFNULL(v_oppaydr, 0) + IFNULL(v_opjurdr, 0) + IFNULL(v_opcondr, 0);
    SET v_opencr = IFNULL(v_oppurcr, 0) + IFNULL(v_opreccr, 0);
    SET v_open = IFNULL(v_opdr, 0) + IFNULL(v_OpBal, 0) - IFNULL(v_opencr, 0);
   
    IF v_open < 0 THEN
        SET v_opencr = -1 * IFNULL(v_open, 0);
        SET v_opendr = 0;
    ELSE
        SET v_opendr = IFNULL(v_open, 0);
        SET v_opencr = 0;
    END IF;
   
    -- current
    SET v_curdr = IFNULL(v_cursalesdr, 0) + IFNULL(v_curpaydr, 0) + IFNULL(v_curjurdr, 0) + IFNULL(v_curcondr, 0);
    SET v_curcr = IFNULL(v_curpurcr, 0) + IFNULL(v_curreccr, 0);
    SET v_closebal = (IFNULL(v_curdr, 0) + IFNULL(v_opendr, 0)) - (IFNULL(v_curcr, 0) + IFNULL(v_opencr, 0));
   
    IF v_closebal < 0 THEN
        SET v_closbaldr = 0;
        SET v_closbalcr = -1 * IFNULL(v_closebal, 0);
    ELSE
        SET v_closbaldr = IFNULL(v_closebal, 0);
        SET v_closbalcr = 0;
    END IF;
   
    SELECT * FROM (
        SELECT 1 AS SlNo, DATE_FORMAT(FromDate_, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Opening Balance' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, v_opendr AS Dr, v_opencr AS Cr
        UNION ALL
        SELECT 2 AS slno, DATE_FORMAT(EntryDate, '%d/%m/%Y') AS E_Date,
               DATE_FORMAT(DATE_ADD(EntryDate, INTERVAL PaymentTerms DAY), '%d/%m/%Y') AS Terms,
               DATEDIFF(CURDATE(), DATE_ADD(EntryDate, INTERVAL PaymentTerms DAY)) AS Date_Dif,
               Acc_Name AS Particular, InvNo AS VoucherNo, 'Sales' AS Voucher,
               CONCAT('lpo-', LPONo, ',Do-', DONo) AS Narration, CurrecnyName AS TransactionCurrency,
               AccountType_Name AS EntryMode, (NetTotal - IFNULL(SUM(Receipt_Reference.amount), 0)) AS Dr, 0 AS Cr
        FROM SalesMaster
        INNER JOIN AccountType ON AccountType.AccountType_Id = SalesMaster.TypeId
        AND EntryDate BETWEEN FromDate_ AND ToDate_ AND SalesMaster.DeleteStatus = 'false'
        INNER JOIN CurrencyDetails ON CurrencyDetails.CurrencyDetails_Id = SalesMaster.CurrencyId
        INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = SalesMaster.Account_Party_Id AND ClientAccounts_Id = Client_Id_
        LEFT JOIN Receipt_Reference ON Receipt_Reference.SalesId = SalesMaster.SalesMaster_Id
        AND Receipt_Reference.DeleteStatus = 'false'
        AND SalesMaster.TypeId = IF(TypeId_ > 0, TypeId_, SalesMaster.TypeId)
        AND SalesMaster.CurrencyId = IF(CurrencyId_ > 0, CurrencyId_, SalesMaster.CurrencyId)
        GROUP BY SalesMaster.SalesMaster_Id, SalesMaster.EntryDate, SalesMaster.PaymentTerms, ClientAccounts.Acc_Name,
                 SalesMaster.InvNo, LPONo, DONo, CurrecnyName, AccountType_Name, NetTotal
        HAVING (NetTotal - IFNULL(SUM(Receipt_Reference.amount), 0)) > 0
       
        UNION ALL
       
        SELECT 2 AS slno, DATE_FORMAT(PurchaseDate, '%d/%m/%Y') AS E_Date,
               DATE_FORMAT(DATE_ADD(PurchaseDate, INTERVAL PaymentTerms DAY), '%d/%m/%Y') AS Terms,
               DATEDIFF(CURDATE(), DATE_ADD(EntryDate, INTERVAL PaymentTerms DAY)) AS Date_Dif,
               Acc_Name AS Particular, InvoiceNo AS VoucherNo, 'Purchase' AS Voucher,
               PurchaseMaster.Description1 AS Narration, CurrecnyName AS TransactionCurrency, AccountType_Name AS EntryMode,
               0 AS Dr, NetTotal - IFNULL(SUM(Payment_Reference.Amount), 0) AS Cr
        FROM PurchaseMaster
        INNER JOIN AccountType ON AccountType.AccountType_Id = PurchaseMaster.TypeId
        AND PurchaseDate BETWEEN FromDate_ AND ToDate_ AND PurchaseMaster.DeleteStatus = 'false'
        INNER JOIN CurrencyDetails ON CurrencyDetails.CurrencyDetails_Id = PurchaseMaster.CurrencyId
        INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = PurchaseMaster.Account_Party_Id AND ClientAccounts_Id = Client_Id_
        LEFT JOIN Payment_Reference ON Payment_Reference.PurchaseMaster_Id = PurchaseMaster.PurchaseMaster_Id
        AND Payment_Reference.DeleteStatus = 'false'
        AND PurchaseMaster.TypeId = IF(TypeId_ > 0, TypeId_, PurchaseMaster.TypeId)
        AND PurchaseMaster.CurrencyId = IF(CurrencyId_ > 0, CurrencyId_, PurchaseMaster.CurrencyId)
        GROUP BY PurchaseMaster.PurchaseMaster_Id, PurchaseMaster.PurchaseDate, PaymentTerms, ClientAccounts.Acc_Name,
                 InvoiceNo, PurchaseMaster.NetTotal, PurchaseMaster.Description1, CurrecnyName, AccountType_Name, EntryDate
        HAVING NetTotal - IFNULL(SUM(Payment_Reference.Amount), 0) > 0
       
        UNION ALL
       
        SELECT 2 AS slno, DATE_FORMAT(PaymentVoucher.Date, '%d/%m/%Y') AS E_Date, Mode AS Terms, '' AS Date_Dif, Acc_Name AS Particular,
               CAST(Voucher_No AS CHAR) AS VoucherNo, 'Payment' AS Voucher, PaymentVoucher.Description1 AS Narration, '' AS TransactionCurrency, '' AS EntryMode, Amount AS Dr, 0 AS Cr
        FROM PaymentVoucher
        INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = PaymentVoucher.To_Party_Id
        WHERE ClientAccounts_Id = Client_Id_
        AND PaymentVoucher.Date BETWEEN FromDate_ AND ToDate_
        AND PaymentVoucher.PaymentVoucher_Id NOT IN (SELECT Payment_Id FROM Payment_Reference)
        AND PaymentVoucher.DeleteStatus = 'false'
        AND PaymentVoucher.CurrencyId = IF(CurrencyId_ > 0, CurrencyId_, PaymentVoucher.CurrencyId)
       
        UNION ALL
       
        SELECT 2 AS slno, DATE_FORMAT(RecieptVoucher.Date, '%d/%m/%Y') AS E_Date, Mode AS Terms, '' AS Date_Dif, Acc_Name AS Particular,
               CAST(Receipt_No AS CHAR) AS VoucherNo, 'Receipt' AS Voucher, RecieptVoucher.Description1 AS Narration, '' AS TransactionCurrency, '' AS EntryMode, 0 AS Dr, Amount AS Cr
        FROM RecieptVoucher
        INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = RecieptVoucher.Frm_Party_Id
        WHERE ClientAccounts_Id = Client_Id_
        AND RecieptVoucher.Date BETWEEN FromDate_ AND ToDate_
        AND RecieptVoucher.DeleteStatus = 'false'
        AND RecieptVoucher.RecieptVoucher_Id NOT IN (SELECT Receipt_Id FROM Receipt_Reference)
        AND RecieptVoucher.CurrencyId = IF(CurrencyId_ > 0, CurrencyId_, RecieptVoucher.CurrencyId)
       
        UNION ALL
       
        SELECT 2 AS slno, DATE_FORMAT(Journal_Entry.Date, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, Acc_Name AS Particular,
               CAST(Voucher_No AS CHAR) AS VoucherNo, 'Journal' AS Voucher, Journal_Entry.Description1 AS Narration, '' AS TransactionCurrency, '' AS EntryMode, Amount AS Dr, 0 AS Cr
        FROM Journal_Entry
        INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = Journal_Entry.ToAccount_Id
        WHERE ClientAccounts_Id = Client_Id_
        AND Journal_Entry.Date BETWEEN FromDate_ AND ToDate_
        AND Journal_Entry.DeleteStatus = 'false'
       
        UNION ALL
       
        SELECT 2 AS slno, DATE_FORMAT(ContraEntry.Date, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, Acc_Name AS Particular,
               CAST(Voucher_No AS CHAR) AS VoucherNo, 'Contra' AS Voucher, ContraEntry.Description1 AS Narration, '' AS TransactionCurrency, '' AS EntryMode, Amount AS Dr, 0 AS Cr
        FROM ContraEntry
        INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = ContraEntry.ToAccount_Id
        WHERE ClientAccounts_Id = Client_Id_
        AND ContraEntry.Date BETWEEN FromDate_ AND ToDate_
        AND ContraEntry.DeleteStatus = 'false'
       
        UNION ALL
       
        SELECT 3 AS SlNo, DATE_FORMAT(ToDate_, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Total' AS Voucher,
               '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, v_curdr AS Dr, v_curcr AS Cr    
       
        UNION ALL
       
        SELECT 4 AS SlNo, DATE_FORMAT(ToDate_, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Balance Payment' AS Voucher,
               '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, v_closbaldr AS Dr, v_closbalcr AS Cr  
    ) x
    ORDER BY SlNo, STR_TO_DATE(E_Date, '%d/%m/%Y') ASC;


ELSEIF Voucher_ = 'Sales' THEN
    SET v_open = IFNULL(v_opsalesdr, 0) + IFNULL(v_OpBal, 0);
    SET v_opendr = IFNULL(v_open, 0);
    SET v_opencr = 0;
    SET v_closebal = (IFNULL(v_cursalesdr, 0) + IFNULL(v_opendr, 0));
    SET v_closbaldr = IFNULL(v_closebal, 0);
    SET v_closbalcr = 0;

    SELECT * FROM (
        SELECT 1 AS SlNo, DATE_FORMAT(FromDate_, '%d/%m/%Y') AS E_Date,
               '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo,
               'Opening Balance' AS Voucher, '' AS Narration, '' AS TransactionCurrency,
               '' AS EntryMode, v_opendr AS Dr, v_opencr AS Cr
       
        UNION ALL
       
        SELECT 2 AS slno, DATE_FORMAT(SalesMaster.EntryDate, '%d/%m/%Y') AS E_Date,
               DATE_FORMAT(DATE_ADD(EntryDate, INTERVAL PaymentTerms DAY), '%d/%m/%Y') AS Terms,
               DATEDIFF(CURDATE(), DATE_ADD(EntryDate, INTERVAL PaymentTerms DAY)) AS Date_Dif,
               Acc_Name AS Particular, InvNo AS VoucherNo, 'Sales' AS Voucher,
               CONCAT('lpo-', LPONo, ',Do-', DONo) AS Narration,
               CurrecnyName AS TransactionCurrency, AccountType_Name AS EntryMode,
               (NetTotal - IFNULL(SUM(Receipt_Reference.amount), 0)) AS Dr, 0 AS Cr
        FROM SalesMaster
        INNER JOIN AccountType ON AccountType.AccountType_Id = SalesMaster.TypeId
        AND SalesMaster.DeleteStatus = 'false'
        AND SalesMaster.EntryDate BETWEEN FromDate_ AND ToDate_
        INNER JOIN CurrencyDetails ON CurrencyDetails.CurrencyDetails_Id = SalesMaster.CurrencyId
        INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = SalesMaster.Account_Party_Id
        AND ClientAccounts_Id = Client_Id_
        LEFT JOIN Receipt_Reference ON Receipt_Reference.SalesId = SalesMaster.SalesMaster_Id
        AND Receipt_Reference.DeleteStatus = 'false'
        AND SalesMaster.TypeId = IF(TypeId_ > 0, TypeId_, SalesMaster.TypeId)
        AND SalesMaster.CurrencyId = IF(CurrencyId_ > 0, CurrencyId_, SalesMaster.CurrencyId)
        GROUP BY SalesMaster.SalesMaster_Id, SalesMaster.EntryDate, SalesMaster.PaymentTerms,
                 ClientAccounts.Acc_Name, SalesMaster.InvNo, LPONo, DONo, CurrecnyName,
                 AccountType_Name, NetTotal
        HAVING (NetTotal - IFNULL(SUM(Receipt_Reference.amount), 0)) > 0
       
        UNION ALL
       
        SELECT 3 AS SlNo, DATE_FORMAT(ToDate_, '%d/%m/%Y') AS E_Date,
               '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo,
               'Total' AS Voucher, '' AS Narration, '' AS TransactionCurrency,
               '' AS EntryMode, v_cursalesdr AS Dr, 0 AS Cr
       
        UNION ALL
       
        SELECT 4 AS SlNo, DATE_FORMAT(ToDate_, '%d/%m/%Y') AS E_Date,
               '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo,
               'Balance Payment' AS Voucher, '' AS Narration, '' AS TransactionCurrency,
               '' AS EntryMode, v_closbaldr AS Dr, v_closbalcr AS Cr
    ) x
    ORDER BY SlNo, STR_TO_DATE(E_Date, '%d/%m/%Y') ASC;


ELSEIF Voucher_ = 'Purchase' THEN
