               Mode AS Terms, '' AS Date_Dif, Acc_Name AS Particular,
               CAST(Voucher_No AS CHAR) AS VoucherNo, 'Payment' AS Voucher,
               PaymentVoucher.Description1 AS Narration, '' AS TransactionCurrency,
