               '' AS Date_Dif,
               '' AS Particular,
               '' AS VoucherNo,
               'Total' AS Voucher,
               '' AS Narration,
               '' AS TransactionCurrency,
               '' AS EntryMode,
               v_curcondr AS Dr,
               0 AS Cr
        UNION
        SELECT 4 AS SlNo,
               DATE_FORMAT(CAST(ToDate_ AS DATETIME), '%d/%m/%Y') AS E_Date,
               '' AS Terms,
               '' AS Date_Dif,
               '' AS Particular,
               '' AS VoucherNo,
               'Balance Payment' AS Voucher,
               '' AS Narration,
               '' AS TransactionCurrency,
               '' AS EntryMode,
               v_closbaldr AS Dr,
               v_closbalcr AS Cr
    ) AS x
    ORDER BY SlNo, STR_TO_DATE(E_Date, '%d/%m/%Y') ASC;

END IF;
END
$$
DELIMITER ;

