    Declare Cur Cursor for select ItemId, ItemCode, ItemName, GroupName/*, UnitPrice*/,IFNULL(sum(Quantity),0) from packinglist_details
where DeleteStatus=0 and PackingList_Master_Id  in(select distinct PackingList_Master_Id from quotation_packinglist where DeleteStatus=0
and SalesQuotationMaster_Id =SalesQuotationMaster_Id_)group by ItemId,ItemCode,ItemName,GroupName;#UnitPrice;

