CREATE PROCEDURE `Load_ProfitAndLoss_Report`
BEGIN
    DECLARE SalesValue_PurchaseRate DECIMAL(18,2);
    DECLARE StockValue DECIMAL(18,2);
    DECLARE PurchaseValue DECIMAL(18,2);
    DECLARE SalesValue DECIMAL(18,2);
    DECLARE OpenStock DECIMAL(18,2);
    DECLARE Profit DECIMAL(18,2);
    DECLARE Loss DECIMAL(18,2);

    -- Calculate Stock Value
    SELECT COALESCE(SUM(IFNULL(Quantity, 0) * IFNULL(Stock.PurchaseRate, 0)), 0)
    INTO StockValue
    FROM Stock
    WHERE DeleteStatus = 'False';

    -- Calculate Purchase Value
    SELECT COALESCE(SUM(purchase_details.NetValue), 0)
    INTO PurchaseValue
    FROM purchase_details
    INNER JOIN purchase_master ON purchase_details.Purchase_Master_Id = purchase_master.Purchase_Master_Id
    WHERE purchase_details.DeleteStatus = 'False'
    AND DATE(purchase_master.PurchaseDate) BETWEEN DATE(FromDate) AND DATE(ToDate)
    AND purchase_master.user_id = CASE WHEN User_Type = 2 THEN Login_User ELSE purchase_master.user_id END;
    

    -- Calculate Sales Value
    SELECT COALESCE(SUM(IFNULL(sales_details.Quantity, 0) * IFNULL(sales_details.UnitPrice, 0)) 
    - COALESCE(SUM(sales_details.Item_Discount_Amount), 0), 0)
    INTO SalesValue
    FROM sales_details
    INNER JOIN sales_master ON sales_details.Sales_Master_Id = sales_master.Sales_Master_Id
    WHERE sales_details.DeleteStatus = 'False'
    AND DATE(sales_master.EntryDate) BETWEEN DATE(FromDate) AND DATE(ToDate)
	AND sales_master.user_id = CASE WHEN User_Type = 2 THEN Login_User ELSE sales_master.user_id END;

    -- Calculate Sales Value at Purchase Rate
    SELECT COALESCE(SUM(IFNULL(sales_details.Quantity, 0) * IFNULL(sales_details.PurchaseRate, 0)) 
    - COALESCE(SUM(sales_details.Item_Discount_Amount), 0), 0)
    INTO SalesValue_PurchaseRate
    FROM sales_details
    INNER JOIN sales_master ON sales_details.Sales_Master_Id = sales_master.Sales_Master_Id
    WHERE sales_details.DeleteStatus = 'False'
    AND DATE(sales_master.EntryDate) BETWEEN DATE(FromDate) AND DATE(ToDate)
	AND sales_master.user_id = CASE WHEN User_Type = 2 THEN Login_User ELSE sales_master.user_id END;


    -- Check for NULL values and set to 0 if necessary
    IF StockValue IS NULL THEN SET StockValue = 0; END IF;
    IF SalesValue IS NULL THEN SET SalesValue = 0; END IF;
    IF PurchaseValue IS NULL THEN SET PurchaseValue = 0; END IF;
    IF SalesValue_PurchaseRate IS NULL THEN SET SalesValue_PurchaseRate = 0; END IF;

    -- Calculate Open Stock
    SET OpenStock = (COALESCE(StockValue, 0) + COALESCE(SalesValue_PurchaseRate, 0)) - COALESCE(PurchaseValue, 0);
    IF OpenStock IS NULL THEN SET OpenStock = 0; END IF;

    -- Calculate Profit and Loss
    SET Profit = OpenStock + PurchaseValue;
    SET Loss = SalesValue + StockValue;
    SET Profit = Profit - Loss;

    IF Profit > 0 THEN
        SET Loss = 0;
    ELSE
        SET Loss = -Profit;
        SET Profit = 0;
    END IF;

    -- Return the result set
    SELECT 1 AS tp, 'Opening Stock' AS Caption1, OpenStock AS Data1, 'Sales' AS Caption2, SalesValue AS Data2
    UNION
    SELECT 2 AS tp, 'Purchase' AS Caption1, PurchaseValue AS Data1, 'Closing Stock' AS Caption2, StockValue AS Data2
    UNION
    SELECT 3 AS tp, 'Profit' AS Caption1, Profit AS Data1, 'Loss' AS Caption2, Loss AS Data2
    ORDER BY tp;

END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Load_Profoma_Items_Pending_List_ByQuotation`
BEGIN
    declare tempItem_Id numeric(18,0);	declare tempItem_code  nvarchar(500);	declare tempItem_Name nvarchar(500);	declare tempGroupName varchar(200);
	declare tempUnitPrice decimal(18,2);	declare tempQuantity numeric(18,3);   declare fetch_status decimal(18,0); 
    DECLARE hasRows BOOLEAN DEFAULT TRUE;


    Declare Cur Cursor for 
		select distinct
            ItemId,ItemCode,ItemName,GroupName,UnitPrice,IFNULL(sum(Quantity),0) Quantity from performainvoicedetails
			where DeleteStatus=0 and PerformaMaster_Id  in(
											select distinct PerformaInvoiceMaster_Id 
                                            from quotation_performa 
                                            where DeleteStatus=0
											and SalesQuotationMaster_Id =SalesQuotationMaster_Id_
										  )
group by ItemId,ItemCode,ItemName,GroupName,UnitPrice;
	DECLARE CONTINUE HANDLER FOR NOT FOUND SET hasRows = FALSE;

delete from db_logs;

set fetch_status=(
				select distinct Count(ItemId) 
                  from salesquotationdetails
                  where  
					DeleteStatus = 0
					and QuotationMaster_Id = SalesQuotationMaster_Id_
                );
                
insert into db_logs values(0,1,'','');


DROP TEMPORARY TABLE IF EXISTS temp_1;
CREATE TEMPORARY TABLE temp_1(
ItemId numeric(18, 0) ,
ItemCode nvarchar(500) ,
ItemName nvarchar(500),
GroupName varchar(200),
UnitPrice decimal(18,2),
Quantity numeric(18,3)
);
insert into temp_1
select distinct
ItemId, ItemCode, ItemName, GroupName, UnitPrice,IFNULL(sum(Quantity),0) Quantity 
            from salesquotationdetails
			where DeleteStatus=0 
				and QuotationMaster_Id = SalesQuotationMaster_Id_
			group by ItemId,ItemCode,ItemName,GroupName,UnitPrice;

insert into db_logs values(0,2,'','');


Open Cur;
Fetch next from Cur into tempItem_Id, tempItem_code, tempItem_Name, tempGroupName, tempUnitPrice, tempQuantity;

insert into db_logs values(0,3,'','');

IF hasRows THEN
While(fetch_status!=0) do
begin

insert into db_logs values(0,4.1,'','');

	update temp_1 set  
				Quantity =Quantity-tempQuantity 
	where  
		ItemId =tempItem_Id   
        and ItemCode =tempItem_code 
        and ItemName =tempItem_Name   
        and GroupName =tempGroupName   
        and UnitPrice =tempUnitPrice;	
        insert into db_logs values(0,4.2,'','');

    	set fetch_status=fetch_status-1;
        
		insert into db_logs values(0,4.3,fetch_status,'fetch_status');

         if(fetch_status != 0)
			then
				insert into db_logs values(0,4.4,'','');

				 Fetch next from Cur into tempItem_Id, tempItem_code, tempItem_Name, tempGroupName, tempUnitPrice, tempQuantity; 
			end if;
End;
END WHILE;
ELSE
SELECT ItemId, ItemCode, ItemName, GroupName, UnitPrice,IFNULL(sum(Quantity),0) Quantity 
            from salesquotationdetails
			where DeleteStatus=0 
				and QuotationMaster_Id = SalesQuotationMaster_Id_
			group by ItemId,ItemCode,ItemName,GroupName,UnitPrice; 
END IF;
close Cur;

insert into db_logs values(0,5,'','');

select * from temp_1 where Quantity>0;
DROP TEMPORARY TABLE temp_1;
END
$$
DELIMITER ;

