Begin
declare data_status decimal(18,0) ;

declare MastId_ int;Declare Date_ datetime;Declare Party_ varchar(200);Declare Bilno_ varchar(100);Declare gstin_ varchar(100);
Declare 0net_ decimal(18,2) default 0;declare 5net_ decimal(18,2) default 0;declare 2p5cgst_ decimal(18,2) default 0;declare 2p5sgst_ decimal(18,2) default 0;
declare 12net_ decimal(18,2) default 0;declare 6cgst_ decimal(18,2) default 0;declare 6sgst_ decimal(18,2) default 0;declare 18net_ decimal(18,2) default 0;
declare 9cgst_ decimal(18,2) default 0;declare 9sgst_ decimal(18,2) default 0;declare 28net_ decimal(18,2) default 0;declare 14cgst_ decimal(18,2) default 0;
declare 14sgst_ decimal(18,2) default 0;declare trans_charge_ decimal(18,2) default 0;declare trans_gst_ decimal(18,2) default 0;declare hand_charge_ decimal(18,2) default 0;
declare hand_gst_ decimal(18,2) default 0;declare roundoff_ decimal(18,2) default 0;
DECLARE done INT DEFAULT 0;

#DECLARE done INT DEFAULT FALSE;

DECLARE  Cur CURSOR FOR
select  Purchase_Return_Master.Purchase_Return_Master_Id, (Date_Format(PurchaseDate,'%Y-%m-%d')),client_accounts.Client_Accounts_Name,
InvoiceNo,client_accounts.GSTNo,COALESCE(Transportation_Charge,0),COALESCE(Transportation_Gst,0),
COALESCE(Handling_Charge,0),COALESCE(Handling_Gst,0),Roundoff
from Purchase_Return_Master
inner join client_accounts on Purchase_Return_Master.Account_Party_Id=client_accounts.Client_Accounts_Id
where   Purchase_Return_Master.PurchaseDate >= From_Date_  and  Purchase_Return_Master.PurchaseDate <= To_Date_  
and Purchase_Return_Master.DeleteStatus=0
order by Purchase_Return_Master.Purchase_Return_Master_Id asc;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;
delete from Purchase_Return_Tax;
Open Cur;
read_loop: LOOP

FETCH Cur INTO MastId_,Date_,Party_,Bilno_,gstin_,trans_charge_,trans_gst_,hand_charge_,hand_gst_,roundoff_;
#set data_status=data_status-1;
IF done = 1 THEN
LEAVE read_loop;
END IF;
#insert into db_logs values(1,2,2,0);

set 0net_=(select COALESCE(sum(Purchase_Return_Details.NetValue),0) from Purchase_Return_Details
where Purchase_Return_Details.Purchase_Return_Master_Id=MastId_ and Purchase_Return_Details.DeleteStatus=0 and Purchase_Return_Details.SaleTax=0.00
group by  Purchase_Return_Details.SaleTax);
set 5net_=(select COALESCE(sum(Purchase_Return_Details.NetValue),0) from Purchase_Return_Details
where Purchase_Return_Details.Purchase_Return_Master_Id=MastId_ and Purchase_Return_Details.DeleteStatus=0 and  Purchase_Return_Details.SaleTax=5.00
