set 2p5sgst_=(select COALESCE(sum(Purchase_Return_Details.SGST_Amt),0) from Purchase_Return_Details
where Purchase_Return_Details.Purchase_Return_Master_Id=MastId_ and Purchase_Return_Details.DeleteStatus=0 and  Purchase_Return_Details.SGST=2.50
group by  Purchase_Return_Details.SGST);
set 12net_=(select COALESCE(sum(Purchase_Return_Details.NetValue),0) from Purchase_Return_Details
where Purchase_Return_Details.Purchase_Return_Master_Id=MastId_ and Purchase_Return_Details.DeleteStatus=0 and  Purchase_Return_Details.SaleTax=12.00
group by  Purchase_Return_Details.SaleTax);
set 6cgst_=(select COALESCE(sum(Purchase_Return_Details.CGST_Amt),0) from Purchase_Return_Details
where Purchase_Return_Details.Purchase_Return_Master_Id=MastId_ and Purchase_Return_Details.DeleteStatus=0 and  Purchase_Return_Details.CGST=6.00
