group by  Purchase_Return_Details.SGST);
set 18net_=(select COALESCE(sum(Purchase_Return_Details.NetValue),0) from Purchase_Return_Details
where Purchase_Return_Details.Purchase_Return_Master_Id=MastId_ and Purchase_Return_Details.DeleteStatus=0 and  Purchase_Return_Details.SaleTax=18
group by  Purchase_Return_Details.SaleTax);
set 9cgst_= (select COALESCE(sum(Purchase_Return_Details.CGST_Amt),0) from Purchase_Return_Details
where Purchase_Return_Details.Purchase_Return_Master_Id=MastId_ and Purchase_Return_Details.DeleteStatus=0 and  Purchase_Return_Details.CGST=9
group by  Purchase_Return_Details.CGST);
set 9sgst_ =(select COALESCE(sum(Purchase_Return_Details.SGST_Amt),0) from Purchase_Return_Details
