group by  Purchase_Return_Details.SGST);

insert into Purchase_Return_Tax values
( 0,Date_,Bilno_,Party_,gstin_,COALESCE(0net_,0),COALESCE(5net_,0),COALESCE(2p5cgst_,0),COALESCE(2p5sgst_,0),COALESCE(12net_,0),COALESCE(6cgst_,0),
COALESCE(6sgst_,0),(COALESCE(18net_,0)+COALESCE(trans_charge_,0)+COALESCE(hand_charge_,0)),
COALESCE(9cgst_,0)+(COALESCE(trans_gst_,0)/2)+(COALESCE(hand_gst_,0)/2),COALESCE(9sgst_,0)+(COALESCE(trans_gst_,0)/2)+(COALESCE(hand_gst_,0)/2),
COALESCE(28net_,0),COALESCE(14cgst_,0),COALESCE(14sgst_,0),COALESCE(roundoff_,0),
COALESCE(0net_,0)+COALESCE(5net_,0)+COALESCE(2p5cgst_,0)+COALESCE(2p5sgst_,0) +COALESCE(12net_,0)+COALESCE(6cgst_,0)+COALESCE(6sgst_,0)+
(COALESCE(18net_,0)+COALESCE(trans_charge_,0)+COALESCE(hand_charge_,0))+
(COALESCE(9cgst_,0)+(COALESCE(trans_gst_,0)/2)+(COALESCE(hand_gst_,0)/2))+(COALESCE(9sgst_,0)+(COALESCE(trans_gst_,0)/2)+(COALESCE(hand_gst_,0)/2))+
COALESCE(28net_,0)+COALESCE(14cgst_,0)+COALESCE(14sgst_,0)+COALESCE(roundoff_,0));


END Loop;
Close Cur;
#end if;
select  (Date_Format(Date,'%Y-%m-%d')) Date,Bill_No,Supplier,GSN_No,Zero_Net_Value,
Five_Net_Value,Five_GST,Five_SGST,Twelve_Net_Value,Six_CGST,Six_SGST,Eighteen_Net_Value,
Nine_CGST,Nine_SGST,Twentyeight_Net_Value,Fourteen_CGST,Fourteen_SGST,Round_Off,Total
 from Purchase_Return_Tax;
end
$$
