CREATE PROCEDURE `Load_SalesMaster`
BEGIN
    DECLARE Search_Date_ VARCHAR(500);
    DECLARE SearchbyName_Value VARCHAR(2000);

   SET @query = CONCAT("
    SELECT DISTINCT
        sm.*,
        DATE_FORMAT(sm.EntryDate, '%d-%m-%Y') AS FormattedEntryDate,
		(Date_Format(sm.EntryDate, '%d-%m-%Y')) AS PrintDate,
        sm.LPONo,
        sm.NetTotal,
        ca.Client_Accounts_Name AS Customer,
        sm.TypeId as AccountType_Id,
        at.AccountType_Name,
        IFNULL(qsm.SalesQuotationMaster_Id,0) SalesQuotationMaster_Id,
        (Date_Format(sm.SupplyDate,'%d-%m-%Y')) SupplyPrintDate,
        (Date_Format(sm.DueDate,'%d-%m-%Y')) DuePrintDate
    FROM sales_master sm
	INNER JOIN sales_details sd ON sm.Sales_Master_Id = sd.Sales_Master_Id
    INNER JOIN client_accounts ca ON sm.Account_Party_Id = ca.Client_Accounts_Id 
    LEFT JOIN accounttype at ON sm.TypeId = at.AccountType_Id
    LEFT JOIN quotation_salesmaster qsm ON qsm.SalesMaster_Id = sm.Sales_Master_Id
    WHERE sm.DeleteStatus = FALSE 
    AND sm.Sales_Master_Id =",Sales_Master_Id_," 
    "
);

delete from db_logs;
insert into db_logs values(0,@query,'Load_SalesMaster','');
    PREPARE QUERY FROM @query;
    EXECUTE QUERY;
END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Load_SalesQuotationMaster`
BEGIN
    DECLARE Search_Date_ VARCHAR(500);
    DECLARE SearchbyName_Value VARCHAR(2000);

   SET @query = CONCAT("
    SELECT DISTINCT
        salesquotationmaster.*,
        DATE_FORMAT(salesquotationmaster.EntryDate, '%d-%m-%Y') AS FormattedEntryDate,
        salesquotationmaster.QuotationNo,
        salesquotationmaster.NetTotal,
        client_accounts.Client_Accounts_Name AS Customer,
              client_accounts.Address1,client_accounts.Address2,client_accounts.Address3,client_accounts.Address4,client_accounts.PinCode,client_accounts.GSTNo
  
    FROM salesquotationmaster 
    INNER JOIN salesquotationdetails ON salesquotationmaster.SalesQuotationMaster_Id = salesquotationdetails.QuotationMaster_Id
    INNER JOIN client_accounts ON salesquotationmaster.Account_Party_Id = client_accounts.Client_Accounts_Id 
    WHERE salesquotationmaster.DeleteStatus = FALSE AND salesquotationmaster.SalesQuotationMaster_Id =",SalesQuotationMaster_Id_," 
    "
);

    PREPARE QUERY FROM @query;
    EXECUTE QUERY;
END
$$
DELIMITER ;

