CREATE PROCEDURE `Load_SaleTax_Report`
Begin
declare data_status decimal(18,0);
declare MastId_ int;Declare Date_ datetime;Declare Party_ varchar(200);Declare Bilno_ varchar(100);Declare gstin_ varchar(100);
Declare 0net_ decimal(18,2) default 0;declare 5net_ decimal(18,2) default 0;declare 2p5cgst_ decimal(18,2) default 0;declare 2p5sgst_ decimal(18,2) default 0;
declare 12net_ decimal(18,2) default 0;declare 6cgst_ decimal(18,2) default 0;declare 6sgst_ decimal(18,2) default 0;declare 18net_ decimal(18,2) default 0;
declare 9cgst_ decimal(18,2) default 0;declare 9sgst_ decimal(18,2) default 0;declare 28net_ decimal(18,2) default 0;declare 14cgst_ decimal(18,2) default 0;
declare 14sgst_ decimal(18,2) default 0;declare trans_charge_ decimal(18,2) default 0;declare trans_gst_ decimal(18,2) default 0;declare hand_charge_ decimal(18,2) default 0;
declare hand_gst_ decimal(18,2) default 0;declare roundoff_ decimal(18,2) default 0;
DECLARE done INT DEFAULT 0;
DECLARE  Cur CURSOR FOR
select  COUNT(Sales_master.Sales_Master_Id), (Date_Format(Bill_Date,'%Y-%m-%d')),COALESCE(SUM(Transportation_Charge),0),COALESCE(SUM(Transportation_Gst),0),
COALESCE(SUM(Handling_Charge),0),COALESCE(SUM(Handling_Gst),0),COALESCE(SUM(Roundoff),0)
from Sales_master
where Sales_Master.Bill_Date >= From_Date_ and Sales_Master.Bill_Date <= To_Date_ and BillType=2 and Sales_master.DeleteStatus=0
GROUP BY Bill_Date
order by Sales_master.Bill_Date asc;
DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;
delete from Sale_Tax;
Open Cur;
read_loop: LOOP
FETCH Cur INTO MastId_,Date_,trans_charge_,trans_gst_,hand_charge_,hand_gst_,roundoff_;
#set data_status=data_status-1;
IF done = 1 THEN
LEAVE read_loop;
END IF;
set 0net_=(select COALESCE(sum(Sales_details.NetValue),0) from Sales_details inner join sales_master
on Sales_details.Sales_Master_Id=sales_master.Sales_Master_Id
where sales_master.Date=Date_ and BillType=2 and Sales_details.DeleteStatus=0 and Sales_details.SaleTax=0.00
group by  Sales_details.SaleTax);
set 5net_=(select COALESCE(sum(Sales_details.NetValue),0) from Sales_details inner join sales_master
on Sales_details.Sales_Master_Id=sales_master.Sales_Master_Id
where sales_master.Date=Date_ and BillType=2 and Sales_details.DeleteStatus=0 and  Sales_details.SaleTax=5.00
group by  Sales_details.SaleTax);
set 2p5cgst_=(select COALESCE(sum(Sales_details.CGSTAmt),0) from Sales_details inner join sales_master
