where sales_master.Date=Date_ and BillType=2 and Sales_details.DeleteStatus=0 and  Sales_details.CGST=2.50
group by  Sales_details.CGST);
set 2p5sgst_=(select COALESCE(sum(Sales_details.SGSTAmt),0) from Sales_details inner join sales_master
on Sales_details.Sales_Master_Id=sales_master.Sales_Master_Id
where sales_master.Date=Date_ and BillType=2 and Sales_details.DeleteStatus=0 and  Sales_details.SGST=2.50
group by  Sales_details.SGST);
set 12net_=(select COALESCE(sum(Sales_details.NetValue),0) from Sales_details inner join sales_master
on Sales_details.Sales_Master_Id=sales_master.Sales_Master_Id
where sales_master.Date=Date_ and BillType=2 and Sales_details.DeleteStatus=0 and  Sales_details.SaleTax=12.00
group by  Sales_details.SaleTax);
set 6cgst_=(select COALESCE(sum(Sales_details.CGSTAmt),0) from Sales_details inner join sales_master
on Sales_details.Sales_Master_Id=sales_master.Sales_Master_Id
where sales_master.Date=Date_ and BillType=2 and Sales_details.DeleteStatus=0 and  Sales_details.CGST=6.00
