where sales_master.Date=Date_ and BillType=2 and Sales_details.DeleteStatus=0 and  Sales_details.SGST=6.00
group by  Sales_details.SGST);
set 18net_=(select COALESCE(sum(Sales_details.NetValue),0) from Sales_details inner join sales_master
on Sales_details.Sales_Master_Id=sales_master.Sales_Master_Id
where sales_master.Date=Date_ and BillType=2 and Sales_details.DeleteStatus=0 and  Sales_details.SaleTax=18
group by  Sales_details.SaleTax);
set 9cgst_= (select COALESCE(sum(Sales_details.CGSTAmt),0) from Sales_details inner join sales_master
on Sales_details.Sales_Master_Id=sales_master.Sales_Master_Id
where sales_master.Date=Date_ and BillType=2 and Sales_details.DeleteStatus=0 and  Sales_details.CGST=9
group by  Sales_details.CGST);
set 9sgst_ =(select COALESCE(sum(Sales_details.SGSTAmt),0) from Sales_details inner join sales_master
on Sales_details.Sales_Master_Id=sales_master.Sales_Master_Id
where sales_master.Date=Date_ and BillType=2 and Sales_details.DeleteStatus=0 and  Sales_details.SGST=9
group by  Sales_details.SGST);
set 28net_ =(select COALESCE(sum(Sales_details.NetValue),0) from Sales_details inner join sales_master
on Sales_details.Sales_Master_Id=sales_master.Sales_Master_Id
where sales_master.Date=Date_ and BillType=2 and Sales_details.DeleteStatus=0 and  Sales_details.SaleTax=28.00
group by  Sales_details.SaleTax);
set 14cgst_ =(select COALESCE(sum(Sales_details.CGSTAmt),0) from Sales_details inner join sales_master
on Sales_details.Sales_Master_Id=sales_master.Sales_Master_Id
where sales_master.Date=Date_ and BillType=2 and Sales_details.DeleteStatus=0 and  Sales_details.CGST=14.00
group by Sales_details.CGST);
set 14sgst_ =(select COALESCE(sum(Sales_details.SGSTAmt),0) from Sales_details inner join sales_master
on Sales_details.Sales_Master_Id=sales_master.Sales_Master_Id
where sales_master.Date=Date_ and BillType=2 and Sales_details.DeleteStatus=0 and  Sales_details.SGST=14.00
group by  Sales_details.SGST);
insert into Sale_Tax values
(0,Date_,Bilno_,'','',COALESCE(0net_,0),COALESCE(5net_,0),COALESCE(2p5cgst_,0),COALESCE(2p5sgst_,0),COALESCE(12net_,0),COALESCE(6cgst_,0),
COALESCE(6sgst_,0),(COALESCE(18net_,0)+COALESCE(trans_charge_,0)+COALESCE(hand_charge_,0)),
COALESCE(9cgst_,0)+(COALESCE(trans_gst_,0)/2)+(COALESCE(hand_gst_,0)/2),COALESCE(9sgst_,0)+(COALESCE(trans_gst_,0)/2)+(COALESCE(hand_gst_,0)/2),
COALESCE(28net_,0),COALESCE(14cgst_,0),COALESCE(14sgst_,0),COALESCE(roundoff_,0),
COALESCE(0net_,0)+COALESCE(5net_,0)+COALESCE(2p5cgst_,0)+COALESCE(2p5sgst_,0) +COALESCE(12net_,0)+COALESCE(6cgst_,0)+COALESCE(6sgst_,0)+
(COALESCE(18net_,0)+COALESCE(trans_charge_,0)+COALESCE(hand_charge_,0))+
(COALESCE(9cgst_,0)+(COALESCE(trans_gst_,0)/2)+(COALESCE(hand_gst_,0)/2))+(COALESCE(9sgst_,0)+(COALESCE(trans_gst_,0)/2)+(COALESCE(hand_gst_,0)/2))+
COALESCE(28net_,0)+COALESCE(14cgst_,0)+COALESCE(14sgst_,0)+COALESCE(roundoff_,0));
END Loop;
Close Cur;
select (Date_Format(Date,'%Y-%m-%d')) Date,Bill_No,Zero_Net_Value,Five_Net_Value,Five_GST,Five_SGST,Twelve_Net_Value,Six_CGST,Six_SGST,Eighteen_Net_Value,
Nine_CGST,Nine_SGST,Twentyeight_Net_Value,Fourteen_CGST,Fourteen_SGST,Round_Off,Total
from Sale_Tax;
end
$$
