CREATE PROCEDURE `Load_Sale_Billno`
Begin
declare Voucher_No_ varchar(50);
declare Bill_Prefix_ varchar(5);
declare Bill_No_ varchar(50);
	set Voucher_No_=(SELECT COALESCE( MAX(Invoice_No ),0)+1 FROM Sales_Master
	where BillType=Bill_Type_Id_ );
    set Bill_Prefix_=(select Bill_Prefix from Bill_Type where Bill_Type_Id=Bill_Type_Id_ );
  if Bill_Type_Id_=1 then
    set Bill_No_=concat(Bill_Prefix_ , Voucher_No_);
  else
    set Bill_No_=Voucher_No_;
end if;
SELECT COALESCE( MAX(Invoice_No ),0)+1 FROM Sales_Master
	where BillType=Bill_Type_Id_ ;
    select Bill_Prefix from Bill_Type where Bill_Type_Id=Bill_Type_Id_ ;
select Bill_No_ as billno;
 End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Load_Service_Tax_Report`
Begin
