declare 14sgst_ decimal(18,2) default 0;
DECLARE done INT DEFAULT 0;
DECLARE  Cur CURSOR FOR
select  Service.Service_Id, (Date_Format(Service.Entry_Date,'%Y-%m-%d')) Entry_Date,client_accounts.Client_Accounts_Name,
InvoiceNo,client_accounts.GSTNo
