set 0net_=(select COALESCE(sum(Service_Details.NetValue),0) from Service_Details
where Service_Details.Service_Id=MastId_ and Service_Details.DeleteStatus=0 and Service_Details.GST=0.00
group by  Service_Details.GST);
set 5net_=(select COALESCE(sum(Service_Details.NetValue),0) from Service_Details
