where Service_Details.Service_Id=MastId_ and Service_Details.DeleteStatus=0 and  Service_Details.SGST=2.50
group by  Service_Details.SGST);
set 12net_=(select COALESCE(sum(Service_Details.NetValue),0) from Service_Details
where Service_Details.Service_Id=MastId_ and Service_Details.DeleteStatus=0 and  Service_Details.GST=12.00
group by  Service_Details.GST);
set 6cgst_=(select COALESCE(sum(Service_Details.CGST_Amt),0) from Service_Details
where Service_Details.Service_Id=MastId_ and Service_Details.DeleteStatus=0 and  Service_Details.CGST=6.00
group by  Service_Details.CGST);
set 6sgst_=(select COALESCE(sum(Service_Details.SGST_Amt),0) from Service_Details
where Service_Details.Service_Id=MastId_ and Service_Details.DeleteStatus=0 and  Service_Details.SGST=6.00
group by  Service_Details.SGST);
set 18net_=(select COALESCE(sum(Service_Details.NetValue),0) from Service_Details
where Service_Details.Service_Id=MastId_ and Service_Details.DeleteStatus=0 and  Service_Details.GST=18
group by  Service_Details.GST);
set 9cgst_= (select COALESCE(sum(Service_Details.CGST_Amt),0) from Service_Details
where Service_Details.Service_Id=MastId_ and Service_Details.DeleteStatus=0 and  Service_Details.CGST=9
group by  Service_Details.CGST);
set 9sgst_ =(select COALESCE(sum(Service_Details.SGST_Amt),0) from Service_Details
where Service_Details.Service_Id=MastId_ and Service_Details.DeleteStatus=0 and  Service_Details.SGST=9
group by  Service_Details.SGST);
set 28net_ =(select COALESCE(sum(Service_Details.NetValue),0) from Service_Details
where Service_Details.Service_Id=MastId_ and Service_Details.DeleteStatus=0 and  Service_Details.GST=28.00
group by  Service_Details.GST);
set 14cgst_ =(select COALESCE(sum(Service_Details.CGST_Amt),0) from Service_Details
where Service_Details.Service_Id=MastId_ and Service_Details.DeleteStatus=0 and  Service_Details.CGST=14.00
group by  Service_Details.CGST);
set 14sgst_ =(select COALESCE(sum(Service_Details.SGST_Amt),0) from Service_Details
where Service_Details.Service_Id=MastId_ and Service_Details.DeleteStatus=0 and  Service_Details.SGST=14.00
group by  Service_Details.SGST);
insert into Service_Tax values
( 0,Date_,Bilno_,Party_,gstin_,COALESCE(0net_,0),COALESCE(5net_,0),COALESCE(2p5cgst_,0),COALESCE(2p5sgst_,0),
COALESCE(12net_,0),COALESCE(6cgst_,0),COALESCE(6sgst_,0),(COALESCE(18net_,0)),
COALESCE(9cgst_,0),COALESCE(9sgst_,0),COALESCE(28net_,0),COALESCE(14cgst_,0),COALESCE(14sgst_,0),
COALESCE(0net_,0)+COALESCE(5net_,0)+COALESCE(2p5cgst_,0)+COALESCE(2p5sgst_,0) +COALESCE(12net_,0)+
COALESCE(6cgst_,0)+COALESCE(6sgst_,0)+(COALESCE(18net_,0))+(COALESCE(9cgst_,0))+(COALESCE(9sgst_,0))+
COALESCE(28net_,0)+COALESCE(14cgst_,0)+COALESCE(14sgst_,0));
END Loop;
Close Cur;
#end if;
select (Date_Format(Date,'%Y-%m-%d')) Date,Bill_No,Supplier,GSN_No,Zero_Net_Value,
