CREATE PROCEDURE `Load_StatementofAccount_Report`
BEGIN
    -- Declare variables
    DECLARE opsalesdr_ DECIMAL(18,3);
    DECLARE op_sales_ DECIMAL(18,3);
    DECLARE op_rec_ DECIMAL(18,3);
    DECLARE oppurcr_ DECIMAL(18,3);
    DECLARE op_pur_ DECIMAL(18,3);
    DECLARE op_pay_ DECIMAL(18,3);
    DECLARE oppaydr_ DECIMAL(18,3);
    DECLARE opreccr_ DECIMAL(18,3);
    DECLARE opjurcr_ DECIMAL(18,3);
    DECLARE opconcr_ DECIMAL(18,3);
    declare opnsalrtn_ decimal(18,3);
    declare opnpurrtn_ decimal(18,3);
    declare opndebitnote_ decimal(18,3);
    declare opncreditnote_ decimal(18,3);
	DECLARE opdr_ DECIMAL(18,3);
    DECLARE opcr_ DECIMAL(18,3);
    DECLARE open_ DECIMAL(18,3);
    DECLARE opendr_ DECIMAL(18,3);
    DECLARE opencr_ DECIMAL(18,3);
    DECLARE OpBal_ DECIMAL(18,3);
   
    -- Current total balance
    DECLARE cursalesdr_ DECIMAL(18,3);
    DECLARE cur_sales_ DECIMAL(18,3);
    DECLARE cur_rec_ DECIMAL(18,3);
    DECLARE curpurcr_ DECIMAL(18,3);
    DECLARE cur_purcr_ DECIMAL(18,3);
    DECLARE cur_pay_ DECIMAL(18,3);
    DECLARE curpaydr_ DECIMAL(18,3);
    DECLARE curreccr_ DECIMAL(18,3);
    DECLARE curjurcr_ DECIMAL(18,3);
    DECLARE curconcr_ DECIMAL(18,3);
    DECLARE curdr_ DECIMAL(18,3);
    DECLARE curcr_ DECIMAL(18,3);
    declare cursalesrtncr_ decimal(18,3);
    declare curpurrtndr_ decimal(18,3);
    declare curdebitnotedr_ decimal(18,3);
    declare curcreditnotecr_ decimal(18,3);
    DECLARE closebal_ DECIMAL(18,3);
   
    -- Closing balance
    DECLARE closbaldr_ DECIMAL(18,3);
    DECLARE closbalcr_ DECIMAL(18,3);

    -- Initialize variables
    SET OpBal_ = COALESCE((SELECT Opening_Balance FROM client_accounts WHERE Client_Accounts_Id = Client_Id_), 0);

    -- Calculate opening balances
    SELECT COALESCE(SUM(NetTotal), 0) INTO op_sales_
    FROM sales_master
    WHERE sales_master.Account_Party_Id = Client_Id_ AND sales_master.DeleteStatus = 0
	#AND sales_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE sales_master.user_id END)
    and sales_master.TypeId=(case when TypeId_>0 then TypeId_ else sales_master.TypeId end)
    and sales_master.CurrencyId=(case when CurrencyId_>0 then CurrencyId_ else sales_master.CurrencyId end)
    AND DATE(sales_master.EntryDate) < DATE(FromDate_);

    SELECT COALESCE(SUM(Receipt_Reference.Receiving_Amount), 0) INTO op_rec_
    FROM sales_master INNER JOIN Receipt_Reference ON Receipt_Reference.Master_Id = sales_master.sales_master_Id
    WHERE sales_master.Account_Party_Id = Client_Id_ AND Receipt_Reference.DeleteStatus = 0 AND sales_master.DeleteStatus = 0
    AND Receipt_Reference.Voucher_Type_Id = 5
    #AND sales_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE sales_master.user_id END)
	and sales_master.TypeId=(case when TypeId_>0 then TypeId_ else sales_master.TypeId end)
    and sales_master.CurrencyId=(case when CurrencyId_>0 then CurrencyId_ else sales_master.CurrencyId end)
    AND DATE(sales_master.EntryDate) < DATE(FromDate_);
    
    SET opsalesdr_ = op_sales_ - op_rec_;
   
    SET op_pur_ = (SELECT IFNULL(SUM(NetTotal), 0)
    FROM purchase_master WHERE purchase_master.Account_Party_Id = Client_Id_ AND purchase_master.DeleteStatus = 0
	#AND purchase_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE purchase_master.user_id END)
	and purchase_master.TypeId=(case when TypeId_>0 then TypeId_ else purchase_master.TypeId end)
    and purchase_master.Currency_Id=(case when CurrencyId_>0 then CurrencyId_ else purchase_master.Currency_Id end)
    AND DATE(purchase_master.PurchaseDate) < DATE(FromDate_));
   
    SET op_pay_ = (SELECT IFNULL(SUM(payment_reference.Paying_Amount), 0)
    FROM purchase_master INNER JOIN payment_reference ON payment_reference.Master_Id = purchase_master.Purchase_Master_Id
    AND payment_reference.DeleteStatus = 0
    WHERE purchase_master.Account_Party_Id = Client_Id_
	#AND purchase_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE purchase_master.user_id END)
	and purchase_master.TypeId=(case when TypeId_>0 then TypeId_ else purchase_master.TypeId end)
    and purchase_master.Currency_Id=(case when CurrencyId_>0 then CurrencyId_ else purchase_master.Currency_Id end)
    AND purchase_master.DeleteStatus = 0 AND payment_reference.Voucher_Type_Id = 1
    AND DATE(purchase_master.PurchaseDate) < DATE(FromDate_));

	set oppurcr_=op_pur_-op_pay_;

	SET oppaydr_ = (SELECT ifnull(SUM(Amount),0)
	FROM payment_voucher WHERE payment_voucher.DeleteStatus = 0 AND To_Party_Id = Client_Id_
	AND DATE(payment_voucher.Date) < DATE(FromDate_)
	#AND payment_voucher.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE payment_voucher.user_id END)
	and payment_voucher.CurrencyId=(case when CurrencyId_>0 then CurrencyId_ else payment_voucher.CurrencyId end)
	AND payment_voucher.Payment_Voucher_Id NOT IN (SELECT Payment_Voucher_Id FROM payment_reference));
   
    SET opreccr_ = (SELECT ifnull(SUM(Amount),0)
    FROM receipt_voucher WHERE Frm_Party_Id = Client_Id_ AND receipt_voucher.DeleteStatus = 0 AND DATE(receipt_voucher.Date) < DATE(FromDate_)    
	#AND receipt_voucher.user_id =( CASE WHEN User_Type = 2 THEN Login_User ELSE receipt_voucher.user_id END)
     and receipt_voucher.CurrencyId=(case when CurrencyId_>0 then CurrencyId_ else receipt_voucher.CurrencyId end)
    AND receipt_voucher.Receipt_Voucher_Id NOT IN (SELECT Receipt_Voucher_Id FROM receipt_reference));
   
    SET opjurcr_ = (SELECT ifnull(SUM(Amount),0) FROM journal_entry
    WHERE To_Account_Id = Client_Id_ AND journal_entry.DeleteStatus = 0 AND DATE(journal_entry.Date) < DATE(FromDate_)  
	#AND journal_entry.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE journal_entry.user_id END)
    and journal_entry.CurrencyId=(case when CurrencyId_>0 then CurrencyId_ else journal_entry.CurrencyId end)
    and journal_entry.TypeId=(case when TypeId_>0 then TypeId_ else journal_entry.TypeId end)
    AND Journal_Entry_Id NOT IN (SELECT Master_Id FROM payment_reference WHERE Voucher_Type_Id = 2));
   
    SET opconcr_ = (SELECT ifnull(SUM(Amount),0)
    FROM contra_entry WHERE To_Account_Id = Client_Id_ AND contra_entry.DeleteStatus = 0 AND DATE(contra_entry.Date) < DATE(FromDate_)
	#AND contra_entry.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE contra_entry.user_id END)
    );
   
    SELECT COALESCE(SUM(NetTotal), 0) INTO opnsalrtn_
    FROM sales_return_master
    WHERE sales_return_master.Account_Party_Id = Client_Id_
    AND sales_return_master.DeleteStatus = 0
	#AND sales_return_master.user_id = CASE WHEN User_Type = 2 THEN Login_User ELSE sales_return_master.user_id END
    AND sales_return_master.CurrencyId = CASE WHEN CurrencyId_>0 THEN CurrencyId_ ELSE sales_return_master.CurrencyId END
    AND sales_return_master.TypeId = CASE WHEN TypeId_>0 THEN TypeId_ ELSE sales_return_master.TypeId END
    AND DATE(sales_return_master.EntryDate) < DATE(FromDate_);
   
	SET opnpurrtn_ = (SELECT IFNULL(SUM(NetTotal),0)
    FROM purchase_return_master WHERE purchase_return_master.Account_Party_Id = Client_Id_ AND purchase_return_master.DeleteStatus = 0
	#AND purchase_return_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE purchase_return_master.user_id END)
    AND purchase_return_master.CurrencyId = (CASE WHEN CurrencyId_>0 THEN CurrencyId_ ELSE purchase_return_master.CurrencyId END)
    AND purchase_return_master.TypeId = (CASE WHEN TypeId_>0 THEN TypeId_ ELSE purchase_return_master.TypeId END)
    AND DATE(purchase_return_master.PurchaseDate) < DATE(FromDate_));
       
    SELECT COALESCE(SUM(NetTotal), 0) INTO opndebitnote_
    FROM debitnote_master WHERE debitnote_master.Account_Party_Id = Client_Id_ AND debitnote_master.DeleteStatus = 0
	#AND debitnote_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE debitnote_master.user_id END)
    AND debitnote_master.CurrencyId = (CASE WHEN CurrencyId_>0 THEN CurrencyId_ ELSE debitnote_master.CurrencyId END)
	AND debitnote_master.TypeId = (CASE WHEN TypeId_>0 THEN TypeId_ ELSE debitnote_master.TypeId END)
    AND DATE(debitnote_master.EntryDate) < DATE(FromDate_);
   
	SET opncreditnote_ = (SELECT IFNULL(SUM(NetTotal), 0)
    FROM creditnote_master WHERE creditnote_master.Account_Party_Id = Client_Id_ AND creditnote_master.DeleteStatus = 0
	#AND creditnote_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE creditnote_master.user_id END)
    AND creditnote_master.CurrencyId = (CASE WHEN CurrencyId_>0 THEN CurrencyId_ ELSE creditnote_master.CurrencyId END)
    AND creditnote_master.TypeId = (CASE WHEN TypeId_>0 THEN TypeId_ ELSE creditnote_master.TypeId END)
    AND DATE(creditnote_master.EntryDate) < DATE(FromDate_));
   
    -- Calculate current balances
    SELECT COALESCE(SUM(NetTotal), 0) INTO cur_sales_
    FROM sales_master WHERE sales_master.Account_Party_Id = Client_Id_ AND sales_master.DeleteStatus = 0
    AND DATE(sales_master.EntryDate) BETWEEN DATE(FromDate_) AND DATE(ToDate_)
    AND sales_master.TypeId = (case when TypeId_ > 0 then TypeId_ else sales_master.TypeId end)
	#AND sales_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE sales_master.user_id END)
    AND sales_master.CurrencyId = (case when CurrencyId_ > 0 then CurrencyId_ else sales_master.CurrencyId end);
   
    SET cur_rec_ = (SELECT IFNULL(SUM(receipt_reference.Receiving_Amount), 0)
    FROM sales_master INNER JOIN receipt_reference ON receipt_reference.Master_Id = sales_master.Sales_Master_Id
    WHERE sales_master.Account_Party_Id = Client_Id_ AND receipt_reference.DeleteStatus = 0 AND sales_master.DeleteStatus = 0
    AND DATE(sales_master.EntryDate) BETWEEN DATE(FromDate_) AND DATE(ToDate_)
	#AND sales_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE sales_master.user_id END)
    AND sales_master.TypeId = (CASE WHEN TypeId_ > 0 THEN TypeId_ ELSE sales_master.TypeId END)
    AND sales_master.CurrencyId = (CASE WHEN CurrencyId_ > 0 THEN CurrencyId_ ELSE sales_master.CurrencyId END));
   
    SET cursalesdr_ = cur_sales_ - cur_rec_;
   
    SET cur_purcr_ = IFNULL((SELECT SUM(NetTotal)
    FROM purchase_master iNNER JOIN accounttype ON accounttype.AccountType_Id = purchase_master.TypeId
    INNER JOIN currencydetails ON currencydetails.CurrencyDetails_Id = purchase_master.Currency_Id
    INNER JOIN client_accounts ON client_accounts.Client_Accounts_Id = purchase_master.Account_Party_Id
    #LEFT JOIN payment_reference ON payment_reference.Master_Id = purchase_master.Purchase_Master_Id
	#AND payment_reference.DeleteStatus = 0 AND payment_reference.Voucher_Type_Id = 1
    WHERE purchase_master.DeleteStatus = 0 and purchase_master.TypeId = (CASE WHEN TypeId_ > 0 THEN TypeId_ ELSE purchase_master.TypeId END)
	#AND purchase_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE purchase_master.user_id END)
    AND DATE(purchase_master.PurchaseDate) BETWEEN DATE(FromDate_) AND DATE(ToDate_)        
    AND purchase_master.Currency_Id = CASE WHEN CurrencyId_ > 0 THEN CurrencyId_ ELSE purchase_master.Currency_Id END
    AND client_accounts.Client_Accounts_Id = Client_Id_), 0);
   
    SELECT COALESCE(SUM(payment_reference.Paying_Amount), 0) INTO cur_pay_
	FROM purchase_master INNER JOIN payment_reference ON payment_reference.Master_Id = purchase_master.Purchase_Master_Id
	AND payment_reference.DeleteStatus = 0 AND purchase_master.DeleteStatus = 0
	WHERE purchase_master.Account_Party_Id = Client_Id_ AND payment_reference.Voucher_Type_Id = 1
	AND DATE(purchase_master.PurchaseDate) BETWEEN DATE(FromDate_) AND DATE(ToDate_)
	#AND purchase_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE purchase_master.user_id END)
	AND purchase_master.TypeId = (CASE WHEN TypeId_ > 0 THEN TypeId_ ELSE purchase_master.TypeId END)
	AND purchase_master.Currency_Id = (CASE WHEN CurrencyId_ > 0 THEN CurrencyId_ ELSE purchase_master.Currency_Id END);

set curpurcr_= cur_purcr_-cur_pay_;
   
    SELECT ifnull(SUM(Amount),0) INTO curpaydr_
	FROM payment_voucher WHERE payment_voucher.DeleteStatus = 0 AND To_Party_Id = Client_Id_
	AND payment_voucher.CurrencyId = (CASE WHEN CurrencyId_ > 0 THEN CurrencyId_ ELSE payment_voucher.CurrencyId END)
	#AND payment_voucher.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE payment_voucher.user_id END)
	AND DATE(payment_voucher.Date) BETWEEN DATE(FromDate_) AND DATE(ToDate_)
	AND payment_voucher.Payment_Voucher_Id NOT IN (SELECT Payment_Voucher_Id FROM Payment_Reference);
     
	SELECT ifnull(SUM(Amount),0) INTO curreccr_
	FROM receipt_voucher WHERE receipt_voucher.DeleteStatus = 0 AND Frm_Party_Id = Client_Id_
	AND receipt_voucher.CurrencyId = (CASE WHEN CurrencyId_ > 0 THEN CurrencyId_ ELSE receipt_voucher.CurrencyId END)
	#AND receipt_voucher.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE receipt_voucher.user_id END)
	AND DATE(receipt_voucher.Date) BETWEEN DATE(FromDate_) AND DATE(ToDate_)
	AND receipt_voucher.Receipt_Voucher_Id NOT IN (SELECT Receipt_Voucher_Id FROM receipt_reference);
     
	SELECT ifnull(SUM(Amount),0) INTO curjurcr_
	FROM journal_entry WHERE journal_entry.DeleteStatus = 0 AND To_Account_Id = Client_Id_
	AND DATE(journal_entry.Date) BETWEEN DATE(FromDate_) AND DATE(ToDate_)
	AND journal_entry.CurrencyId = (CASE WHEN CurrencyId_ > 0 THEN CurrencyId_ ELSE journal_entry.CurrencyId END)
	AND journal_entry.TypeId = (CASE WHEN TypeId_ > 0 THEN TypeId_ ELSE journal_entry.TypeId END)
	#AND journal_entry.user_id = CASE WHEN User_Type = 2 THEN Login_User ELSE journal_entry.user_id END
	AND journal_entry.Journal_Entry_Id NOT IN (SELECT Master_Id FROM payment_reference WHERE Voucher_Type_Id = 2);
     
	SELECT ifnull(SUM(Amount),0) INTO curconcr_
	FROM contra_entry WHERE contra_entry.DeleteStatus = 0 AND To_Account_Id = Client_Id_
	#AND contra_entry.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE contra_entry.user_id END)
	AND DATE(contra_entry.Date) BETWEEN DATE(FromDate_) AND DATE(ToDate_);      
     
    SELECT COALESCE(SUM(NetTotal), 0) INTO cursalesrtncr_
    FROM sales_return_master WHERE sales_return_master.Account_Party_Id = Client_Id_ AND sales_return_master.DeleteStatus = 0
    AND DATE(sales_return_master.EntryDate) BETWEEN DATE(FromDate_) AND DATE(ToDate_)
    AND sales_return_master.TypeId=(case when TypeId_ > 0 then TypeId_ else sales_return_master.TypeId end)
	#AND sales_return_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE sales_return_master.user_id END)
    AND sales_return_master.CurrencyId = (case when CurrencyId_ > 0 then CurrencyId_ else sales_return_master.CurrencyId end);
     
    SET curpurrtndr_ = (select IFNULL(SUM(NetTotal),0)
    FROM purchase_return_master WHERE purchase_return_master.DeleteStatus = 0
    and purchase_return_master.TypeId = (CASE WHEN TypeId_ > 0 THEN TypeId_ ELSE purchase_return_master.TypeId END)
	#AND purchase_return_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE purchase_return_master.user_id END)
	AND DATE(purchase_return_master.PurchaseDate) BETWEEN DATE(FromDate_) AND DATE(ToDate_)
	AND purchase_return_master.CurrencyId = (CASE WHEN CurrencyId_ > 0 THEN CurrencyId_ ELSE purchase_return_master.CurrencyId END)
	AND purchase_return_master.Account_Party_Id = Client_Id_);

	SELECT COALESCE(SUM(NetTotal),0) INTO curdebitnotedr_
	FROM debitnote_master WHERE debitnote_master.Account_Party_Id = Client_Id_ AND debitnote_master.DeleteStatus = 0
	AND DATE(debitnote_master.EntryDate) BETWEEN DATE(FromDate_) AND DATE(ToDate_)
	AND debitnote_master.TypeId = (case when TypeId_ > 0 then TypeId_ else debitnote_master.TypeId end)
	#AND debitnote_master.user_id = CASE WHEN User_Type = 2 THEN Login_User ELSE debitnote_master.user_id END
	AND (CurrencyId_ = 0 OR debitnote_master.CurrencyId = CurrencyId_);
     
	SET curcreditnotecr_ = (SELECT IFNULL(SUM(NetTotal), 0)
	FROM creditnote_master WHERE creditnote_master.DeleteStatus = 0
	and creditnote_master.TypeId = (CASE WHEN TypeId_ > 0 THEN TypeId_ ELSE creditnote_master.TypeId END)
	#AND creditnote_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE creditnote_master.user_id END)
	AND DATE(creditnote_master.EntryDate) BETWEEN DATE(FromDate_) AND DATE(ToDate_)
	AND creditnote_master.CurrencyId = (CASE WHEN CurrencyId_ > 0 THEN CurrencyId_ ELSE creditnote_master.CurrencyId END)
	AND creditnote_master.Account_Party_Id = Client_Id_);
   
    -- Main logic based on voucher type
    IF Voucher_ = 0 THEN
        -- Logic for 'All' vouchers
        SET opdr_ = COALESCE(opsalesdr_, 0) + COALESCE(oppaydr_, 0) + COALESCE(opnpurrtn_,0) + COALESCE(opndebitnote_,0);
        SET opcr_ = COALESCE(oppurcr_, 0) + COALESCE(opreccr_, 0) + COALESCE(opjurcr_, 0) + COALESCE(opconcr_, 0) + COALESCE(opnsalrtn_,0) + COALESCE(opncreditnote_,0);
        SET open_ = opdr_ + OpBal_ - opcr_;

        IF open_ < 0 THEN
            SET opencr_ = -open_;
            SET opendr_ = 0;
        ELSE
            SET opendr_ = open_;
            SET opencr_ = 0;
        END IF;

        -- Current
        SET curdr_ = COALESCE(cursalesdr_, 0) + COALESCE(curpaydr_, 0)  + COALESCE(curpurrtndr_,0) + COALESCE(curdebitnotedr_,0) ;
        SET curcr_ = COALESCE(curpurcr_, 0) + COALESCE(curreccr_, 0) + COALESCE(curjurcr_, 0) + COALESCE(curconcr_, 0) + COALESCE(cursalesrtncr_,0) + COALESCE(curcreditnotecr_,0);
       
        IF curcr_ < 0 THEN
            SET curcr_ = -curcr_;
        END IF;

        SET closebal_ = (curdr_ + opendr_) - (curcr_ + opencr_);

        IF closebal_ < 0 THEN
            SET closbalcr_ = -closebal_;
            SET closbaldr_ = 0;
        ELSE
            SET closbaldr_ = closebal_;
            SET closbalcr_ = 0;
        END IF;

        SELECT * FROM (
	SELECT 1 AS SlNo, DATE_FORMAT(FromDate_, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo,
    'Opening Balance' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, opendr_ AS Dr, opencr_ AS Cr
    
UNION ALL

	SELECT 2 AS slno, DATE_FORMAT(EntryDate, '%d/%m/%Y') AS E_Date,
	DATE_FORMAT(DATE_ADD(EntryDate, INTERVAL CAST(PaymentTermValue AS SIGNED) DAY), '%d/%m/%Y') AS Terms,
	DATEDIFF(CURDATE(), DATE_ADD(EntryDate, INTERVAL CAST(PaymentTermValue AS SIGNED) DAY)) AS Date_Dif, Client_Accounts_Name AS Particular,
	Invoice_No AS VoucherNo, 'Sales' AS Voucher, CONCAT('lpo-', LPONo, ',Do-', DONo) AS Narration, currencydetails.CurrecnyName AS TransactionCurrency,
	AccountType_Name AS EntryMode, (ifnull(sales_master.NetTotal,0) - IFNULL(sales_master.PaidAmount, 0)) AS Dr, 0 AS Cr
	FROM sales_master INNER JOIN accounttype ON accounttype.AccountType_Id = sales_master.TypeId
	INNER JOIN currencydetails ON currencydetails.CurrencyDetails_Id = sales_master.CurrencyId
	INNER JOIN client_accounts ON client_accounts.Client_Accounts_Id = sales_master.Account_Party_Id
	#LEFT JOIN receipt_reference ON receipt_reference.Master_Id = sales_master.Sales_Master_Id AND receipt_reference.DeleteStatus = 0
	WHERE sales_master.TypeId = (case when TypeId_ > 0 then TypeId_ else sales_master.TypeId end)
	AND DATE(sales_master.EntryDate) BETWEEN FromDate_ AND ToDate_ AND sales_master.DeleteStatus = 0
	#AND sales_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE sales_master.user_id END)
	AND sales_master.CurrencyId = (case when CurrencyId_ > 0 then CurrencyId_ else sales_master.CurrencyId end)
	AND client_accounts.Client_Accounts_Id = Client_Id_        
	#GROUP BY sales_master.Sales_Master_Id, sales_master.EntryDate, sales_master.PaymentTerms, client_accounts.Client_Accounts_Name,
	#sales_master.Invoice_No, LPONo, DONo, AccountType_Name, NetTotal
	and (ifnull(sales_master.NetTotal,0) - IFNULL(sales_master.PaidAmount, 0)) > 0
       
UNION ALL

	SELECT 3 AS slno, DATE_FORMAT(purchase_master.PurchaseDate, '%d/%m/%Y') AS E_Date,
	DATE_FORMAT(DATE_ADD(purchase_master.PurchaseDate, INTERVAL CAST(PaymentTermValue AS SIGNED) DAY), '%d/%m/%Y') AS Terms,
	DATEDIFF(CURDATE(), DATE_ADD(purchase_master.Entry_Date, INTERVAL CAST(PaymentTermValue AS SIGNED) DAY)) AS Date_Dif,
	Client_Accounts_Name AS Particular, purchase_master.InvoiceNo AS VoucherNo, 'Purchase' AS Voucher,
	purchase_master.Description1 AS Narration, purchase_master.CurrecnyName AS TransactionCurrency, AccountType_Name AS EntryMode,
	0 AS Dr, (ifnull(purchase_master.NetTotal,0) - IFNULL(purchase_master.PaidAmount, 0)) AS Cr
	FROM purchase_master
	INNER JOIN accounttype ON accounttype.AccountType_Id = purchase_master.TypeId
	INNER JOIN currencydetails ON currencydetails.CurrencyDetails_Id = purchase_master.Currency_Id
	INNER JOIN client_accounts ON client_accounts.Client_Accounts_Id = purchase_master.Account_Party_Id
	#LEFT JOIN payment_reference ON payment_reference.Master_Id = purchase_master.Purchase_Master_Id
	#AND payment_reference.DeleteStatus = 0 AND BillType = 1
	WHERE purchase_master.TypeId = (case when TypeId_ > 0 then TypeId_ else purchase_master.TypeId end)
	#AND purchase_master.user_id = CASE WHEN User_Type = 2 THEN Login_User ELSE purchase_master.user_id END
	AND DATE(purchase_master.PurchaseDate) BETWEEN FromDate_ AND ToDate_ AND purchase_master.DeleteStatus = 0
	AND purchase_master.Currency_Id = (case when CurrencyId_ > 0 then CurrencyId_ else purchase_master.Currency_Id end)
	AND client_accounts.Client_Accounts_Id = Client_Id_
	#GROUP BY purchase_master.PurchaseDate, PaymentTerms, client_accounts.Client_Accounts_Name,
	#purchase_master.InvoiceNo, purchase_master.NetTotal, purchase_master.Description1, purchase_master.CurrecnyName,
	# AccountType_Name, purchase_master.Entry_Date
	and (ifnull(purchase_master.NetTotal,0) - IFNULL(purchase_master.PaidAmount, 0)) > 0
       
UNION ALL

	SELECT 4 AS slno, DATE_FORMAT(payment_voucher.Date, '%d/%m/%Y') AS E_Date,'' AS Terms, '' AS Date_Dif, Client_Accounts_Name AS Particular,
    CAST(Voucher_No AS CHAR) AS VoucherNo, 'Payment' AS Voucher,payment_voucher.Description AS Narration, 
    currencydetails.CurrecnyName AS TransactionCurrency, '' AS EntryMode, Amount AS Dr,	0 AS Cr
	FROM payment_voucher
	INNER JOIN currencydetails ON payment_voucher.CurrencyId = currencydetails.CurrencyDetails_Id
	INNER JOIN client_accounts ON client_accounts.client_accounts_Id = payment_voucher.To_Party_Id
	WHERE payment_voucher.CurrencyId = (case when CurrencyId_ > 0 then CurrencyId_ else payment_voucher.CurrencyId end)
	#AND payment_voucher.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE payment_voucher.user_id END)
	AND client_accounts.Client_Accounts_Id = Client_Id_
	AND DATE(payment_voucher.Date) BETWEEN FromDate_ AND ToDate_ AND payment_voucher.DeleteStatus = 0
	AND payment_voucher.Payment_Voucher_Id NOT IN (SELECT Payment_Voucher_Id FROM payment_reference)
       
UNION ALL

	SELECT 5 AS slno, DATE_FORMAT(journal_entry.Date, '%d/%m/%Y') AS E_Date,
	DATE_FORMAT(DATE_ADD(journal_entry.Date, INTERVAL CAST(PaymentTermValue AS SIGNED) DAY), '%d/%m/%Y') AS Terms,
	DATEDIFF(CURDATE(), DATE_ADD(Journal_Entry.Date, INTERVAL CAST(PaymentTermValue AS SIGNED) DAY)) AS Date_Dif, Client_Accounts_Name AS Particular,
	CAST(journal_entry.InvNo AS CHAR) AS InvNo, 'Journal' AS Voucher, journal_entry.Description AS Narration,
	CurrencyDetails.CurrecnyName AS TransactionCurrency,AccountType_Name AS EntryMode, 0 AS Dr,
    (ifnull(journal_entry.Amount,0) - IFNULL(journal_entry.PaidAmount, 0)) AS Cr
	FROM journal_entry
	INNER JOIN client_accounts ON client_accounts.client_accounts_Id = journal_entry.To_Account_Id
	INNER JOIN CurrencyDetails ON CurrencyDetails.CurrencyDetails_Id = journal_entry.CurrencyId
	INNER JOIN AccountType ON AccountType.AccountType_Id = journal_entry.TypeId
	#LEFT JOIN Payment_Reference ON Payment_Reference.Master_Id = journal_entry.Journal_Entry_Id
	#AND Payment_Reference.DeleteStatus = 0 AND Voucher_Type_Id = 2
	WHERE journal_entry.CurrencyId = (case when CurrencyId_ > 0 then CurrencyId_ else journal_entry.CurrencyId end)
	#AND journal_entry.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE journal_entry.user_id END)
	AND journal_entry.TypeId = (case when TypeId_ > 0 then CurrencyId_ else Journal_Entry.TypeId end)
	AND client_accounts.client_accounts_Id = Client_Id_
	AND DATE(journal_entry.Date) BETWEEN FromDate_ AND ToDate_ AND journal_entry.DeleteStatus = 0
	#GROUP BY journal_entry.Date, PaymentTerms, client_accounts.Client_Accounts_Name, journal_entry.InvNo, journal_entry.Amount,
	#journal_entry.Description, CurrencyDetails.CurrecnyName,AccountType_Name
	and  (ifnull(journal_entry.Amount,0) - IFNULL(journal_entry.PaidAmount, 0)) > 0
       
UNION ALL

	SELECT 6 AS slno, DATE_FORMAT(receipt_voucher.Date, '%d/%m/%Y') AS E_Date,
	Payment_Mode_Id AS Terms, '' AS Date_Dif, Client_Accounts_Name AS Particular, CAST(Receipt_No AS CHAR) AS VoucherNo, 'Receipt' AS Voucher,
	receipt_voucher.Description AS Narration, CurrencyDetails.CurrecnyName AS TransactionCurrency, '' AS EntryMode, 0 AS Dr, Amount AS Cr
	FROM receipt_voucher
	INNER JOIN CurrencyDetails ON receipt_voucher.CurrencyId = CurrencyDetails.CurrencyDetails_Id
	INNER JOIN client_accounts ON client_accounts.client_accounts_Id = receipt_voucher.Frm_Party_Id
	WHERE receipt_voucher.CurrencyId = (case when CurrencyId_ > 0 then CurrencyId_ else receipt_voucher.CurrencyId end)
	#AND receipt_voucher.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE receipt_voucher.user_id END)
	AND client_accounts.client_accounts_Id = Client_Id_
	AND DATE(receipt_voucher.Date) BETWEEN FromDate_ AND ToDate_ AND receipt_voucher.DeleteStatus = 0
	AND receipt_voucher.Receipt_Voucher_Id NOT IN (SELECT Receipt_Voucher_Id FROM Receipt_Reference)
       
UNION ALL

	SELECT 7 AS slno, DATE_FORMAT(contra_entry.Date, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, Client_Accounts_Name AS Particular,
	CAST(Voucher_No AS CHAR) AS VoucherNo, 'Contra' AS Voucher, contra_entry.Description AS Narration, '' AS TransactionCurrency, '' AS EntryMode,
	0 AS Dr, Amount AS Cr
	FROM contra_entry
	INNER JOIN client_accounts ON client_accounts.client_accounts_Id = contra_entry.To_Account_Id
	WHERE client_accounts.client_accounts_Id = Client_Id_
	AND DATE(contra_entry.Date) BETWEEN FromDate_ AND ToDate_ AND contra_entry.DeleteStatus = 0
	#AND contra_entry.user_id = CASE WHEN User_Type = 2 THEN Login_User ELSE contra_entry.user_id END
       
UNION ALL      
  
	SELECT 8 AS slno, DATE_FORMAT(EntryDate, '%d/%m/%Y') AS E_Date,
	DATE_FORMAT(DATE_ADD(EntryDate, INTERVAL CAST(PaymentTermValue AS SIGNED) DAY), '%d/%m/%Y') AS Terms,
	DATEDIFF(CURDATE(), DATE_ADD(EntryDate, INTERVAL CAST(PaymentTermValue AS SIGNED) DAY)) AS Date_Dif, Client_Accounts_Name AS Particular,
	InvNo AS VoucherNo, 'Debit Note' AS Voucher, CONCAT('lpo-', LPONo, ',Do-', DONo) AS Narration, currencydetails.CurrecnyName  AS TransactionCurrency,
	AccountType_Name AS EntryMode, ifnull(NetTotal,0) AS Dr, 0 AS Cr
	FROM debitnote_master
	INNER JOIN accounttype ON accounttype.AccountType_Id = debitnote_master.TypeId
	INNER JOIN currencydetails ON currencydetails.CurrencyDetails_Id = debitnote_master.CurrencyId
	INNER JOIN client_accounts ON client_accounts.Client_Accounts_Id = debitnote_master.Account_Party_Id
	WHERE debitnote_master.TypeId = (case when TypeId_ > 0 then TypeId_ else debitnote_master.TypeId end)
	AND DATE(debitnote_master.EntryDate) BETWEEN FromDate_ AND ToDate_ AND debitnote_master.DeleteStatus = 0
	#AND debitnote_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE debitnote_master.user_id END)
	AND debitnote_master.CurrencyId = (case when CurrencyId_ > 0 then CurrencyId_ else debitnote_master.CurrencyId end)
	AND client_accounts.Client_Accounts_Id = Client_Id_
       
UNION ALL

	SELECT 9 AS slno, DATE_FORMAT(purchase_return_master.PurchaseDate, '%d/%m/%Y') AS E_Date,
	DATE_FORMAT(DATE_ADD(purchase_return_master.PurchaseDate, INTERVAL CAST(PaymentTermValue AS SIGNED) DAY), '%d/%m/%Y') AS Terms,
	DATEDIFF(CURDATE(), DATE_ADD(purchase_return_master.Entry_Date, INTERVAL CAST(PaymentTermValue AS SIGNED) DAY)) AS Date_Dif,
	Client_Accounts_Name AS Particular,purchase_return_master.Purchase_Return_No AS VoucherNo, 'Purchase Return' AS Voucher,
	purchase_return_master.Description AS Narration, purchase_return_master.CurrecnyName AS TransactionCurrency, AccountType_Name AS EntryMode,
	ifnull(NetTotal,0) AS Dr, 0 AS Cr
	FROM purchase_return_master
	INNER JOIN accounttype ON accounttype.AccountType_Id = purchase_return_master.TypeId
	INNER JOIN currencydetails ON currencydetails.CurrencyDetails_Id = purchase_return_master.CurrencyId
	INNER JOIN client_accounts ON client_accounts.Client_Accounts_Id = purchase_return_master.Account_Party_Id
	WHERE purchase_return_master.TypeId = (case when TypeId_ > 0 then TypeId_ else purchase_return_master.TypeId end)
	#AND purchase_return_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE purchase_return_master.user_id END)
	AND DATE(purchase_return_master.PurchaseDate) BETWEEN FromDate_ AND ToDate_ AND purchase_return_master.DeleteStatus = 0
	AND purchase_return_master.CurrencyId = (case when CurrencyId_ > 0 then CurrencyId_ else purchase_return_master.CurrencyId end)
	AND client_accounts.Client_Accounts_Id = Client_Id_

UNION ALL   
     
	SELECT 10 AS slno, DATE_FORMAT(EntryDate, '%d/%m/%Y') AS E_Date,
	DATE_FORMAT(DATE_ADD(EntryDate, INTERVAL CAST(Payment_Term_value AS SIGNED) DAY), '%d/%m/%Y') AS Terms,
	DATEDIFF(CURDATE(), DATE_ADD(EntryDate, INTERVAL CAST(Payment_Term_value AS SIGNED) DAY)) AS Date_Dif, Client_Accounts_Name AS Particular,
	InvNo AS VoucherNo, 'Credit Note' AS Voucher, CONCAT('lpo-', LPONo, ',Do-', DONo) AS Narration, currencydetails.CurrecnyName  AS TransactionCurrency,
	AccountType_Name AS EntryMode,0 AS Dr, ifnull(NetTotal,0) AS Cr
	FROM creditnote_master
	INNER JOIN accounttype ON accounttype.AccountType_Id = creditnote_master.TypeId
	INNER JOIN currencydetails ON currencydetails.CurrencyDetails_Id = creditnote_master.CurrencyId
	INNER JOIN client_accounts ON client_accounts.Client_Accounts_Id = creditnote_master.Account_Party_Id
	WHERE creditnote_master.TypeId = (case when TypeId_ > 0 then TypeId_ else creditnote_master.TypeId end)
	AND DATE(creditnote_master.EntryDate) BETWEEN FromDate_ AND ToDate_ AND creditnote_master.DeleteStatus = 0
	#AND creditnote_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE creditnote_master.user_id END)
	AND creditnote_master.CurrencyId = (case when CurrencyId_ > 0 then CurrencyId_ else creditnote_master.CurrencyId end)
	AND client_accounts.Client_Accounts_Id = Client_Id_
       
        union all
        
	SELECT 11 AS slno, DATE_FORMAT(EntryDate, '%d/%m/%Y') AS E_Date,
	DATE_FORMAT(DATE_ADD(EntryDate, INTERVAL CAST(PaymentTermValue AS SIGNED) DAY), '%d/%m/%Y') AS Terms,
	DATEDIFF(CURDATE(), DATE_ADD(EntryDate, INTERVAL CAST(PaymentTermValue AS SIGNED) DAY)) AS Date_Dif, Client_Accounts_Name AS Particular,
	Invoice_No AS VoucherNo, 'Sales Return' AS Voucher, CONCAT('lpo-', LPONo, ',Do-', DONo) AS Narration, 
    currencydetails.CurrecnyName  AS TransactionCurrency,AccountType_Name AS EntryMode, 0 AS Dr, ifnull(NetTotal,0) AS  Cr
	FROM sales_return_master
	INNER JOIN accounttype ON accounttype.AccountType_Id = sales_return_master.TypeId
