#GROUP BY sales_return_master.Sales_Return_Master_Id, sales_return_master.EntryDate, PaymentTerms, client_accounts.Client_Accounts_Name,  sales_return_master.Invoice_No,
#sales_return_master.NetTotal, sales_return_master.Description1, sales_return_master.CurrecnyName, AccountType_Name, sales_return_master.EntryDate
#HAVING NetTotal -  0 > 0
UNION
SELECT 4 AS SlNo, DATE_FORMAT(ToDate_, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo,
  'Total' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, 0 AS Dr, curpurcr_ AS Cr
UNION
SELECT 5 AS SlNo, DATE_FORMAT(ToDate_, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo,
  'Balance Payment' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, closbaldr_ AS Dr, closbalcr_ AS Cr
) AS x
ORDER BY SlNo, STR_TO_DATE(E_Date, '%d/%m/%Y');
           
ELSEIF Voucher_ = 10 THEN -- cn
SET open_ = IFNULL(oppurcr_, 0) + IFNULL(OpBal_, 0);

IF open_ < 0 THEN
SET opendr_ = -(IFNULL(open_, 0));
SET opencr_ = 0;
ELSE
SET opencr_ = IFNULL(open_, 0);
SET opendr_ = 0;
END IF;

SET closebal_ = (IFNULL(open_, 0) + IFNULL(curpurcr_, 0));

IF closebal_ < 0 THEN
SET closbaldr_ = -(IFNULL(closebal_, 0));
SET closbalcr_ = 0;
ELSE
SET closbalcr_ = IFNULL(closebal_, 0);
SET closbaldr_ = 0;
END IF;

SELECT * FROM (
SELECT 1 AS SlNo, DATE_FORMAT(FromDate_, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo,
  'Opening Balance' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, opendr_ AS Dr, opencr_ AS Cr
UNION
SELECT 2 AS slno, DATE_FORMAT(creditnote_master.EntryDate, '%d/%m/%Y') AS E_Date, DATE_FORMAT(DATE_ADD(creditnote_master.EntryDate, INTERVAL Payment_Term_value DAY), '%d/%m/%Y') AS Terms,
  DATEDIFF(CURDATE(), DATE_ADD(creditnote_master.EntryDate, INTERVAL Payment_Term_value DAY)) AS Date_Dif, Client_Accounts_Name AS Particular,  creditnote_master.InvNo AS VoucherNo,
  'Credit Note' AS Voucher, creditnote_master.Description1 AS Narration, creditnote_master.CurrecnyName AS TransactionCurrency, AccountType_Name AS EntryMode,
  0 AS Dr, ifnull(NetTotal,0) AS Cr
FROM creditnote_master
INNER JOIN AccountType ON AccountType.AccountType_Id = creditnote_master.TypeId
AND creditnote_master.TypeId = (CASE WHEN TypeId_ > 0 THEN TypeId_ ELSE creditnote_master.TypeId END)
AND DATE(creditnote_master.EntryDate) BETWEEN DATE(FromDate_) AND DATE(ToDate_)
AND creditnote_master.DeleteStatus = 0
#AND creditnote_master.user_id = (CASE WHEN User_Type = 2 THEN Login_User ELSE creditnote_master.user_id END)
INNER JOIN CurrencyDetails ON CurrencyDetails.CurrencyDetails_Id = creditnote_master.CurrencyId
AND creditnote_master.CurrencyId = (CASE WHEN CurrencyId_ > 0 THEN CurrencyId_ ELSE creditnote_master.CurrencyId END)
INNER JOIN client_accounts ON client_accounts.client_accounts_Id = creditnote_master.Account_Party_Id AND client_accounts_Id = Client_Id_
#LEFT JOIN Payment_Reference ON Payment_Reference.Master_Id = creditnote_master.purchase_master_Id
#AND Payment_Reference.DeleteStatus = 'False' AND Voucher_Type_Id = 1
#GROUP BY creditnote_master.CreditNote_Master_Id, creditnote_master.EntryDate, PaymentTerms, client_accounts.Client_Accounts_Name,  creditnote_master.InvNo,
#creditnote_master.NetTotal, creditnote_master.Description1, creditnote_master.CurrecnyName, AccountType_Name, creditnote_master.EntryDate
#HAVING NetTotal -  0 > 0
UNION
SELECT 4 AS SlNo, DATE_FORMAT(ToDate_, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo,
  'Total' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, 0 AS Dr, curpurcr_ AS Cr
UNION
SELECT 5 AS SlNo, DATE_FORMAT(ToDate_, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo,
  'Balance Payment' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, closbaldr_ AS Dr, closbalcr_ AS Cr
) AS x
ORDER BY SlNo, STR_TO_DATE(E_Date, '%d/%m/%Y');
           
ELSEIF Voucher_ = 9 THEN -- dn
SET open_ = IFNULL(opsalesdr_, 0) + IFNULL(OpBal_, 0);

IF open_ < 0 THEN
SET opencr_ = -(IFNULL(open_, 0));
SET opendr_ = 0;
ELSE
SET opendr_ = IFNULL(open_, 0);
SET opencr_ = 0;
END IF;

SET closebal_ = (IFNULL(cursalesdr_, 0) + IFNULL(open_, 0));

IF closebal_ < 0 THEN
SET closbalcr_ = -(IFNULL(closebal_, 0));
SET closbaldr_ = 0;
ELSE
SET closbaldr_ = IFNULL(closebal_, 0);
SET closbalcr_ = 0;
END IF;

SELECT * FROM (
SELECT 1 AS SlNo, DATE_FORMAT(FromDate_, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo,
  'Opening Balance' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, opendr_ AS Dr, opencr_ AS Cr
UNION
SELECT 2 AS slno, DATE_FORMAT(EntryDate, '%d/%m/%Y') AS E_Date, DATE_FORMAT(DATE_ADD(EntryDate, INTERVAL PaymentTerms DAY), '%d/%m/%Y') AS Terms,
  DATEDIFF(CURDATE(), DATE_ADD(EntryDate, INTERVAL PaymentTerms DAY)) AS Date_Dif, Client_Accounts_Name AS Particular, InvNo AS VoucherNo,
  'Debit Note' AS Voucher, CONCAT('lpo-', LPONo, ',Do-', DONo) AS Narration, currencydetails.CurrecnyName  AS TransactionCurrency,
  AccountType_Name AS EntryMode, ifnull(NetTotal,0) AS Dr, 0 AS Cr
FROM debitnote_master
INNER JOIN AccountType ON AccountType.AccountType_Id = debitnote_master.TypeId
AND debitnote_master.TypeId = (CASE WHEN TypeId_ > 0 THEN TypeId_ ELSE debitnote_master.TypeId END)
AND DATE(debitnote_master.EntryDate) BETWEEN DATE(FromDate_) AND DATE(ToDate_)
AND debitnote_master.DeleteStatus = 0
#AND debitnote_master.user_id = CASE WHEN User_Type = 2 THEN Login_User ELSE debitnote_master.user_id END
INNER JOIN CurrencyDetails ON CurrencyDetails.CurrencyDetails_Id = debitnote_master.CurrencyId
AND debitnote_master.CurrencyId = (CASE WHEN CurrencyId_ > 0 THEN CurrencyId_ ELSE debitnote_master.CurrencyId END)
INNER JOIN client_accounts ON client_accounts.client_accounts_Id = debitnote_master.Account_Party_Id AND client_accounts_Id = Client_Id_
#LEFT JOIN Receipt_Reference ON Receipt_Reference.Master_Id = debitnote_master.sales_master_Id
#AND Receipt_Reference.DeleteStatus = 'False'
#GROUP BY debitnote_master.DebitNote_Master_Id, debitnote_master.EntryDate, debitnote_master.PaymentTerms, client_accounts.Client_Accounts_Name,
#debitnote_master.InvNo, LPONo, DONo, AccountType_Name, NetTotal
#HAVING (NetTotal -  0) > 0
UNION
SELECT 3 AS SlNo, DATE_FORMAT(ToDate_, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo,
  'Total' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, cursalesdr_ AS Dr, 0 AS Cr
UNION
SELECT 4 AS SlNo, DATE_FORMAT(ToDate_, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo,
  'Balance Payment' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, closbaldr_ AS Dr, closbalcr_ AS Cr
) AS x
ORDER BY SlNo, STR_TO_DATE(E_Date, '%d/%m/%Y');            
END IF;    
END
$$
DELIMITER ;

