CREATE PROCEDURE `Profit_Loss_Report`
Begin
Select SecondAccount.Client_Accounts_Name as Particular,Accounts.Dr,Accounts.Cr 
from Accounts 
inner join Client_Accounts as FirstAccount  on FirstAccount.Client_Accounts_Id=Accounts.Client_Id 
 inner join Client_Accounts as SecondAccount  on SecondAccount.Client_Accounts_Id=Accounts.X_Client_Id 
 inner join Voucher_Type on Accounts.VoucherType=Voucher_Type.Voucher_Type_Id
where Date_Format(Accounts.Entry_Date,'%Y-%m-%d') 
between Date_Format(FromDate_,'%Y-%m-%d') and Date_Format(ToDate_,'%Y-%m-%d') 
and Accounts.Client_Id=5
union
Select SecondAccount.Client_Accounts_Name as Particular,Accounts.Dr,Accounts.Cr 
from Accounts 
inner join Client_Accounts as FirstAccount  on FirstAccount.Client_Accounts_Id=Accounts.Client_Id 
inner join Client_Accounts as SecondAccount  on SecondAccount.Client_Accounts_Id=Accounts.X_Client_Id 
 inner join Voucher_Type on Accounts.VoucherType=Voucher_Type.Voucher_Type_Id
where  Date_Format(Accounts.Entry_Date,'%Y-%m-%d') 
between Date_Format(FromDate_,'%Y-%m-%d') and Date_Format(ToDate_,'%Y-%m-%d') 
and Accounts.Client_Id=3;
#and  SecondAccount.Account_Group_Id in(select Account_Group_Id from account_group where Under_Group in(30,32));
End
$$
