DELIMITER $$
CREATE PROCEDURE `Sales_receipt_Bill`
Begin
Select distinct 5 as Voucher_Type_Id,'Sales' as Voucher_Type_Name,Sales_Master_Id,Invoice_No as InvoiceNo,
(Date_Format(Sales_Master.EntryDate,'%d-%m-%Y')) As Date,
0 as Receiving_Amount,NetTotal as Amount,0 as Discount,Account_Party_Id,
(COALESCE(NetTotal,0)-COALESCE(PaidAmount,0)) as BalAmt
from Sales_Master
where DeleteStatus=0 AND Account_Party_Id=Account_Party_Id_ 
and (COALESCE(NetTotal,0)-COALESCE(PaidAmount,0))>0
union
select 2 as Voucher_Type_Id,'Expense' as Voucher_Type_Name,journal_entry.Journal_Entry_Id as Sales_Master_Id,
Voucher_No as InvoiceNo,(Date_Format(journal_entry.Date,'%d-%m-%Y')) As Date,
0 as Receiving_Amount, journal_entry.Amount,0 as Discount,journal_entry.From_Account_Id as Account_Party_Id,
(journal_entry.Amount-ifnull(journal_entry.PaidAmount,0))BalAmt
from journal_entry where journal_entry.DeleteStatus=0 
AND journal_entry.From_Account_Id=Account_Party_Id_ 
and (COALESCE(journal_entry.Amount,0)-(ifnull(journal_entry.PaidAmount,0)))>0;
End
$$
DELIMITER ;

