CREATE PROCEDURE `Save_AddStock`
BEGIN
if(Stock_Add_Master_Id_ > 0) then
     CALL Update_Stock (Stock_Add_Master_Id_);
Delete From Stock_Add_Details Where  Stock_Add_Master_Id=Stock_Add_Master_Id_ ;

UPDATE stock_add_master SET
Entry_Date=EntryDate_,Description1=Description_,User_Id=User_Id_
WHERE Stock_Add_Master_Id = Stock_Add_Master_Id_;

else
SET Stock_Add_Master_Id_ = (SELECT  COALESCE( MAX(Stock_Add_Master_Id ),0)+1 FROM stock_add_master);

INSERT INTO stock_add_master
(Stock_Add_Master_Id,Entry_Date,Description1,DeleteStatus,User_Id)
VALUES
(Stock_Add_Master_Id_,EntryDate_,Description_,0,User_Id_);

end if;
CALL Save_AddStock_Details(Stock_Add_Details_,Stock_Add_Master_Id_);
select Stock_Add_Master_Id_;
END
$$
