DELIMITER $$
CREATE PROCEDURE `Save_AddStock_Details`
BEGIN
declare ItemId_ int;declare ItemCode_ varchar(500);
declare ItemName_ varchar(1000);declare UnitId_ int;
declare UnitName_ varchar(100);declare StockId_ int;
declare HSNMasterId_ int;declare HSNCODE_ varchar(50);
declare UnitPrice_ decimal;declare Quantity_ decimal;
declare Amount_ decimal;declare Sale_Tax_ decimal;declare Stock_Add_Details_Id_ int;
DECLARE i int  DEFAULT 0;declare GroupId_ int;declare GroupName_ varchar(100);declare PurchaseRate_ decimal;
declare Barcode_ varchar(200);declare MRP_ decimal(18,2);declare SaleTax_ decimal(18,2);
declare Country_Id_ int;declare Country_Name_ varchar(500);
WHILE i < JSON_LENGTH(Stock_Add_Details_) DO
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].StockId'))) INTO StockId_;  
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].ItemId'))) INTO ItemId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].ItemName'))) INTO ItemName_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].Item_Code'))) INTO Barcode_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].GroupId'))) INTO GroupId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].UnitId'))) INTO UnitId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].UnitName'))) INTO UnitName_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].Purchase_Rate'))) INTO PurchaseRate_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Stock_Add_Details_, CONCAT('$[', i, '].Purchase_Rate'))), 'null'), 0) INTO PurchaseRate_;

#SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].SaleRate'))) INTO UnitPrice_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Stock_Add_Details_, CONCAT('$[', i, '].SaleRate'))), 'null'), 0) INTO UnitPrice_;

#SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].MRP'))) INTO MRP_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Stock_Add_Details_, CONCAT('$[', i, '].MRP'))), 'null'), 0) INTO MRP_;

#SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].HSNMasterId'))) INTO HSNMasterId_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Stock_Add_Details_, CONCAT('$[', i, '].HSNMasterId'))), 'null'), 0) INTO HSNMasterId_;

SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].HSNCODE'))) INTO HSNCODE_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].SaleTax'))) INTO SaleTax_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Stock_Add_Details_, CONCAT('$[', i, '].SaleTax'))), 'null'), 0) INTO SaleTax_;

#SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Stock_Add_Details_, CONCAT('$[', i, '].Quantity'))), 'null'), 0) INTO Quantity_;

SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].Item_Code'))) INTO ItemCode_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].Amount'))) INTO Amount_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Stock_Add_Details_, CONCAT('$[', i, '].Amount'))), 'null'), 0) INTO Amount_;

#SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].Country_Id'))) INTO Country_Id_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Stock_Add_Details_, CONCAT('$[', i, '].Country_Id'))), 'null'), 0) INTO Country_Id_;

SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details_,CONCAT('$[',i,'].Country_Name'))) INTO Country_Name_;

        SET Stock_Add_Details_Id_ = (SELECT  COALESCE( MAX(Stock_Add_Details_Id ),0)+1 FROM stock_add_details);        
        Set StockId_=(select COALESCE( MAX(Stock_Id ),0)  from Stock where ItemId=ItemId_  and PurchaseRate=PurchaseRate_ 
        and SaleRate=UnitPrice_ and DeleteStatus=False order by Stock_Id desc Limit 1);        
        if(StockId_>0)then		                
			update Stock set Quantity= Quantity+Quantity_ where Stock_Id=StockId_ ;
		else 
        set StockId_ =(SELECT  COALESCE( MAX(Stock_Id ),0)+1 FROM stock);
			insert into Stock(Stock_Id,ItemId,ItemName,GroupId,GroupName,UnitId,UnitName,PurchaseRate,SaleRate,MRP,HSNMasterId,HSNCODE,
			SaleTax,Quantity,Item_Code,DeleteStatus,Country_Id,Country_Name)
			values(StockId_,ItemId_,ItemName_,GroupId_,GroupName_,UnitId_,UnitName_,PurchaseRate_,UnitPrice_,MRP_,HSNMasterId_,HSNCODE_,
			SaleTax_,Quantity_,ItemCode_,False,Country_Id_,Country_Name_);                   
			#set StockId_ =(SELECT LAST_INSERT_ID());
	   end if;        
		INSERT INTO stock_add_details(Stock_Add_Details_Id,Stock_Add_Master_Id,ItemId,Item_Code,ItemName,
        GroupId,GroupName,UnitId,UnitName,StockId,PurchaseRate,SaleRate,HSNMasterId,HSNCODE,Country_Id,Country_Name,SaleTax,Quantity,Amount,DeleteStatus)
		VALUES(Stock_Add_Details_Id_,Stock_Add_Master_Id_,ItemId_,ItemCode_,ItemName_,
