CREATE PROCEDURE `Save_Cheque_Book`
Begin 
 Declare i int ;
 if  Cheque_Book_Id_>0
 THEN
 delete from Cheque_Leaves where Cheque_Leaves.Cheque_Book_Id=Cheque_Book_Id_;
 UPDATE Cheque_Book set Bank_Id=Bank_Id_,Book_No=Book_No_,From_No=From_No_,
 Total_Leaves=Total_Leaves_,To_No=To_No_,User_Id=User_Id_
Where Cheque_Book_Id=Cheque_Book_Id_ ;
 ELSE
 SET Cheque_Book_Id_ = (SELECT  COALESCE( MAX(Cheque_Book_Id ),0)+1 FROM Cheque_Book);
 INSERT INTO Cheque_Book(Cheque_Book_Id, Bank_Id, Book_No,From_No, Total_Leaves, To_No, User_Id,DeleteStatus )
values (Cheque_Book_Id_,Bank_Id_,Book_No_,From_No_,Total_Leaves_,To_No_,User_Id_,false);
 End If ; 
set i=From_No_;
WHILE i < To_No_  DO
insert into Cheque_Leaves(Cheque_Book_Id,Cheque_No,Status,DeleteStatus) values(Cheque_Book_Id_,i,'Available',0);
 SELECT i + 1 INTO i;
END WHILE;  
 select Cheque_Book_Id_;
 End
$$
DELIMITER ;

