CREATE PROCEDURE `Save_Client_Accounts`
Begin
declare Entry_Date_ datetime;declare Duplicate_Id int;
set Entry_Date_=(SELECT CURRENT_DATE());
 if  Client_Accounts_Id_>0 THEN
	Set Duplicate_Id = (select Client_Accounts_Id from Client_Accounts where Client_Accounts_Id != Client_Accounts_Id_  and Client_Accounts_Name =Client_Accounts_Name_ limit 1);
	if(Duplicate_Id>0) then
	SET Client_Accounts_Id_ = -1;  
    else
	UPDATE Client_Accounts set
	Account_Group_Id = Account_Group_Id_ ,Client_Accounts_Name = Client_Accounts_Name_ ,Address1 = Address1_ ,Address2 = Address2_ ,Address3 = Address3_ ,Address4 = Address4_ ,
	PinCode = PinCode_ ,GSTNo =GSTNo_,Country = Country_ ,Phone = Phone_ ,Mobile = Mobile_ ,Email = Email_ ,  Opening_Balance = Opening_Balance_ ,Payment_Term = Payment_Term_ ,
	Entry_Date = Entry_Date_ , UserId = UserId_,  Employee_Id=Employee_Id_  Where Client_Accounts_Id=Client_Accounts_Id_ ;
	end if;
ELSE
	Set Duplicate_Id = (select Client_Accounts_Id from Client_Accounts where  Client_Accounts_Name =Client_Accounts_Name_ limit 1);
	if(Duplicate_Id>0) then
	SET Client_Accounts_Id_ = -1;  
	else
	SET Client_Accounts_Id_ = (SELECT  COALESCE( MAX(Client_Accounts_Id ),0)+1 FROM Client_Accounts);
	INSERT INTO Client_Accounts(Client_Accounts_Id ,Account_Group_Id ,Client_Accounts_Code ,Client_Accounts_Name ,Address1 ,Address2 ,Address3 ,Address4 ,
	PinCode ,GSTNo, Country ,Phone ,Mobile ,Email ,Opening_Balance ,Entry_Date ,UserId ,LedgerInclude ,CanDelete ,Commision ,
	Employee_Id,Payment_Term,DeleteStatus)
	values (Client_Accounts_Id_ ,Account_Group_Id_ ,Client_Accounts_Id_ ,Client_Accounts_Name_ ,Address1_ ,Address2_ ,Address3_ ,Address4_ ,PinCode_ ,GSTNo_, Country_ ,Phone_ ,
	Mobile_ ,Email_ ,Opening_Balance_ , now() ,UserId_ ,'Y' ,'Y' ,0 ,Employee_Id_,Payment_Term_,false);
	End If ;
 End If ;
 select Client_Accounts_Id_;
 End
$$
DELIMITER ;

