CREATE PROCEDURE `Save_Company`
Begin 
            delete from db_logs;
            insert into db_logs values(0,Company_Id_,'Company_Id_0','');
            
            if Company_Id_>0 THEN 
                UPDATE company_info 
                SET 
                    Company_Name=Company_Name_,
                    Address1=Address1_,
                    Address2=Address2_,
                    Address3=Address3_,
                    Phone=Phone_Number_,
