CREATE PROCEDURE `Save_CreditNote_Details_1`
Begin 

Declare ItemId_ decimal(18,0);  Declare ItemCode_ varchar(50);  Declare ItemName_ varchar(1000); 
Declare GroupId_ int; Declare GroupName_ varchar(100); Declare UnitId_ int;
Declare UnitName_ varchar(100); Declare StockId_ INT; Declare PurchaseRate_ decimal(18,3);
Declare MRP_ decimal(18,3);  Declare HSNMasterId_ decimal(18,0); Declare HSNCODE_ varchar(50); 
Declare SaleTax_ decimal(18,3); Declare UnitPrice_ decimal(18,3); Declare Quantity_ decimal(18,3);
Declare Unit_Discount_ decimal(18,3); Declare Discount_ decimal(18,3); 
Declare NetValue_ decimal(18,3); Declare Amount_ decimal(18,3); Declare TaxableAmount_ decimal(18,3); 
Declare TaxAmount_ decimal(18,3); DECLARE i int  DEFAULT 0;  declare Item_Discount_Amount_ decimal(18,3);
declare Country_Id_ int; declare Country_Name_ varchar(45);declare CreditNote_Details_Id_ int;

#declare NetValue_ decimal;
#declare HSNMasterId_ decimal;

	UPDATE creditnote_details SET DeleteStatus = 1 WHERE CreditNote_Master_Id = CreditNote_Master_Id_;
    
	WHILE i < JSON_LENGTH(Credit_Note_Details_) DO
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Credit_Note_Details_,CONCAT('$[',i,'].ItemId'))) INTO ItemId_;
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(Credit_Note_Details_,CONCAT('$[',i,'].StockId'))) INTO StockId_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Credit_Note_Details_, CONCAT('$[',i,'].StockId')) ),  'null' ), 0 ) INTO StockId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Credit_Note_Details_,CONCAT('$[',i,'].ItemCode'))) INTO ItemCode_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Credit_Note_Details_,CONCAT('$[',i,'].ItemName'))) INTO ItemName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Credit_Note_Details_,CONCAT('$[',i,'].GroupId'))) INTO GroupId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Credit_Note_Details_,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Credit_Note_Details_,CONCAT('$[',i,'].UnitId'))) INTO UnitId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Credit_Note_Details_,CONCAT('$[',i,'].UnitName'))) INTO UnitName_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Credit_Note_Details_,CONCAT('$[',i,'].HSNCODE'))) INTO HSNCODE_;
        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Credit_Note_Details_, CONCAT('$[',i,'].UnitPrice')) ),  'null' ), 0 ) INTO UnitPrice_;
		SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Credit_Note_Details_, CONCAT('$[',i,'].PurchaseRate')) ),  'null' ), 0 ) INTO PurchaseRate_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Credit_Note_Details_,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Credit_Note_Details_, CONCAT('$[',i,'].Amount')) ),  'null' ), 0 ) INTO Amount_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Credit_Note_Details_, CONCAT('$[',i,'].Sale_Tax')) ),  'null' ), 0 ) INTO SaleTax_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Credit_Note_Details_, CONCAT('$[',i,'].TaxableAmount')) ),  'null' ), 0 ) INTO TaxableAmount_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Credit_Note_Details_, CONCAT('$[',i,'].TaxAmount')) ),  'null' ), 0 ) INTO TaxAmount_; 	
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Credit_Note_Details_, CONCAT('$[',i,'].HSNMasterId')) ),  'null' ), 0 ) INTO HSNMasterId_; 	
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Credit_Note_Details_, CONCAT('$[',i,'].Item_Discount_Amount')) ),  'null' ), 0 ) INTO Item_Discount_Amount_; 	
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Credit_Note_Details_, CONCAT('$[',i,'].NetValue')) ),  'null' ), 0 ) INTO NetValue_; 	
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Credit_Note_Details_, CONCAT('$[',i,'].Country_Id')) ),  'null' ), 0 ) INTO Country_Id_; 	
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Credit_Note_Details_, CONCAT('$[',i,'].Country_Name')) ),  'null' ), 0 ) INTO Country_Name_; 	
SET CreditNote_Details_Id_ = (select COALESCE( MAX(CreditNote_Details_Id ),0)+1 from creditnote_details);
INSERT INTO creditnote_details 
(CreditNote_Details_Id,
    CreditNote_Master_Id, ItemId, ItemCode, ItemName, GroupId, GroupName, 
    UnitId, UnitName, HSNCODE, UnitPrice, Quantity, Amount, 
     SaleTax, TaxableAmount, TaxAmount, PurchaseRate, DeleteStatus,
     HSNMasterId  ,Item_Discount_Amount ,NetValue, Country_Id ,Country_Name, StockId
     
) 
VALUES (CreditNote_Details_Id_,
    CreditNote_Master_Id_, ItemId_, ItemCode_, ItemName_, GroupId_, GroupName_,
    UnitId_, UnitName_, HSNCODE_, UnitPrice_, Quantity_, Amount_,
     SaleTax_, TaxableAmount_, TaxAmount_, PurchaseRate_, false ,
     HSNMasterId_  ,Item_Discount_Amount_ , NetValue_, Country_Id_, Country_Name_, StockId_
); 	
		SELECT i + 1 INTO i;
	END WHILE;  

 select CreditNote_Master_Id_;
 End
$$
DELIMITER ;

