declare InvNo_ varchar(100);
declare NetTotal_ decimal(18,2);
declare PaymentTerms_ VARCHAR(250);
declare Payment_Term_Description_ INT ;
declare LPONo_ varchar(250);
declare PriceBasis_  varchar(50);
declare TotalDiscount_ decimal(18,2);
declare TypeId_ int;
declare Credit_Note_Details_ JSON ;
declare User_Id_ int;
declare VAT_Amount_ decimal(18,2);
declare VAT_Description_ varchar(500);
declare VAT_Percentage_ decimal(18,2);
declare charge1_Amount_ decimal(18,2);
declare charge2_Amount_ decimal(18,2);
DECLARE CurrecnyName_ VARCHAR(45);
DECLARE payment_Term_Value_ INT;


if CreditNote_Master_Value_>0 then

SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.CreditNote_Master_Id')) INTO CreditNote_Master_Id_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.Account_Party_Id')) INTO Account_Party_Id_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.EntryDate')) INTO EntryDate_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.Additional_Discount')) INTO Additional_Discount_;
SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(CreditNote_Master_, '$.Additional_Discount') ),  'null' ), 0 ) INTO Additional_Discount_;

SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.Amount_In_Words')) INTO Amount_In_Words_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.Makes')) INTO Makes_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.Charge1')) INTO Charge1_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.Charge2')) INTO Charge2_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.CurrencyId')) INTO CurrencyId_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.CurrencyId')) INTO CurrencyId_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.Discount_Description')) INTO Discount_Description_;
SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(CreditNote_Master_, '$.Discount_Description') ),  'null' ), 0 ) INTO Discount_Description_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.InvNo')) INTO InvNo_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.NetTotal')) INTO NetTotal_;
SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(CreditNote_Master_, '$.NetTotal') ),  'null' ), 0 ) INTO NetTotal_;

SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.PaymentTerms')) INTO PaymentTerms_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.Payment_Term_Description')) INTO Payment_Term_Description_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.payment_Term_Value')) INTO payment_Term_Value_;
SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(CreditNote_Master_, '$.payment_Term_Value') ),  'null' ), 0 ) INTO payment_Term_Value_;

SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.LPONo')) INTO LPONo_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.PriceBasis')) INTO PriceBasis_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.TotalDiscount')) INTO TotalDiscount_;
SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(CreditNote_Master_, '$.TotalDiscount') ),  'null' ), 0 ) INTO TotalDiscount_;

SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.TypeId')) INTO TypeId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.Credit_Note_Details')) INTO Credit_Note_Details_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.User_Id')) INTO User_Id_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.VAT_Amount')) INTO VAT_Amount_;
SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(CreditNote_Master_, '$.VAT_Amount') ),  'null' ), 0 ) INTO VAT_Amount_;

SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.VAT_Description')) INTO VAT_Description_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.VAT_Percentage')) INTO VAT_Percentage_;
SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(CreditNote_Master_, '$.VAT_Percentage') ),  'null' ), 0 ) INTO VAT_Percentage_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.charge1_Amount')) INTO charge1_Amount_;
SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(CreditNote_Master_, '$.charge1_Amount') ),  'null' ), 0 ) INTO charge1_Amount_;

#SELECT JSON_UNQUOTE (JSON_EXTRACT(CreditNote_Master_,'$.charge2_Amount')) INTO charge2_Amount_;
SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(CreditNote_Master_, '$.charge2_Amount') ),  'null' ), 0 ) INTO charge2_Amount_;

end if;

if  CreditNote_Master_Id_>0  THEN
UPDATE creditnote_master 
SET Account_Party_Id =Account_Party_Id_, EntryDate =EntryDate_, InvNo =InvNo_ ,
	TotalDiscount =TotalDiscount_, NetTotal =NetTotal_, User_Id =User_Id_, 
    Additional_Discount =Additional_Discount_, Amount_In_Words =Amount_In_Words_, Makes =Makes_,
    Charge1 =Charge1_, Charge2 =Charge2_, CurrencyId =CurrencyId_, 
    Discount_Description =Discount_Description_, PaymentTerms =PaymentTerms_,
    Payment_Term_Description =Payment_Term_Description_, payment_Term_Value =payment_Term_Value_,
    LPONo = LPONo_, PriceBasis =PriceBasis_, TypeId =TypeId_, VAT_Amount =VAT_Amount_, 
    VAT_Description =VAT_Description_, VAT_Percentage =VAT_Percentage_, 
    charge1_Amount =charge1_Amount_, charge2_Amount =charge2_Amount_, CurrecnyName =CurrecnyName_
WHERE CreditNote_Master_Id = CreditNote_Master_Id_;
else
	SET CreditNote_Master_Id_ = (SELECT  COALESCE( MAX(CreditNote_Master_Id ),0)+1 FROM creditnote_master);
    
		INSERT INTO creditnote_master 
        (
        CreditNote_Master_Id, Account_Party_Id, EntryDate, InvNo, TotalDiscount, NetTotal,
        User_Id, Additional_Discount, Amount_In_Words, Makes, Charge1,
		Charge2, CurrencyId, Discount_Description, PaymentTerms, Payment_Term_Description, 
        LPONo, PriceBasis, TypeId, VAT_Amount, VAT_Description, VAT_Percentage, charge1_Amount,
		charge2_Amount, CurrecnyName, payment_Term_Value, DeleteStatus
        )
		VALUES 
        (
        CreditNote_Master_Id_, Account_Party_Id_, EntryDate_, InvNo_, TotalDiscount_, NetTotal_,
        User_Id_, Additional_Discount_, Amount_In_Words_, Makes_, Charge1_,
        Charge2_,CurrencyId_, Discount_Description_, PaymentTerms_, Payment_Term_Description_, 
        LPONo_, PriceBasis_, TypeId_, VAT_Amount_, VAT_Description_, VAT_Percentage_, charge1_Amount_,
        charge2_Amount_, CurrecnyName_, payment_Term_Value_, 0
        );
	End If ;



CALL Save_CreditNote_Details_1(Credit_Note_Details_ ,CreditNote_Master_Id_ );
SELECT CreditNote_Master_Id_;
 End
$$
DELIMITER ;

