CREATE PROCEDURE `Save_currencydetails`
BEGIN
if  CurrencyDetails_Id_>0
 THEN 
 UPDATE currencydetails set CurrencyDetails_Id = CurrencyDetails_Id_ ,
CurrecnyName = CurrecnyName_ ,SubCurrecnyName=SubCurrecnyName_ Where CurrencyDetails_Id = CurrencyDetails_Id_ ;
