CREATE PROCEDURE `Save_Damage_Details`
Begin  
	DECLARE Item_Id_ decimal(18,0);DECLARE Barcode_ varchar(1000);DECLARE GroupId_ decimal(18,0);DECLARE GroupName_ varchar(100);
    DECLARE UnitId_ decimal(18,0);DECLARE UnitName_ varchar(100);DECLARE PurchaseRate_ decimal(18,2);DECLARE SaleRate_ decimal(18,2);
    DECLARE MRP_ decimal(18,2);DECLARE HSNMasterId_ decimal(18,0);DECLARE HSNCODE_ varchar(50);DECLARE GST_ decimal(18,2);
    DECLARE Quantity_ decimal(18,2);DECLARE CGST_ decimal(18,2);DECLARE SGST_ decimal(18,2);DECLARE StockId_ decimal(18,0);
    DECLARE Amount_ decimal(18,2);DECLARE Item_Name_ varchar(1000);
DECLARE i int  DEFAULT 0;
	WHILE i < JSON_LENGTH(Damage_Details) DO    		
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].ItemId'))) INTO Item_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].Barcode'))) INTO Barcode_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].ItemName'))) INTO Item_Name_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].GroupId'))) INTO GroupId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].UnitId'))) INTO UnitId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].UnitName'))) INTO UnitName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].StockId'))) INTO StockId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].PurchaseRate'))) INTO PurchaseRate_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].SaleRate'))) INTO SaleRate_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].MRP'))) INTO MRP_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].HSNMasterId'))) INTO HSNMasterId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].HSNCODE'))) INTO HSNCODE_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].GST'))) INTO GST_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].Amount'))) INTO Amount_;		  
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].CGST'))) INTO CGST_;   
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Damage_Details,CONCAT('$[',i,'].SGST'))) INTO SGST_;    
		INSERT INTO Damage_Details(Damage_Master_Id,ItemId,Barcode,ItemName,GroupId,GroupName,UnitId,
UnitName,StockId,HSNMasterId,HSNCODE,Quantity,GST,CGST,SGST ,SaleRate,MRP,PurchaseRate,Amount,DeleteStatus)
		values (Damage_Master_Id_,Item_Id_,Barcode_,Item_Name_,GroupId_,GroupName_,UnitId_,
UnitName_,StockId_,HSNMasterId_,HSNCODE_,Quantity_,GST_,CGST_,SGST_ ,SaleRate_,MRP_,PurchaseRate_,Amount_,false);		
      
		SELECT i + 1 INTO i;
	END WHILE;    
SELECT Damage_Master_Id_;
End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_Damage_Master`
Begin 
/*DECLARE exit handler for sqlexception
BEGIN
	GET DIAGNOSTICS CONDITION 1
	@p1 = RETURNED_SQLSTATE, @p2 = MESSAGE_TEXT;
	SELECT @p2 AS MESSAGE_TEXT, @p1 AS RETURNED_SQLSTATE;
	ROLLBACK;
END;
    DECLARE exit handler for sqlwarning
BEGIN
	GET DIAGNOSTICS CONDITION 1
	@p1 = RETURNED_SQLSTATE, @p2 = MESSAGE_TEXT;
	SELECT @p2 AS MESSAGE_TEXT, @p1 AS RETURNED_SQLSTATE;
	ROLLBACK;
END;
    START TRANSACTION;*/
 if  Damage_Master_Id_>0
	 THEN 
	 Delete From Damage_Details Where  Damage_Master_Id=Damage_Master_Id_ ;
	 UPDATE Damage_Master set Date = Date_ ,Damage_No = Damage_No_ ,User_Id = User_Id_  
	 Where Damage_Master_Id=Damage_Master_Id_ ;
	 ELSE 
	 SET Damage_No_ = (SELECT COALESCE( MAX(Damage_No ),0)+1 FROM Damage_Master); 
	 SET Damage_Master_Id_ = (SELECT COALESCE( MAX(Damage_Master_Id ),0)+1 FROM Damage_Master); 
	 INSERT INTO Damage_Master(Damage_Master_Id ,Date ,Damage_No ,User_Id ,DeleteStatus ) 
	 values (Damage_Master_Id_ ,Date_ ,Damage_No_ ,User_Id_ ,false);
End If ;
 CALL Save_Damage_Details(Damage_Details  , Damage_Master_Id_ );
 select Damage_Master_Id_;
 #Commit;
 End
