	Set File_Name_2_ = File_Name_;
else
	Set File_Name_2_ = File_Name_1_;
end if;*/

  IF Daybook_Id_>0 THEN
  
	IF File_Name_ IS NOT NULL || File_Name_ <> '' || File_Path_ IS NOT NULL || File_Path_ <> '' THEN
    
		UPDATE Daybook 
		SET 
			Item_Id=Item_Id_, Item_Name=Item_Name_, Item_Code=Item_Code_,
			Item_Group_Id=Item_Group_Id_, Item_Group_Name=Item_Group_Name_, 
			Master_Category_Id=Master_Category_Id_, Master_Category_Name=Master_Category_Name_,
			Client_Accounts_Id=Client_Accounts_Id_, Client_Accounts_Name=Client_Accounts_Name_, 
			File_Name=File_Name_, File_Path=File_Path_, Quantity=Quantity_,  Remarks=Remarks_,
            Amount=Amount_
		WHERE 
			Daybook_Id = Daybook_Id_;
	ELSE
		UPDATE Daybook 
		SET 
			Item_Id=Item_Id_, Item_Name=Item_Name_, Item_Code=Item_Code_,
			Item_Group_Id=Item_Group_Id_, Item_Group_Name=Item_Group_Name_, 
			Master_Category_Id=Master_Category_Id_, Master_Category_Name=Master_Category_Name_,
			Client_Accounts_Id=Client_Accounts_Id_, Client_Accounts_Name=Client_Accounts_Name_, 
			Quantity=Quantity_,  Remarks=Remarks_, Amount=Amount_
		WHERE 
			Daybook_Id = Daybook_Id_;
	 END IF;
    
ELSE
	SET Daybook_Id_ = (SELECT  COALESCE( MAX(Daybook_Id ),0)+1 FROM Daybook);
	SET Reference_Number_ = (SELECT  COALESCE( MAX(Reference_Number ),0)+1 FROM Daybook); 

    
	INSERT INTO Daybook (
		Daybook_Id, Item_Id, Item_Name, Item_Code, Item_Group_Id, Item_Group_Name, 
        Master_Category_Id, Master_Category_Name, Client_Accounts_Id, Client_Accounts_Name, DeleteStatus,
        File_Name, Quantity, Remarks, Entry_Date, Reference_Number, File_Path,Amount)
    VALUES (
		Daybook_Id_, Item_Id_, Item_Name_, Item_Code_, Item_Group_Id_, Item_Group_Name_, 
        Master_Category_Id_, Master_Category_Name_, Client_Accounts_Id_, Client_Accounts_Name_, 0,
        File_Name_, Quantity_, Remarks_, NOW(), Reference_Number_, File_Path_,Amount_);
end if; 
    end if;
select Daybook_Id_;
END
$$
