CREATE PROCEDURE `Save_debitnote_details`
Begin 
    DECLARE StockId_ decimal(18,0);DECLARE ItemId_ decimal(18,0);DECLARE ItemName_ varchar(1000);DECLARE ItemCode_ VARCHAR(100);
    DECLARE GroupId_ decimal(18,0); DECLARE GroupName_ VARCHAR(100);DECLARE UnitId_ decimal(18,0);DECLARE UnitName_ VARCHAR(100);declare Unit_Discount_ decimal(18,3);
    DECLARE PurchaseRate_ decimal(18,3);DECLARE UnitPrice_ decimal(18,3);DECLARE MRP_ decimal(18,3);DECLARE HSNMasterId_ decimal(18,0);declare TaxableAmount_ decimal(18,3);
    DECLARE HSNCODE_ varchar(50);DECLARE SaleTax_ decimal(18,3);DECLARE CGST_ decimal(18,3);DECLARE SGST_ decimal(18,3);DECLARE IGST_ decimal(18,3);
    DECLARE Cesspers_ decimal(18,3);DECLARE Quantity_ decimal(18,3);DECLARE GrossValue_ decimal(18,3);DECLARE Discount_ decimal(18,3);declare Amount_ decimal(18,3);
    declare NetValue_ decimal(18,3);DECLARE CGSTAMT_ decimal(18,3);DECLARE SGSTAMT_ decimal(18,3);declare TaxAmount_ decimal(18,3);
    DECLARE IGSTAMT_ decimal(18,3);DECLARE CessAMT_ decimal(18,3);DECLARE TotalAmount_ decimal(18,3);DECLARE Description_ varchar(4500);
	DECLARE i int  DEFAULT 0;declare Country_Id_ int;declare Country_Name_ varchar(100);declare Item_Discount_Amount_ decimal(18,3);
    DECLARE DebitNote_Details_Id_ int;
    delete from debitnote_details where DebitNote_Master_Id = DebitNote_Master_Id_;
    
	WHILE i < JSON_LENGTH(debitnote_details) DO
		SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].StockId'))) INTO StockId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].ItemId'))) INTO ItemId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].ItemName'))) INTO ItemName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].ItemCode'))) INTO ItemCode_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].GroupId'))) INTO GroupId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].UnitId'))) INTO UnitId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].UnitName'))) INTO UnitName_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(debitnote_details, CONCAT('$.PurchaseRate')) ),  'null' ), 0 ) INTO PurchaseRate_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].Unit_Discount'))) INTO Unit_Discount_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].TaxableAmount'))) INTO TaxableAmount_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].UnitPrice'))) INTO UnitPrice_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(debitnote_details, CONCAT('$.MRP')) ),  'null' ), 0 ) INTO MRP_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(debitnote_details, CONCAT('$.HSNMasterId')) ),  'null' ), 0 ) INTO HSNMasterId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].HSNCODE'))) INTO HSNCODE_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(debitnote_details, CONCAT('$.SaleTax')) ),  'null' ), 0 ) INTO SaleTax_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].Item_Discount_Amount'))) INTO Item_Discount_Amount_;
		/*SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].CGST'))) INTO CGST_;   
		SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].SGST'))) INTO SGST_;    
		SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].IGST'))) INTO IGST_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].Cesspers'))) INTO Cesspers_;*/
		SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;  
        SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].Amount'))) INTO Amount_; 
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].GrossValue'))) INTO GrossValue_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].Discount'))) INTO Discount_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].NetValue'))) INTO NetValue_;
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].CGSTAMT'))) INTO CGSTAMT_;
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].SGSTAMT'))) INTO SGSTAMT_; 
        SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].TaxAmount'))) INTO TaxAmount_;
        #SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].IGSTAMT'))) INTO IGSTAMT_;
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].CessAMT'))) INTO CessAMT_;
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].TotalAmount'))) INTO TotalAmount_;     
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(debitnote_details,CONCAT('$[',i,'].Description'))) INTO Description_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(debitnote_details, CONCAT('$.Country_Id')) ),  'null' ), 0 ) INTO Country_Id_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(debitnote_details, CONCAT('$.Country_Name')) ),  'null' ), 0 ) INTO Country_Name_;

        
        set DebitNote_Details_Id_ = (select COALESCE( MAX(DebitNote_Details_Id ),0)+1 from debitnote_details);
        
		INSERT INTO debitnote_details(DebitNote_Details_Id,DebitNote_Master_Id ,StockId ,ItemId ,ItemName ,ItemCode ,GroupId ,GroupName ,
		UnitId ,UnitName ,PurchaseRate ,UnitPrice ,MRP ,HSNMasterId ,HSNCODE ,SaleTax ,TaxableAmount,
		Quantity  ,Discount,NetValue,TaxAmount  ,Unit_Discount,Amount,DeleteStatus,Country_Id,Country_Name,Item_Discount_Amount ) 
		values (DebitNote_Details_Id_,DebitNote_Master_Id_ ,StockId_ ,ItemId_ ,ItemName_ ,ItemCode_ ,GroupId_ ,GroupName_ ,UnitId_ ,
		UnitName_ ,PurchaseRate_ ,UnitPrice_ ,MRP_ ,HSNMasterId_ ,HSNCODE_ ,SaleTax_,TaxableAmount_,
		Quantity_  ,Discount_ ,NetValue_ ,TaxAmount_ ,Unit_Discount_,Amount_,false,Country_Id_,Country_Name_,Item_Discount_Amount_);
		update Stock Set Quantity=Quantity-Quantity_ where Stock_Id=StockId_ ;
		SELECT i + 1 INTO i;
	END WHILE;  
SELECT DebitNote_Master_Id_,Voucher_No_;
End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_debitnote_master`
Begin
declare Voucher_No_ int;declare Accounts_Id_ decimal;declare YearFrom datetime;declare YearTo datetime;declare billtypes_ varchar(100);

 if  DebitNote_Master_Id_>0
 THEN
 
 set Voucher_No_ =(select InvNo from debitnote_master where DebitNote_Master_Id = DebitNote_Master_Id_ and deletestatus = 0);
/*call Update_Stock_FromSales(DebitNote_Master_Id_);
  Delete From Sales_Details Where DebitNote_Master_Id = DebitNote_Master_Id_;*/
  delete from Accounts where Tran_Id = DebitNote_Master_Id_ and Tran_Type = 'DBN';
UPDATE debitnote_master set Account_Party_Id = Account_Party_Id_ ,User_Id = User_Id_ ,EntryDate = EntryDate_,LPONo = LPONo_,DONo = DONo_,PackingListNumber= PackingListNumber_,
    TotalDiscount = TotalDiscount_ ,NetTotal = NetTotal_ ,CurrencyId = CurrencyId_,TypeId=TypeId_,PaymentTerms=PaymentTerms_,TaxableAmount=TaxableAmount_,Charge2=Charge2_,
    Total_Amount = Total_Amount_ ,Roundoff_Amt = Roundoff_Amt_ ,TotalAmount = TotalAmount_ ,charge1_Amount=charge1_Amount_,charge2_Amount=charge2_Amount_,SupplyDate=SupplyDate_,Basic_Discount=Basic_Discount_,
Delivery_Address1=Delivery_Address1_,Delivery_Address2=Delivery_Address2_,Delivery_Address3=Delivery_Address3_,Delivery_Address4=Delivery_Address4_,Discount_Description=Discount_Description_,
    Additional_Discount=Additional_Discount_,Description2=Description2_,Employee=Employee_,Amount_In_Words=Amount_In_Words_,Charge1per=Charge1per_,Payment_Term_Description=Payment_Term_Description_,
    VAT_percentage=VAT_percentage_,VAT_Amount=VAT_Amount_,DueDate=DueDate_,KindAttend=KindAttend_,AttendEmployee=AttendEmployee_,
    PaymentTermValue=PaymentTermValue_,Charge1=Charge1_,
    InvNo =Voucher_No_
    Where DebitNote_Master_Id = DebitNote_Master_Id_ ;
   
 ELSE
 set YearFrom=(select Account_Years.YearFrom from Account_Years where Date_Format(EntryDate_,'%Y-%m-%d')
    between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));
set YearTo=(select Account_Years.YearTo from Account_Years where Date_Format(EntryDate_,'%Y-%m-%d')
    between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));  
if exists(select distinct InvNo from debitnote_master)then
set Voucher_No_=(SELECT COALESCE( MAX(InvNo),0)+1 FROM debitnote_master where Date_Format(EntryDate,'%Y-%m-%d')
    between Date_Format(YearFrom,'%Y-%m-%d') and Date_Format(YearTo,'%Y-%m-%d'));  
else
if exists(select DebitNote_No from General_Settings)
then
set Voucher_No_=(select COALESCE(DebitNote_No,0) from General_Settings);
else
set Voucher_No_=1;
end if;    
end if;
    SET DebitNote_Master_Id_ = (SELECT COALESCE( MAX(DebitNote_Master_Id ), 0) + 1 FROM debitnote_master );
INSERT INTO debitnote_master(DebitNote_Master_Id,Account_Party_Id,User_Id,EntryDate,InvNo,LPONo,DONo,PackingListNumber,TotalDiscount,NetTotal,CurrencyId,TypeId,TotalAmount,
    PaymentTerms,TaxableAmount,Charge2,Total_Amount,Roundoff_Amt,charge1_Amount,charge2_Amount,SupplyDate,Basic_Discount,
    Delivery_Address1,Delivery_Address2,Delivery_Address3,  Delivery_Address4,Discount_Description,Additional_Discount,Description2,Employee,Amount_In_Words,
    Charge1per,Payment_Term_Description,  VAT_percentage,VAT_Amount,DueDate,KindAttend,AttendEmployee,PaymentTermValue,Charge1,DeleteStatus)
   
values (DebitNote_Master_Id_,Account_Party_Id_,User_Id_,EntryDate_,Voucher_No_,LPONo_,DONo_,PackingListNumber_,TotalDiscount_,NetTotal_,CurrencyId_,TypeId_, TotalAmount_,
    PaymentTerms_,TaxableAmount_,Charge2_,Total_Amount_,Roundoff_Amt_,charge1_Amount_,charge2_Amount_,SupplyDate_,Basic_Discount_,
    Delivery_Address1_,Delivery_Address2_,Delivery_Address3_,Delivery_Address4_,Discount_Description_,Additional_Discount_,Description2_,Employee_,Amount_In_Words_,
    Charge1per_,Payment_Term_Description_,VAT_percentage_,VAT_Amount_,DueDate_,KindAttend_,AttendEmployee_,PaymentTermValue_,Charge1_,False );
End If ;
 /* if DebitNote_Master_Id_ = 0 then
set DebitNote_Master_Id_ = (SELECT LAST_INSERT_ID());    
  end if;*/
 
 if(NetTotal_>0)
 then
insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,VoucherType,Description1,Status,DayBook,Payment_Status)
values(0,EntryDate_,5,0,NetTotal_,Account_Party_Id_,'DBN',DebitNote_Master_Id_, Voucher_No_,5,'','','',1);
#set Accounts_Id_ = (select COALESCE( MAX(Accounts_Id ),0)+1 from Accounts);
insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,VoucherType,Description1,Status,DayBook,Payment_Status)
values(0,EntryDate_,Account_Party_Id_,NetTotal_,0,5,'DBN',DebitNote_Master_Id_, Voucher_No_ ,5,'','','Y',1);
 end IF;
  if(VAT_Amount_>0)
 then
 insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,VoucherType,Description1,Status,DayBook,Payment_Status)
 values(0,EntryDate_,18,0,VAT_Amount_,5,'DBN',DebitNote_Master_Id_, Voucher_No_,5,'','','',1);
 #set Accounts_Id_ = (select COALESCE( MAX(Accounts_Id ),0)+1 from Accounts);
 insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,VoucherType,Description1,Status,DayBook,Payment_Status)
 values(0,EntryDate_,5,VAT_Amount_,0,18,'DBN',DebitNote_Master_Id_, Voucher_No_ ,5,'','','Y',1);
 end IF;

CALL Save_debitnote_details(debitnote_details_ ,DebitNote_Master_Id_,Voucher_No_);
 select DebitNote_Master_Id_,Voucher_No_;
 #COMMIT;
 End
$$
DELIMITER ;

