CREATE PROCEDURE `Save_Delivery_Order_Details`
BEGIN

declare ItemId_ int;declare ItemCode_ varchar(500);
declare ItemName_ varchar(1000);declare UnitId_ int;
declare UnitName_ varchar(100);declare StockId_ int;
declare HSNMasterId_ int;declare HSNCODE_ varchar(50);
declare UnitPrice_ decimal(18,3);declare Quantity_ decimal(18,3);
#declare Amount_ decimal;declare TaxableAmount_ decimal;declare TaxAmount_ decimal;

declare Discount_ decimal(18,3);
declare NetValue_ decimal(18,3);declare Availability_ varchar(100);
#declare Unit_Discount_ decimal(18,3); declare Sale_Tax_ decimal(18,3);
declare DeliveryOrderDetails_Id_ INT;
DECLARE i int  DEFAULT 0;declare GroupName_ varchar(45);
declare GroupId_ int; declare Country_Id_ int default 0;declare Country_Name_ varchar(50) default '';
declare  Amount_ decimal(18,3);declare  TaxableAmount_ decimal(18,3) ;declare TaxAmount_ decimal(18,3);
declare Unit_Discount_ decimal(18,3); declare Sale_Tax_ decimal(18,3);
declare Item_Discount_Amount_ decimal(18,3);

UPDATE  deliveryorderdetails SET DeleteStatus = 1 WHERE DeliveryMaster_Id = DeliveryOrderMaster_Id_;

WHILE i < JSON_LENGTH(Delivery_Order_Details_) DO
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].ItemId'))) INTO ItemId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].Item_Code'))) INTO ItemCode_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].ItemName'))) INTO ItemName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].UnitId'))) INTO UnitId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].UnitName'))) INTO UnitName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].GroupId'))) INTO GroupId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].StockId'))) INTO StockId_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Delivery_Order_Details_, CONCAT('$[', i, '].StockId'))), 'null'), 0) INTO StockId_;

		#SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].HSNMasterId'))) INTO HSNMasterId_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Delivery_Order_Details_, CONCAT('$[', i, '].HSNMasterId'))), 'null'), 0) INTO HSNMasterId_;

        SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].HSNCODE'))) INTO HSNCODE_;
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Delivery_Order_Details_, CONCAT('$[', i, '].Quantity'))), 'null'), 0) INTO Quantity_;
        #SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].UnitPrice'))) INTO UnitPrice_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Delivery_Order_Details_, CONCAT('$[', i, '].UnitPrice'))), 'null'), 0) INTO UnitPrice_;

        #SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].Country_Id'))) INTO Country_Id_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Delivery_Order_Details_, CONCAT('$[', i, '].Country_Id'))), 'null'), 0) INTO Country_Id_;

        SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].Country_Name'))) INTO Country_Name_;   
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].Sale_Tax'))) INTO Sale_Tax_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Delivery_Order_Details_, CONCAT('$[', i, '].Sale_Tax'))), 'null'), 0) INTO Sale_Tax_;

		#SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].Amount'))) INTO Amount_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Delivery_Order_Details_, CONCAT('$[', i, '].Amount'))), 'null'), 0) INTO Amount_;

		#SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].TaxableAmount'))) INTO TaxableAmount_; 
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Delivery_Order_Details_, CONCAT('$[', i, '].TaxableAmount'))), 'null'), 0) INTO TaxableAmount_;

		#SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].TaxAmount'))) INTO TaxAmount_; 
        SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Delivery_Order_Details_, CONCAT('$[', i, '].TaxAmount'))), 'null'), 0) INTO TaxAmount_;

		#SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].Discount'))) INTO Discount_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Delivery_Order_Details_, CONCAT('$[', i, '].Discount'))), 'null'), 0) INTO Discount_;
        #SELECT JSON_UNQUOTE (JSON_EXTRACT(Delivery_Order_Details_,CONCAT('$[',i,'].NetValue'))) INTO NetValue_;   
        SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Delivery_Order_Details_, CONCAT('$[', i, '].NetValue'))), 'null'), 0) INTO NetValue_;
        SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Delivery_Order_Details_, CONCAT('$[', i, '].Unit_Discount'))), 'null'), 0) INTO Unit_Discount_;
        SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Delivery_Order_Details_, CONCAT('$[', i, '].Sale_Tax'))), 'null'), 0) INTO Sale_Tax_;
        SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Delivery_Order_Details_, CONCAT('$[', i, '].Item_Discount_Amount'))), 'null'), 0) INTO Item_Discount_Amount_;



        SET DeliveryOrderDetails_Id_ = (SELECT  COALESCE( MAX(DeliveryOrderDetails_Id ),0)+1 FROM deliveryorderdetails);
        
		INSERT INTO deliveryorderdetails
        (
			DeliveryOrderDetails_Id, DeliveryMaster_Id, ItemId, ItemCode, ItemName,
		    UnitId, UnitName, StockId, HSNMasterId, HSNCODE,Quantity,DeleteStatus,GroupId,GroupName,UnitPrice,
            Country_Id,Country_Name,Amount,TaxableAmount,TaxAmount,Discount,NetValue,
            Item_Discount_Amount,
			SaleTax,
			Unit_Discount
            )
		VALUES(
			DeliveryOrderDetails_Id_, DeliveryOrderMaster_Id_, ItemId_, ItemCode_, ItemName_,
            UnitId_, UnitName_, StockId_, HSNMasterId_, HSNCODE_,Quantity_,0,GroupId_,GroupName_,UnitPrice_,
            Country_Id_,Country_Name_,Amount_,TaxableAmount_,TaxAmount_,Discount_,NetValue_,
			 Item_Discount_Amount_,
             Sale_Tax_,
			 Unit_Discount_
            );
		SELECT i + 1 INTO i;
END WHILE;  
SELECT DeliveryOrderMaster_Id_,DONo_;

END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_Delivery_Order_Master`
BEGIN
DECLARE i int  DEFAULT 0;
DECLARE Invoice_ VARCHAR(250)  DEFAULT '';
DECLARE PurchaseOrderMaster_Id_ int  DEFAULT 0;
DECLARE YearFrom DATETIME;
DECLARE YearTo DATETIME;DECLARE Performa_Delivery_Id_ int;
DECLARE DeliveryOrderMaster_PurchaseOrderMaster_Id_ int;
# From Year Set up
IF(DeliveryOrderMaster_Id_ > 0) THEN

UPDATE deliveryordermaster
SET DeliveryOrderMaster_Id = DeliveryOrderMaster_Id_,
Account_Party_Id = Account_Party_Id_,
    EntryDate = EntryDate_,
CurrencyId = CurrencyId_,
    PaymentTerms = PaymentTerms_,
User_Id = User_Id_,
    Delivery_Address1 = Delivery_Address1_,
    Delivery_Address2 = Delivery_Address2_,
Delivery_Address3 = Delivery_Address3_,
    Delivery_Address4 = Delivery_Address4_,
Received_By = Received_By_,
Payment_Term_Description = Payment_Term_Description_,
Kind_Attend = Kind_Attend_,
    payment_Term_Value = payment_Term_Value_,
    UserName = UserName_,
    TypeId = TypeId_,
    TotalAmount =TotalAmount_,
    TotalDiscount =TotalDiscount_,
    NetTotal =NetTotal_,
    LPONo = LPONo1_,
    DONo=DONo_
WHERE DeliveryOrderMaster_Id = DeliveryOrderMaster_Id_;

ELSE
SET YearFrom=(
SELECT Account_Years.YearFrom FROM Account_Years
WHERE  Date_Format(EntryDate_,'%Y-%m-%d')
BETWEEN Date_Format(Account_Years.YearFrom,'%Y-%m-%d')
AND Date_Format(Account_Years.YearTo,'%Y-%m-%d')
              );
     
# To Year Set up

SET YearTo=(
SELECT Account_Years.YearTo FROM Account_Years
   WHERE Date_Format(EntryDate_,'%Y-%m-%d')
                BETWEEN Date_Format(Account_Years.YearFrom,'%Y-%m-%d')
