CREATE PROCEDURE `Save_Department`
BEGIN
        IF p_Department_Id = 0 THEN
            IF EXISTS (SELECT 1 FROM Department WHERE Department_Name = p_Department_Name AND DeleteStatus = 0) THEN
                SELECT -1 AS Department_Id_;
            ELSE
                INSERT INTO Department (Department_Name, Description, DeleteStatus)
                VALUES (p_Department_Name, p_Description, 0);
                SELECT LAST_INSERT_ID() AS Department_Id_;
            END IF;
        ELSE
            IF EXISTS (SELECT 1 FROM Department WHERE Department_Name = p_Department_Name AND Department_Id != p_Department_Id AND DeleteStatus = 0) THEN
                SELECT -1 AS Department_Id_;
            ELSE
                UPDATE Department 
                SET Department_Name = p_Department_Name,
                    Description = p_Description
                WHERE Department_Id = p_Department_Id;
                SELECT p_Department_Id AS Department_Id_;
            END IF;
        END IF;
    END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_DepartmentStatus`
BEGIN
        IF p_DepartmentStatus_Id = 0 THEN
            IF EXISTS (SELECT 1 FROM DepartmentStatus WHERE Status_Name = p_Status_Name AND DeleteStatus = 0) THEN
                SELECT -1 AS DepartmentStatus_Id_;
            ELSE
                INSERT INTO DepartmentStatus (Status_Name, Description, DeleteStatus)
                VALUES (p_Status_Name, p_Description, 0);
                SELECT LAST_INSERT_ID() AS DepartmentStatus_Id_;
            END IF;
        ELSE
            IF EXISTS (SELECT 1 FROM DepartmentStatus WHERE Status_Name = p_Status_Name AND DepartmentStatus_Id != p_DepartmentStatus_Id AND DeleteStatus = 0) THEN
                SELECT -1 AS DepartmentStatus_Id_;
            ELSE
                UPDATE DepartmentStatus 
                SET Status_Name = p_Status_Name,
                    Description = p_Description
                WHERE DepartmentStatus_Id = p_DepartmentStatus_Id;
                SELECT p_DepartmentStatus_Id AS DepartmentStatus_Id_;
            END IF;
        END IF;
    END
$$
DELIMITER ;

