CREATE PROCEDURE `Save_Document`
BEGIN
declare Document_Id_ int;declare Branch_Name_ varchar(500);
declare Period_From_ datetime;
declare Period_To_ datetime;
declare Document_Type_Name_ varchar(500);
declare Document_Type_Id_ int;
declare Branch_Id_ int;
declare Document_Description_ varchar(500);
 declare Doc_Photo_ varchar(500);
declare Document_Name_ text;
declare File_Name_1_ longtext;
declare File_Name_2_ longtext;
declare File_Name_3_ longtext;
if( Value_>0) then
SELECT JSON_UNQUOTE (JSON_EXTRACT(Document_,'$.Document_Id')) INTO Document_Id_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Document_,'$.Period_From')) INTO Period_From_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Document_,'$.Period_To')) INTO Period_To_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Document_,'$.Document_Type_Id')) INTO Document_Type_Id_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Document_,'$.Document_Type_Name')) INTO Document_Type_Name_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Document_,'$.Document_Description')) INTO Document_Description_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Document_,'$.Document_Name')) INTO Document_Name_;
 SELECT JSON_UNQUOTE (JSON_EXTRACT(Document_,'$.Doc_Photo')) INTO Doc_Photo_;
  SELECT JSON_UNQUOTE (JSON_EXTRACT(Document_,'$.Branch_Id')) INTO Branch_Id_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Document_,'$.Branch_Name')) INTO Branch_Name_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Document_,'$.File_Path_2')) INTO File_Name_2_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Document_,'$.File_Path_1')) INTO File_Name_1_;


delete from db_logs;
insert into db_logs values(0,File_Name_1_,File_Name_2_,'fileupload');
if File_Name_1_ is null || File_Name_1_ = '' then
	Set File_Name_3_ = File_Name_2_;
else
	Set File_Name_3_ = File_Name_1_;
end if;


if Document_Id_>0 then
UPDATE Document set  Document_Name = Document_Name_ ,Period_From=Period_From_,Period_To=Period_To_,Document_Type_Id=Document_Type_Id_ ,
