SET Document_Id_ = (SELECT  COALESCE( MAX(Document_Id ),0)+1 FROM Document);
insert into Document(Document_Id,Period_From,Period_To,Document_Type_Id,Document_Type_Name,Document_Description,Doc_Photo,File_Upload,Document_Name,DeleteStatus,Branch_Id,Branch_Name,Entry_Date)
values(Document_Id_,Period_From_,Period_To_,Document_Type_Id_,Document_Type_Name_,Document_Description_,Doc_Photo_,File_Name_3_,Document_Name_,0,Branch_Id_,Branch_Name_,now());
 end if;
    end if;
select Document_Id_;
END
