CREATE PROCEDURE `Save_Employee_Details`
Begin 
declare Employee_Details_Id_ decimal;Declare Level_Id_ decimal;Declare Client_Accounts_Id_JSON int;
declare DesigId_ decimal;declare DateOfBirth_ datetime;declare DateOfJoin_ datetime;
declare ReleiveDate_ datetime;declare WorkingStatus_ varchar(100);declare Locations_ varchar(4000);
declare Manager_Id_ int;declare Is_SalesMan_ varchar(25);declare Can_Delete_ varchar(25);

	SELECT JSON_UNQUOTE (JSON_EXTRACT(Employee_Details_,'$.Employee_Details_Id')) INTO Employee_Details_Id_;
	SELECT JSON_UNQUOTE (JSON_EXTRACT(Employee_Details_,'$.Client_Accounts_Id')) INTO Client_Accounts_Id_JSON;
	if (Client_Accounts_Id_JSON>0) then
		set Client_Accounts_Id_=Client_Accounts_Id_JSON;
	end if;
	SELECT JSON_UNQUOTE  (JSON_EXTRACT(Employee_Details_,'$.Level_Id')) INTO Level_Id_;
	SELECT JSON_UNQUOTE (JSON_EXTRACT(Employee_Details_,'$.DesigId')) INTO DesigId_;
	SELECT JSON_UNQUOTE (JSON_EXTRACT(Employee_Details_,'$.DateOfBirth')) INTO DateOfBirth_;
	SELECT JSON_UNQUOTE (JSON_EXTRACT(Employee_Details_,'$.DateOfJoin')) INTO DateOfJoin_;
	SELECT JSON_UNQUOTE (JSON_EXTRACT(Employee_Details_,'$.ReleiveDate')) INTO ReleiveDate_;
	SELECT JSON_UNQUOTE (JSON_EXTRACT(Employee_Details_,'$.WorkingStatus')) INTO WorkingStatus_;
	SELECT JSON_UNQUOTE (JSON_EXTRACT(Employee_Details_,'$.Locations')) INTO Locations_;
	SELECT JSON_UNQUOTE (JSON_EXTRACT(Employee_Details_,'$.Manager_Id')) INTO Manager_Id_;
	SELECT JSON_UNQUOTE (JSON_EXTRACT(Employee_Details_,'$.Is_SalesMan')) INTO Is_SalesMan_;
    
      if(Is_SalesMan_='true') 
			then set Is_SalesMan_=1;
			else set Is_SalesMan_=0;
		end if;
	SELECT JSON_UNQUOTE (JSON_EXTRACT(Employee_Details_,'$.Can_Delete')) INTO Can_Delete_; 
      if(Can_Delete_='true') 
			then set Can_Delete_=1;
			else set Can_Delete_=0;
		end if;
		


 if  Employee_Details_Id_>0
 THEN 
 UPDATE Employee_Details set Client_Accounts_Id = Client_Accounts_Id_ ,Level_Id = Level_Id_ ,
DesigId = DesigId_ ,DateOfBirth = DateOfBirth_ ,DateOfJoin = DateOfJoin_ ,ReleiveDate = ReleiveDate_ ,
WorkingStatus = WorkingStatus_ ,Locations = Locations_ ,Manager_Id = Manager_Id_ ,Is_SalesMan = Is_SalesMan_ ,
Can_Delete = Can_Delete_  
Where Employee_Details_Id=Employee_Details_Id_ ;
 ELSE 
 #SET Employee_Details_Id_ = (SELECT  COALESCE( MAX(Employee_Details_Id ),0)+1 FROM Employee_Details); 
 INSERT INTO Employee_Details(Employee_Details_Id ,Client_Accounts_Id ,Level_Id ,
DesigId ,DateOfBirth ,DateOfJoin ,ReleiveDate ,WorkingStatus ,Locations ,Manager_Id ,Is_SalesMan ,
Can_Delete ,DeleteStatus )
 values (Employee_Details_Id_ ,Client_Accounts_Id_ ,Level_Id_ ,DesigId_ ,DateOfBirth_ ,DateOfJoin_ ,
ReleiveDate_ ,WorkingStatus_ ,Locations_ ,Manager_Id_ ,Is_SalesMan_ ,Can_Delete_ ,false);
 End If ;
 set Employee_Details_Id_ =(SELECT LAST_INSERT_ID());
 select Client_Accounts_Id_;
 End
$$
