end if;
 ELSE 
 insert into db_logs values(0,'item_id_ else > 0','','');

  Set Duplicate_Id = (select Item_Id from Item where  Item_Name =Item_Name_ limit 1);
   if(Duplicate_Id>0) then
       insert into db_logs values(0,'Duplicate_Id 2 > 0','','');

SET Item_Id_ = -1;  
else
