CREATE PROCEDURE `Save_PackingDetails`
BEGIN
declare YearFrom datetime;declare YearTo datetime;
DECLARE Quotation_Packinglist_Id_ INT;
DECLARE PackingList_No_ INT;

if(PackingList_Master_Id_ > 0) then
set PackingList_No_ = (select Packing_List_No from packinglist_master where PackingList_Master_Id = PackingList_Master_Id_ and DeleteStatus = 0);

UPDATE packinglist_master SET PackingList_Master_Id=PackingList_Master_Id_,
#PO_No=PO_No_,Invoice_No=Invoice_No_,Consignee_Name=Consignee_Name_,
EntryDate=EntryDate_,
Consignee_Address=Consignee_Address_,Total_No_Of_Boxes=Total_No_Of_Boxes_,Box_Details=Box_Details_,Total_Weight=Total_Weight_,
Account_Party_Id=Account_Party_Id_,
CurrencyId=CurrencyId_,PaymentTerms=PaymentTerms_,AttendEmployee=AttendEmployee_,Brand=Brand_,PriceBasis=PriceBasis_,Delivery=Delivery_,
Validity=Validity_,Description1=Description1_,User_Id=User_Id_,Delivery_Address1=Delivery_Address1_,Delivery_Address2=Delivery_Address2_,
Delivery_Address3=Delivery_Address3_,Delivery_Address4=Delivery_Address4_,KindAttend=KindAttend_,Payment_Term_Description=Payment_Term_Description_,
Reference=Description2_,PaymentTermValue =PaymentTermValue_,Invoice_No=Invoice_No_,POnumber=POnumber_,
    TotalAmount =TotalAmount_,
    TotalDiscount =TotalDiscount_,
    NetTotal =NetTotal_,
    Packing_List_No = PackingList_No_
WHERE PackingList_Master_Id = PackingList_Master_Id_;

ELSE
 set YearFrom=(select Account_Years.YearFrom from Account_Years where Date_Format(EntryDate_,'%Y-%m-%d')
    between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));
set YearTo=(select Account_Years.YearTo from Account_Years where Date_Format(EntryDate_,'%Y-%m-%d')
    between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));  
if exists(select distinct Packing_List_No from packinglist_master)then
set PackingList_No_=(SELECT COALESCE( MAX(Packing_List_No),0)+1 FROM packinglist_master where Date_Format(EntryDate,'%Y-%m-%d')
    between Date_Format(YearFrom,'%Y-%m-%d') and Date_Format(YearTo,'%Y-%m-%d'));  
else
if exists(select Packing_List_No from General_Settings)
then
set PackingList_No_=(select COALESCE(Packing_List_No,0) from General_Settings);
else
set PackingList_No_=1;
end if;    
end if;
SET PackingList_Master_Id_ = (SELECT  COALESCE( MAX(PackingList_Master_Id ),0)+1 FROM packinglist_master);
#SET Invoice_No_ = (SELECT COALESCE(MAX(CAST(Invoice_No AS UNSIGNED)), 0) + 1 FROM packinglist_master );
#SET PackingList_No_ = (SELECT  COALESCE( MAX(Packing_List_No ),0)+1 FROM packinglist_master);


INSERT INTO packinglist_master
(PackingList_Master_Id,Packing_List_No,
#PO_No,Invoice_No,Consignee_Name,
EntryDate,Consignee_Address,Total_No_Of_Boxes,
Box_Details,Total_Weight,DeleteStatus,
Account_Party_Id,
CurrencyId,PaymentTerms,AttendEmployee,Brand,PriceBasis,Delivery,
Validity,Description1,User_Id,Delivery_Address1,Delivery_Address2,
Delivery_Address3,Delivery_Address4,KindAttend,Payment_Term_Description,
Reference,PaymentTermValue,
TotalAmount, TotalDiscount, NetTotal,Invoice_No,POnumber )
VALUES
(PackingList_Master_Id_,PackingList_No_,
#PO_No_,Invoice_No_,Consignee_Name_,
EntryDate_,Consignee_Address_,Total_No_Of_Boxes_,
Box_Details_,Total_Weight_,false,
Account_Party_Id_,
CurrencyId_,PaymentTerms_,AttendEmployee_,Brand_,PriceBasis_,Delivery_,
Validity_,Description1_,User_Id_,Delivery_Address1_,Delivery_Address2_,
Delivery_Address3_,Delivery_Address4_,KindAttend_,Payment_Term_Description_,
Description2_,PaymentTermValue_,
 TotalAmount_, TotalDiscount_, NetTotal_,Invoice_No_,POnumber_);


SET Quotation_Packinglist_Id_ = (SELECT  COALESCE( MAX(Quotation_Packinglist_Id),0)+1 FROM Quotation_Packinglist);

IF(SalesQuotationMaster_Id_ > 0) THEN
INSERT INTO quotation_packinglist
(Quotation_Packinglist_Id, PackingList_Master_Id, SalesQuotationMaster_Id, DeleteStatus)
VALUES
(Quotation_Packinglist_Id_, PackingList_Master_Id_, SalesQuotationMaster_Id_, 0);
END IF;

end if;

CALL Save_Packing_List_Details(packinglist_details_ ,PackingList_Master_Id_,PackingList_No_);
select PackingList_Master_Id_,PackingList_No_;
END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_Packing_List_Details`
BEGIN

declare ItemId_ int;declare ItemCode_ varchar(500);
declare ItemName_ varchar(1000);declare UnitId_ int;
declare UnitName_ varchar(100);declare StockId_ int;
declare HSNMasterId_ int;declare HSNCODE_ varchar(50);
declare UnitPrice_ decimal;declare Quantity_ decimal(18,3);
declare Amount_ decimal;declare Discount_ decimal;
declare TaxableAmount_ decimal;declare TaxAmount_ decimal;
declare NetValue_ decimal;declare Availability_ varchar(100);
declare Unit_Discount_ decimal; declare Sale_Tax_ decimal;declare PackingList_Details_Id_ int;
declare GroupId_ int;declare GroupName_ varchar(69);declare Country_Of_Origin_ varchar(70);
declare Country_Id_ int default 0;
DECLARE i int  DEFAULT 0;


delete from packinglist_details where PackingList_Master_Id = PackingList_Master_Id_;
WHILE i < JSON_LENGTH(packinglist_details_) DO
		SELECT JSON_UNQUOTE (JSON_EXTRACT(packinglist_details_,CONCAT('$[',i,'].ItemId'))) INTO ItemId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(packinglist_details_,CONCAT('$[',i,'].Item_Code'))) INTO ItemCode_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(packinglist_details_,CONCAT('$[',i,'].ItemName'))) INTO ItemName_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(packinglist_details_,CONCAT('$[',i,'].GroupId'))) INTO GroupId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(packinglist_details_,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(packinglist_details_,CONCAT('$[',i,'].UnitId'))) INTO UnitId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(packinglist_details_,CONCAT('$[',i,'].UnitName'))) INTO UnitName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(packinglist_details_,CONCAT('$[',i,'].StockId'))) INTO StockId_;
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(packinglist_details_,CONCAT('$[',i,'].HSNMasterId'))) INTO HSNMasterId_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(packinglist_details_, CONCAT('$[', i, '].HSNMasterId'))), 'null'), 0) INTO HSNMasterId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(packinglist_details_,CONCAT('$[',i,'].HSNCODE'))) INTO HSNCODE_;
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(packinglist_details_,CONCAT('$[',i,'].Country_Id'))) INTO Country_Id_;
        SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(packinglist_details_, CONCAT('$[', i, '].Country_Id'))), 'null'), 0) INTO Country_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(packinglist_details_,CONCAT('$[',i,']. Country_Name'))) INTO  Country_Of_Origin_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(packinglist_details_,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;   
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(packinglist_details_, CONCAT('$[', i, '].Amount'))), 'null'), 0) INTO Amount_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(packinglist_details_, CONCAT('$[', i, '].Discount'))), 'null'), 0) INTO Discount_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(packinglist_details_, CONCAT('$[', i, '].TaxableAmount'))), 'null'), 0) INTO TaxableAmount_;
        SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(packinglist_details_, CONCAT('$[', i, '].TaxAmount'))), 'null'), 0) INTO TaxAmount_;
        SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(packinglist_details_, CONCAT('$[', i, '].NetValue'))), 'null'), 0) INTO NetValue_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(packinglist_details_,CONCAT('$[',i,'].Availability'))) INTO Availability_; 
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(packinglist_details_, CONCAT('$[', i, '].Unit_Discount'))), 'null'), 0) INTO Unit_Discount_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(packinglist_details_, CONCAT('$[', i, '].Sale_Tax'))), 'null'), 0) INTO Sale_Tax_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(packinglist_details_, CONCAT('$[', i, '].UnitPrice'))), 'null'), 0) INTO UnitPrice_;

        
        IF Country_Of_Origin_ = 'null' THEN
			SET Country_Of_Origin_ = '';
            SET Country_Id_ = 0;
		END IF;
        
        SET PackingList_Details_Id_ = (SELECT  COALESCE( MAX(PackingList_Details_Id ),0)+1 FROM packinglist_details);
        
		INSERT INTO packinglist_details(PackingList_Details_Id,PackingList_Master_Id,ItemId,ItemCode,ItemName,
        GroupId,GroupName,UnitId,UnitName,StockId,HSNMasterId,HSNCODE,Country_Of_Origin,DeleteStatus,
        Quantity, 
        UnitPrice, SaleTax, Amount, Discount, TaxableAmount, TaxAmount, NetValue,
        Country_Id)
		VALUES(PackingList_Details_Id_,PackingList_Master_Id_,ItemId_,ItemCode_,ItemName_,GroupId_,GroupName_,UnitId_,UnitName_,
        StockId_,HSNMasterId_,HSNCODE_,Country_Of_Origin_,false,
        Quantity_,
        UnitPrice_, Sale_Tax_, Amount_, Discount_, TaxableAmount_, TaxAmount_, NetValue_, 
        Country_Id_);
		SELECT i + 1 INTO i;
END WHILE;  
SELECT PackingList_Master_Id_,PackingList_No_;

END
$$
DELIMITER ;

