CREATE PROCEDURE `Save_Payment_Voucher`
Begin
declare Voucher_No_ decimal(18,0);declare Accounts_Id_ DECIMAL(18,0);
declare YearFrom datetime;declare YearTo datetime;DECLARE Check_Box_ varchar(25);
declare Discount_ decimal(18,3);declare Paying_Amount_ DECIMAL(18,3);declare Voucher_Type_Name_ varchar(100);
declare Purchase_Master_Id_ int;declare Amount2_ DECIMAL(18,3);declare InvoiceNo_ varchar(45);
DECLARE i int  DEFAULT 0; declare PurchaseDate_ varchar(45);declare Voucher_Type_Id_ int;
declare Payment_Reference_Id_ int;
set YearFrom=(select Account_Years.YearFrom from Account_Years
where  Date_Format(Date_,'%Y-%m-%d') between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and
Date_Format(Account_Years.YearTo,'%Y-%m-%d'));
set YearTo=(select Account_Years.YearTo from Account_Years
 where Date_Format(Date_,'%Y-%m-%d') between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and
Date_Format(Account_Years.YearTo,'%Y-%m-%d'));
if exists(select distinct Voucher_No from Payment_Voucher)
then
set Voucher_No_=(SELECT  COALESCE( MAX(Voucher_No ),0)+1 FROM Payment_Voucher
where Date_Format(Date,'%Y-%m-%d') between Date_Format(YearFrom,'%Y-%m-%d') and
 Date_Format(YearTo,'%Y-%m-%d') and DeleteStatus=false);  
else
if exists(select Payment_Voucher_No from General_Settings)
then
set Voucher_No_=(select COALESCE(Payment_Voucher_No,0) from General_Settings);
else
set Voucher_No_=1;
end if;    
end if;
 if  Payment_Voucher_Id_>0
 THEN
DELETE FROM Accounts WHERE Tran_Type='PV' AND Tran_Id=Payment_Voucher_Id_;
call Delete_Purchase_Payment(Payment_Voucher_Id_); 
UPDATE Payment_Voucher set Date = Date_,From_Account_Id = From_Account_Id_ ,Amount = Amount_ ,
To_Party_Id = To_Account_Id_ ,Payment_Mode_Name = Payment_Mode_ ,User_Id = User_Id_ ,
Payment_Status=Payment_Status_,Description=Description_, CurrencyId = CurrencyId_ Where Payment_Voucher_Id=Payment_Voucher_Id_ ;
ELSE
SET Payment_Voucher_Id_ = (SELECT  COALESCE( MAX(Payment_Voucher_Id ),0)+1 FROM Payment_Voucher);
INSERT INTO Payment_Voucher(Payment_Voucher_Id ,Date ,CurrencyId ,From_Account_Id ,Amount ,To_Party_Id , Payment_Mode_Name ,User_Id ,Payment_Status,Description,DeleteStatus,Voucher_No )
values (Payment_Voucher_Id_ ,Date_ ,CurrencyId_ ,From_Account_Id_ ,Amount_ ,To_Account_Id_ ,Payment_Mode_ , User_Id_ ,Payment_Status_,Description_,false,Voucher_No_);
End If ;
 if(Payment_Voucher_Id_>0)then
set Accounts_Id_=(select COALESCE( MAX(Accounts_Id ),0)+1 from Accounts);
insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,VoucherType,Description1,Status,DayBook,Payment_Status)
values(Accounts_Id_,Date_,From_Account_Id_,0,Amount_,To_Account_Id_,'PV',Payment_Voucher_Id_,Voucher_No_,1,Description_,'','Y',Payment_Status_);
set Accounts_Id_=(select COALESCE( MAX(Accounts_Id ),0)+1 from Accounts);
insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,VoucherType,Description1,Status,DayBook,Payment_Status)
values(Accounts_Id_,Date_,To_Account_Id_,Amount_,0,From_Account_Id_,'PV',Payment_Voucher_Id_,Voucher_No_ ,1,Description_,'','Y',Payment_Status_);
 end if; 
 
 if(Purchase_Payment_Value_ >0) then
WHILE i < JSON_LENGTH(Purchase_Details) DO
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].Check_Box'))) INTO Check_Box_;
insert into db_logs values(0,Check_Box_,'',0);
if(Check_Box_='true'||Check_Box_=1 || Check_Box_=true)
then set Check_Box_=1;
else set Check_Box_=0;
end if;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].Purchase_Master_Id'))) INTO Purchase_Master_Id_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].Amount'))) INTO Amount2_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].Paying_Amount'))) INTO Paying_Amount_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].PurchaseDate'))) INTO PurchaseDate_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].InvoiceNo'))) INTO InvoiceNo_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].Voucher_Type_Id'))) INTO Voucher_Type_Id_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].Voucher_Type_Name'))) INTO Voucher_Type_Name_;

set Payment_Reference_Id_=(select COALESCE( MAX(Payment_Reference_Id ),0)+1 from payment_reference);
INSERT INTO payment_reference(Payment_Reference_Id,Payment_Voucher_Id,Master_Id,Amount,Discount,Paying_Amount,PurchaseDate,InvoiceNo,Voucher_Type_Id,Voucher_Type_Name,Check_Box,DeleteStatus )
values (Payment_Reference_Id_,Payment_Voucher_Id_,Purchase_Master_Id_,Amount2_,0,Paying_Amount_,PurchaseDate_ ,InvoiceNo_ ,Voucher_Type_Id_,Voucher_Type_Name_,Check_Box_,false);
#update purchase_master set Paid_Amount=Paid_Amount+Paying_Amount_,Paying_Discount=Paying_Discount+Discount_ where Purchase_Master_Id=Purchase_Master_Id_ ;
if Voucher_Type_Id_=1 then
update purchase_master set PaidAmount=ifnull(PaidAmount,0)+Paying_Amount_ where Purchase_Master_Id=Purchase_Master_Id_;
else
update journal_entry set PaidAmount=ifnull(PaidAmount,0)+Paying_Amount_ where Journal_Entry_Id=Purchase_Master_Id_;
end if;
SELECT i + 1 INTO i;
END WHILE;
end if;

#COMMIT;
select Payment_Voucher_Id_;
End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_PerformaInvoice`
BEGIN
#insert into db_logs values(0,performainvoicedetails_,'performainvoicedetails_',0);
if(PerformaInvoiceMaster_Id_ > 0) then

UPDATE performainvoicemaster SET PerformaInvoiceMaster_Id = PerformaInvoiceMaster_Id_,Account_Party_Id = Account_Party_Id_,
