#Delivery_Address1 = Delivery_Address1_,Delivery_Address2 = Delivery_Address2_,Delivery_Address3 = Delivery_Address3_,Delivery_Address4 = Delivery_Address4_,
Charge1 = Charge1_,charge1_Amount = charge1_Amount_,Charge2 = Charge2_,
charge2_Amount = charge2_Amount_,Discount_Description = Discount_Description_,
Additional_Discount = Additional_Discount_,
#Roundoff_Amt = Additional_Discount_,
Description2 = Description2_,
Amount_In_Words = Amount_In_Words_,PreparedBy = PreparedBy_,Charge1per = Charge1per_,Payment_Term_Description = Payment_Term_Description_,
