#SET InvoiceNo_ = (SELECT COALESCE(MAX(CAST(PerformaInvNo AS UNSIGNED)), 0) + 1 FROM performainvoicemaster );
INSERT INTO performainvoicemaster
(PerformaInvoiceMaster_Id,Account_Party_Id,EntryDate,PerformaInvNo,CurrencyId,PaymentTerms,Brand,LPONo,
#AttendEmployee,POnumber,Brand,
TotalAmount,TotalDiscount,TaxableAmount,Roundoff_Amt,
#Total_Amount,
NetTotal,
PriceBasis,Delivery,Validity,Description1,User_Id,DeleteStatus,
#Delivery_Address1,Delivery_Address2,Delivery_Address3,Delivery_Address4,
Charge1,charge1_Amount,
Charge2,charge2_Amount,Discount_Description,Description2,Amount_In_Words,PreparedBy,
Charge1per,Payment_Term_Description,VAT_Percentage,VAT_Amount, KindAttend,TypeId,PaymentTermValue,Total_Amount,
Additional_Discount )
VALUES
(PerformaInvoiceMaster_Id_,Account_Party_Id_,EntryDate_,InvoiceNo_,CurrencyId_,PaymentTerms_,Brand_,LPONo_,
#AttendEmployee_,POnumber_,Brand_,
TotalAmount_,TotalDiscount_,TaxableAmount_,
Roundoff_Amt_,
NetTotal_,
PriceBasis_,Delivery_,Validity_,Description1_,User_Id_,0,
#Delivery_Address1_,Delivery_Address2_,Delivery_Address3_,Delivery_Address4_,
Charge1_,charge1_Amount_,Charge2_,charge2_Amount_,Discount_Description_,Description2_,Amount_In_Words_,PreparedBy_,Charge1per_,
Payment_Term_Description_,VAT_Percentage_,VAT_Amount_, KindAttend_,
AccountType_Id_,PaymentTermValue_,Total_,
Additional_Discount_);

if(SalesQuotationMaster_Id_ > 0)then
insert into quotation_performa (SalesQuotationMaster_Id,PerformaInvoiceMaster_Id,DeleteStatus) values (SalesQuotationMaster_Id_,PerformaInvoiceMaster_Id_,0);
end if;
end if;

CALL Save_Performa_Details(performainvoicedetails_ ,PerformaInvoiceMaster_Id_);
select PerformaInvoiceMaster_Id_;
END
$$
DELIMITER ;

