CREATE PROCEDURE `Save_Performa_Details`
BEGIN

declare ItemId_ int;declare ItemCode_ varchar(500);
declare ItemName_ varchar(1000);declare UnitId_ int;
declare UnitName_ varchar(100);declare StockId_ int;
declare HSNMasterId_ int;declare HSNCODE_ varchar(50);
declare UnitPrice_ decimal(18,3);declare Quantity_ decimal(18,3);
declare Amount_ decimal(18,3);declare Discount_ decimal(18,3);
declare TaxableAmount_ decimal(18,3);declare TaxAmount_ decimal(18,3);
declare NetValue_ decimal(18,3);declare Availability_ varchar(100);
declare Unit_Discount_ decimal(18,3); declare Sale_Tax_ decimal(18,3);
declare PerformaInvoiceDetails_Id_ int;
DECLARE i int  DEFAULT 0;declare GroupId_ int;declare GroupName_ varchar(45);declare Item_Discount_Amount_ decimal(18,3);
declare Country_Id_ int; declare Country_Name_ varchar(45);

delete from performainvoicedetails where PerformaMaster_Id = PerformaInvoiceMaster_Id_;

WHILE i < JSON_LENGTH(performainvoicedetails_) DO
		SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].ItemId'))) INTO ItemId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].Item_Code'))) INTO ItemCode_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].ItemName'))) INTO ItemName_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].GroupId'))) INTO GroupId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].UnitId'))) INTO UnitId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].UnitName'))) INTO UnitName_;
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].StockId'))) INTO StockId_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(performainvoicedetails_, CONCAT('$[',i,'].StockId')) ),  'null' ), 0 ) INTO StockId_;

        #SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].HSNMasterId'))) INTO HSNMasterId_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(performainvoicedetails_, CONCAT('$[',i,'].HSNMasterId')) ),  'null' ), 0 ) INTO HSNMasterId_;

        #SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].HSNCODE'))) INTO HSNCODE_;
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].UnitPrice'))) INTO UnitPrice_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(performainvoicedetails_, CONCAT('$[',i,'].UnitPrice')) ),  'null' ), 0 ) INTO UnitPrice_;

		#SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;   
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(performainvoicedetails_, CONCAT('$[',i,'].Quantity')) ),  'null' ), 0 ) INTO Quantity_;

        #SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].Amount'))) INTO Amount_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(performainvoicedetails_, CONCAT('$[',i,'].Amount')) ),  'null' ), 0 ) INTO Amount_;

        #SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].Discount'))) INTO Discount_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(performainvoicedetails_, CONCAT('$[',i,'].Discount')) ),  'null' ), 0 ) INTO Discount_;

        #SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].TaxableAmount'))) INTO TaxableAmount_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(performainvoicedetails_, CONCAT('$[',i,'].TaxableAmount')) ),  'null' ), 0 ) INTO TaxableAmount_;

		#SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].TaxAmount'))) INTO TaxAmount_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(performainvoicedetails_, CONCAT('$[',i,'].TaxAmount')) ),  'null' ), 0 ) INTO TaxAmount_;

		#SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].NetValue'))) INTO NetValue_;   
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(performainvoicedetails_, CONCAT('$[',i,'].NetValue')) ),  'null' ), 0 ) INTO NetValue_;

		#SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].Availability'))) INTO Availability_; 
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].Unit_Discount'))) INTO Unit_Discount_;
		SELECT  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(performainvoicedetails_, CONCAT('$[',i,'].Unit_Discount')) ),  'null' ), 0 ) INTO Unit_Discount_;
        #SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].Sale_Tax'))) INTO Sale_Tax_;
		SELECT  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(performainvoicedetails_, CONCAT('$[',i,'].Sale_Tax')) ),  'null' ), 0 ) INTO Sale_Tax_;
		SELECT  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(performainvoicedetails_, CONCAT('$[',i,'].Item_Discount_Amount')) ),  'null' ), 0 ) INTO Item_Discount_Amount_;
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].Country_Id'))) INTO Country_Id_;
		SELECT  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(performainvoicedetails_, CONCAT('$[',i,'].Country_Id')) ),  'null' ), 0 ) INTO Country_Id_;
         SELECT JSON_UNQUOTE (JSON_EXTRACT(performainvoicedetails_,CONCAT('$[',i,'].Country_Name'))) INTO Country_Name_;

        SET PerformaInvoiceDetails_Id_ = (SELECT  COALESCE( MAX(PerformaInvoiceDetails_Id ),0)+1 FROM performainvoicedetails);
        
		INSERT INTO performainvoicedetails(PerformaInvoiceDetails_Id,PerformaMaster_Id,ItemId,ItemCode,ItemName,
		UnitId,UnitName,StockId,HSNMasterId,HSNCODE,UnitPrice,Quantity,Amount,Discount,TaxableAmount,TaxAmount,
		NetValue,DeleteStatus,Unit_Discount,GroupId,GroupName,SaleTax,Item_Discount_Amount,Country_Id,Country_Name)
        
		VALUES(PerformaInvoiceDetails_Id_,PerformaInvoiceMaster_Id_,ItemId_,ItemCode_,ItemName_,UnitId_,UnitName_,StockId_,HSNMasterId_,
		HSNCODE_,UnitPrice_,Quantity_,Amount_,Discount_,TaxableAmount_,TaxAmount_,NetValue_,0,Unit_Discount_,GroupId_,GroupName_,
        Sale_Tax_,Item_Discount_Amount_,Country_Id_,Country_Name_);
		SELECT i + 1 INTO i;
END WHILE;  
SELECT PerformaInvoiceMaster_Id_;

END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_performa_salesmaster`
Begin 
 if  performa_salesmaster_Id_>0
 THEN 
 UPDATE performa_salesmaster set Performa_SalesMaster_Id = Performa_SalesMaster_Id_ ,
PerformaInvoiceMaster_Id = PerformaInvoiceMaster_Id_ ,
