PerformaInvoiceMaster_Id ,
SalesMaster_Id ,
DeleteStatus ) values (Performa_SalesMaster_Id_ ,
PerformaInvoiceMaster_Id_ ,
SalesMaster_Id_ ,
false);
 End If ;
 select performa_salesmaster_Id_;
 End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_Petty_Cash`
BEGIN

 
declare Petty_Cash_Id_ int;declare Date_ datetime;declare Branch_Id_ int;declare Branch_Name_ varchar(500);
 declare Type_Id_ int;declare Type_Name_ varchar(500);
declare Amount_ decimal(18,2);declare Document_Name_ text;declare File_Name_ text;
  declare Particular_ varchar(500);
declare Expense_ int;
declare Ho_ int;
declare Salary_ int;
declare Management_ int;
declare SumTotal_ decimal(18,2);
declare Cash_ int;
declare Upi_ int;
