DELIMITER $$
CREATE PROCEDURE `Save_Production_Materials`
Begin
  DECLARE Stock_Id_ decimal(18,0);DECLARE Item_Id_ int;DECLARE Item_Name_ varchar(1000);
    DECLARE Group_Id_ decimal(18,0); DECLARE Group_Name_ VARCHAR(100);DECLARE Unit_Id_ decimal(18,0);
    DECLARE Unit_Name_ VARCHAR(100); DECLARE Quanity_ decimal(18,2);DECLARE SaleRate_ decimal(18,2);
    declare Include_Tax_ decimal(18,2);declare Amount_ decimal(18,2);declare CGSTAMT_ decimal(18,2);declare SGSAMT_ decimal(18,2);
    DECLARE GSTAMT_ decimal(18,2);    DECLARE HSN_Id_ int;    DECLARE HSN_Code_ varchar(50);
    DECLARE TOTAL_ decimal(18,2); DECLARE CGST_ decimal(18,2);   DECLARE GST_ decimal(18,2);DECLARE SGST_ decimal(18,2);
    DECLARE i int  DEFAULT 0;
	WHILE i < JSON_LENGTH(Production_Materials) DO
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].Stock_Id'))) INTO Stock_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].Item_Id'))) INTO Item_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].Item_Name'))) INTO Item_Name_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].Quanity'))) INTO Quanity_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].SaleRate'))) INTO SaleRate_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].Include_Tax'))) INTO Include_Tax_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].Amount'))) INTO Amount_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].CGSTAMT'))) INTO CGSTAMT_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].SGSAMT'))) INTO SGSAMT_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].GSTAMT'))) INTO GSTAMT_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].TOTAL'))) INTO TOTAL_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].HSN_Id'))) INTO HSN_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].HSN_Code'))) INTO HSN_Code_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].CGST'))) INTO CGST_;   
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].SGST'))) INTO SGST_;    
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].GST'))) INTO GST_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].Group_Id'))) INTO Group_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].Group_Name'))) INTO Group_Name_;    
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].Unit_Id'))) INTO Unit_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Production_Materials,CONCAT('$[',i,'].Unit_Name'))) INTO Unit_Name_;
		INSERT INTO Production_Materials(Prodution_Master_Id ,Stock_Id ,Item_Id ,Item_Name ,Quanity ,SaleRate ,Include_Tax ,
		Amount ,CGSTAMT ,SGSAMT ,GSTAMT ,TOTAL ,HSN_Id ,HSN_Code ,CGST ,SGST ,GST  ,Group_Id ,
		Group_Name ,Unit_Id ,Unit_Name,DeleteStatus ) 
		values (Prodution_Master_Id_ ,Stock_Id_ ,Item_Id_ ,Item_Name_ ,Quanity_ ,SaleRate_ ,Include_Tax_ ,Amount_ ,
		CGSTAMT_ ,SGSAMT_ ,GSTAMT_ ,TOTAL_ ,HSN_Id_ ,HSN_Code_ ,CGST_ ,SGST_ ,GST_,Group_Id_ ,
		Group_Name_ ,Unit_Id_ ,Unit_Name_,false);
        update Stock set Quantity=Quantity-Quanity_ where Stock_Id=Stock_Id_;
		SELECT i + 1 INTO i;
	END WHILE;  
SELECT Prodution_Master_Id_;
End
$$
DELIMITER ;

