    DECLARE HSN_Code_ varchar(50);DECLARE CGST_ decimal(18,2);DECLARE GST_ decimal(18,2);DECLARE SGST_ decimal(18,2);
	
    DECLARE Prodcution_Details_Id_Old_ int;declare Prodcution_Details_Id_Temp_ int;declare Prodcution_Details_Id_ int;
    DECLARE i int  DEFAULT 0;
/*DECLARE exit handler for sqlexception
BEGIN
	GET DIAGNOSTICS CONDITION 1
	@p1 = RETURNED_SQLSTATE, @p2 = MESSAGE_TEXT;
	SELECT @p2 AS MESSAGE_TEXT, @p1 AS RETURNED_SQLSTATE;
	ROLLBACK;
END;
    DECLARE exit handler for sqlwarning
BEGIN
	GET DIAGNOSTICS CONDITION 1
	@p1 = RETURNED_SQLSTATE, @p2 = MESSAGE_TEXT;
	SELECT @p2 AS MESSAGE_TEXT, @p1 AS RETURNED_SQLSTATE;
	ROLLBACK;
END;
    START TRANSACTION;	*/  
 if  Prodution_Master_Id_>0 THEN
	CALL Update_Stock_From_Production(Prodution_Master_Id_);
	CALL Update_Stock_From_Production_Materials(Prodution_Master_Id_);
	Delete From Prodcution_Details Where Prodution_Master_Id = Prodution_Master_Id_;
	Delete From Production_Materials Where Prodution_Master_Id = Prodution_Master_Id_;
	UPDATE Prodution_Master set Date=Date_,Labour_Charge=Labour_Charge_,Additional_Expense=Additional_Expense_,
    Production_No=Production_No_,UserId=UserId_,TotalAmount=TotalAmount_
	Where Prodution_Master_Id = Prodution_Master_Id_ ;
 ELSE 	
    SET Prodution_Master_Id_ = (SELECT  COALESCE( MAX(Prodution_Master_Id ),0)+1 FROM Prodution_Master); 
	INSERT INTO Prodution_Master(Prodution_Master_Id,Date,Labour_Charge,Additional_Expense,Production_No,UserId,TotalAmount,DeleteStatus ) 
	values (Prodution_Master_Id_,Date_,Labour_Charge_,Additional_Expense_,Production_No_,UserId_,TotalAmount_,False );
End If ;
		WHILE i < JSON_LENGTH(Prodcution_Details) DO
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].Item_Id'))) INTO Item_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].Item_Name'))) INTO Item_Name_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].Quanity'))) INTO Quanity_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].PurchaseRate'))) INTO PurchaseRate_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].SaleRate'))) INTO SaleRate_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].MRP'))) INTO MRP_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].HSN_Id'))) INTO HSN_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].HSN_Code'))) INTO HSN_Code_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].CGST'))) INTO CGST_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].SGST'))) INTO SGST_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].GST'))) INTO GST_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].Group_Id'))) INTO Group_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].Group_Name'))) INTO Group_Name_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].Unit_Id'))) INTO Unit_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].Unit_Name'))) INTO Unit_Name_;
if exists(select Stock_Id from Stock where ItemId=Item_Id_ and ItemName=Item_Name_ and DeleteStatus=False )
then
	set Stock_Id_=(select Stock_Id from Stock where ItemId=Item_Id_ and ItemName=Item_Name_ and DeleteStatus=False order by Stock_Id desc Limit 1);
	update Stock set ItemId=Item_Id_,ItemName=Item_Name_,GroupId=Group_Id_,GroupName=Group_Name_,UnitId=Unit_Id_,UnitName=Unit_Name_,
    PurchaseRate=PurchaseRate_,SaleRate=SaleRate_,MRP=MRP_,HSNMasterId=HSN_Id_,HSNCODE=HSN_Code_,SaleTax=GST_,Quantity=Quantity+Quanity_,CGST=CGST_,
    SGST=SGST_,IGST=GST_ where Stock_Id=Stock_Id_ and DeleteStatus=False;
else 
	if exists(select distinct Barcode from Stock)
then
	set Barcode_=(SELECT COALESCE( MAX(Barcode ),0)+1 FROM Stock);  
else 
	if exists(select Barcode from General_Settings)
	then
		set Barcode_=(select COALESCE(Barcode,0) from General_Settings);
	else
		set Barcode_=1;
	end if;    
end if;
insert into Stock(ItemId,Barcode,ItemName,GroupId,GroupName,UnitId,UnitName,PurchaseRate,SaleRate,MRP,HSNMasterId,HSNCODE,SaleTax,Quantity,CGST,SGST,IGST,DeleteStatus)
values(Item_Id_,Barcode_,Item_Name_,Group_Id_,Group_Name_,Unit_Id_,Unit_Name_,PurchaseRate_,SaleRate_,MRP_,HSN_Id_,HSN_Code_,GST_,Quanity_,CGST_,SGST_,GST_,False);
set Stock_Id_ =(SELECT LAST_INSERT_ID());

end if;             
	#SET Prodcution_Details_Id_ = (SELECT  COALESCE( MAX(Prodcution_Details_Id ),0)+1 FROM Prodcution_Details); 
	insert into Prodcution_Details(Prodution_Master_Id,Stock_Id,Item_Id,Item_Name,Quanity,PurchaseRate,SaleRate,MRP,HSN_Id,HSN_Code,CGST,SGST,GST,Group_Id,Group_Name,Unit_Id,Unit_Name,DeleteStatus)
	values(Prodution_Master_Id_,Stock_Id_,Item_Id_,Item_Name_,Quanity_,PurchaseRate_,SaleRate_,MRP_,HSN_Id_,HSN_Code_,CGST_,SGST_,GST_,Group_Id_,Group_Name_,Unit_Id_,Unit_Name_,false);
SELECT i + 1 INTO i;
	END WHILE;  
CALL Save_Production_Materials(Production_Materials,Prodution_Master_Id_);
 select Prodution_Master_Id_;
 #COMMIT;
 End
$$
DELIMITER ;

