		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].GST'))) INTO GST_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].Group_Id'))) INTO Group_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].Group_Name'))) INTO Group_Name_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].Unit_Id'))) INTO Unit_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].Unit_Name'))) INTO Unit_Name_;
if exists(select Stock_Id from Stock where ItemId=Item_Id_ and ItemName=Item_Name_ and SaleRate=SaleRate_ and MRP=MRP_ and DeleteStatus=False)
