	values(Prodcution_Details_Id_,Prodution_Master_Id_,Stock_Id_,Item_Id_,Item_Name_,Quanity_,PurchaseRate_,SaleRate_,MRP_,HSN_Id_,HSN_Code_,CGST_,SGST_,GST_,Group_Id_,Group_Name_,Unit_Id_,Unit_Name_,false);
