		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].CGST_p'))) INTO CGST_p;   
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].SGST_p'))) INTO SGST_p;    
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].GST_p'))) INTO GST_p;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].Group_Id_p'))) INTO Group_Id_p;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].Group_Name_p'))) INTO Group_Name_p;    
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].Unit_Id_p'))) INTO Unit_Id_p;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Prodcution_Details,CONCAT('$[',i,'].Unit_Name_p'))) INTO Unit_Name_p;
		INSERT INTO production_sub(Prodcution_Details_Id,Prodution_Master_Id ,Stock_Id ,Item_Id ,Item_Name ,Quanity ,SaleRate ,Include_Tax ,
		Amount ,CGSTAMT ,SGSAMT ,GSTAMT ,TOTAL ,HSN_Id ,HSN_Code ,CGST ,SGST ,GST  ,Group_Id ,
		Group_Name ,Unit_Id ,Unit_Name,DeleteStatus ) 
		values (Prodcution_Details_Id_,Prodution_Master_Id_ ,Stock_Id_p ,Item_Id_p ,Item_Name_p ,Quanity_p ,SaleRate_p ,
		Include_Tax_ ,Amount_ ,CGSTAMT_ ,SGSAMT_ ,GSTAMT_ ,TOTAL_ ,HSN_Id_p ,HSN_Code_p ,CGST_p ,SGST_p ,GST_p,Group_Id_p ,
		Group_Name_p ,Unit_Id_p ,Unit_Name_p,false);
end if;
	set  Prodcution_Details_Id_Old_ = Prodcution_Details_Id_Temp_;
	SELECT i + 1 INTO i;
	END WHILE;  
	CALL Save_Production_Materials(Production_Materials ,Prodution_Master_Id_);
end if;
select Prodution_Master_Id_;
COMMIT;
End
