CREATE PROCEDURE `Save_PurchaseOrder_Details`
BEGIN

declare ItemId_ int;
declare ItemCode_ varchar(500);
declare ItemName_ varchar(1000);
declare UnitId_ int;
declare UnitName_ varchar(100);
declare StockId_ int;
declare HSNMasterId_ int;
declare HSNCODE_ varchar(50);
declare UnitPrice_ decimal(18,3);
declare Quantity_ decimal(18,3);
declare Amount_ decimal(18,3);
declare Discount_ decimal(18,3);
declare TaxableAmount_ decimal(18,3);
declare TaxAmount_ decimal(18,3);
declare NetValue_ decimal(18,3);
declare Availability_ varchar(100);
declare Unit_Discount_ decimal(18,3); 
declare Sale_Tax_ decimal(18,3);
declare PurchaseOrderDetails_Id_ int;
declare GroupName_ varchar(45);
declare GroupId_ int;
declare SaleRate_ decimal(18,3);
declare Item_Discount_Amount_ decimal(18,3);
DECLARE i int  DEFAULT 0;        
declare Country_Id_ int;
declare Country_Name_ varchar(45);


delete from purchaseorderdetails where PurchaseOrderId = Purchase_OrderMaster_Id_;
WHILE i < JSON_LENGTH(Purchase_Orderdetails_) DO
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].ItemId'))) INTO ItemId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].Item_Code'))) INTO ItemCode_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].ItemName'))) INTO ItemName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].UnitId'))) INTO UnitId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].UnitName'))) INTO UnitName_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].GroupId'))) INTO GroupId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
        SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_Orderdetails_, CONCAT('$[', i, '].StockId'))), 'null'), 0) INTO StockId_;
        SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_Orderdetails_, CONCAT('$[', i, '].HSNMasterId'))), 'null'), 0) INTO HSNMasterId_;
        SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_Orderdetails_, CONCAT('$[', i, '].SaleRate'))), 'null'), 0) INTO SaleRate_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].HSNCODE'))) INTO HSNCODE_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].UnitPrice'))) INTO UnitPrice_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;   
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].Amount'))) INTO Amount_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].Discount'))) INTO Discount_;
        #SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].TaxableAmount'))) INTO TaxableAmount_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_Orderdetails_, CONCAT('$[', i, '].TaxableAmount'))), 'null'), 0) INTO TaxableAmount_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_Orderdetails_, CONCAT('$[', i, '].TaxAmount'))), 'null'), 0) INTO TaxAmount_;
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].TaxAmount'))) INTO TaxAmount_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_Orderdetails_, CONCAT('$[', i, '].NetValue'))), 'null'), 0) INTO NetValue_;
        SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_Orderdetails_, CONCAT('$[', i, '].Item_Discount_Amount'))), 'null'), 0) INTO Item_Discount_Amount_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].Unit_Discount'))) INTO Unit_Discount_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].Sale_Tax'))) INTO Sale_Tax_;
        #SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].Country_Id'))) INTO Country_Id_;
        #SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Orderdetails_,CONCAT('$[',i,'].Country_Name'))) INTO Country_Name_;

        SET PurchaseOrderDetails_Id_ = (SELECT  COALESCE( MAX(PurchaseOrderDetails_Id ),0)+1 FROM purchaseorderdetails);
        
		INSERT INTO purchaseorderdetails(PurchaseOrderDetails_Id,PurchaseOrderId,ItemId,ItemCode,ItemName,
		UnitId,UnitName,StockId,HSNMasterId,HSNCODE,UnitPrice,Quantity,Amount,Discount,TaxableAmount,TaxAmount,
		NetValue,DeleteStatus,Unit_Discount,GroupId,GroupName,SaleRate,SaleTax,Item_Discount_Amount,Country_Id,Country_Name)
        
		VALUES(PurchaseOrderDetails_Id_,Purchase_OrderMaster_Id_,ItemId_,ItemCode_,ItemName_,UnitId_,UnitName_,StockId_,HSNMasterId_,
		HSNCODE_,UnitPrice_,Quantity_,Amount_,Discount_,TaxableAmount_,TaxAmount_,NetValue_,0,Unit_Discount_,GroupId_,GroupName_,
        SaleRate_,Sale_Tax_,Item_Discount_Amount_,0,'');
		SELECT i + 1 INTO i;
END WHILE;  
SELECT Purchase_OrderMaster_Id_,OrderNumber_;

END
$$
DELIMITER ;

