DELIMITER $$
CREATE PROCEDURE `Save_Purchase_Details`
Begin
Declare ItemId_ decimal(18,0); Declare Item_Code_ varchar(50); Declare ItemName_ varchar(1000); Declare GroupId_ int;
Declare GroupName_ varchar(100); Declare UnitId_ int;Declare UnitName_ varchar(100); Declare StockId_ decimal(18,0);
Declare PurchaseRate_ decimal(18,3);Declare SaleRate_ decimal(18,3);  Declare MRP_ decimal(18,3);  Declare HSNMasterId_ decimal(18,0);
Declare HSNCODE_ varchar(50); Declare Include_Tax_ decimal(18,3);  Declare SaleTax_ decimal(18,3);Declare UnitPrice_ decimal(18,3);
Declare Quantity_ decimal(18,3);declare Sale_Tax_ decimal(18,3); Declare To_Employee_Id_ decimal(18,0);Declare Unit_Discount_ decimal(18,3);
Declare Discount_ decimal(18,3); Declare NetValue_ decimal(18,3);Declare Amount_ decimal(18,3); Declare TaxableAmount_ decimal(18,3);
Declare TaxAmount_ decimal(18,3); Declare SGST_AMT_ decimal(18,3); Declare IGST_ decimal(18,3); Declare IGST_AMT_ decimal(18,3);
Declare TotalAmount_ decimal(18,3); Declare isnull_ varchar(500); DECLARE i int  DEFAULT 0; Declare Description_ varchar(4000);
declare Country_Id_ int;declare Country_Name_ varchar(200);Declare Purchase_Details_Id_ int;
delete from purchase_details where Purchase_Master_Id = Purchase_Master_Id_;
WHILE i < JSON_LENGTH(Purchase_Details) DO
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].ItemId'))) INTO ItemId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].Item_Code'))) INTO Item_Code_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].ItemName'))) INTO ItemName_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].UnitId'))) INTO UnitId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].UnitName'))) INTO UnitName_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].HSNCODE'))) INTO HSNCODE_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_Details, CONCAT('$[',i,'].UnitPrice')) ),  'null' ), 0 ) INTO UnitPrice_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_Details, CONCAT('$[',i,'].SaleRate')) ),  'null' ), 0 ) INTO SaleRate_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].NetValue'))) INTO NetValue_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_Details, CONCAT('$[',i,'].Country_Id')) ),  'null' ), 0 ) INTO Country_Id_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].Country_Name'))) INTO Country_Name_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_Details, CONCAT('$[',i,'].GroupId')) ),  'null' ), 0 ) INTO GroupId_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Details,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_Details, CONCAT('$[',i,'].Amount')) ),  'null' ), 0 ) INTO Amount_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_Details, CONCAT('$[',i,'].Sale_Tax')) ),  'null' ), 0 ) INTO Sale_Tax_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_Details, CONCAT('$[',i,'].TaxableAmount')) ),  'null' ), 0 ) INTO TaxableAmount_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_Details, CONCAT('$[',i,'].TaxAmount')) ),  'null' ), 0 ) INTO TaxAmount_;
if SaleRate_=0 then
set SaleRate_=PurchaseRate_+(PurchaseRate_*8/100);
            end if;
if MRP_=0 then
set MRP_=SaleRate_+(SaleRate_*8/100);
            end if;    
if(Item_Code_ <>0 and Item_Code_ <>'' and  Item_Code_ <>null)
then
if exists(select Stock_Id from Stock where ItemId=ItemId_ and ItemName=ItemName_ and DeleteStatus=False and Item_Code=Item_Code_)
then
        set StockId_=(select Stock_Id from Stock where ItemName=ItemName_ and DeleteStatus=False and ItemId=ItemId_  and Item_Code=Item_Code_ order by Stock_Id desc Limit 1);                
update Stock set ItemId=ItemId_,Item_Code=Item_Code_,ItemName=ItemName_,GroupId=GroupId_,GroupName=GroupName_,UnitId=UnitId_,UnitName=UnitName_,
            PurchaseRate=PurchaseRate_,Quantity=Quantity+Quantity_,SaleRate=SaleRate_,MRP=MRP_, HSNMasterId=HSNMasterId_,HSNCODE=HSNCODE_,SaleTax=SaleTax_

             where Stock_Id=StockId_ and DeleteStatus=False;
else
       
        set StockId_ =(select COALESCE(MAX(Stock_Id),0)+1 from stock);
insert into Stock(Stock_Id,ItemId,Item_Code,ItemName,GroupId,GroupName,UnitId,UnitName,PurchaseRate,SaleRate,MRP,HSNMasterId,HSNCODE,SaleTax,Quantity,DeleteStatus)
values(StockId_,ItemId_,Item_Code_,ItemName_,GroupId_,GroupName_,UnitId_,UnitName_,PurchaseRate_,SaleRate_,MRP_,HSNMasterId_,HSNCODE_,SaleTax_,Quantity_,False);
#set StockId_ =(SELECT LAST_INSERT_ID());
end if;
else if exists(select Stock_Id from Stock where ItemId=ItemId_ and ItemName=ItemName_ and DeleteStatus=False)
then
set StockId_=(select Stock_Id from Stock where ItemId=ItemId_ and ItemName=ItemName_ and DeleteStatus=False order by Stock_Id desc Limit 1);
update Stock set  ItemId=ItemId_,Item_Code=Item_Code_,ItemName=ItemName_,GroupId=GroupId_,Quantity=Quantity+Quantity_,GroupName=GroupName_,
            UnitId=UnitId_,UnitName=UnitName_,PurchaseRate=PurchaseRate_,SaleRate=SaleRate_,MRP=MRP_, HSNMasterId=HSNMasterId_,HSNCODE=HSNCODE_,
            SaleTax=SaleTax_ where Stock_Id=StockId_ and DeleteStatus=False;
else
         set StockId_ =(select COALESCE(MAX(Stock_Id),0)+1 from stock);
insert into Stock(Stock_Id,ItemId,Item_Code,ItemName,GroupId,GroupName,UnitId,UnitName,PurchaseRate,SaleRate,MRP,HSNMasterId,HSNCODE,SaleTax,Quantity,DeleteStatus)
values(StockId_,ItemId_,Item_Code_,ItemName_,GroupId_,GroupName_,UnitId_,UnitName_,PurchaseRate_,SaleRate_,MRP_,HSNMasterId_,HSNCODE_,SaleTax_,Quantity_,False);
#set StockId_ =(SELECT LAST_INSERT_ID());                
end if;    
end if;    
    set Purchase_Details_Id_ =(select COALESCE(MAX(Purchase_Details_Id),0)+1 from purchase_details);
INSERT INTO Purchase_Details (Purchase_Details_Id,
    Purchase_Master_Id, ItemId, Item_Code, ItemName,NetValue,StockId,
   # GroupId, GroupName,
    UnitId, UnitName, HSNCODE, UnitPrice, Quantity, SaleRate, Amount,
     SaleTax, TaxableAmount, TaxAmount, DeleteStatus,Country_Id,Country_Name,GroupId,GroupName
)
VALUES (Purchase_Details_Id_,
    Purchase_Master_Id_, ItemId_, Item_Code_, ItemName_, NetValue_,StockId_,
    #GroupId_, GroupName_,
    UnitId_, UnitName_, HSNCODE_, UnitPrice_, Quantity_, SaleRate_, Amount_,
     Sale_Tax_, TaxableAmount_, TaxAmount_, false,Country_Id_,Country_Name_,GroupId_,GroupName_
);
SELECT i + 1 INTO i;
END WHILE;  
 select Purchase_Master_Id_;
 End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_Purchase_Master`
Begin
declare Voucher_No_ varchar(50);declare Accounts_Id_ decimal;
declare YearFrom datetime;declare YearTo datetime;declare Duplicate_Purchase_Master_Id int;
#declare Entry_Date_ datetime;declare hsncode_ varchar(50);declare  Tax_Pers_ decimal(18,2);

 declare Purchase_Master_Id_ decimal(18,0);declare Account_Party_Id_ decimal(18,0);declare PurchaseDate_ datetime;declare Additional_Discount_ decimal(18,3);
 declare Amount_In_Words_ longtext;declare Brand_ longtext;declare Charge1_ varchar(100);declare Charge2_ varchar(100);declare Conversion_ decimal(18,3);
declare Currency_Id_ int;declare Discount_Description_ varchar(250);declare InvoiceNo_ varchar(100);declare NetTotal_ decimal(18,3);
declare PaymentTerms_ varchar(250);declare Payment_Term_Description_ int ;declare Ponumber_ varchar(200);declare PriceBasis_  longtext;
declare TotalDiscount_ decimal(18,3);declare TypeId_ int;declare Purchase_Details_ JSON ;declare User_Id_ int;declare VAT_Amount_ decimal(18,3);
declare VAT_Description_ varchar(500);declare VAT_Percentage_ decimal(18,3);declare charge1_Amount_ decimal(18,3);declare charge2_Amount_ decimal(18,3);
declare Entry_Date_ varchar(45);declare PurchaseOrderMaster_Id_ int;declare PurchaseOrder_Purchasemaster_Id_ int;declare TotalAmount_ decimal (18,3);
declare PaymentTermValue_ INT;declare Supplier_Ref_No_ VARCHAR(250);declare Roundoff_ DECIMAL(18,3);
#insert into db_logs values(0,PurchaseOrderMaster_Id_,'PurchaseOrderMaster_Id_',0);

if Purchase_Value_>0 then

SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_,'$.Purchase_Master_Id')) INTO Purchase_Master_Id_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_,'$.Account_Party_Id')) INTO Account_Party_Id_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_,'$.PurchaseDate')) INTO PurchaseDate_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_,'$.Additional_Discount')) INTO Additional_Discount_;
SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_, CONCAT('$.Additional_Discount')) ),  'null' ), 0 ) INTO Additional_Discount_;

SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_,'$.Amount_In_Words')) INTO Amount_In_Words_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_,'$.Brand')) INTO Brand_;
