CREATE PROCEDURE `Save_Purchase_order`
BEGIN

declare YearFrom datetime;declare YearTo datetime;
if(Purchase_OrderMaster_Id_ > 0) then

UPDATE purchaseordermaster SET Account_Party_Id = Account_Party_Id_,
EntryDate = EntryDate_,InvoiceNo = OrderNumber_,
CurrencyId = CurrencyId_,PaymentTerms =  PaymentTerms_,TotalAmount = TotalAmount_,
TotalDiscount = TotalDiscount_,
Roundoff_Amt = Roundoff_Amt_,Total_Amount = Total_Amount_,NetTotal =NetTotal_,Brand = Brand_,
#Brand = Brand_,POnumber = POnumber_,
AttendEmployee = AttendEmployee_,
PriceBasis = PriceBasis_,Delivery = Delivery_,
Validity = Validity_,Description1 = Description1_,User_Id = User_Id_,DeleteStatus = 0,Customer_Reference=Customer_Reference_,
Delivery_Address1 = Delivery_Address1_,Delivery_Address2 = Delivery_Address2_,Delivery_Address3 = Delivery_Address3_,
Delivery_Address4 = Delivery_Address4_,
Charge1 = Charge1_,charge1_Amount = charge1_Amount_,Charge2 = Charge2_,
charge2_Amount = charge2_Amount_,Discount_Description = Discount_Description_,Additional_Discount = Additional_Discount_,
Description2 = Description2_,
Amount_In_Words = Amount_In_Words_,PreparedBy = PreparedBy_,Charge1per = Charge1per_,Payment_Term_Description = Payment_Term_Description_,
VAT_Percentage = VAT_Percentage_,VAT_Amount = VAT_Amount_, TaxableAmount = TaxableAmount_, KindAttend = KindAttend_,
TypeId=AccountType_Id_,PaymentTermValue=PaymentTermValue_,PurchaseDate=EntryDate_,
Basic_Discount=Basic_Discount_,Supplier_Ref_No=Supplier_Ref_No_,
DeliveryDate=DeliveryDate_
WHERE PurchaseOrderMaster_Id = Purchase_OrderMaster_Id_;

else

 set YearFrom=(select Account_Years.YearFrom from Account_Years where Date_Format(EntryDate_,'%Y-%m-%d')
    between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));
set YearTo=(select Account_Years.YearTo from Account_Years where Date_Format(EntryDate_,'%Y-%m-%d')
    between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));  
if exists(select distinct Packing_List_No from packinglist_master)then
set OrderNumber_=(SELECT COALESCE( MAX(InvoiceNo),0)+1 FROM purchaseordermaster where Date_Format(EntryDate,'%Y-%m-%d')
    between Date_Format(YearFrom,'%Y-%m-%d') and Date_Format(YearTo,'%Y-%m-%d'));  
else
if exists(select PurchaseOrderNo from General_Settings)
then
set OrderNumber_=(select COALESCE(PurchaseOrderNo,0) from General_Settings);
else
set OrderNumber_=1;
end if;    
end if;

SET Purchase_OrderMaster_Id_ = (SELECT  COALESCE( MAX(PurchaseOrderMaster_Id ),0)+1 FROM purchaseordermaster);

INSERT INTO purchaseordermaster
(PurchaseOrderMaster_Id,Account_Party_Id,EntryDate,InvoiceNo,CurrencyId,PaymentTerms,Brand,
AttendEmployee,
#POnumber,Brand,
TotalAmount,TotalDiscount,TaxableAmount,Roundoff_Amt,Total_Amount,
NetTotal,
PriceBasis,Delivery,Validity,Description1,User_Id,DeleteStatus,
Delivery_Address1,Delivery_Address2,Delivery_Address3,Delivery_Address4,
Charge1,charge1_Amount,
Charge2,charge2_Amount,Discount_Description,Additional_Discount,Description2,Amount_In_Words,PreparedBy,
Charge1per,Payment_Term_Description,VAT_Percentage,VAT_Amount, KindAttend,TypeId,PaymentTermValue,PurchaseDate,
Basic_Discount,Customer_Reference,Supplier_Ref_No,
DeliveryDate)
VALUES
(Purchase_OrderMaster_Id_,Account_Party_Id_,EntryDate_,OrderNumber_,CurrencyId_, PaymentTerms_,Brand_,
AttendEmployee_,
#POnumber_,Brand_,
TotalAmount_,TotalDiscount_,TaxableAmount_,
Roundoff_Amt_,Total_Amount_,NetTotal_,
PriceBasis_,Delivery_,Validity_,Description1_,User_Id_,0,
Delivery_Address1_,Delivery_Address2_,Delivery_Address3_,Delivery_Address4_,
Charge1_,charge1_Amount_,Charge2_,charge2_Amount_,Discount_Description_,Additional_Discount_,Description2_,Amount_In_Words_,
PreparedBy_,Charge1per_,
Payment_Term_Description_,VAT_Percentage_,VAT_Amount_, KindAttend_,AccountType_Id_,PaymentTermValue_,EntryDate_,Basic_Discount_,Customer_Reference_,Supplier_Ref_No_,
DeliveryDate_);

if(SalesQuotationMaster_Id_ > 0)then
insert into quotation_purchaseordermaster (SalesQuotationMaster_Id,PurchaseOrderMaster_Id,DeleteStatus) values (SalesQuotationMaster_Id_,Purchase_OrderMaster_Id_,0);
end if;
end if;

CALL Save_PurchaseOrder_Details(Purchase_Orderdetails_ ,Purchase_OrderMaster_Id_,OrderNumber_);
select Purchase_OrderMaster_Id_,OrderNumber_;
END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_Purchase_Return_Details`
Begin
Declare ItemId_ int; Declare Item_Code_ varchar(50); Declare ItemName_ varchar(1000); 
Declare GroupId_ int;declare GroupName_ varchar(100); Declare UnitId_ int;Declare UnitName_ varchar(100); 
Declare StockId_ decimal(18,0);Declare SaleRate_ decimal(18,3); Declare UnitPrice_ decimal(18,3);
Declare HSNMasterId_ decimal(18,0);Declare HSNCODE_ varchar(50);declare Country_Id_ int;
declare Country_Name_ varchar(100);Declare Quantity_ decimal(18,3);Declare Amount_ decimal(18,3);
Declare Discount_ decimal(18,3);Declare NetValue_ decimal(18,3); 
declare Item_Discount_Amount_ decimal(18,3);Declare Unit_Discount_ decimal(18,3); 
DECLARE i int  DEFAULT 0;DECLARE Purchase_Return_Details_Id_ int;

delete from purchase_return_details where Purchase_Return_Master_Id = Purchase_Return_Master_Id_ ;

WHILE i < JSON_LENGTH(Purchase_Return_Details) DO
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].ItemId'))) INTO ItemId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].Item_Code'))) INTO Item_Code_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].ItemId'))) INTO ItemId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].ItemName'))) INTO ItemName_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].GroupId'))) INTO GroupId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].UnitId'))) INTO UnitId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].UnitName'))) INTO UnitName_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].StockId'))) INTO StockId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].UnitPrice'))) INTO UnitPrice_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].HSNMasterId'))) INTO HSNMasterId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].HSNCODE'))) INTO HSNCODE_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].Country_Id'))) INTO Country_Id_;  
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].Country_Name'))) INTO Country_Name_;    
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;    
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].Amount'))) INTO Amount_;    
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].Discount'))) INTO Discount_;  
SELECT JSON_UNQUOTE(JSON_EXTRACT(Purchase_Return_Details, CONCAT('$[',i,'].NetValue'))) INTO NetValue_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Purchase_Return_Details,CONCAT('$[',i,'].Item_Discount_Amount'))) INTO Item_Discount_Amount_;  
SELECT JSON_UNQUOTE(JSON_EXTRACT(Purchase_Return_Details, CONCAT('$[',i,'].Unit_Discount'))) INTO Unit_Discount_;

set Purchase_Return_Details_Id_ = (select COALESCE(MAX(Purchase_Return_Details_Id),0)+1 
from purchase_return_details);
INSERT INTO purchase_return_details
(Purchase_Return_Details_Id,Purchase_Return_Master_Id,ItemId,Item_Code,ItemName,GroupId,GroupName,UnitId,UnitName,
StockId,UnitPrice,HSNMasterId,HSNCODE,Country_Id,Country_Name,Quantity,Amount,Discount,NetValue,
DeleteStatus,Item_Discount_Amount,Unit_Discount)
VALUES
(Purchase_Return_Details_Id_,Purchase_Return_Master_Id_,ItemId_,Item_Code_,ItemName_,GroupId_,GroupName_,UnitId_,
UnitName_,StockId_,UnitPrice_,0,'',Country_Id_,Country_Name_,Quantity_,Amount_,Discount_,NetValue_,0,
Item_Discount_Amount_,Unit_Discount_);

update Stock set Quantity=Quantity-Quantity_ where Stock_Id=StockId_ ;
SELECT i + 1 INTO i;
END WHILE;  
 select Purchase_Return_Master_Id_, Purchase_Return_No_;
 End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_Purchase_Return_Master`
BEGIN
    -- Declare variables
    declare Purchase_Return_No_ int;
    DECLARE Duplicate_Purchase_Return_Master_Id INT;
    DECLARE Purchase_Return_Master_Id_ DECIMAL(18,0);
    DECLARE Purchase_Master_Id_ INT;
    DECLARE Account_Party_Id_ DECIMAL(18,0);
    DECLARE PurchaseDate_ DATETIME;
    DECLARE Additional_Discount_ DECIMAL(18,3);
    DECLARE Amount_In_Words_ VARCHAR(500);
    DECLARE Brand_ VARCHAR(100);
    DECLARE Charge1_ VARCHAR(100);
    DECLARE Charge2_ VARCHAR(100);
    DECLARE Conversion_ DECIMAL(18,3);
    DECLARE CurrencyId_ INT;
    DECLARE Discount_Description_ VARCHAR(250);
    DECLARE InvoiceNo_ VARCHAR(100);
    DECLARE NetTotal_ DECIMAL(18,3);
    DECLARE PaymentTerms_ varchar(1000);
    DECLARE Payment_Term_Description_ int;
    DECLARE Ponumber_ VARCHAR(200);
    DECLARE PriceBasis_ VARCHAR(500);
    DECLARE TotalDiscount_ DECIMAL(18,3);
    DECLARE TypeId_ INT;
    DECLARE Purchase_Return_Details_ JSON;
    DECLARE User_Id_ INT;
    declare TotalAmount_ DECIMAL(18,3);
    DECLARE VAT_Amount_ DECIMAL(18,3);
    DECLARE VAT_Description_ VARCHAR(500);
    DECLARE VAT_Percentage_ DECIMAL(18,3);
    DECLARE charge1_Amount_ DECIMAL(18,3);
    DECLARE charge2_Amount_ DECIMAL(18,3);
    DECLARE PaymentTermValue_ INT;
    DECLARE Entry_Date_ DATE;
    declare Accounts_Id_ decimal;
    declare YearFrom datetime;
    declare YearTo datetime;
    declare billtypes_ varchar(100);
    declare Discount_ decimal(18,3) default 0;
    declare TaxableAmount_ decimal(18,3);
    declare Basic_Discount_ varchar(50);
    declare Roundoff_ decimal(18,3);
    declare UserName_ varchar(50);
    declare CurrecnyName_ varchar(50);
    -- Extract values from JSON input
    IF Purchase_Value_ > 0 THEN
        SET Purchase_Return_Master_Id_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Purchase_Return_Master_Id'));
        SET Purchase_Master_Id_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Purchase_Master_Id'));
        SET Account_Party_Id_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Account_Party_Id'));
        SET PurchaseDate_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.PurchaseDate'));
        #SET Additional_Discount_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Additional_Discount'));
		SET Additional_Discount_ =  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Additional_Discount')),'null'),0);
        SET Amount_In_Words_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Amount_In_Words'));
        SET Brand_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Brand'));
        SET Charge1_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Charge1'));
        SET Charge2_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Charge2'));
        SET Conversion_ = IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Conversion')),'null'),0);
        SET CurrencyId_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.CurrencyId'));
       # SET Discount_Description_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Discount_Description'));
        SET Discount_Description_ =  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Discount_Description')),'null'),0);
        SET InvoiceNo_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.InvoiceNo'));
        #SET NetTotal_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.NetTotal'));
        SET NetTotal_ =  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.NetTotal')),'null'),0);
        SET PaymentTerms_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.PaymentTerms'));
        SET Payment_Term_Description_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Payment_Term_Description'));
        SET Ponumber_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Ponumber'));
        SET PriceBasis_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.PriceBasis'));
        #SET TotalDiscount_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.TotalDiscount'));
		SET TotalDiscount_ =  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.TotalDiscount')),'null'),0);
        SET TypeId_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.TypeId'));
        SET Purchase_Return_Details_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Purchase_Return_Details'));
        SET User_Id_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.User_Id'));
        set UserName_ =  JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.UserName'));
        set CurrecnyName_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.CurrecnyName'));
        #SET VAT_Amount_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.VAT_Amount'));
		SET VAT_Amount_ =  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.VAT_Amount')),'null'),0);
        SET VAT_Description_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.VAT_Description'));
        #SET VAT_Percentage_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.VAT_Percentage'));
		SET VAT_Percentage_ =  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.VAT_Percentage')),'null'),0);
       # SET charge1_Amount_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.charge1_Amount'));
		SET charge1_Amount_ =  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.charge1_Amount')),'null'),0);
        #SET charge2_Amount_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.charge2_Amount'));
		SET charge2_Amount_ =  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.charge2_Amount')),'null'),0);
        #SET TotalAmount_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.TotalAmount'));
		SET TotalAmount_ =  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.TotalAmount')),'null'),0);
        #SET PaymentTermValue_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.PaymentTermValue'));
		SET PaymentTermValue_ =  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.PaymentTermValue')),'null'),0);
         SET Roundoff_ =  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Roundoff')),'null'),0);
        SET Discount_ =  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Discount')),'null'),0);
        SET TaxableAmount_ =  IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.TaxableAmount')),'null'),0);
         SET Basic_Discount_ = JSON_UNQUOTE(JSON_EXTRACT(Purchase_, '$.Basic_Discount'));
         
    END IF;
		SET Entry_Date_ = CURRENT_DATE();    
        IF Purchase_Return_Master_Id_ > 0 THEN
        call Update_Stock_Purchase_Return(Purchase_Return_Master_Id_);
		#Delete From Purchase_Return_Details Where Purchase_Return_Master_Id=Purchase_Return_Master_Id_;
		delete from Accounts where Tran_Id=Purchase_Return_Master_Id_ and Tran_Type='PUR';
            -- Update existing record
		set Purchase_Return_No_ = (select Purchase_Return_No from purchase_return_master where Purchase_Return_Master_Id=Purchase_Return_Master_Id_);
            UPDATE purchase_return_master
            SET
                Purchase_Master_Id = Purchase_Master_Id_, Account_Party_Id = Account_Party_Id_, PurchaseDate = PurchaseDate_, 
				Purchase_Return_No = Purchase_Return_No_, InvoiceNo = InvoiceNo_, CurrencyId =CurrencyId_, TypeId = TypeId_, PaymentTerms = PaymentTerms_, 
                TotalAmount = TotalAmount_, TotalDiscount = TotalDiscount_, Discount = Discount_, NetTotal=NetTotal_, Brand=Brand_, PriceBasis=PriceBasis_,
                Payment_Term_Description=Payment_Term_Description_, User_Id=User_Id_, Charge1 = Charge1_, charge1_Amount = charge1_Amount_, 
                Charge2 = Charge2_, charge2_Amount = charge2_Amount_ , Discount_Description = Discount_Description_, Additional_Discount = Additional_Discount_,
                Basic_Discount = Basic_Discount_ , Amount_In_Words = Amount_In_Words_, Ponumber = Ponumber_, Conversion = Conversion_, 
                VAT_Description = VAT_Description_, VAT_Percentage = VAT_Percentage_, VAT_Amount = VAT_Amount_, Roundoff = Roundoff_, 
                UserName = UserName_, CurrecnyName = CurrecnyName_, PaymentTermValue = PaymentTermValue_,TaxableAmount = TaxableAmount_
            WHERE
                Purchase_Return_Master_Id = Purchase_Return_Master_Id_;
        ELSE
			set YearFrom=(select Account_Years.YearFrom from Account_Years where Date_Format(Entry_Date_,'%Y-%m-%d')
			between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));
			set YearTo=(select Account_Years.YearTo from Account_Years where Date_Format(Entry_Date_,'%Y-%m-%d')
			between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));  
			if exists(select distinct Invoice_No from Sales_Master)then
			set Purchase_Return_No_=(SELECT COALESCE( MAX(Purchase_Return_No ),0)+1 FROM purchase_return_master 
			where Date_Format(Entry_Date,'%Y-%m-%d')
			between Date_Format(YearFrom,'%Y-%m-%d') and Date_Format(YearTo,'%Y-%m-%d'));  
			else
			if exists(select Purchase_Return_No from General_Settings)
			then
			set Purchase_Return_No_=(select COALESCE(Purchase_Return_No,0) from General_Settings);
			else
			set Purchase_Return_No_=1;
			end if;    
			end if;
            -- Insert new record
            SET Purchase_Return_Master_Id_ = (SELECT COALESCE(MAX(Purchase_Return_Master_Id), 0) + 1 FROM purchase_return_master);
            INSERT INTO purchase_return_master (
                Purchase_Return_Master_Id, Purchase_Master_Id, Account_Party_Id, Entry_Date, PurchaseDate,Purchase_Return_No, InvoiceNo,
                CurrencyId,TypeId,PaymentTerms,TotalAmount,TotalDiscount,Discount,TaxableAmount,NetTotal,Brand,PriceBasis,Payment_Term_Description,User_Id,
                DeleteStatus,Charge1,charge1_Amount,Charge2,charge2_Amount, Discount_Description,Additional_Discount,Basic_Discount,Amount_In_Words,
                Ponumber,Conversion,VAT_Description,VAT_Percentage,VAT_Amount, Roundoff,UserName,CurrecnyName,PaymentTermValue) 
                VALUES (
				Purchase_Return_Master_Id_, Purchase_Master_Id_, Account_Party_Id_, now(), PurchaseDate_,Purchase_Return_No_, InvoiceNo_,
                CurrencyId_,TypeId_,PaymentTerms_,TotalAmount_,TotalDiscount_,Discount_,TaxableAmount_,NetTotal_,Brand_,PriceBasis_,Payment_Term_Description_,
                User_Id_,0,Charge1_,charge1_Amount_,Charge2_,charge2_Amount_, Discount_Description_,Additional_Discount_,Basic_Discount_,Amount_In_Words_,
                Ponumber_,Conversion_,VAT_Description_,VAT_Percentage_,VAT_Amount_,Roundoff_,UserName_,CurrecnyName_,PaymentTermValue_);
        END IF;
			 if(NetTotal_>0)
			 then
			 #set Accounts_Id_=(select COALESCE( MAX(Accounts_Id ),0)+1 from Accounts);
			insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,VoucherType,Description1,Status,DayBook,Payment_Status)
			 values(0,Entry_Date_,8,0,NetTotal_,Account_Party_Id_,'PUR',Purchase_Return_Master_Id_, Purchase_Return_No_,5,'','','',1);
			  #set Accounts_Id_=(select COALESCE( MAX(Accounts_Id ),0)+1 from Accounts);
			insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,VoucherType,Description1,Status,DayBook,Payment_Status)
			 values(0,Entry_Date_,Account_Party_Id_,NetTotal_,0,8,'PUR',Purchase_Return_Master_Id_, Purchase_Return_No_ ,5,'','','Y',1);
			 end IF;
			  if(VAT_Amount_>0)
			 then
			# set Accounts_Id_=(select COALESCE(MAX(Accounts_Id),0)+1 from Accounts);
			insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,VoucherType,Description1,Status,DayBook,Payment_Status)
			 values(0,Entry_Date_,18,0,VAT_Amount_,8,'PUR',Purchase_Return_Master_Id_, Purchase_Return_No_,5,'','','',1);
			#set Accounts_Id_=(select COALESCE(MAX(Accounts_Id),0)+1 from Accounts);
			insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,VoucherType,Description1,Status,DayBook,Payment_Status)
			 values(0,Entry_Date_,8,VAT_Amount_,0,18,'PUR',Purchase_Return_Master_Id_, Purchase_Return_No_ ,5,'','','Y',1);
			 end IF;       
        CALL Save_Purchase_Return_Details(Purchase_Return_Details_, Purchase_Return_Master_Id_,Purchase_Return_No_);
    #END IF;
    -- Return the Purchase_Return_Master_Id
    SELECT Purchase_Return_Master_Id_,Purchase_Return_No_;
END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_Quotation`
BEGIN
declare YearFrom datetime;declare YearTo datetime;declare QuotationNo_ int;
if(SalesQuotationMaster_Id_ > 0) then
set QuotationNo_ = (select QuotationNo from salesquotationmaster where SalesQuotationMaster_Id = SalesQuotationMaster_Id_ and DeleteStatus = 0);
UPDATE salesquotationmaster SET Account_Party_Id = Account_Party_Id_,EntryDate = EntryDate_,POnumber = POnumber_,CurrencyId = CurrencyId_,
PaymentTerms = PaymentTerms_,AttendEmployee = AttendEmployee_,TotalAmount = TotalAmount_,TotalDiscount = TotalDiscount_,Roundoff_Amt = Roundoff_Amt_,
Total_Amount = Total_Amount_,Basic_Discount=Basic_Discount_,NetTotal =NetTotal_,Brand = Brand_,PriceBasis = PriceBasis_,Delivery = Delivery_,
Validity = Validity_,Description1 = Description1_,User_Id = User_Id_,Delivery_Address1 = Delivery_Address1_,Delivery_Address2 = Delivery_Address2_,
Delivery_Address3 = Delivery_Address3_,Delivery_Address4 = Delivery_Address4_,Charge1 = Charge1_,charge1_Amount = charge1_Amount_,Charge2 = Charge2_,
charge2_Amount = charge2_Amount_,Discount_Description = Discount_Description_,Additional_Discount = Additional_Discount_,Description2 = Description2_,
Amount_In_Words = Amount_In_Words_,PreparedBy = PreparedBy_,Charge1per = Charge1per_,Payment_Term_Description = Payment_Term_Description_,
VAT_Percentage = VAT_Percentage_,VAT_Amount = VAT_Amount_, TaxableAmount = TaxableAmount_, KindAttend = KindAttend_, PaymentTermValue = PaymentTermValue_,
QuotationNo =QuotationNo_, Supplier_Ref_No= Supplier_Ref_No_
WHERE SalesQuotationMaster_Id = SalesQuotationMaster_Id_;
else
set YearFrom=(select Account_Years.YearFrom from Account_Years where Date_Format(EntryDate_,'%Y-%m-%d')
    between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));
set YearTo=(select Account_Years.YearTo from Account_Years where Date_Format(EntryDate_,'%Y-%m-%d')
    between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));     
if exists(select distinct QuotationNo from SalesQuotationMaster)then
set QuotationNo_=(SELECT COALESCE( MAX(QuotationNo ),0)+1 FROM SalesQuotationMaster where Date_Format(EntryDate,'%Y-%m-%d')
    between Date_Format(YearFrom,'%Y-%m-%d') and Date_Format(YearTo,'%Y-%m-%d'));
else
if exists(select QuotationNo from General_Settings)
then
set QuotationNo_=(select COALESCE(QuotationNo,0) from General_Settings);
else
set QuotationNo_=1;
end if;    
end if;
SET SalesQuotationMaster_Id_ = (SELECT  COALESCE( MAX(SalesQuotationMaster_Id ),0)+1 FROM salesquotationmaster);
INSERT INTO salesquotationmaster
(SalesQuotationMaster_Id,Account_Party_Id,EntryDate,QuotationNo,POnumber,CurrencyId,PaymentTerms,AttendEmployee,TotalAmount,TotalDiscount,TaxableAmount,
Roundoff_Amt,Total_Amount,Basic_Discount,NetTotal,Brand,PriceBasis,Delivery,Validity,Description1,User_Id,DeleteStatus,Delivery_Address1,Delivery_Address2,
Delivery_Address3,Delivery_Address4,Charge1,charge1_Amount,Charge2,charge2_Amount,Discount_Description,Additional_Discount,Description2,Amount_In_Words,
PreparedBy,Charge1per,Payment_Term_Description,VAT_Percentage,VAT_Amount, KindAttend,PaymentTermValue,TypeId,
Supplier_Ref_No)
VALUES
(SalesQuotationMaster_Id_,Account_Party_Id_,EntryDate_,QuotationNo_,POnumber_,CurrencyId_,PaymentTerms_,AttendEmployee_,TotalAmount_,TotalDiscount_,
TaxableAmount_,Roundoff_Amt_,Total_Amount_,Basic_Discount_,NetTotal_,Brand_,PriceBasis_,Delivery_,Validity_,Description1_,User_Id_,0,Delivery_Address1_,
Delivery_Address2_,Delivery_Address3_,Delivery_Address4_,Charge1_,charge1_Amount_,Charge2_,charge2_Amount_,Discount_Description_,Additional_Discount_,
Description2_,Amount_In_Words_,PreparedBy_,Charge1per_,Payment_Term_Description_,VAT_Percentage_,VAT_Amount_, KindAttend_,PaymentTermValue_,1,
Supplier_Ref_No_);
end if;
CALL Save_Quotation_Details(Quotation_Details_ ,SalesQuotationMaster_Id_,QuotationNo_);
select SalesQuotationMaster_Id_,QuotationNo_;
END
$$
DELIMITER ;

