CREATE PROCEDURE `Save_Receipt_Voucher`
Begin 
declare Voucher_No_ DECIMAL(18,0);declare Accounts_Id_ decimal(18,0);
declare YearFrom datetime;declare YearTo datetime;
declare Receipt_Voucher_Reference_Id_ int;declare Sales_Master_Id_ int;DECLARE Amount2_ decimal(18,2);
declare Discount_ decimal(18,3);declare Receiving_Amount_ DECIMAL(18,3);declare Master_Date_ varchar(45);
declare InvoiceNo_ varchar(45);declare Voucher_Type_Id_ int;declare Voucher_Type_Name_ varchar(100);
DECLARE Check_Box_ varchar(25);DECLARE i int  DEFAULT 0;

set YearFrom=(select Account_Years.YearFrom from Account_Years where  
Date_Format(Date_,'%Y-%m-%d') between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));
set YearTo=(select Account_Years.YearTo from Account_Years where 
Date_Format(Date_,'%Y-%m-%d') between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));

if exists(select distinct Receipt_No from Receipt_Voucher)
then
	set Voucher_No_=(SELECT  COALESCE( MAX(Receipt_No ),0)+1 FROM Receipt_Voucher
where Date_Format(Date,'%Y-%m-%d') between Date_Format(YearFrom,'%Y-%m-%d') and Date_Format(YearTo,'%Y-%m-%d'));  
else 
	if exists(select Receipt_Voucher_No from General_Settings)
	then
		set Voucher_No_=(select COALESCE(Receipt_Voucher_No,0) from General_Settings);
	else
		set Voucher_No_=1;
	end if;
end if;

 if  Receipt_Voucher_Id_>0
 THEN 
  set Voucher_No_=(select Receipt_No from Receipt_Voucher Where  Receipt_Voucher_Id=Receipt_Voucher_Id_ );
call Delete_Receipt_Reference(Receipt_Voucher_Id_);
DELETE FROM Accounts WHERE Tran_Type='RV' AND Tran_Id=Receipt_Voucher_Id_;
 UPDATE Receipt_Voucher set Date = Date_,Frm_Party_Id =From_Account_Id_,To_Party_Id =To_Account_Id_,
 CurrencyId = CurrencyId_,Amount = Amount_ ,Payment_Mode_Id =2,Payment_Mode_Name = Payment_Mode_Name_,
User_Id = User_Id_,UserName=User_Name_,Payment_Status=2,Description=Description_,
Print_Caption_Id = Print_Caption_Id_  Where Receipt_Voucher_Id=Receipt_Voucher_Id_ ;

 ELSE 
 SET Receipt_Voucher_Id_ = (SELECT  COALESCE( MAX(Receipt_Voucher_Id ),0)+1 FROM Receipt_Voucher); 
 INSERT INTO Receipt_Voucher(Receipt_Voucher_Id ,Date,Amount,Receipt_No,Frm_Party_Id,To_Party_Id,
 Payment_Mode_Id,Payment_Mode_Name,Description,User_Id,CurrencyId,DeleteStatus,Payment_Status,UserName,Print_Caption_Id) 
 
values (Receipt_Voucher_Id_,Date_,Amount_,Voucher_No_,From_Account_Id_,To_Account_Id_,2,Payment_Mode_Name_,
Description_,User_Id_ ,CurrencyId_,false,2,User_Name_,Print_Caption_Id_);
 End If ;
 insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,VoucherType,Description1,Status,DayBook,Payment_Status,Voucher_Type_Id)
  values(0,Date_,From_Account_Id_,0,Amount_,To_Account_Id_,'RV',Receipt_Voucher_Id_,Voucher_No_,'Receipt Voucher',Description_,'','Y',2,5);
 insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,VoucherType,Description1,Status,DayBook,Payment_Status,Voucher_Type_Id) 
  values(0,Date_,To_Account_Id_,Amount_,0,From_Account_Id_,'RV',Receipt_Voucher_Id_,Voucher_No_ ,'Receipt Voucher',Description_,'','',2,5); 
 if Salesrecipt_value_>0 then
 WHILE i < JSON_LENGTH(Sales_Details) DO
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Check_Box'))) INTO Check_Box_;
		if(Check_Box_='true'||Check_Box_=1 || Check_Box_=true)
		then set Check_Box_=1;
		else set Check_Box_=0;
		end if;
    SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Sales_Master_Id'))) INTO Sales_Master_Id_;
	SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Amount'))) INTO Amount2_;
	SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Receiving_Amount'))) INTO Receiving_Amount_;
	SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Date'))) INTO Master_Date_;
	SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].InvoiceNo'))) INTO InvoiceNo_;
	SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Voucher_Type_Id'))) INTO Voucher_Type_Id_;
	SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Voucher_Type_Name'))) INTO Voucher_Type_Name_;

         SET Receipt_Voucher_Reference_Id_ = (SELECT  COALESCE( MAX(Receipt_Voucher_Reference_Id ),0)+1 FROM receipt_reference); 

        INSERT INTO Receipt_Reference(Receipt_Voucher_Reference_Id,Receipt_Voucher_Id,Master_Id,Amount,Discount,Receiving_Amount,DeleteStatus,Date,InvoiceNo,Voucher_Type_Id ,Voucher_Type_Name,Check_Box) 
		values (Receipt_Voucher_Reference_Id_,Receipt_Voucher_Id_,Sales_Master_Id_,Amount2_,0,Receiving_Amount_,false,Master_Date_,InvoiceNo_,Voucher_Type_Id_,Voucher_Type_Name_,Check_Box_);
		if Voucher_Type_Id_=5 then
        update sales_master set PaidAmount=ifnull(PaidAmount,0)+Receiving_Amount_ where Sales_Master_Id=Sales_Master_Id_ ;
        else
		update journal_entry set PaidAmount=ifnull(PaidAmount,0)+Receiving_Amount_ where Journal_Entry_Id=Sales_Master_Id_;
		end if;
      SELECT i + 1 INTO i;
	END WHILE;
    end if;
 select Receipt_Voucher_Id_,Voucher_No_,To_Account_Id_;
 End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_Receipt_Voucher_Mobile`
Begin
declare Date_ datetime;declare Payment_Status_ int;
declare Voucher_No_ DECIMAL(18,0);declare Accounts_Id_ decimal(18,0);
declare YearFrom datetime;declare YearTo datetime;
set Date_=curdate();
set YearFrom=(select Account_Years.YearFrom from Account_Years where Date_Format(Date_,'%Y-%m-%d') between 
Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));
set YearTo=(select Account_Years.YearTo from Account_Years where Date_Format(Date_,'%Y-%m-%d') between 
Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));
if exists(select distinct Voucher_No from Receipt_Voucher)
then
	set Voucher_No_=(SELECT  COALESCE( MAX(Voucher_No ),0)+1 FROM Receipt_Voucher
	where Date_Format(Date,'%Y-%m-%d') between Date_Format(YearFrom,'%Y-%m-%d') 
	and Date_Format(YearTo,'%Y-%m-%d') and DeleteStatus=false);  
else 
	if exists(select Receipt_Voucher_No from General_Settings)
	then
		set Voucher_No_=(select COALESCE(Receipt_Voucher_No,0) from General_Settings);
	else
		set Voucher_No_=1;
	end if;
end if;
 if  Receipt_Voucher_Id_>0
 THEN 
	 set Date_=(select Date from Receipt_Voucher Where  Receipt_Voucher_Id=Receipt_Voucher_Id_ );
	 set Voucher_No_=(select Voucher_No from Receipt_Voucher Where  Receipt_Voucher_Id=Receipt_Voucher_Id_ );
	 DELETE FROM Accounts WHERE Tran_Type='RV' AND Tran_Id=Receipt_Voucher_Id_;
	 delete from Sales_Receipt where Receipt_Voucher_Id_=Receipt_Voucher_Id_;
     
	 UPDATE Receipt_Voucher set Date = Date_ ,From_Account_Id = From_Account_Id_ ,	Amount = Amount_ ,To_Account_Id = To_Account_Id_ ,
	 Payment_Mode = Payment_Mode_ ,User_Id = User_Id_,Description=Description_
	 where Receipt_Voucher_Id=Receipt_Voucher_Id_ ;    
 ELSE 
	 SET Receipt_Voucher_Id_ = (SELECT  COALESCE( MAX(Receipt_Voucher_Id ),0)+1 FROM Receipt_Voucher); 
	 INSERT INTO Receipt_Voucher(Receipt_Voucher_Id ,Date ,Voucher_No ,From_Account_Id ,Amount ,
	To_Account_Id ,Payment_Mode ,User_Id ,Payment_Status,Description,DeleteStatus ) 
	values (Receipt_Voucher_Id_ ,Date_ ,Voucher_No_ ,From_Account_Id_ ,Amount_ ,To_Account_Id_ ,Payment_Mode_ ,
	User_Id_ ,1,Description_,false);   
 End If ;
  insert into Sales_Receipt(Receipt_Voucher_Id,Sales_Master_Id,DeleteStatus)
  values(Receipt_Voucher_Id_,Sales_Master_Id_,false);
 if(Amount_>0) then
	 set Accounts_Id_=(select COALESCE( MAX(Accounts_Id ),0)+1 from Accounts);
	 insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,
	 VoucherType,Description1,Status,DayBook,Payment_Status)
	 values(Accounts_Id_,Date_,From_Account_Id_,0,Amount_,To_Account_Id_,'RV',Receipt_Voucher_Id_,Voucher_No_,2,Description_,'','',1);
 
	 set Accounts_Id_=(select COALESCE( MAX(Accounts_Id ),0)+1 from Accounts);
	 insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,
	 VoucherType,Description1,Status,DayBook,Payment_Status) 
	 values(Accounts_Id_,Date_,To_Account_Id_,Amount_,0,From_Account_Id_,'RV',Receipt_Voucher_Id_,Voucher_No_ ,2,Description_,'','Y',1); 
 end if;
 select Receipt_Voucher_Id_,Voucher_No_,To_Account_Id_;
End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_Requirement`
BEGIN
    DECLARE _RequirementMaster_Id INT;
    IF (RequirementNo_ IS NULL OR RequirementNo_ = '' OR RequirementNo_ = '0') THEN
        SET RequirementNo_ = (SELECT IFNULL(MAX(CAST(RequirementNo AS UNSIGNED)), 0) + 1 FROM requirementmaster);
    END IF;

    IF (RequirementMaster_Id_ = 0) THEN
        INSERT INTO requirementmaster (
            Account_Party_Id, EntryDate, RequirementNo, POnumber, CurrencyId, PaymentTerms, AttendEmployee,
            TotalAmount, TotalDiscount, Roundoff_Amt, Total_Amount, Basic_Discount, NetTotal, Brand, PriceBasis,
            Delivery, Validity, Description1, User_Id, Delivery_Address1, Delivery_Address2, Delivery_Address3,
            Delivery_Address4, Charge1, charge1_Amount, Charge2, charge2_Amount, Discount_Description,
            Additional_Discount, Description2, Amount_In_Words, PreparedBy, Charge1per,
            Payment_Term_Description, VAT_Percentage, VAT_Amount, TaxableAmount, KindAttend, PaymentTermValue, Supplier_Ref_No, DeleteStatus
        )
        VALUES (
            Account_Party_Id_, EntryDate_, RequirementNo_, POnumber_, CurrencyId_, PaymentTerms_, AttendEmployee_,
            TotalAmount_, TotalDiscount_, Roundoff_Amt_, Total_Amount_, Basic_Discount_, NetTotal_, Brand_, PriceBasis_,
            Delivery_, Validity_, Description1_, User_Id_, Delivery_Address1_, Delivery_Address2_, Delivery_Address3_,
            Delivery_Address4_, Charge1_, charge1_Amount_, Charge2_, charge2_Amount_, Discount_Description_,
            Additional_Discount_, Description2_, Amount_In_Words_, PreparedBy_, Charge1per_,
            Payment_Term_Description_, VAT_Percentage_, VAT_Amount_, TaxableAmount_, KindAttend_, PaymentTermValue_, Supplier_Ref_No_, 0
        );
        SET _RequirementMaster_Id = LAST_INSERT_ID();
    ELSE
        UPDATE requirementmaster SET
            Account_Party_Id = Account_Party_Id_, EntryDate = EntryDate_, RequirementNo = RequirementNo_,
            POnumber = POnumber_, CurrencyId = CurrencyId_, PaymentTerms = PaymentTerms_,
            AttendEmployee = AttendEmployee_, TotalAmount = TotalAmount_, TotalDiscount = TotalDiscount_,
            Roundoff_Amt = Roundoff_Amt_, Total_Amount = Total_Amount_, Basic_Discount = Basic_Discount_,
            NetTotal = NetTotal_, Brand = Brand_, PriceBasis = PriceBasis_,
            Delivery = Delivery_, Validity = Validity_, Description1 = Description1_, User_Id = User_Id_,
            Delivery_Address1 = Delivery_Address1_, Delivery_Address2 = Delivery_Address2_,
            Delivery_Address3 = Delivery_Address3_, Delivery_Address4 = Delivery_Address4_,
            Charge1 = Charge1_, charge1_Amount = charge1_Amount_,
            Charge2 = Charge2_, charge2_Amount = charge2_Amount_, Discount_Description = Discount_Description_,
            Additional_Discount = Additional_Discount_, Description2 = Description2_,
            Amount_In_Words = Amount_In_Words_, PreparedBy = PreparedBy_, Charge1per = Charge1per_,
            Payment_Term_Description = Payment_Term_Description_, VAT_Percentage = VAT_Percentage_,
            VAT_Amount = VAT_Amount_, TaxableAmount = TaxableAmount_, KindAttend = KindAttend_,
            PaymentTermValue = PaymentTermValue_, Supplier_Ref_No = Supplier_Ref_No_
        WHERE RequirementMaster_Id = RequirementMaster_Id_;
        SET _RequirementMaster_Id = RequirementMaster_Id_;
    END IF;

    DELETE FROM requirementdetails WHERE RequirementMaster_Id = _RequirementMaster_Id;

    INSERT INTO requirementdetails (
        RequirementMaster_Id, ItemId, ItemCode, ItemName, GroupId, GroupName, UnitId, UnitName,
        StockId, HSNMasterId, HSNCODE, Country_Id, Country_Name, UnitPrice, Quantity,
        Amount, Discount, TaxableAmount, TaxAmount, NetValue, Availability,
        Item_Discount_Amount, Unit_Discount, Sale_Tax, part_number, DeleteStatus
    )
    SELECT
        _RequirementMaster_Id,
        CAST(j.ItemId AS UNSIGNED),
        j.Item_Code,
        j.ItemName,
        CAST(j.GroupId AS UNSIGNED),
        j.GroupName,
        CAST(j.UnitId AS UNSIGNED),
        j.UnitName,
        CAST(j.StockId AS UNSIGNED),
        CAST(j.HSNMasterId AS UNSIGNED),
        j.HSNCODE,
        CAST(j.Country_Id AS UNSIGNED),
        j.Country_Name,
        CAST(j.UnitPrice AS DECIMAL(18,4)),
        CAST(j.Quantity AS DECIMAL(18,4)),
        CAST(j.Amount AS DECIMAL(18,4)),
        CAST(j.Discount AS DECIMAL(18,4)),
        CAST(j.TaxableAmount AS DECIMAL(18,4)),
        CAST(j.TaxAmount AS DECIMAL(18,4)),
        CAST(j.NetValue AS DECIMAL(18,4)),
        j.Availability,
        CAST(j.Item_Discount_Amount AS DECIMAL(18,4)),
        CAST(j.Unit_Discount AS DECIMAL(18,4)),
        COALESCE(CAST(j.SaleTax AS DECIMAL(18,4)), CAST(j.gst AS DECIMAL(18,4)), 0),
        COALESCE(j.part_number, j.Item_Code),
        0
    FROM JSON_TABLE(Requirement_Details_, '$[*]'
        COLUMNS (
            ItemId INT PATH '$.ItemId',
            Item_Code VARCHAR(100) PATH '$.Item_Code',
            ItemName VARCHAR(500) PATH '$.ItemName',
            GroupId INT PATH '$.GroupId',
            GroupName VARCHAR(200) PATH '$.GroupName',
            UnitId INT PATH '$.UnitId',
            UnitName VARCHAR(100) PATH '$.UnitName',
            StockId INT PATH '$.StockId',
            HSNMasterId INT PATH '$.HSNMasterId',
            HSNCODE VARCHAR(100) PATH '$.HSNCODE',
            Country_Id INT PATH '$.Country_Id',
            Country_Name VARCHAR(100) PATH '$.Country_Name',
            UnitPrice DECIMAL(18,4) PATH '$.UnitPrice',
            Quantity DECIMAL(18,4) PATH '$.Quantity',
            Amount DECIMAL(18,4) PATH '$.Amount',
            Discount DECIMAL(18,4) PATH '$.Discount',
            TaxableAmount DECIMAL(18,4) PATH '$.TaxableAmount',
            TaxAmount DECIMAL(18,4) PATH '$.TaxAmount',
            NetValue DECIMAL(18,4) PATH '$.NetValue',
            Availability VARCHAR(100) PATH '$.Availability',
            Item_Discount_Amount DECIMAL(18,4) PATH '$.Item_Discount_Amount',
            Unit_Discount DECIMAL(18,4) PATH '$.Unit_Discount',
            SaleTax DECIMAL(18,4) PATH '$.SaleTax',
            gst DECIMAL(18,4) PATH '$.gst',
            part_number VARCHAR(100) PATH '$.part_number'
        )
    ) AS j;

    SELECT _RequirementMaster_Id AS RequirementMaster_Id_;
END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_requirementdetails`
BEGIN
declare ItemId_ int;declare ItemCode_ varchar(500);
declare ItemName_ longtext;declare UnitId_ int;
declare UnitName_ varchar(100);declare StockId_ int;
declare HSNMasterId_ int;declare HSNCODE_ varchar(50);
declare UnitPrice_ decimal(18,3);declare Quantity_ decimal(18,3);
declare Amount_ decimal(18,3);declare Discount_ decimal(18,3);
declare TaxableAmount_ decimal(18,3);declare TaxAmount_ decimal(18,3);
declare NetValue_ decimal(18,3);declare Availability_ varchar(200);
declare Unit_Discount_ decimal(18,3); declare Sale_Tax_ decimal(18,3);
declare RequirementDetails_Id_ int;
declare Item_Discount_Amount_ decimal(18,3);
DECLARE i int  DEFAULT 0;declare GroupId_ int; declare GroupName_ varchar(100);
DECLARE Country_Id_ INT DEFAULT 0;
DECLARE Country_Name_ VARCHAR(250) DEFAULT '';
delete from requirementdetails where RequirementMaster_Id = RequirementMaster_Id_;
WHILE i < JSON_LENGTH(Requirement_Details_) DO
SELECT COALESCE(NULLIF(JSON_UNQUOTE (JSON_EXTRACT(Requirement_Details_,CONCAT('$[',i,'].ItemId'))), 'null'), 0)  INTO ItemId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Requirement_Details_,CONCAT('$[',i,'].Item_Code'))) INTO ItemCode_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Requirement_Details_,CONCAT('$[',i,'].ItemName'))) INTO ItemName_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(PaymentTermValue_,CONCAT('$[',i,'].UnitId'))) INTO UnitId_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Requirement_Details_, CONCAT('$[', i, '].UnitId'))), 'null'), 0) INTO UnitId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Requirement_Details_,CONCAT('$[',i,'].UnitName'))) INTO UnitName_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Requirement_Details_, CONCAT('$[', i, '].GroupId'))), 'null'), 0) INTO GroupId_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Requirement_Details_, CONCAT('$[', i, '].GroupName'))), 'null'), '') INTO GroupName_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(PaymentTermValue_,CONCAT('$[',i,'].StockId'))) INTO StockId_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Requirement_Details_, CONCAT('$[', i, '].StockId'))), 'null'), 0) INTO StockId_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(PaymentTermValue_,CONCAT('$[',i,'].HSNMasterId'))) INTO HSNMasterId_;
		SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Requirement_Details_, CONCAT('$[', i, '].HSNMasterId'))), 'null'), 0) INTO HSNMasterId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Requirement_Details_,CONCAT('$[',i,'].HSNCODE'))) INTO HSNCODE_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(PaymentTermValue_,CONCAT('$[',i,'].UnitPrice'))) INTO UnitPrice_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Requirement_Details_, CONCAT('$[', i, '].UnitPrice'))), 'null'), 0) INTO UnitPrice_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Requirement_Details_,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;   
#SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(PaymentTermValue_, CONCAT('$[', i, '].Quantity'))), 'null'), 0) INTO Quantity_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(PaymentTermValue_,CONCAT('$[',i,'].Amount'))) INTO Amount_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Requirement_Details_, CONCAT('$[', i, '].Amount'))), 'null'), 0) INTO Amount_;

/*SELECT JSON_UNQUOTE (JSON_EXTRACT(PaymentTermValue_,CONCAT('$[',i,'].Discount'))) INTO Discount_;*/
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Requirement_Details_, CONCAT('$[', i, '].Discount'))), 'null'), 0) INTO Discount_;

#SELECT JSON_UNQUOTE (JSON_EXTRACT(PaymentTermValue_,CONCAT('$[',i,'].TaxableAmount'))) INTO TaxableAmount_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Requirement_Details_, CONCAT('$[', i, '].TaxableAmount'))), 'null'), 0) INTO TaxableAmount_;

#SELECT JSON_UNQUOTE (JSON_EXTRACT(PaymentTermValue_,CONCAT('$[',i,'].TaxAmount'))) INTO TaxAmount_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Requirement_Details_, CONCAT('$[', i, '].TaxAmount'))), 'null'), 0) INTO TaxAmount_;

#SELECT JSON_UNQUOTE (JSON_EXTRACT(PaymentTermValue_,CONCAT('$[',i,'].NetValue'))) INTO NetValue_;  
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Requirement_Details_, CONCAT('$[', i, '].NetValue'))), 'null'), 0) INTO NetValue_;

SELECT JSON_UNQUOTE (JSON_EXTRACT(Requirement_Details_,CONCAT('$[',i,'].Availability'))) INTO Availability_; 

#SELECT JSON_UNQUOTE (JSON_EXTRACT(PaymentTermValue_,CONCAT('$[',i,'].Unit_Discount'))) INTO Unit_Discount_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Requirement_Details_, CONCAT('$[', i, '].Unit_Discount'))), 'null'), 0) INTO Unit_Discount_;

#SELECT JSON_UNQUOTE (JSON_EXTRACT(PaymentTermValue_,CONCAT('$[',i,'].SaleTax'))) INTO Sale_Tax_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Requirement_Details_, CONCAT('$[', i, '].SaleTax'))), 'null'), 0) INTO Sale_Tax_;

#SELECT JSON_UNQUOTE (JSON_EXTRACT(PaymentTermValue_,CONCAT('$[',i,'].Item_Discount_Amount'))) INTO Item_Discount_Amount_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Requirement_Details_, CONCAT('$[', i, '].Item_Discount_Amount'))), 'null'), 0) INTO Item_Discount_Amount_;

#SELECT JSON_UNQUOTE (JSON_EXTRACT(PaymentTermValue_,CONCAT('$[',i,'].Country_Id'))) INTO Country_Id_;
SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Requirement_Details_, CONCAT('$[', i, '].Country_Id'))), 'null'), 0) INTO Country_Id_;

SELECT JSON_UNQUOTE (JSON_EXTRACT(Requirement_Details_,CONCAT('$[',i,'].Country_Name'))) INTO Country_Name_;

if Availability_ is null or Availability_ = 'null' then
   set Availability_ = '';
end if;

SET RequirementDetails_Id_ = (SELECT  COALESCE( MAX(RequirementDetails_Id ),0)+1 FROM requirementdetails);

INSERT INTO requirementdetails(RequirementDetails_Id,RequirementMaster_Id,ItemId,ItemCode,ItemName,
UnitId,UnitName,StockId,HSNMasterId,HSNCODE,UnitPrice,Quantity,Amount,Discount,TaxableAmount,TaxAmount,
NetValue,Availability,DeleteStatus,Unit_Discount,Sale_Tax,GroupId,GroupName,Item_Discount_Amount,
Country_Id, Country_Name)
VALUES(RequirementDetails_Id_,RequirementMaster_Id_,ItemId_,ItemCode_,ItemName_,UnitId_,UnitName_,StockId_,HSNMasterId_,
HSNCODE_,UnitPrice_,Quantity_,Amount_,Discount_,TaxableAmount_,TaxAmount_,NetValue_,Availability_,0,Unit_Discount_,Sale_Tax_,GroupId_,GroupName_,Item_Discount_Amount_,
Country_Id_, Country_Name_);
SELECT i + 1 INTO i;
END WHILE;  
SELECT RequirementMaster_Id_, RequirementNo_;

END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_requirementmaster`
BEGIN
declare YearFrom datetime;declare YearTo datetime;declare RequirementNo_ int;
if(RequirementMaster_Id_ > 0) then
set RequirementNo_ = (select RequirementNo from requirementmaster where RequirementMaster_Id = RequirementMaster_Id_ and DeleteStatus = 0);
UPDATE salesquotationmaster SET Account_Party_Id = Account_Party_Id_,EntryDate = EntryDate_,POnumber = POnumber_,CurrencyId = CurrencyId_,
PaymentTerms = PaymentTerms_,AttendEmployee = AttendEmployee_,TotalAmount = TotalAmount_,TotalDiscount = TotalDiscount_,Roundoff_Amt = Roundoff_Amt_,
Total_Amount = Total_Amount_,Basic_Discount=Basic_Discount_,NetTotal =NetTotal_,Brand = Brand_,PriceBasis = PriceBasis_,Delivery = Delivery_,
Validity = Validity_,Description1 = Description1_,User_Id = User_Id_,Delivery_Address1 = Delivery_Address1_,Delivery_Address2 = Delivery_Address2_,
Delivery_Address3 = Delivery_Address3_,Delivery_Address4 = Delivery_Address4_,Charge1 = Charge1_,charge1_Amount = charge1_Amount_,Charge2 = Charge2_,
charge2_Amount = charge2_Amount_,Discount_Description = Discount_Description_,Additional_Discount = Additional_Discount_,Description2 = Description2_,
Amount_In_Words = Amount_In_Words_,PreparedBy = PreparedBy_,Charge1per = Charge1per_,Payment_Term_Description = Payment_Term_Description_,
VAT_Percentage = VAT_Percentage_,VAT_Amount = VAT_Amount_, TaxableAmount = TaxableAmount_, KindAttend = KindAttend_, PaymentTermValue = PaymentTermValue_,
RequirementNo = RequirementNo_, Supplier_Ref_No= Supplier_Ref_No_
WHERE RequirementMaster_Id = RequirementMaster_Id_;
else
set YearFrom=(select Account_Years.YearFrom from Account_Years where Date_Format(EntryDate_,'%Y-%m-%d')
    between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));
set YearTo=(select Account_Years.YearTo from Account_Years where Date_Format(EntryDate_,'%Y-%m-%d')
    between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));     
if exists(select distinct RequirementNo from requirementmaster)then
set RequirementNo_=(SELECT COALESCE( MAX(RequirementNo ),0)+1 FROM requirementmaster where Date_Format(EntryDate,'%Y-%m-%d')
    between Date_Format(YearFrom,'%Y-%m-%d') and Date_Format(YearTo,'%Y-%m-%d'));
else
if exists(select RequirementNo from General_Settings)
then
set RequirementNo_=(select COALESCE(RequirementNo,0) from General_Settings);
else
set RequirementNo_=1;
end if;    
end if;
SET RequirementMaster_Id_ = (SELECT  COALESCE( MAX(RequirementMaster_Id ),0)+1 FROM requirementmaster);

INSERT INTO requirementmaster
(RequirementMaster_Id,Account_Party_Id,EntryDate,RequirementNo,POnumber,CurrencyId,PaymentTerms,AttendEmployee,TotalAmount,TotalDiscount,TaxableAmount,
Roundoff_Amt,Total_Amount,Basic_Discount,NetTotal,Brand,PriceBasis,Delivery,Validity,Description1,User_Id,DeleteStatus,Delivery_Address1,Delivery_Address2,
Delivery_Address3,Delivery_Address4,Charge1,charge1_Amount,Charge2,charge2_Amount,Discount_Description,Additional_Discount,Description2,Amount_In_Words,
PreparedBy,Charge1per,Payment_Term_Description,VAT_Percentage,VAT_Amount, KindAttend,PaymentTermValue,TypeId,Supplier_Ref_No)
VALUES
(RequirementMaster_Id_,Account_Party_Id_,EntryDate_,RequirementNo_,POnumber_,CurrencyId_,PaymentTerms_,AttendEmployee_,TotalAmount_,TotalDiscount_,
TaxableAmount_,Roundoff_Amt_,Total_Amount_,Basic_Discount_,NetTotal_,Brand_,PriceBasis_,Delivery_,Validity_,Description1_,User_Id_,0,Delivery_Address1_,
Delivery_Address2_,Delivery_Address3_,Delivery_Address4_,Charge1_,charge1_Amount_,Charge2_,charge2_Amount_,Discount_Description_,Additional_Discount_,
Description2_,Amount_In_Words_,PreparedBy_,Charge1per_,Payment_Term_Description_,VAT_Percentage_,VAT_Amount_, KindAttend_,PaymentTermValue_,1,
Supplier_Ref_No_);
end if;
CALL Save_Quotation_Details(PaymentTermValue_ ,RequirementMaster_Id_,RequirementNo_);
select RequirementMaster_Id_,RequirementNo_;
END
$$
DELIMITER ;

