CREATE PROCEDURE `Save_Sales_Details`
Begin 
    DECLARE Stock_Id_ INT;DECLARE ItemId_ decimal(18,0);DECLARE ItemName_ varchar(1000);DECLARE ItemCode_ VARCHAR(100);
    DECLARE GroupId_ decimal(18,0); DECLARE GroupName_ VARCHAR(100);DECLARE UnitId_ decimal(18,0);DECLARE UnitName_ VARCHAR(100);declare Unit_Discount_ decimal(18,3);
    DECLARE PurchaseRate_ decimal(18,3);DECLARE UnitPrice_ decimal(18,3);DECLARE MRP_ decimal(18,3);DECLARE HSNMasterId_ decimal(18,0);declare TaxableAmount_ decimal(18,3);
    DECLARE HSNCODE_ varchar(50);DECLARE SaleTax_ decimal(18,3);DECLARE CGST_ decimal(18,2);DECLARE SGST_ decimal(18,3);DECLARE IGST_ decimal(18,3);
    DECLARE Cesspers_ decimal(18,3);DECLARE Quantity_ decimal(18,3);DECLARE GrossValue_ decimal(18,3);DECLARE Discount_ decimal(18,3);declare Amount_ decimal(18,3);
    declare NetValue_ decimal(18,3);DECLARE CGSTAMT_ decimal(18,3);DECLARE SGSTAMT_ decimal(18,3);declare TaxAmount_ decimal(18,3);
    DECLARE IGSTAMT_ decimal(18,3);DECLARE CessAMT_ decimal(18,3);DECLARE TotalAmount_ decimal(18,3);DECLARE Description_ varchar(4500);
	DECLARE i int  DEFAULT 0;declare Item_Discount_Amount_ decimal(18,3);declare SaleRate_ decimal(18,3);declare Country_Id_ int;declare Country_Name_ varchar(100);
    DECLARE Sales_Details_Id_ int;
    delete from Sales_Details where Sales_Master_Id = Sales_Master_Id_;
    
	WHILE i < JSON_LENGTH(Sales_Details) DO
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].Stock_Id')) ),  'null' ), 0 ) INTO Stock_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].ItemId'))) INTO ItemId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].ItemName'))) INTO ItemName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].ItemCode'))) INTO ItemCode_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].GroupId'))) INTO GroupId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].UnitId')) ),  'null' ), 0 ) INTO UnitId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].UnitName'))) INTO UnitName_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].PurchaseRate')) ),  'null' ), 0 ) INTO PurchaseRate_;
        
        #SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Unit_Discount'))) INTO Unit_Discount_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].Unit_Discount')) ),  'null' ), 0 ) INTO Unit_Discount_;

        #SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].TaxableAmount'))) INTO TaxableAmount_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].TaxableAmount')) ),  'null' ), 0 ) INTO TaxableAmount_;

		#SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].UnitPrice'))) INTO UnitPrice_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].UnitPrice')) ),  'null' ), 0 ) INTO UnitPrice_;

        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].MRP')) ),  'null' ), 0 ) INTO MRP_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].HSNMasterId')) ),  'null' ), 0 ) INTO HSNMasterId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].HSNCODE'))) INTO HSNCODE_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].SaleTax')) ),  'null' ), 0 ) INTO SaleTax_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].Cesspers')) ),  'null' ), 0 ) INTO Cesspers_;
		#SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Quantity'))) INTO Quantity_; 
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].Quantity')) ),  'null' ), 0 ) INTO Quantity_;

        #SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Amount'))) INTO Amount_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].Amount')) ),  'null' ), 0 ) INTO Amount_;

		#SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Discount'))) INTO Discount_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].Discount')) ),  'null' ), 0 ) INTO Discount_;

        #SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].NetValue'))) INTO NetValue_;
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].NetValue')) ),  'null' ), 0 ) INTO NetValue_;

        #SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].TaxAmount'))) INTO TaxAmount_; 
		SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].TaxAmount')) ),  'null' ), 0 ) INTO TaxAmount_;

		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Description'))) INTO Description_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].Item_Discount_Amount')) ),  'null' ), 0 ) INTO Item_Discount_Amount_;

		#SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Item_Discount_Amount'))) INTO Item_Discount_Amount_;
        SELECT   IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Details, CONCAT('$[',i,'].Country_Id')) ),  'null' ), 0 ) INTO Country_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Country_Name'))) INTO Country_Name_;
        set Sales_Details_Id_ = (select COALESCE( MAX(Sales_Details_Id ),0)+1 from Sales_Details);
        
        DELETE FROM Db_Logs;
        INSERT INTO DB_LOGS VALUES(0,Stock_Id_,'Stock_Id_','');
        
		INSERT INTO Sales_Details(Sales_Details_Id,Sales_Master_Id ,Stock_Id ,ItemId ,ItemName ,ItemCode ,GroupId ,GroupName ,
		UnitId ,UnitName ,PurchaseRate ,UnitPrice ,MRP ,HSNMasterId ,HSNCODE ,SaleTax ,TaxableAmount,Item_Discount_Amount,
		Quantity ,Discount,NetValue,TaxAmount  ,Unit_Discount,Amount,DeleteStatus,Country_Id,Country_Name ) 
		values (Sales_Details_Id_,Sales_Master_Id_ ,Stock_Id_ ,ItemId_ ,ItemName_ ,ItemCode_ ,GroupId_ ,GroupName_ ,UnitId_ ,
		UnitName_ ,PurchaseRate_ ,UnitPrice_ ,MRP_ ,HSNMasterId_ ,HSNCODE_ ,SaleTax_ ,TaxableAmount_,Item_Discount_Amount_,
		Quantity_ ,Discount_ ,NetValue_,TaxAmount_ ,Unit_Discount_,Amount_,false,Country_Id_,Country_Name_);
		update Stock Set Quantity=Quantity-Quantity_ where Stock_Id=Stock_Id_ ;
		SELECT i + 1 INTO i;
	END WHILE;  
SELECT Sales_Master_Id_,Voucher_No_;
End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_Sales_Details_Mobile`
Begin 
    DECLARE Stock_Id_ decimal(18,0);DECLARE ItemId_ decimal(18,0);DECLARE ItemName_ varchar(1000);
	DECLARE Barcode_ VARCHAR(100);DECLARE GroupId_ decimal(18,0); DECLARE GroupName_ VARCHAR(100);
	DECLARE UnitId_ decimal(18,0);DECLARE UnitName_ VARCHAR(100);DECLARE PurchaseRate_ decimal(18,2);
	DECLARE SaleRate_ decimal(18,2);DECLARE MRP_ decimal(18,2);DECLARE HSNMasterId_ decimal(18,0);
    DECLARE HSNCODE_ varchar(50);DECLARE SaleTax_ decimal(18,2);DECLARE CGST_ decimal(18,2);
	DECLARE SGST_ decimal(18,2);DECLARE IGST_ decimal(18,2);DECLARE Cesspers_ decimal(18,2);
	DECLARE Quantity_ decimal(18,3);DECLARE GrossValue_ decimal(18,2);DECLARE Discount_ decimal(18,2);
	declare NetValue_ decimal(18,2);DECLARE CGSTAMT_ decimal(18,2);DECLARE SGSTAMT_ decimal(18,2);
    declare TaxAmount_ decimal(18,2);DECLARE IGSTAMT_ decimal(18,2);DECLARE CessAMT_ decimal(18,2);
    DECLARE TotalAmount_ decimal(18,2);DECLARE ACTUAL_ decimal(18,2); 
	DECLARE i int  DEFAULT 0;    
   #set BillType_ =(select BillType from Sales_Master where Sales_Master_Id=Sales_Master_Id_); 
    set Cesspers_ = (select IFNULL(Cess, 0 ) from General_Settings); 
       
	WHILE i < JSON_LENGTH(Sales_Details) DO
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Stock_Id'))) INTO Stock_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].ItemName'))) INTO ItemName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].GroupId'))) INTO GroupId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].SaleRate'))) INTO SaleRate_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;  

        /*SELECT ItemId,Barcode ,UnitId,UnitName,PurchaseRate,MRP,HSNMasterId,HSNCODE,SaleTax,CGST,SGST
        INTO ItemId_ ,Barcode_,UnitId_,UnitName_,PurchaseRate_,MRP_,HSNMasterId_,HSNCODE_,SaleTax_,CGST_,SGST_
        from Stock where Stock_Id = Stock_Id_ ; */
         
         SELECT ItemId,Barcode ,UnitId,UnitName,PurchaseRate,MRP,HSNMasterId,HSNCODE,SaleTax,CGST,SGST,IGST
        INTO ItemId_ ,Barcode_,UnitId_,UnitName_,PurchaseRate_,MRP_,HSNMasterId_,HSNCODE_,SaleTax_,CGST_,SGST_,IGST_
        from Stock where Stock_Id = Stock_Id_ ;         
       # set SGST_=(select SGST from Stock where Stock_Id = Stock_Id_);        
        set Discount_ = 0;
		set GrossValue_ = Quantity_ * SaleRate_;
        set ACTUAL_ = GrossValue_ - Discount_;        
        if(BillType_=2)THEN
			set NetValue_ = (ACTUAL_ * 100) / (100 + CGST_+SGST_);        
			set CGSTAMT_ = (NetValue_ * CGST_ / 100);
			set SGSTAMT_ = (NetValue_ * SGST_ / 100);
            set TaxAmount_ = CGSTAMT_ + SGSTAMT_;  
            set IGST_=0;
            set IGSTAMT_=0;
        else
			set NetValue_ = (ACTUAL_ * 100) / (100 + IGST_);   
        	set IGSTAMT_ = (NetValue_ * IGST_ / 100);
            set TaxAmount_ = IGSTAMT_;
            set CGST_=0; set SGST_=0;
            set SGSTAMT_=0;set CGSTAMT_=0;
		end if;
        if(SaleTax_>5) then
			set CessAMT_ = ACTUAL_ * Cesspers_ / 100;
            else
            set Cesspers_=0;set CessAMT_=0;            
         end if;
         set TotalAmount_ = ACTUAL_ + CessAMT_;            
		INSERT INTO Sales_Details(Sales_Master_Id ,Stock_Id ,ItemId ,ItemName ,Barcode ,GroupId ,GroupName ,
		UnitId ,UnitName ,PurchaseRate ,SaleRate ,MRP ,HSNMasterId ,HSNCODE ,SaleTax ,CGST ,SGST,IGST ,Cesspers ,
		Quantity ,GrossValue ,Discount,NetValue,CGSTAMT ,SGSTAMT,TaxAmount ,IGSTAMT ,CessAMT ,TotalAmount ,DeleteStatus ) 
		values (Sales_Master_Id_ ,Stock_Id_ ,ItemId_ ,ItemName_ ,Barcode_ ,GroupId_ ,GroupName_ ,UnitId_ ,
		UnitName_ ,PurchaseRate_ ,SaleRate_ ,MRP_ ,HSNMasterId_ ,HSNCODE_ ,SaleTax_ ,CGST_ ,CGST_,IGST_ ,Cesspers_ ,
		Quantity_ ,GrossValue_ ,Discount_ ,NetValue_,CGSTAMT_ ,SGSTAMT_ ,TaxAmount_,IGSTAMT_ ,CessAMT_ ,TotalAmount_ ,false);
		update Stock_Details Set Quantity=Quantity-Quantity_ where Stock_Id=Stock_Id_ and To_Employee_Id=Employee_Id_;
		SELECT i + 1 INTO i;
	END WHILE;  
SELECT Sales_Master_Id_,Voucher_No_;
End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_Sales_Master`
Begin
declare Voucher_No_ int;declare Accounts_Id_ decimal;declare YearFrom datetime;declare YearTo datetime;declare billtypes_ varchar(100);
Declare Performa_SalesMaster_Id_ int;Declare Quotation_Salesmaster_Id_ int;
DECLARE Delivery_SalesMaster_Id_ INT;

 if  Sales_Master_Id_>0
 THEN
 set Voucher_No_ = (select Invoice_No from Sales_Master where Sales_Master_Id =Sales_Master_Id_ and deletestatus = 0);
call Update_Stock_FromSales(Sales_Master_Id_);
  Delete From Sales_Details Where Sales_Master_Id = Sales_Master_Id_;
  delete from Accounts where Tran_Id = Sales_Master_Id_ and Tran_Type = 'SA';
UPDATE Sales_Master set Account_Party_Id = Account_Party_Id_ ,User_Id = User_Id_ ,EntryDate = EntryDate_,LPONo = LPONo_,DONo = DONo_,
PackingListNumber= PackingListNumber_,TotalDiscount = TotalDiscount_ ,NetTotal = NetTotal_ ,CurrencyId = CurrencyId_,TypeId=TypeId_,
PaymentTerms=PaymentTerms_,TaxableAmount=TaxableAmount_,Charge2=Charge2_,Total_Amount = Total_Amount_ ,Roundoff_Amt = Roundoff_Amt_ ,
charge1_Amount=charge1_Amount_,charge2_Amount=charge2_Amount_,SupplyDate=SupplyDate_,Basic_Discount=Basic_Discount_,TotalAmount=TotalAmount_,
Delivery_Address1=Delivery_Address1_,Delivery_Address2=Delivery_Address2_,Delivery_Address3=Delivery_Address3_,Delivery_Address4=Delivery_Address4_,
Discount_Description=Discount_Description_,Additional_Discount=Additional_Discount_,Description2=Description2_,Employee=Employee_,
Amount_In_Words=Amount_In_Words_,Charge1per=Charge1per_,Payment_Term_Description=Payment_Term_Description_,
    VAT_percentage=VAT_percentage_,VAT_Amount=VAT_Amount_,DueDate=DueDate_,KindAttend=KindAttend_,PaymentTermValue=PaymentTermValue_,Charge1=Charge1_,
   Invoice_No =Voucher_No_
    Where Sales_Master_Id = Sales_Master_Id_ ;
   
 ELSE
 set YearFrom=(select Account_Years.YearFrom from Account_Years where Date_Format(EntryDate_,'%Y-%m-%d')
    between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));
set YearTo=(select Account_Years.YearTo from Account_Years where Date_Format(EntryDate_,'%Y-%m-%d')
    between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));  
if exists(select distinct Invoice_No from Sales_Master)then
set Voucher_No_=(SELECT COALESCE( MAX(Invoice_No ),0)+1 FROM Sales_Master where Date_Format(EntryDate,'%Y-%m-%d')
    between Date_Format(YearFrom,'%Y-%m-%d') and Date_Format(YearTo,'%Y-%m-%d'));  
else
if exists(select Invoice_No from General_Settings)
then
set Voucher_No_=(select COALESCE(Invoice_No,0) from General_Settings);
else
set Voucher_No_=1;
end if;    
end if;
        SET Sales_Master_Id_ = (SELECT COALESCE(MAX(Sales_Master_Id), 0) + 1 FROM Sales_Master);
INSERT INTO Sales_Master(Sales_Master_Id,Account_Party_Id,User_Id,EntryDate,Invoice_No,LPONo,DONo,PackingListNumber,TotalAmount,TotalDiscount,NetTotal,
