DELIMITER $$
CREATE PROCEDURE `Save_Sales_Master_Mobile`
Begin
declare Accounts_Id_ decimal;declare YearFrom datetime;declare YearTo datetime;
declare TotalDiscount_ decimal(18,2);declare NetTotal_ decimal(18,2);declare TotalCGST_ decimal(18,2);declare ToalSGST_ decimal(18,2);
declare TotalIGST_ decimal(18,2);declare TotalGST_ decimal(18,2);declare Cess_ decimal(18,2);declare RoundOff_ decimal(18,2);
declare Total_Amount_ decimal(18,2);declare GrandTotal_ decimal(18,2);declare Voucher_No_ decimal(18,0);
declare Description1_ VARCHAR(4000);

DECLARE Stock_Id_ decimal(18,0);DECLARE ItemId_ decimal(18,0);DECLARE ItemName_ varchar(1000);
DECLARE Barcode_ VARCHAR(100);DECLARE GroupId_ decimal(18,0); DECLARE GroupName_ VARCHAR(100);
DECLARE UnitId_ decimal(18,0);DECLARE UnitName_ VARCHAR(100);DECLARE PurchaseRate_ decimal(18,2);
DECLARE SaleRate_ decimal(18,2);DECLARE MRP_ decimal(18,2);DECLARE HSNMasterId_ decimal(18,0);
DECLARE HSNCODE_ varchar(50);DECLARE SaleTax_ decimal(18,2);DECLARE CGST_ decimal(18,2);
DECLARE SGST_ decimal(18,2);DECLARE IGST_ decimal(18,2);DECLARE Cesspers_ decimal(18,2);
DECLARE Quantity_ decimal(18,3);DECLARE GrossValue_ decimal(18,2);DECLARE Discount_ decimal(18,2);
DECLARE NetValue_ decimal(18,2);DECLARE CGSTAMT_ decimal(18,2);DECLARE SGSTAMT_ decimal(18,2);
DECLARE TaxAmount_ decimal(18,2);DECLARE IGSTAMT_ decimal(18,2);DECLARE CessAMT_ decimal(18,2);
DECLARE TotalAmount_ decimal(18,2);DECLARE ACTUAL_ decimal(18,2); declare Place_Id_ int;

DECLARE i int  DEFAULT 0;
/*DECLARE exit handler for sqlexception
BEGIN
	GET DIAGNOSTICS CONDITION 1
	@p1 = RETURNED_SQLSTATE, @p2 = MESSAGE_TEXT;
	SELECT @p2 AS MESSAGE_TEXT, @p1 AS RETURNED_SQLSTATE;
	ROLLBACK;
END;
    DECLARE exit handler for sqlwarning
BEGIN
	GET DIAGNOSTICS CONDITION 1
	@p1 = RETURNED_SQLSTATE, @p2 = MESSAGE_TEXT;
	SELECT @p2 AS MESSAGE_TEXT, @p1 AS RETURNED_SQLSTATE;
	ROLLBACK;
END;
 START TRANSACTION;  */
    set Cesspers_ = (select IFNULL(Cess, 0 ) from General_Settings); 
    set TotalDiscount_ =0;set NetTotal_=0;set TotalCGST_ =0;set ToalSGST_ =0;set TotalIGST_ =0;set TotalGST_ =0;
    set Cess_ =0;set RoundOff_ =0;set Total_Amount_ =0;set GrandTotal_ =0;
    set IGST_ = 0;set IGSTAMT_ = 0;set Discount_ = 0;
    #Set Totals
	WHILE i < JSON_LENGTH(Sales_Details) DO
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Stock_Id'))) INTO Stock_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].ItemName'))) INTO ItemName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].GroupId'))) INTO GroupId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].SaleRate'))) INTO SaleRate_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Details,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;      
        
        SELECT ItemId,Barcode ,UnitId,UnitName,PurchaseRate,MRP,HSNMasterId,HSNCODE,SaleTax,CGST,SGST,IGST
        INTO ItemId_ ,Barcode_,UnitId_,UnitName_,PurchaseRate_,MRP_,HSNMasterId_,HSNCODE_,SaleTax_,CGST_,SGST_,IGST_
        from Stock where Stock_Id = Stock_Id_ ;  
        
        set SaleTax_=(select SaleTax from Stock where Stock_Id = Stock_Id_);  
		set GrossValue_ = Quantity_ * SaleRate_;
        set ACTUAL_ = GrossValue_ - Discount_;
		set NetValue_ = CAST((ACTUAL_ * 100 / 100 +(CGST_+SGST_))as decimal(18,2));
		set CGSTAMT_ =  CAST((NetValue_ * CGST_ / 100)as decimal(18,2));	
		set SGSTAMT_ = CAST((NetValue_ * SGST_ / 100)as decimal(18,2));	
		set TaxAmount_ = CGSTAMT_ + SGSTAMT_;	
        set NetTotal_ = NetTotal_+NetValue_;
        set TotalCGST_ = TotalCGST_+CGSTAMT_;
        set ToalSGST_ = ToalSGST_+SGSTAMT_;		   
        if(BillType_ = 2)THEN	
            if(SaleTax_>5) then
				set CessAMT_ = CAST((ACTUAL_ * Cesspers_ / 100)as decimal(18,2));
				set Cess_ = Cess_ + CessAMT_;
            else
				set Cesspers_ = 0; set CessAMT_ = 0; set Cess_ = 0;    
			end if;
        else
            set Cesspers_ = 0; set CessAMT_ = 0; set Cess_ = 0;
		end if;        
         set TotalGST_ = TotalGST_ + TaxAmount_;        
         set TotalAmount_ = ACTUAL_ + CessAMT_;            
		 set Total_Amount_ = Total_Amount_ + TotalAmount_;
		SELECT i + 1 INTO i;
	END WHILE;	
	set GrandTotal_ = Total_Amount_ + RoundOff_;
    
	set YearFrom = (select Account_Years.YearFrom from Account_Years where  
	Date_Format(Bill_Date_,'%Y-%m-%d') between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and 
	Date_Format(Account_Years.YearTo,'%Y-%m-%d'));
	set YearTo = (select Account_Years.YearTo from Account_Years where 
	Date_Format(Bill_Date_,'%Y-%m-%d') between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and 
	Date_Format(Account_Years.YearTo,'%Y-%m-%d'));    
    
if exists(select distinct Invoice_No from Sales_Master)
then
	set Voucher_No_ = (SELECT COALESCE( MAX(Invoice_No ),0) + 1 FROM Sales_Master
	where BillType = BillType_ and Date_Format(Bill_Date_,'%Y-%m-%d') between Date_Format(YearFrom,'%Y-%m-%d') 
    and Date_Format(YearTo,'%Y-%m-%d'));  
else 
	if exists(select Invoice_No from General_Settings)
	then
		set Voucher_No_ = (select COALESCE(Invoice_No,0) from General_Settings);
	else
		set Voucher_No_ = 1;
	end if;    
end if;

if exists(select Place_Id from Place where City_Name=City_) then
set Place_Id_=(select Place_Id from Place where City_Name=City_);
else
 set Place_Id_=(select COALESCE( MAX(Place_Id ),0)+1 from Place);
 insert into Place(Place_Id,City_Name,Postal_Code,State,Is_Delete)
 values(Place_Id_,City_,Postal_,State_,False);
end if;
     
  /*insert into Db_logs(Description,Description2,id)
  values(GrossTotal_,'',0);*/
#SalesMaster Save
 if Sales_Master_Id_ > 0
 THEN
	call Update_Stock_FromSales(Sales_Master_Id_);
	Delete From Sales_Details Where Sales_Master_Id=Sales_Master_Id_;
	delete from Accounts where Tran_Id=Sales_Master_Id_ and Tran_Type='SA'; 
    
    select Bill_Date,Invoice_No into Bill_Date_,Voucher_No_ from Sales_Master Where Sales_Master_Id = Sales_Master_Id_; 
    
	UPDATE Sales_Master set Account_Party_Id = Account_Party_Id_ ,Employee_Id = Employee_Id_ ,User_Id = User_Id_ ,    
	Bill_Date = Bill_Date_ ,Invoice_No = Voucher_No_ ,GrossTotal = GrossTotal_ ,TotalDiscount = TotalDiscount_ ,NetTotal = NetTotal_ ,
	TotalCGST = TotalCGST_ ,ToalSGST = ToalSGST_ ,TotalIGST = TotalIGST_ ,TotalGST = TotalGST_ , Cess = Cess_ ,RoundOff = RoundOff_ ,
    TotalAmount = Total_Amount_ ,GrandTotal = GrandTotal_,BillType = BillType_, Description1 = Description1_ 
	Where Sales_Master_Id=Sales_Master_Id_ ;
 ELSE
 #set Bill_Date_ = curdate();
	INSERT INTO Sales_Master(Account_Party_Id ,Employee_Id ,User_Id ,Bill_Date ,Invoice_No ,GrossTotal ,TotalDiscount ,
    NetTotal ,TotalCGST ,ToalSGST ,TotalIGST ,TotalGST ,Cess ,RoundOff ,TotalAmount , GrandTotal ,BillType ,Description1 ,Latitude,Longtitude,Place_Id,DeleteStatus ) 
	values (Account_Party_Id_ ,Employee_Id_ ,User_Id_ ,Bill_Date_ ,Voucher_No_ ,GrossTotal_ ,TotalDiscount_,NetTotal_,
    TotalCGST_ ,ToalSGST_ ,TotalIGST_ ,TotalGST_ ,Cess_ ,RoundOff_ ,Total_Amount_ ,GrandTotal_ ,BillType_ ,Description1_ ,Latitude_,Longtitude_,
Place_Id_,False );
End If;

  if Sales_Master_Id_ = 0 then
			set Sales_Master_Id_ = (SELECT LAST_INSERT_ID());
		end if;
        
CALL Save_Sales_Details_Mobile(Sales_Details ,Sales_Master_Id_ ,Employee_Id_,BillType_,Voucher_No_);  
#Accounts Save
if(GrandTotal_>0)
then
set Accounts_Id_ = (select COALESCE( MAX(Accounts_Id ),0)+1 from Accounts);
	 insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,
	 VoucherType,Description1,Status,DayBook,Payment_Status)
	 values(Accounts_Id_,Bill_Date_,5,0,GrandTotal_,Account_Party_Id_,'SA',Sales_Master_Id_, Voucher_No_,5,Description1_,'','Y',1); 
	 set Accounts_Id_ = (select COALESCE( MAX(Accounts_Id ),0)+1 from Accounts);
	 insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,
	 VoucherType,Description1,Status,DayBook,Payment_Status) 
	 values(Accounts_Id_,Bill_Date_,Account_Party_Id_,GrandTotal_,0,5,'SA',Sales_Master_Id_, Voucher_No_ ,5,Description1_,'','',1); 
	 end IF;
if(TotalCGST_>0)
then
	set Accounts_Id_ = (select COALESCE( MAX(Accounts_Id ),0) + 1 from Accounts);
	insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,
	VoucherType,Description1,Status,DayBook,Payment_Status)
	values(Accounts_Id_,Bill_Date_,25,0,TotalCGST_,5,'SA',Sales_Master_Id_, Voucher_No_,5,Description1_,'','Y',1); 
	set Accounts_Id_ = (select COALESCE( MAX(Accounts_Id ),0) + 1 from Accounts);
	insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,
	VoucherType,Description1,Status,DayBook,Payment_Status) 
	values(Accounts_Id_,Bill_Date_,5,TotalCGST_,0,25,'SA',Sales_Master_Id_, Voucher_No_ ,5,Description1_,'','',1); 
 end IF; 
  if(ToalSGST_>0)
 then
	 set Accounts_Id_=(select COALESCE( MAX(Accounts_Id ),0)+1 from Accounts);
	 insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,
	 VoucherType,Description1,Status,DayBook,Payment_Status)
	 values(Accounts_Id_,Bill_Date_,18,0,ToalSGST_,5,'SA',Sales_Master_Id_, Voucher_No_,5,Description1_,'','Y',1); 
	 set Accounts_Id_=(select COALESCE( MAX(Accounts_Id ),0)+1 from Accounts);
	 insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,
	 VoucherType,Description1,Status,DayBook,Payment_Status) 
	 values(Accounts_Id_,Bill_Date_,5,ToalSGST_,0,18,'SA',Sales_Master_Id_, Voucher_No_ ,5,Description1_,'','',1); 
 end IF; 
   if(TotalIGST_>0)
 then
	 set Accounts_Id_=(select COALESCE( MAX(Accounts_Id ),0)+1 from Accounts);
	 insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,
	 VoucherType,Description1,Status,DayBook,Payment_Status)
	 values(Accounts_Id_,Bill_Date_,29,0,TotalIGST_,5,'SA',Sales_Master_Id_, Voucher_No_,5,Description1_,'','Y',1); 
	 set Accounts_Id_=(select COALESCE( MAX(Accounts_Id ),0)+1 from Accounts);
	 insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,
	 VoucherType,Description1,Status,DayBook,Payment_Status) 
	 values(Accounts_Id_,Bill_Date_,5,TotalIGST_,0,29,'SA',Sales_Master_Id_, Voucher_No_ ,5,Description1_,'','',1); 
 end IF;
  if(Cess_>0)
 then
	set Accounts_Id_=(select COALESCE( MAX(Accounts_Id ),0)+1 from Accounts);
	insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,
	VoucherType,Description1,Status,DayBook,Payment_Status)
	values(Accounts_Id_,Bill_Date_,32,0,Cess_,5,'SA',Sales_Master_Id_, Voucher_No_,5,Description1_,'','Y',1); 
	set Accounts_Id_=(select COALESCE( MAX(Accounts_Id ),0)+1 from Accounts);
	insert into Accounts(Accounts_Id,Entry_Date,Client_Id,Dr,Cr,X_Client_Id,Tran_Type,Tran_Id,Voucher_No,
	VoucherType,Description1,Status,DayBook,Payment_Status) 
	values(Accounts_Id_,Bill_Date_,5,Cess_,0,32,'SA',Sales_Master_Id_, Voucher_No_ ,5,Description1_,'','',1); 
 end IF;
select Sales_Master_Id_,Voucher_No_;
#COMMIT;
End
$$
