DELIMITER $$
CREATE PROCEDURE `Save_Sales_Order_Details`
BEGIN

    DECLARE Stock_Id_ INT;
    DECLARE ItemId_ DECIMAL(18,0);
    DECLARE ItemName_ VARCHAR(1000);
    DECLARE ItemCode_ VARCHAR(100);
    DECLARE GroupId_ DECIMAL(18,0);
    DECLARE GroupName_ VARCHAR(100);
    DECLARE UnitId_ DECIMAL(18,0);
    DECLARE UnitName_ VARCHAR(100);
    DECLARE Unit_Discount_ DECIMAL(18,3);
    DECLARE PurchaseRate_ DECIMAL(18,3);
    DECLARE UnitPrice_ DECIMAL(18,3);
    DECLARE MRP_ DECIMAL(18,3);
    DECLARE HSNMasterId_ DECIMAL(18,0);
    DECLARE TaxableAmount_ DECIMAL(18,3);
    DECLARE HSNCODE_ VARCHAR(50);
    DECLARE SaleTax_ DECIMAL(18,3);
    DECLARE Cesspers_ DECIMAL(18,3);
    DECLARE Quantity_ DECIMAL(18,3);
    DECLARE Discount_ DECIMAL(18,3);
    DECLARE Amount_ DECIMAL(18,3);
    DECLARE NetValue_ DECIMAL(18,3);
    DECLARE TaxAmount_ DECIMAL(18,3);
    DECLARE Description_ VARCHAR(4500);
    DECLARE Item_Discount_Amount_ DECIMAL(18,3);
    DECLARE Country_Id_ INT;
    DECLARE Country_Name_ VARCHAR(100);
    DECLARE Sales_Order_Details_Id_ INT;
    DECLARE i INT DEFAULT 0;

    -- Delete old order details
    DELETE FROM sales_order_details 
    WHERE Sales_Order_Master_Id = Sales_Order_Master_Id_;

    WHILE i < JSON_LENGTH(Sales_Order_Details) DO

        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].Stock_Id'))),'null'),0) INTO Stock_Id_;
        SELECT JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details,CONCAT('$[',i,'].ItemId'))) INTO ItemId_;
        SELECT JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details,CONCAT('$[',i,'].ItemName'))) INTO ItemName_;
        SELECT JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details,CONCAT('$[',i,'].ItemCode'))) INTO ItemCode_;
        SELECT JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details,CONCAT('$[',i,'].GroupId'))) INTO GroupId_;
        SELECT JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].UnitId'))),'null'),0) INTO UnitId_;
        SELECT JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details,CONCAT('$[',i,'].UnitName'))) INTO UnitName_;
        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].PurchaseRate'))),'null'),0) INTO PurchaseRate_;
        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].Unit_Discount'))),'null'),0) INTO Unit_Discount_;
        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].TaxableAmount'))),'null'),0) INTO TaxableAmount_;
        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].UnitPrice'))),'null'),0) INTO UnitPrice_;
        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].MRP'))),'null'),0) INTO MRP_;
        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].HSNMasterId'))),'null'),0) INTO HSNMasterId_;
        SELECT JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details,CONCAT('$[',i,'].HSNCODE'))) INTO HSNCODE_;
        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].SaleTax'))),'null'),0) INTO SaleTax_;
        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].Quantity'))),'null'),0) INTO Quantity_;
        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].Amount'))),'null'),0) INTO Amount_;
        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].Discount'))),'null'),0) INTO Discount_;
        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].NetValue'))),'null'),0) INTO NetValue_;
        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].TaxAmount'))),'null'),0) INTO TaxAmount_;
        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].Item_Discount_Amount'))),'null'),0) INTO Item_Discount_Amount_;
        SELECT IFNULL(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].Country_Id'))),'null'),0) INTO Country_Id_;
        SELECT JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details,CONCAT('$[',i,'].Country_Name'))) INTO Country_Name_;

        -- Generate new Order Details Id
        SET Sales_Order_Details_Id_ =
            (SELECT COALESCE(MAX(Sales_Order_Details_Id),0) + 1 FROM sales_order_details);

        -- Insert into sales_order_details
        INSERT INTO sales_order_details(
            Sales_Order_Details_Id,
            Sales_Order_Master_Id,
            Stock_Id,
            ItemId,
            ItemName,
            ItemCode,
            GroupId,
            GroupName,
            UnitId,
            UnitName,
            PurchaseRate,
            UnitPrice,
            MRP,
            HSNMasterId,
            HSNCODE,
            SaleTax,
            TaxableAmount,
            Item_Discount_Amount,
            Quantity,
            Discount,
            NetValue,
            TaxAmount,
            Unit_Discount,
            Amount,
            DeleteStatus,
            Country_Id,
            Country_Name
        )
        VALUES (
            Sales_Order_Details_Id_,
            Sales_Order_Master_Id_,
            Stock_Id_,
            ItemId_,
            ItemName_,
            ItemCode_,
            GroupId_,
            GroupName_,
            UnitId_,
            UnitName_,
            PurchaseRate_,
            UnitPrice_,
            MRP_,
            HSNMasterId_,
            HSNCODE_,
            SaleTax_,
            TaxableAmount_,
            Item_Discount_Amount_,
            Quantity_,
            Discount_,
            NetValue_,
            TaxAmount_,
            Unit_Discount_,
            Amount_,
            FALSE,
            Country_Id_,
            Country_Name_
        );

        -- Update stock
        UPDATE Stock 
        SET Quantity = Quantity - Quantity_
        WHERE Stock_Id = Stock_Id_;

        SET i = i + 1;

    END WHILE;

    SELECT Sales_Order_Master_Id_, Voucher_No_;

END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_Sales_Order_Master`
BEGIN

DECLARE Voucher_No_ INT;
DECLARE YearFrom DATETIME;
DECLARE YearTo DATETIME;
DECLARE Quotation_SalesOrderMaster_Id_ INT;
DECLARE Performa_SalesOrderMaster_Id_ INT;
DECLARE Delivery_SalesOrderMaster_Id_ INT;

IF Sales_Order_Master_Id_ > 0 THEN

    SET Voucher_No_ =
        (SELECT Invoice_No
         FROM Sales_Order_Master
         WHERE Sales_Order_Master_Id = Sales_Order_Master_Id_
         AND DeleteStatus = 0);

    CALL Update_Stock_FromSalesOrder(Sales_Order_Master_Id_);

    DELETE FROM Sales_Order_Details
    WHERE Sales_Order_Master_Id = Sales_Order_Master_Id_;

    DELETE FROM Accounts
    WHERE Tran_Id = Sales_Order_Master_Id_
    AND Tran_Type = 'SO';

    UPDATE Sales_Order_Master
    SET Account_Party_Id = Account_Party_Id_,
        User_Id = User_Id_,
        EntryDate = EntryDate_,
        LPONo = LPONo_,
        DONo = DONo_,
        PackingListNumber = PackingListNumber_,
        TotalDiscount = TotalDiscount_,
        NetTotal = NetTotal_,
        CurrencyId = CurrencyId_,
        TypeId = TypeId_,
        PaymentTerms = PaymentTerms_,
        TaxableAmount = TaxableAmount_,
        Charge2 = Charge2_,
        Total_Amount = Total_Amount_,
        Roundoff_Amt = Roundoff_Amt_,
        charge1_Amount = charge1_Amount_,
        charge2_Amount = charge2_Amount_,
        SupplyDate = SupplyDate_,
        Basic_Discount = Basic_Discount_,
        TotalAmount = TotalAmount_,
        Delivery_Address1 = Delivery_Address1_,
        Delivery_Address2 = Delivery_Address2_,
        Delivery_Address3 = Delivery_Address3_,
        Delivery_Address4 = Delivery_Address4_,
        Discount_Description = Discount_Description_,
        Additional_Discount = Additional_Discount_,
        Description2 = Description2_,
        Employee = Employee_,
        Amount_In_Words = Amount_In_Words_,
        Charge1per = Charge1per_,
        Payment_Term_Description = Payment_Term_Description_,
        VAT_percentage = VAT_percentage_,
        VAT_Amount = VAT_Amount_,
        DueDate = DueDate_,
        KindAttend = KindAttend_,
        PaymentTermValue = PaymentTermValue_,
        Charge1 = Charge1_,
        Invoice_No = Voucher_No_
    WHERE Sales_Order_Master_Id = Sales_Order_Master_Id_;

ELSE

    SET YearFrom = (
        SELECT YearFrom
        FROM Account_Years
        WHERE DATE(EntryDate_) BETWEEN DATE(YearFrom) AND DATE(YearTo)
    );

    SET YearTo = (
        SELECT YearTo
        FROM Account_Years
        WHERE DATE(EntryDate_) BETWEEN DATE(YearFrom) AND DATE(YearTo)
    );

    IF EXISTS (SELECT 1 FROM Sales_Order_Master) THEN
        SET Voucher_No_ =
        (SELECT COALESCE(MAX(Invoice_No),0)+1
         FROM Sales_Order_Master
         WHERE DATE(EntryDate) BETWEEN DATE(YearFrom) AND DATE(YearTo));
    ELSE
        SET Voucher_No_ = 1;
    END IF;

    SET Sales_Order_Master_Id_ =
        (SELECT COALESCE(MAX(Sales_Order_Master_Id),0)+1
         FROM Sales_Order_Master);

    INSERT INTO Sales_Order_Master(
        Sales_Order_Master_Id,
        Account_Party_Id,
        User_Id,
        EntryDate,
        Invoice_No,
        LPONo,
        DONo,
        PackingListNumber,
        TotalAmount,
        TotalDiscount,
        NetTotal,
        CurrencyId,
        TypeId,
        PaymentTerms,
        TaxableAmount,
        Charge2,
        Total_Amount,
        Roundoff_Amt,
        charge1_Amount,
        charge2_Amount,
        SupplyDate,
        Basic_Discount,
        Delivery_Address1,
        Delivery_Address2,
        Delivery_Address3,
        Delivery_Address4,
        Discount_Description,
        Additional_Discount,
        Description2,
        Employee,
        Amount_In_Words,
        Charge1per,
        Payment_Term_Description,
        VAT_percentage,
        VAT_Amount,
        DueDate,
        KindAttend,
        PaymentTermValue,
        Charge1,
        DeleteStatus
    )
    VALUES(
        Sales_Order_Master_Id_,
        Account_Party_Id_,
        User_Id_,
        EntryDate_,
        Voucher_No_,
        LPONo_,
        DONo_,
        PackingListNumber_,
        TotalAmount_,
        TotalDiscount_,
        NetTotal_,
        CurrencyId_,
        TypeId_,
        PaymentTerms_,
        TaxableAmount_,
        Charge2_,
        Total_Amount_,
        Roundoff_Amt_,
        charge1_Amount_,
        charge2_Amount_,
        SupplyDate_,
        Basic_Discount_,
        Delivery_Address1_,
        Delivery_Address2_,
        Delivery_Address3_,
        Delivery_Address4_,
        Discount_Description_,
        Additional_Discount_,
        Description2_,
        Employee_,
        Amount_In_Words_,
        Charge1per_,
        Payment_Term_Description_,
        VAT_percentage_,
        VAT_Amount_,
        DueDate_,
        KindAttend_,
        PaymentTermValue_,
        Charge1_,
        FALSE
    );

END IF;

/* ACCOUNTS ENTRY */

IF NetTotal_ > 0 THEN

    INSERT INTO Accounts
    VALUES (0,EntryDate_,5,0,NetTotal_,Account_Party_Id_,'SO',
            Sales_Order_Master_Id_,Voucher_No_,5,'','','',1);

    INSERT INTO Accounts
    VALUES (0,EntryDate_,Account_Party_Id_,NetTotal_,0,5,'SO',
            Sales_Order_Master_Id_,Voucher_No_,5,'','','Y',1);

END IF;

IF VAT_Amount_ > 0 THEN

    INSERT INTO Accounts
    VALUES (0,EntryDate_,18,0,VAT_Amount_,5,'SO',
            Sales_Order_Master_Id_,Voucher_No_,5,'','','',1);

    INSERT INTO Accounts
    VALUES (0,EntryDate_,5,VAT_Amount_,0,18,'SO',
            Sales_Order_Master_Id_,Voucher_No_,5,'','','Y',1);

END IF;

CALL Save_Sales_Order_Details(
    Sales_Order_Details_,
    Sales_Order_Master_Id_,
    Voucher_No_
);

SELECT Sales_Order_Master_Id_, Voucher_No_;

END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_Sales_Order_Master_Mobile`
BEGIN

    DECLARE Voucher_No_ DECIMAL(18,0);
    DECLARE NetTotal_ DECIMAL(18,2) DEFAULT 0;
    DECLARE TotalCGST_ DECIMAL(18,2) DEFAULT 0;
    DECLARE TotalSGST_ DECIMAL(18,2) DEFAULT 0;
    DECLARE TotalGST_ DECIMAL(18,2) DEFAULT 0;
    DECLARE Total_Amount_ DECIMAL(18,2) DEFAULT 0;
    DECLARE GrandTotal_ DECIMAL(18,2) DEFAULT 0;
    DECLARE Place_Id_ INT;
    DECLARE i INT DEFAULT 0;

    DECLARE Stock_Id_ DECIMAL(18,0);
    DECLARE SaleRate_ DECIMAL(18,2);
    DECLARE Quantity_ DECIMAL(18,3);
    DECLARE CGST_ DECIMAL(18,2);
    DECLARE SGST_ DECIMAL(18,2);
    DECLARE NetValue_ DECIMAL(18,2);
    DECLARE CGSTAMT_ DECIMAL(18,2);
    DECLARE SGSTAMT_ DECIMAL(18,2);

    /* ===============================
       CALCULATE TOTALS
    =============================== */

    WHILE i < JSON_LENGTH(Sales_Order_Details) DO

        SELECT JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].Stock_Id')))
        INTO Stock_Id_;

        SELECT JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].SaleRate')))
        INTO SaleRate_;

        SELECT JSON_UNQUOTE(JSON_EXTRACT(Sales_Order_Details, CONCAT('$[',i,'].Quantity')))
        INTO Quantity_;

        SELECT IFNULL(CGST,0), IFNULL(SGST,0)
        INTO CGST_, SGST_
        FROM Stock
        WHERE Stock_Id = Stock_Id_;

        SET NetValue_ = Quantity_ * SaleRate_;
        SET CGSTAMT_ = (NetValue_ * CGST_) / 100;
        SET SGSTAMT_ = (NetValue_ * SGST_) / 100;

        SET NetTotal_ = NetTotal_ + NetValue_;
        SET TotalCGST_ = TotalCGST_ + CGSTAMT_;
        SET TotalSGST_ = TotalSGST_ + SGSTAMT_;
        SET TotalGST_ = TotalCGST_ + TotalSGST_;
        SET Total_Amount_ = Total_Amount_ + NetValue_;

        SET i = i + 1;

    END WHILE;

    SET GrandTotal_ = Total_Amount_ + RoundOff_;

    /* ===============================
       GENERATE VOUCHER NUMBER
    =============================== */

    IF EXISTS (SELECT 1 FROM Sales_Order_Master) THEN
        SELECT COALESCE(MAX(Invoice_No),0) + 1
        INTO Voucher_No_
        FROM Sales_Order_Master
        WHERE BillType = BillType_;
    ELSE
        SET Voucher_No_ = 1;
    END IF;

    /* ===============================
       SAVE PLACE
    =============================== */

    IF EXISTS (SELECT 1 FROM Place WHERE City_Name = City_) THEN
        SELECT Place_Id INTO Place_Id_
        FROM Place
        WHERE City_Name = City_;
    ELSE
        SELECT COALESCE(MAX(Place_Id),0) + 1
        INTO Place_Id_
        FROM Place;

        INSERT INTO Place(Place_Id, City_Name, Postal_Code, State, Is_Delete)
        VALUES(Place_Id_, City_, Postal_, State_, FALSE);
    END IF;

    /* ===============================
       MASTER SAVE
    =============================== */

    IF Sales_Order_Master_Id_ > 0 THEN

        DELETE FROM Sales_Order_Details
        WHERE Sales_Order_Master_Id = Sales_Order_Master_Id_;

        UPDATE Sales_Order_Master
        SET Account_Party_Id = Account_Party_Id_,
            Employee_Id = Employee_Id_,
            User_Id = User_Id_,
            Bill_Date = Bill_Date_,
            Invoice_No = Voucher_No_,
            GrossTotal = GrossTotal_,
            NetTotal = NetTotal_,
            TotalCGST = TotalCGST_,
            ToalSGST = TotalSGST_,
            TotalGST = TotalGST_,
            RoundOff = RoundOff_,
            TotalAmount = Total_Amount_,
            GrandTotal = GrandTotal_,
            BillType = BillType_,
            Latitude = Latitude_,
            Longtitude = Longtitude_,
            Place_Id = Place_Id_
        WHERE Sales_Order_Master_Id = Sales_Order_Master_Id_;

    ELSE

        INSERT INTO Sales_Order_Master(
            Account_Party_Id,
            Employee_Id,
            User_Id,
            Bill_Date,
            Invoice_No,
            GrossTotal,
            NetTotal,
            TotalCGST,
            ToalSGST,
            TotalGST,
            RoundOff,
            TotalAmount,
            GrandTotal,
            BillType,
            Latitude,
            Longtitude,
            Place_Id,
            DeleteStatus
        )
        VALUES(
            Account_Party_Id_,
            Employee_Id_,
            User_Id_,
            Bill_Date_,
            Voucher_No_,
            GrossTotal_,
            NetTotal_,
            TotalCGST_,
            TotalSGST_,
            TotalGST_,
            RoundOff_,
            Total_Amount_,
            GrandTotal_,
            BillType_,
            Latitude_,
            Longtitude_,
            Place_Id_,
            FALSE
        );

        SET Sales_Order_Master_Id_ = LAST_INSERT_ID();

    END IF;

    /* ===============================
       SAVE DETAILS
    =============================== */

    CALL Save_Sales_Order_Details_Mobile(
        Sales_Order_Details,
        Sales_Order_Master_Id_,
        Employee_Id_,
        BillType_,
        Voucher_No_
    );

    SELECT Sales_Order_Master_Id_ AS Sales_Order_Master_Id,
           Voucher_No_ AS Voucher_No;

END
$$
DELIMITER ;

DELIMITER $$
