DELIMITER $$
CREATE PROCEDURE `Save_Sales_Returns_Details`
Begin
    DECLARE Stock_Id_ decimal(18,0);DECLARE ItemId_ decimal(18,0);DECLARE ItemName_ varchar(1000);DECLARE ItemCode_ VARCHAR(100);
    DECLARE GroupId_ decimal(18,0); DECLARE GroupName_ VARCHAR(100);DECLARE UnitId_ decimal(18,0);DECLARE UnitName_ VARCHAR(100);
    declare Unit_Discount_ decimal(18,3);
    DECLARE PurchaseRate_ decimal(18,3);DECLARE UnitPrice_ decimal(18,3);DECLARE MRP_ decimal(18,3);DECLARE HSNMasterId_ decimal(18,0);
    declare TaxableAmount_ decimal(18,3);
    DECLARE HSNCODE_ varchar(50);DECLARE SaleTax_ decimal(18,3);DECLARE CGST_ decimal(18,3);DECLARE SGST_ decimal(18,3);DECLARE IGST_ decimal(18,3);
    DECLARE Cesspers_ decimal(18,3);DECLARE Quantity_ decimal(18,3);DECLARE GrossValue_ decimal(18,3);DECLARE Discount_ decimal(18,3);
    declare Amount_ decimal(18,3);
    declare NetValue_ decimal(18,3);DECLARE CGSTAMT_ decimal(18,3);DECLARE SGSTAMT_ decimal(18,3);declare TaxAmount_ decimal(18,3);
    DECLARE IGSTAMT_ decimal(18,3);DECLARE CessAMT_ decimal(18,3);DECLARE TotalAmount_ decimal(18,3);DECLARE Description_ varchar(4500);
DECLARE i int  DEFAULT 0;        declare Country_Id_ int;declare Country_Name_ varchar(45);
    declare Item_Discount_Amount_ decimal;
declare Sales_Return_Details_Id_ int;
   
    delete from sales_return_details where Sales_Return_Master_Id = Sales_Return_Master_Id_;
   
WHILE i < JSON_LENGTH(Sales_Return_Details_) DO
SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].StockId'))) INTO Stock_Id_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].ItemId'))) INTO ItemId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].ItemName'))) INTO ItemName_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].ItemCode'))) INTO ItemCode_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].GroupId'))) INTO GroupId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].UnitId'))) INTO UnitId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].UnitName'))) INTO UnitName_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].PurchaseRate'))) INTO PurchaseRate_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].Unit_Discount'))) INTO Unit_Discount_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].TaxableAmount'))) INTO TaxableAmount_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].UnitPrice'))) INTO UnitPrice_;
        SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Return_Details_, CONCAT('$[', i, '].MRP'))), 'null'), 0) INTO MRP_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].HSNMasterId'))) INTO HSNMasterId_;
        SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Return_Details_, CONCAT('$[', i, '].HSNMasterId'))), 'null'), 0) INTO HSNMasterId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].HSNCODE'))) INTO HSNCODE_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].Sale_Tax'))) INTO SaleTax_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;  
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].Amount'))) INTO Amount_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].Discount'))) INTO Discount_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].NetValue'))) INTO NetValue_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].TaxAmount'))) INTO TaxAmount_;
        SELECT COALESCE(NULLIF(JSON_UNQUOTE(JSON_EXTRACT(Sales_Return_Details_, CONCAT('$[', i, '].TotalAmount'))), 'null'), 0) INTO TotalAmount_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].Description'))) INTO Description_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].Country_Id'))) INTO Country_Id_;    
#SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].Country_Name'))) INTO Country_Name_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Sales_Return_Details_,CONCAT('$[',i,'].Item_Discount_Amount'))) INTO Item_Discount_Amount_;

set Sales_Return_Details_Id_ = (select COALESCE( MAX(Sales_Return_Details_Id ),0)+1 from sales_return_details);
INSERT INTO sales_return_details(Sales_Return_Details_Id,Sales_Return_Master_Id ,Stock_Id ,ItemId ,ItemName ,ItemCode ,GroupId ,GroupName ,
UnitId ,UnitName ,PurchaseRate ,UnitPrice ,MRP ,HSNMasterId ,HSNCODE ,SaleTax ,TaxableAmount,Quantity ,Discount,NetValue,
        TaxAmount ,TotalAmount , Description,Unit_Discount,Amount,DeleteStatus,Country_Id, Country_Name,Item_Discount_Amount )
values (Sales_Return_Details_Id_,Sales_Return_Master_Id_ ,Stock_Id_ ,ItemId_ ,ItemName_ ,ItemCode_ ,GroupId_ ,GroupName_ ,UnitId_ ,
UnitName_ ,PurchaseRate_ ,UnitPrice_ ,MRP_ ,HSNMasterId_ ,HSNCODE_ ,SaleTax_ ,TaxableAmount_,
Quantity_ ,Discount_ ,NetValue_, TaxAmount_,TotalAmount_ ,
        Description_,Unit_Discount_,Amount_,false,Country_Id_,Country_Name_,Item_Discount_Amount_);
update Stock Set Quantity=Quantity+Quantity_ where Stock_Id=Stock_Id_ ;
SELECT i + 1 INTO i;
END WHILE;  
SELECT Sales_Return_Master_Id_,Voucher_No_;
End
$$
DELIMITER ;

