CREATE PROCEDURE `Save_Sales_Returns_Master`
Begin

declare Invoice_No_ varchar(50);
declare Voucher_No_ int;declare Accounts_Id_ decimal;declare YearFrom datetime;declare YearTo datetime;declare billtypes_ varchar(100);

 if  Sales_Return_Master_Id_>0
 THEN
call Update_Stock_FromSales_Return(Sales_Return_Master_Id_);

  Delete From sales_return_details Where Sales_Return_Master_Id = Sales_Return_Master_Id_ ;
  delete from Accounts where Tran_Id = Sales_Return_Master_Id_ and Tran_Type = 'SR';
