Delivery_Address1=Delivery_Address1_,Delivery_Address2=Delivery_Address2_,Delivery_Address3=Delivery_Address3_,
    Delivery_Address4=Delivery_Address4_,Discount_Description=Discount_Description_,
    Additional_Discount=Additional_Discount_,Description2=Description2_,Employee=Employee_,Amount_In_Words=Amount_In_Words_,
    Charge1per=Charge1per_,Payment_Term_Description=Payment_Term_Description_,
    VAT_percentage=VAT_percentage_,VAT_Amount=VAT_Amount_,kindAttend=KindAttend_,
    AttendEmployee=AttendEmployee_,    PaymentTermValue=PaymentTermValue_,
    Charge1=Charge1_,Sales_Master_Id=SalesMaster_Id_,Sales_Return_InvNo=Sales_return_InvNo_,
    Basic_Discount=Basic_Discount_
    Where Sales_Return_Master_Id = Sales_Return_Master_Id_ ;
   
 ELSE
  SET Sales_Return_Master_Id_ = (SELECT COALESCE(MAX(CAST(Sales_Return_Master_Id AS UNSIGNED)), 0) + 1 FROM sales_return_master );
set YearFrom=(select Account_Years.YearFrom from Account_Years where Date_Format(EntryDate_,'%Y-%m-%d')
