    between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and Date_Format(Account_Years.YearTo,'%Y-%m-%d'));  
    
if exists(select distinct Invoice_No from sales_return_master)then
set Voucher_No_=(SELECT COALESCE( MAX(Invoice_No ),0)+1 FROM sales_return_master where Date_Format(EntryDate,'%Y-%m-%d')
    between Date_Format(YearFrom,'%Y-%m-%d') and Date_Format(YearTo,'%Y-%m-%d'));  
    
    insert into db_logs values (0,Voucher_No_,'voucher_no','');
else
if exists(select SalesRtnNo from General_Settings)
then
set Voucher_No_=(select COALESCE(SalesRtnNo,0) from General_Settings);
else
set Voucher_No_=1;
end if;    
end if;
