    Charge1per,Payment_Term_Description,  VAT_percentage,VAT_Amount,KindAttend,
    AttendEmployee,  
    Charge1,DeleteStatus,Sales_Master_Id,Sales_Return_InvNo, PaymentTermValue,  Basic_Discount)
values (Sales_Return_Master_Id_,Account_Party_Id_,User_Id_,EntryDate_,
Voucher_No_,LPONo_,DONo_,PackingListNumber_,TotalDiscount_,NetTotal_,CurrencyId_,TypeId_, TotalAmount_,
    PaymentTerms_,TaxableAmount_,Charge2_,
    #Total_Amount_,
    Roundoff_Amt_,charge1_Amount_,charge2_Amount_,
    Delivery_Address1_,Delivery_Address2_,Delivery_Address3_,Delivery_Address4_,Discount_Description_,Additional_Discount_,Description2_,Employee_,Amount_In_Words_,
    Charge1per_,Payment_Term_Description_,VAT_percentage_,VAT_Amount_,KindAttend_,
    AttendEmployee_,
    Charge1_,False,SalesMaster_Id_, Sales_return_InvNo_,PaymentTermValue_,Basic_Discount_);
End If ;
  if Sales_Return_Master_Id_ = 0 then
set Sales_Return_Master_Id_ = (SELECT LAST_INSERT_ID());
  end if;
