 values(Accounts_Id_,EntryDate_,7,NetTotal_,0,Account_Party_Id_,'SR',Sales_Return_Master_Id_, Voucher_No_ ,5,'','','Y',1);
 end IF;
  if(VAT_Amount_>0)
