CREATE PROCEDURE `Save_Service_Details`
Begin 
Declare Service_Type_Id_ decimal(18,0); Declare Service_Type_Name_ varchar(50); declare Quantity_ decimal(18,2);
Declare Hsn_Id_ decimal(18,0); Declare Hsn_Name_ varchar(100);declare Unit_Price_ decimal(18,2);
Declare GrossValue_ decimal(18,2);Declare NetValue_ decimal(18,2);Declare GST_ decimal(18,2);
Declare GST_Amount_ decimal(18,2); Declare CGST_ decimal(18,2); Declare CGST_AMT_ decimal(18,2); 
Declare SGST_ decimal(18,2);Declare SGST_AMT_ decimal(18,2); Declare IGST_ decimal(18,2);Declare Discount_ decimal(18,2);
 Declare IGST_AMT_ decimal(18,2); Declare TotalAmount_ decimal(18,2); Declare Cesspers_  decimal(18,2); 
 Declare CessAmt_  decimal(18,2);Declare isnull_ varchar(500); Declare Description_ varchar(4000);
 DECLARE i int  DEFAULT 0;
 
	WHILE i < JSON_LENGTH(Service_Details) DO
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].Service_Type_Id'))) INTO Service_Type_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].Service_Type_Name'))) INTO Service_Type_Name_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].Hsn_Id'))) INTO Hsn_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].Hsn_Name'))) INTO Hsn_Name_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].Unit_Price'))) INTO Unit_Price_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].GrossValue'))) INTO GrossValue_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].Discount'))) INTO Discount_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].NetValue'))) INTO NetValue_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].GST'))) INTO GST_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].GST_Amount'))) INTO GST_Amount_;  
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].CGST'))) INTO CGST_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].CGST_AMT'))) INTO CGST_AMT_;
         SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].SGST'))) INTO SGST_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].SGST_AMT'))) INTO SGST_AMT_;        
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].IGST'))) INTO IGST_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].IGST_AMT'))) INTO IGST_AMT_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].TotalAmount'))) INTO TotalAmount_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].Cesspers'))) INTO Cesspers_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].CessAmt'))) INTO CessAmt_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Service_Details,CONCAT('$[',i,'].Description'))) INTO Description_;
INSERT INTO Service_Details(Service_Id,Service_Type_Id,Service_Type_Name,Hsn_Id,Hsn_Name,Unit_Price,Quantity,GrossValue,Discount,NetValue,
GST,GST_Amount,CGST,CGST_AMT,SGST,SGST_AMT,IGST,IGST_AMT,TotalAmount,Cesspers,CessAmt,Description,DeleteStatus ) 
values (Service_Id_ ,Service_Type_Id_,Service_Type_Name_,Hsn_Id_,Hsn_Name_,Unit_Price_,Quantity_,GrossValue_,Discount_,NetValue_,
	GST_,GST_Amount_,CGST_,CGST_AMT_,SGST_,SGST_AMT_,  IGST_,  IGST_AMT_,TotalAmount_, 
    Cesspers_,  CessAmt_,Description_,false);
 		
		SELECT i + 1 INTO i;
	END WHILE;  
 select Service_Id_;
 End
$$
DELIMITER ;

DELIMITER $$
