DELIMITER $$
CREATE PROCEDURE `Save_Stock`
BEGIN  
	Declare Stock_Id_ decimal(18,0); Declare ItemId_ decimal(18,0);Declare Barcode_ varchar(100);
	Declare ItemName_ varchar(100);Declare GroupId_ decimal(18,0);Declare GroupName_ varchar(100);
	Declare UnitId_ decimal(18,0);Declare UnitName_ varchar(100);Declare PurchaseRate_ decimal(18,2);
	Declare SaleRate_ decimal(18,2);Declare MRP_ decimal(18,2);Declare HSNMasterId_ decimal(18,0);
	Declare HSNCODE_ varchar(50);Declare SaleTax_ decimal(18,2);Declare CGST_ decimal(18,2);
	Declare SGST_ decimal(18,2);Declare IGST_ decimal(18,2);Declare Is_Expiry_ tinyint;
	Declare Expiry_Date_ datetime;Declare Quantity_ tinyint;

DECLARE i int  DEFAULT 0;
	WHILE i < JSON_LENGTH(Stock) DO    		
		#SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].Stock_Id')) INTO Stock_Id_;
		SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].ItemId')) INTO ItemId_;
		SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].Barcode')) INTO Barcode_;
        SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].ItemName')) INTO ItemName_;
		SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].GroupId')) INTO GroupId_;
		SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].GroupName')) INTO GroupName_;
		SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].UnitId')) INTO UnitId_;
		SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].UnitName')) INTO UnitName_;
		SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].PurchaseRate')) INTO PurchaseRate_;
		SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].SaleRate')) INTO SaleRate_;
        SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].MRP')) INTO MRP_;
		SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].HSNMasterId')) INTO HSNMasterId_;
		SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].HSNCODE')) INTO HSNCODE_;
		SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].SaleTax')) INTO SaleTax_;	
        SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].Quantity')) INTO Quantity_;
		SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].CGST')) INTO CGST_;   
		SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].SGST')) INTO SGST_;    
		SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].IGST')) INTO IGST_;
	
        SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].Is_Expiry')) INTO Is_Expiry_;
        SELECT JSON_EXTRACT(Stock,CONCAT('$[',i,'].Expiry_Date')) INTO Expiry_Date_;
        



if(Is_Expiry_=True)
then
	if(BarCode_ <>'')
	then
			if exists(select Stock_Id from Stock where ItemName=ItemName_ and SaleRate=SaleRate_ and MRP=MRP_ and DeleteStatus=False and BarCode=BarCode_ and Date_Format(Expiry_Date,'%Y-%m-%d')=Date_Format(Expiry_Date_,'%Y-%m-%d'))
			then
				set Stock_Id_=(select Stock_Id from Stock where ItemName=ItemName_ and SaleRate=SaleRate_ and MRP=MRP_ and DeleteStatus=False and BarCode=BarCode_ and
				Date_Format(Expiry_Date,'%Y-%m-%d')=Date_Format(Expiry_Date_,'%Y-%m-%d')order by Stock_Id desc);
				update Stock set ItemId=ItemId_,BarCode=BarCode_,ItemName=ItemName_,GroupId=GroupId_,
                GroupName=GroupName_,UnitId=UnitId_,UnitName=UnitName_,PurchaseRate=PurchaseRate_,
                SaleRate=SaleRate_,MRP=MRP_, HSNMasterId=HSNMasterId_,HSNCODE=HSNCODE_,SaleTax=SaleTax_,Quantity=Quantity+Quantity_,
