CREATE PROCEDURE `Save_Stock_Add_Details`
Begin 	
DECLARE StockId_ decimal(18,0);DECLARE Item_Id_ decimal(18,0); DECLARE Item_Name_ varchar(1000);declare Barcode_ varchar(200);
declare GroupId_ decimal(18,0);declare GroupName_ varchar(200);declare UnitId_ decimal(18,0);declare UnitName_ varchar(200);
declare PurchaseRate_ decimal(18,2);declare SaleRate_ decimal(18,2);declare MRP_ decimal(18,2);declare HSNMasterId_ decimal(18,0);
declare HSNCODE_ varchar(200);declare SaleTax_ decimal(18,2);DECLARE Quantity_ decimal(18,2);declare CGST_ decimal(18,2);
declare IGST_ decimal(18,2);declare SGST_ decimal(18,2);declare Is_Expiry_ tinyint;declare Expiry_Date_ datetime;
declare Is_Update_ tinyint;DECLARE Items_ decimal(18,0);DECLARE Items_Name_ varchar(1000);declare Item_Code_ varchar(500);

DECLARE Amount_ DECIMAL(18,0) DEFAULT 0;
DECLARE Description_ LONGTEXT DEFAULT '';
DECLARE File_Path_ VARCHAR(1000) DEFAULT '';
DECLARE File_Name_ VARCHAR(250) DEFAULT '';

DECLARE i int DEFAULT 0;

WHILE i < JSON_LENGTH(Stock_Add_Details) DO
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].StockId'))) INTO StockId_;  
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].ItemId'))) INTO Item_Id_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].ItemName'))) INTO Item_Name_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].Barcode'))) INTO Barcode_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].GroupId'))) INTO GroupId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].UnitId'))) INTO UnitId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].UnitName'))) INTO UnitName_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].PurchaseRate'))) INTO PurchaseRate_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].SaleRate'))) INTO SaleRate_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].MRP'))) INTO MRP_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].HSNMasterId'))) INTO HSNMasterId_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].HSNCODE'))) INTO HSNCODE_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].SaleTax'))) INTO SaleTax_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].CGST'))) INTO CGST_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].IGST'))) INTO IGST_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].SGST'))) INTO SGST_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].Is_Expiry'))) INTO Is_Expiry_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].Expiry_Date'))) INTO Expiry_Date_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].Items'))) INTO Items_;    
#SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].ItemName'))) INTO Items_Name_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].Item_Code'))) INTO Item_Code_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].Amount'))) INTO Amount_;
#SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Add_Details,CONCAT('$[',i,'].Description'))) INTO Description_;



#insert into db_logs values(0,Item_Id_,'item id','');	
		Set StockId_=(select COALESCE( MAX(Stock_Id ),0)  from Stock where ItemName=Item_Name_  and DeleteStatus=False and branch_id = Client_Id_ 
        order by Stock_Id desc Limit 1);

		if(StockId_>0)then
			set StockId_=(select COALESCE( MAX(Stock_Id ),0) from Stock where ItemName=Item_Name_  and DeleteStatus=False and branch_id = Client_Id_ 
            order by Stock_Id desc Limit 1);                
			update Stock set Quantity= Quantity+Quantity_
            where Stock_Id=StockId_ and DeleteStatus=False and branch_id = Client_Id_;
		else 			
        
        insert into Stock(ItemId,ItemName,GroupId,GroupName,UnitId,UnitName,PurchaseRate,SaleRate,MRP,HSNMasterId,HSNCODE,
SaleTax,Quantity,CGST,SGST,IGST,Item_Code,DeleteStatus,branch_id,Amount)
values(Item_Id_,Item_Name_,GroupId_,GroupName_,UnitId_,UnitName_,PurchaseRate_,SaleRate_,MRP_,HSNMasterId_,HSNCODE_,
SaleTax_,Quantity_,CGST_,IGST_,SGST_,Item_Code_,False,Client_Id_,Amount_);                   
set StockId_ =(SELECT LAST_INSERT_ID());
end if;

insert into db_logs values(0,Stock_Add_Master_Id_,Client_Id_,0);

INSERT INTO Stock_Add_Details(Stock_Add_Master_Id,ItemId,ItemName,StockId,Quantity,DeleteStatus,Item_Code,GroupId,GroupName,UnitId,UnitName,
PurchaseRate,SaleRate,MRP,HSNMasterId,HSNCODE,SaleTax,CGST,SGST,IGST,Amount)
values (Stock_Add_Master_Id_,Item_Id_,Item_Name_,StockId_, Quantity_, false, Item_Code_, GroupId_, GroupName_, UnitId_,UnitName_, PurchaseRate_,
 SaleRate_, MRP_, HSNMasterId_, HSNCODE_, SaleTax_, CGST_, SGST_, IGST_,Amount_); 
SELECT i + 1 INTO i;
END WHILE;    
SELECT Stock_Add_Master_Id_;
End
$$
