CREATE PROCEDURE `Save_Stock_Details`
Begin 
	DECLARE Stock_Id_ decimal(18,0);DECLARE To_Employee_Id_ decimal(18,0);DECLARE Quantity_ decimal(18,3);
       
	DECLARE i int  DEFAULT 0;
	WHILE i < JSON_LENGTH(Sales_Details) DO
		SELECT JSON_EXTRACT(Stock_Details,CONCAT('$[',i,'].Stock_Id')) INTO Stock_Id_;
		SELECT JSON_EXTRACT(Stock_Details,CONCAT('$[',i,'].Quantity')) INTO Quantity_;

		INSERT INTO Stock_Details(Stock_Details_Id ,Stock_Id ,To_Employee_Id ,Quantity ,DeleteStatus ) 
		values (Stock_Details_Id_ ,Stock_Id_ ,To_Employee_Id_ ,Quantity_ ,false);

		update Stock_Details set Quantity=Quantity+Quantity_ 
		where Stock_Id=Stock_Id_ and To_Employee_Id=To_Employee_Id_;

	END WHILE;

 select Stock_Add_Master_Id_;
 End
$$
