	 UPDATE stock_take_master set Stock_Take_Name_Id=Stock_Take_Name_Id_,Stocktakename=Stocktakename_,EntryDate = EntryDate_,
     User_Id = User_Id_,User_Name=User_Name_,Description = Description_
	 Where Stock_Take_Master_Id=Stock_Take_Master_Id_ ;
ELSE 
	 SET Stock_Take_Master_Id_ = (SELECT COALESCE(MAX(Stock_Take_Master_Id ),0)+1 FROM stock_take_master); 
	 INSERT INTO stock_take_master(Stock_Take_Master_Id,Stock_Take_Name_Id,Stocktakename,EntryDate,User_Id,User_Name,
     Description,DeleteStatus) 
	 values (Stock_Take_Master_Id_,Stock_Take_Name_Id_,Stocktakename_,EntryDate_,User_Id_,User_Name_,Description_,false);
End If ;
CALL Save_Stock_Take_Details(Stock_Take_Details_,Stock_Take_Details_Value_,Stock_Take_Master_Id_ );
 select Stock_Take_Master_Id_;
 #Commit;
 End
$$
DELIMITER ;

