CREATE PROCEDURE `Save_Stock_Transfer_Details`
Begin 
    declare Stock_Id_ decimal(18,0);DECLARE Stock_IdNew_ decimal(18,0);DECLARE Item_Id_ decimal(18,0);
    DECLARE Item_Name_ varchar(1000);	DECLARE BarCode_ VARCHAR(100);DECLARE GroupId_ decimal(18,0); DECLARE GroupName_ VARCHAR(100);
	DECLARE UnitId_ decimal(18,0);DECLARE UnitName_ VARCHAR(100);DECLARE PurchaseRate_ decimal(18,2);DECLARE SaleRate_ decimal(18,2);
    DECLARE MRP_ decimal(18,2);DECLARE HSN_Id_ decimal(18,0);DECLARE HSNCODE_ varchar(50);DECLARE SaleTax_ decimal(18,2);
    DECLARE CGST_ decimal(18,2);DECLARE SGST_ decimal(18,2);DECLARE IGST_ decimal(18,2);DECLARE Stock_From_Id_ decimal(18,2);
    DECLARE Stock_To_Id_ decimal(18,2);DECLARE Quantity_ decimal(18,3);Declare Is_Expiry_ varchar(20);declare Expiry_Date_ datetime;
	DECLARE i int  DEFAULT 0;
	WHILE i < JSON_LENGTH(Stock_Transfer_Details) DO
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].Stock_Id'))) INTO Stock_IdNew_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].Item_Id'))) INTO Item_Id_;
		SELECT JSON_UNQUOTE  (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].Item_Name'))) INTO Item_Name_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].Barcode'))) INTO BarCode_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].GroupId'))) INTO GroupId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].GroupName'))) INTO GroupName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].UnitId'))) INTO UnitId_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].UnitName'))) INTO UnitName_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].PurchaseRate'))) INTO PurchaseRate_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].SaleRate'))) INTO SaleRate_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].MRP'))) INTO MRP_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].HSN_Id'))) INTO HSN_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].HSNCODE'))) INTO HSNCODE_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].SaleTax'))) INTO SaleTax_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].CGST'))) INTO CGST_;   
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].SGST'))) INTO SGST_;    
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].IGST'))) INTO IGST_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].Stock_From_Id'))) INTO Stock_From_Id_;
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].Stock_To_Id'))) INTO Stock_To_Id_;    
		SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].Quantity'))) INTO Quantity_;
        SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].Is_Expiry'))) INTO Is_Expiry_;
        if(Is_Expiry_='true')
then set Is_Expiry_=1;
else set Is_Expiry_=0;
end if;
        
       SELECT JSON_UNQUOTE (JSON_EXTRACT(Stock_Transfer_Details,CONCAT('$[',i,'].Expiry_Date'))) INTO Expiry_Date_;
    
      #Save Stock Transfer Details
        set Is_Expiry_=(select Is_Expiry from Stock where Stock_Id=Stock_IdNew_);
		set Expiry_Date_=(select Expiry_Date from Stock where Stock_Id=Stock_IdNew_);
     
		INSERT INTO Stock_Transfer_Details(Stock_Transfer_Master_Id ,Stock_Id ,Item_Id ,Item_Name ,Barcode ,GroupId ,GroupName ,
		UnitId ,UnitName ,PurchaseRate ,SaleRate ,MRP ,HSN_Id ,HSNCODE ,SaleTax ,CGST ,IGST ,SGST ,Stock_From_Id ,
		Stock_To_Id ,Quantity ,Is_Expiry,Expiry_Date,New_Stock_Id,DeleteStatus ) 
		values (Stock_Transfer_Master_Id_ ,Stock_IdNew_ ,Item_Id_ ,Item_Name_ ,Barcode_ ,GroupId_ ,GroupName_ ,UnitId_ ,
		UnitName_ ,PurchaseRate_ ,SaleRate_ ,MRP_ ,HSN_Id_ ,HSNCODE_ ,SaleTax_ ,CGST_ ,IGST_ ,SGST_ ,Stock_From_Id_ ,
		Stock_To_Id_ ,Quantity_  ,Is_Expiry_,Expiry_Date_,Stock_IdNew_,false);
		
		update Stock_Details Set Quantity = Quantity - Quantity_ where Stock_Id=Stock_IdNew_ and To_Employee_Id = Stock_From_Id_ ;
        
        if exists(select Stock_Details_Id from Stock_Details where Stock_Id = Stock_IdNew_ and To_Employee_Id = Stock_To_Id_)
        then
			update Stock_Details set Quantity = Quantity + Quantity_ where Stock_Id=Stock_IdNew_ and To_Employee_Id = Stock_To_Id_ ;
        else
			INSERT INTO Stock_Details(Stock_Id ,To_Employee_Id ,Quantity ,DeleteStatus ) 
			values (Stock_IdNew_ ,Stock_To_Id_ ,Quantity_ ,false);
        end if;
		SELECT i + 1 INTO i;
	END WHILE;
  
SELECT Stock_Transfer_Master_Id_;
End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_Stock_Transfer_Master`
Begin 
declare Voucher_No_ varchar(50);declare Accounts_Id_ decimal;
declare YearFrom datetime;declare YearTo datetime;

/*DECLARE exit handler for sqlexception
BEGIN
	GET DIAGNOSTICS CONDITION 1
	@p1 = RETURNED_SQLSTATE, @p2 = MESSAGE_TEXT;
	SELECT @p2 AS MESSAGE_TEXT, @p1 AS RETURNED_SQLSTATE;
	ROLLBACK;
END;
    DECLARE exit handler for sqlwarning
BEGIN
	GET DIAGNOSTICS CONDITION 1
	@p1 = RETURNED_SQLSTATE, @p2 = MESSAGE_TEXT;
	SELECT @p2 AS MESSAGE_TEXT, @p1 AS RETURNED_SQLSTATE;
	ROLLBACK;
END;
    START TRANSACTION;*/

set YearFrom=(select Account_Years.YearFrom from Account_Years where  
Date_Format(Entry_Date_,'%Y-%m-%d') between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and 
Date_Format(Account_Years.YearTo,'%Y-%m-%d'));
set YearTo=(select Account_Years.YearTo from Account_Years where 
Date_Format(Entry_Date_,'%Y-%m-%d') between Date_Format(Account_Years.YearFrom,'%Y-%m-%d') and 
Date_Format(Account_Years.YearTo,'%Y-%m-%d'));
if exists(select distinct Voucher_No from Stock_Transfer_Master)
then
	set Voucher_No_=(SELECT COALESCE( MAX(Voucher_No ),0)+1 FROM Stock_Transfer_Master
	where Date_Format(Entry_Date_,'%Y-%m-%d') between Date_Format(YearFrom,'%Y-%m-%d') and Date_Format(YearTo,'%Y-%m-%d'));  
else 
	if exists(select Voucher_No from General_Settings)
	then
		set Voucher_No_=(select COALESCE(Voucher_No,0) from General_Settings);
	else
		set Voucher_No_=1;
	end if;    
end if;
 if  Stock_Transfer_Master_Id_>0
 THEN 
 call Update_Stock_FromST(Stock_Transfer_Master_Id_);
 	 Delete From Stock_Transfer_Details Where  Stock_Transfer_Master_Id=Stock_Transfer_Master_Id_ ;
 UPDATE Stock_Transfer_Master set Entry_Date = Entry_Date_ ,User_Id = User_Id_ ,Description=Description_ 
	Where Stock_Transfer_Master_Id=Stock_Transfer_Master_Id_ ;
 ELSE 
 #SET Stock_Transfer_Master_Id_ = (SELECT  COALESCE( MAX(Stock_Transfer_Master_Id ),0)+1 FROM Stock_Transfer_Master); 
 INSERT INTO Stock_Transfer_Master(Stock_Transfer_Master_Id ,Entry_Date ,User_Id ,Voucher_No ,Description,DeleteStatus ) 
 values (Stock_Transfer_Master_Id_ ,Entry_Date_ ,User_Id_ ,Voucher_No_ ,Description_,false);
 
End If ;
		if Stock_Transfer_Master_Id_=0 then
			set Stock_Transfer_Master_Id_ =(SELECT LAST_INSERT_ID());
		end if;
  CALL Save_Stock_Transfer_Details(Stock_Transfer_Details  , Stock_Transfer_Master_Id_ );
 select Stock_Transfer_Master_Id_,Voucher_No_;
  #Commit;
 End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Save_User_Details`
BEGIN
    DECLARE Menu_Id_ INT;
    DECLARE IsEdit_ VARCHAR(25);
    DECLARE IsSave_ VARCHAR(25);
    DECLARE IsDelete_ VARCHAR(25);
    DECLARE IsView_ VARCHAR(25);
    DECLARE Menu_Status_ VARCHAR(25);
    DECLARE i INT DEFAULT 0;

    IF User_Details_Id_ > 0 THEN
        DELETE FROM User_Menu_Selection WHERE User_Id = User_Details_Id_;
        UPDATE User_Details 
        SET User_Details_Name = User_Details_Name_,
            Password = Password_,
            User_Type = User_Type_,
            Working_Status = Working_Status_,
            Working_Status_Id = Working_Status_Id_,
            Role_Id = Role_Id_,
            Department_Id = Department_Id_,
            Branch_Id = Branch_Id_,
            Email = Email_,
            Mobile = Mobile_
        WHERE User_Details_Id = User_Details_Id_;
    ELSE
        SET User_Details_Id_ = (SELECT COALESCE(MAX(User_Details_Id), 0) + 1 FROM User_Details);
        INSERT INTO User_Details (User_Details_Id, User_Details_Name, Password, User_Type, DeleteStatus, Working_Status, Working_Status_Id, Role_Id, Department_Id, Branch_Id, Email, Mobile)
        VALUES (User_Details_Id_, User_Details_Name_, Password_, User_Type_, FALSE, Working_Status_, Working_Status_Id_, Role_Id_, Department_Id_, Branch_Id_, Email_, Mobile_);
    END IF;

    WHILE i < JSON_LENGTH(User_Menu_Selection) DO
        SELECT JSON_UNQUOTE(JSON_EXTRACT(User_Menu_Selection, CONCAT('$[', i, '].Menu_Id'))) INTO Menu_Id_;
        SELECT JSON_UNQUOTE(JSON_EXTRACT(User_Menu_Selection, CONCAT('$[', i, '].IsEdit'))) INTO IsEdit_;
        IF (IsEdit_ = 'true') THEN SET IsEdit_ = 1; ELSE SET IsEdit_ = 0; END IF;
        
        SELECT JSON_UNQUOTE(JSON_EXTRACT(User_Menu_Selection, CONCAT('$[', i, '].IsSave'))) INTO IsSave_;
        IF (IsSave_ = 'true') THEN SET IsSave_ = 1; ELSE SET IsSave_ = 0; END IF;
        
        SELECT JSON_UNQUOTE(JSON_EXTRACT(User_Menu_Selection, CONCAT('$[', i, '].IsDelete'))) INTO IsDelete_;
        IF (IsDelete_ = 'true') THEN SET IsDelete_ = 1; ELSE SET IsDelete_ = 0; END IF;
        
        SELECT JSON_UNQUOTE(JSON_EXTRACT(User_Menu_Selection, CONCAT('$[', i, '].IsView'))) INTO IsView_;
        IF (IsView_ = 'true') THEN SET IsView_ = 1; ELSE SET IsView_ = 0; END IF;
        
        SELECT JSON_UNQUOTE(JSON_EXTRACT(User_Menu_Selection, CONCAT('$[', i, '].Menu_Status'))) INTO Menu_Status_;
        IF (Menu_Status_ = 'true') THEN SET Menu_Status_ = 1; ELSE SET Menu_Status_ = 0; END IF;
        
        INSERT INTO User_Menu_Selection (Menu_Id, User_Id, IsEdit, IsSave, IsDelete, IsView, Menu_Status, DeleteStatus)
        VALUES (Menu_Id_, User_Details_Id_, IsEdit_, IsSave_, IsDelete_, IsView_, Menu_Status_, FALSE);
        
        SET i = i + 1;
    END WHILE;
    
    SELECT User_Details_Id_ AS User_Details_Id_;
END
$$
DELIMITER ;

DELIMITER $$
