CREATE PROCEDURE `Save_Waste_Management`
BEGIN
declare Document_Id_ int; 
declare Period_From_ datetime;
declare Period_To_ datetime;
declare Document_Type_Name_ varchar(500);
declare Document_Type_Id_ int;
declare Branch_Id_ int;
declare Document_Description_ varchar(500);
 declare Doc_Photo_ varchar(500);
declare Document_Name_ text;
declare File_Name_ longtext DEFAULT '';
declare Waste_Management_Id_ int;declare Branch_Name_ varchar(500); declare Date_ datetime;
declare Item_Id_ int;declare Item_Name_ varchar(500);declare Item_Quantity_ int;declare Particular_ varchar(500);
declare User_Id_ int ;declare Description_ text;
declare Item_Code_ varchar(500); declare File_Path_ varchar(500) DEFAULT '';
declare File_Name_1_ longtext DEFAULT '';
declare File_Name_2_ longtext DEFAULT '';
if( Value_>0) then
SELECT JSON_UNQUOTE (JSON_EXTRACT(Waste_Management_,'$.Waste_Management_Id')) INTO Waste_Management_Id_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Waste_Management_,'$.User_Id')) INTO User_Id_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Waste_Management_,'$.Date')) INTO Date_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Waste_Management_,'$.Description')) INTO Description_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Waste_Management_,'$.Item_Quantity')) INTO Item_Quantity_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Waste_Management_,'$.Item_Id')) INTO Item_Id_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Waste_Management_,'$.Item_Name')) INTO Item_Name_;
 SELECT JSON_UNQUOTE (JSON_EXTRACT(Waste_Management_,'$.Doc_Photo')) INTO Doc_Photo_;
  SELECT JSON_UNQUOTE (JSON_EXTRACT(Waste_Management_,'$.Branch_Id')) INTO Branch_Id_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Waste_Management_,'$.Branch_Name')) INTO Branch_Name_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Waste_Management_,'$.File_Name')) INTO File_Name_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Waste_Management_,'$.Particular')) INTO Particular_;     
SELECT JSON_UNQUOTE (JSON_EXTRACT(Waste_Management_,'$.Item_Code')) INTO Item_Code_; 
SELECT JSON_UNQUOTE (JSON_EXTRACT(Waste_Management_,'$.File_Path')) INTO File_Path_;
SELECT JSON_UNQUOTE (JSON_EXTRACT(Waste_Management_,'$.File_Name_1')) INTO File_Name_1_;

delete from db_logs;
insert into db_logs values(0,File_Name_1_,File_Name_,'filename');
if File_Name_1_ is null || File_Name_1_ = '' then
	Set File_Name_2_ = File_Name_;
else
	Set File_Name_2_ = File_Name_1_;
end if;

  if Waste_Management_Id_>0 then
	update waste_management set Branch_Id = Branch_Id_,Branch_Name = Branch_Name_,Date = Date_,
    Item_Id = Item_Id_,Item_Name = Item_Name_,Item_Quantity = Item_Quantity_,Particular = Particular_,Description = Description_,
    Item_Code = Item_Code_,File_Name=File_Name_2_,File_Path=File_Path_,Doc_Photo = Doc_Photo_, File_Upload=File_Name_2_
    where Waste_Management_Id = Waste_Management_Id_;
else
	SET Waste_Management_Id_ = (SELECT  COALESCE( MAX(Waste_Management_Id ),0)+1 FROM waste_management); 
	insert into waste_management (Waste_Management_Id,Branch_Id,Branch_Name,Date,Item_Id,Item_Name,Item_Quantity,Particular,Description,DeleteStatus,User_Id,Item_Code,File_Name,File_Path,Doc_Photo,File_Upload)
    values(Waste_Management_Id_,Branch_Id_,Branch_Name_,Date_,Item_Id_,Item_Name_,Item_Quantity_,Particular_,Description_,0,User_Id_,Item_Code_,File_Name_2_,File_Path_,Doc_Photo_,File_Name_2_);
end if; 
    end if;
select Waste_Management_Id_;
END
$$
