CREATE PROCEDURE `Search_AddStock`
BEGIN
    DECLARE Search_Date_ VARCHAR(500);
    DECLARE SearchbyName_Value VARCHAR(2000);
    
    SET Search_Date_ = '';
    SET SearchbyName_Value = '';

    IF Is_Date_Check_ = 1 THEN
        SET Search_Date_ = CONCAT(" AND stock_add_master.Entry_Date >= '", From_Date_, "' AND stock_add_master.Entry_Date <= '", To_Date_, "'");
    END IF;
    
	IF User_Type = 2 THEN
        SET SearchbyName_Value = CONCAT(" AND stock_add_master.User_Id >= ", Login_User_Id);
    END IF;


   SET @query = CONCAT("
    SELECT DISTINCT 
        stock_add_master.Stock_Add_Master_Id,
    DATE_FORMAT(stock_add_master.Entry_Date, '%Y-%m-%d') AS EntryDate,
    stock_add_master.Description1,
    stock_add_master.User_Id,
        stock_add_master.Description1 as Description,
        DATE_FORMAT(stock_add_master.Entry_Date, '%d-%m-%Y') AS FormattedEntryDate
        
    FROM stock_add_master 
    INNER JOIN stock_add_details ON stock_add_master.Stock_Add_Master_Id = stock_add_details.Stock_Add_Master_Id
    WHERE stock_add_master.DeleteStatus = FALSE",
    Search_Date_, 
    SearchbyName_Value,
    " ORDER BY Stock_Add_Master_Id asc "
);

    PREPARE QUERY FROM @query;
    EXECUTE QUERY;
END
$$
DELIMITER ;

