CREATE PROCEDURE `Search_Brand`
BEGIN
    /*SET Brand_Name_ = REPLACE(Brand_Name_, '\\', '\\\\'); -- Escape backslash
    SET Brand_Name_ = REPLACE(Brand_Name_, '%', '\\%');   -- Escape percentage
    SET Brand_Name_ = REPLACE(Brand_Name_, '', '\\');   -- Escape underscore    
    SET Brand_Name_ = CONCAT('%', Brand_Name_, '%');*/
     insert into db_logs values(0,Brand_Name_,"Brand_Name_",0);

      SET Brand_Name_ = REPLACE(Brand_Name_, '\', '\\');
    SET Brand_Name_ = REPLACE(Brand_Name_, '%', '\%');
    SET Brand_Name_ = REPLACE(Brand_Name_, '', '\');
    SET Brand_Name_ = CONCAT('%', Brand_Name_, '%');
    
    -- Query to fetch matching records
    SELECT 
        Brand.Brand_Id,
        Brand.Brand_Name, 
        Brand.under_brand_Id,
        under_brand.under_brand_Name AS under_brand_Name
    FROM 
        Brand
    LEFT JOIN 
        under_brand 
    ON 
        under_brand.under_brand_Id = Brand.under_brand_Id
    WHERE 
        Brand.Brand_Name LIKE Brand_Name_ 
        AND Brand.DeleteStatus = FALSE;
END
$$
