DELIMITER $$
CREATE PROCEDURE `Search_Client_Accounts`
BEGIN
    DECLARE SearchbyName_Value VARCHAR(2000);
    DECLARE Cleaned_Client_Accounts_Name VARCHAR(200);

    -- Initialize SearchbyName_Value as an empty string
    SET SearchbyName_Value = '';

    -- Clean and sanitize Client_Accounts_Name_ for literal or wildcard search
    IF Client_Accounts_Name_ IS NOT NULL AND Client_Accounts_Name_ != '' THEN
        -- Escape '%' for literal searches if required, or allow it for wildcard searches
        SET Cleaned_Client_Accounts_Name = REPLACE(Client_Accounts_Name_, '%', '\%');
        SET Cleaned_Client_Accounts_Name = REPLACE(Cleaned_Client_Accounts_Name, '', '\'); -- Also escape underscores if necessary

        -- Append the LIKE clause to SearchbyName_Value
        SET SearchbyName_Value = CONCAT(
            " AND client_accounts.Client_Accounts_Name LIKE ", 
            QUOTE(CONCAT('%', Cleaned_Client_Accounts_Name, '%')) -- Default wildcard search
        );
    END IF;

    -- Add filtering by Account_Group_ if provided
    IF Account_Group_ > 0 THEN
        SET SearchbyName_Value = CONCAT(
            SearchbyName_Value, 
            " AND client_accounts.Account_Group_Id = ", Account_Group_
        );
    END IF;

    -- Construct the full query dynamically
    SET @query = CONCAT(
        "SELECT client_accounts.Client_Accounts_Id, client_accounts.Client_Accounts_Code, ",
        "client_accounts.Client_Accounts_Name, client_accounts.Client_Accounts_No, ",
        "client_accounts.Address1, client_accounts.Address2, client_accounts.Address3, ",
        "client_accounts.Address4, client_accounts.PinCode, client_accounts.StateCode, ",
        "client_accounts.GSTNo, client_accounts.PanNo, client_accounts.State, ",
        "client_accounts.Country, client_accounts.Phone, client_accounts.Mobile, ",
        "client_accounts.Email, client_accounts.Opening_Balance, client_accounts.Description1, ",
        "client_accounts.UserId, client_accounts.LedgerInclude, client_accounts.CanDelete, ",
        "client_accounts.Opening_Type, client_accounts.Commision, client_accounts.Payment_Term, ",
        "(DATE_FORMAT(client_accounts.Entry_Date, '%Y-%m-%d')) AS Entry_Date, ",
        "client_accounts.Account_Group_Id, account_group.Group_Name AS Account_Group_Name, ",
        "CONCAT(client_accounts.Address1, ', ', client_accounts.Address2, ', ', ",
        "client_accounts.Address3, ', ', client_accounts.Address4) AS Addresses, ",
        "client_accounts.Employee_Id ",
        "FROM client_accounts ",
        "INNER JOIN account_group ON account_group.Account_Group_Id = client_accounts.Account_Group_Id ",
        "WHERE client_accounts.Client_Accounts_Id > 35 ",
        "AND client_accounts.DeleteStatus = FALSE ",
        SearchbyName_Value
    );

    -- Prepare, execute, and clean up the dynamic query
    PREPARE QUERY FROM @query;
    EXECUTE QUERY;
    DEALLOCATE PREPARE QUERY;
END
$$
DELIMITER ;

