DELIMITER $$
CREATE PROCEDURE `Search_Damage_Master`
Begin 
declare Search_Date_ varchar(500);
set Search_Date_="";
 if Is_Date_Check_=true then
set Search_Date_=concat( " and Damage_Master.Date >= '", FromDate_ ,"' and  Damage_Master.Date <= '", ToDate_,"'");
end if;
SET @query = Concat("SELECT Damage_Master.Damage_Master_Id,
(Date_Format(Damage_Master.Date,'%Y-%m-%d')) as Date,
 (Date_Format(Damage_Master.Date,'%d-%m-%Y')) As Search_Date, Damage_Master.Damage_No,
User_Id,User_Details.User_Details_Name
From Damage_Master 
inner join User_Details on Damage_Master.User_Id=User_Details.User_Details_Id
where Damage_Master.DeleteStatus=false ", Search_Date_ ,"
 group by Damage_Master.Damage_Master_Id");
 
	PREPARE QUERY FROM @query;EXECUTE QUERY;
 End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Search_Damage_Report`
Begin 
declare Search_Date_ varchar(500);
declare SearchbyName_Value varchar(2000);
SET SearchbyName_Value ='';
set Search_Date_="";
 if Is_Date_Check_=true then
set Search_Date_=concat( " and Damage_Master.Date >= '", FromDate_ ,"' and  Damage_Master.Date <= '", ToDate_,"'");
end if;
if Item_Id_>0 then
SET SearchbyName_Value =concat(SearchbyName_Value," and damage_details.ItemId =",Item_Id_);
end if;
SET @query = Concat("SELECT Damage_Master.Damage_Master_Id,(Date_Format(Damage_Master.Date,'%d-%m-%Y')) As Search_Date,
 Damage_Master.Damage_No,User_Id,User_Details.User_Details_Name,ItemName  ,Quantity,SaleRate,Amount,ItemId
From Damage_Master 
inner join User_Details on Damage_Master.User_Id=User_Details.User_Details_Id
inner join damage_details on Damage_Master.Damage_Master_Id=damage_details.Damage_Master_Id
where Damage_Master.DeleteStatus=false ", Search_Date_ ,SearchbyName_Value , "
 group by Damage_Master.Damage_Master_Id");
 
	PREPARE QUERY FROM @query;EXECUTE QUERY;
 End
$$
DELIMITER ;

