  declare SearchbyName_Value varchar(2000);
   declare SearchbyName_Value1 varchar(2000);
    declare SearchbyName_Value2 varchar(2000);
     declare SearchbyName_Value3 varchar(2000);
      declare SearchbyName_Value4 varchar(2000);
       declare SearchbyName_Value5 varchar(2000);
    declare SearchbyUser_ varchar(500);
      declare SearchbyUser1_ varchar(500);
        declare SearchbyUser2_ varchar(500);
          declare SearchbyUser3_ varchar(500);
            declare SearchbyUser4_ varchar(500);
              declare SearchbyUser5_ varchar(500);
 
   set Search_Date_="";
  set Search_Date1_="";
   set Search_Date2_="";
  set Search_Date3_="";
   set Search_Date4_="";
      set Search_Date5_="";
   
  set SearchbyUser_="";
   set SearchbyUser1_="";
    set SearchbyUser2_="";
     set SearchbyUser3_="";
      set SearchbyUser4_="";
       set SearchbyUser5_="";
  
   set SearchbyName_Value1="";
    set SearchbyName_Value2="";
     set SearchbyName_Value3="";
      set SearchbyName_Value4="";
       set SearchbyName_Value5="";
       set SearchbyName_Value = "";
         
 
   if Is_Date_Check_>0 then
SET Search_Date_ = CONCAT(" AND date(purchase_master.Entry_Date) >=  '", Fromdate_,  "' and date(purchase_master.Entry_Date) <= '", Todate_,  "'");
set Search_Date1_=concat( " and date(petty_cash.Date) >= '",  Fromdate_,  "' and date(petty_cash.Date) <= '",  Todate_,  "' ");
SET Search_Date2_ = CONCAT(" AND date(petty_cash.Date) >= '", Fromdate_,  "' and date(petty_cash.Date) <= '", Todate_, "' ");
set Search_Date3_=concat( "  and date(payment_voucher.Date) >= '",  Fromdate_, "' and date(payment_voucher.Date) <= '", Todate_,  "' ");
set Search_Date4_=concat( " and date(waste_management.Date) >= '", Fromdate_,  "' and date(waste_management.Date) <= '",  Todate_,  "' ");
set Search_Date5_=concat( "  and date(stock_add_master.Entry_Date) >= '", Fromdate_,  "' and date(stock_add_master.Entry_Date) <= '",  Todate_,  "' ");

     ELSE
	set Search_Date_= " and 1 =1 ";
    set Search_Date1_ = " and 1 =1 ";
    set Search_Date2_ = " and 1 =1 ";
    set Search_Date3_ = " and 1 =1 ";
    set Search_Date4_=  " and 1 =1 ";
    set Search_Date5_ = " and 1 =1 ";
end if;
 
   #insert into db_logs values(0,Search_Date_,Search_Date1_,'2');
 
if Branch_>0 then
SET SearchbyName_Value =concat(SearchbyName_Value," and purchase_master.Account_Party_Id=",Branch_);
