#SET SearchbyName_Value2 =concat(SearchbyName_Value2," and petty_cash.Branch_Id=",Branch_);
SET SearchbyName_Value3 =concat(SearchbyName_Value3,"  and payment_voucher.To_Account_Id=",Branch_);
SET SearchbyName_Value4 =concat(SearchbyName_Value4," and waste_management.Branch_Id=",Branch_);
SET SearchbyName_Value5 =concat(SearchbyName_Value5,"  and stock_add_master.Client_Id=",Branch_);

end if;
  insert into db_logs values(0,SearchbyName_Value,Branch_,'2');
 
 if Login_User_Id_>0 then
SET SearchbyUser_ =concat(SearchbyUser_," and purchase_master.User_Id =",Login_User_Id_);
SET SearchbyUser1_ =concat(SearchbyUser1_," and petty_cash.User_Id =",Login_User_Id_);
SET SearchbyUser2_ =concat(SearchbyUser2_," and petty_cash.User_Id =",Login_User_Id_);
SET SearchbyUser3_ =concat(SearchbyUser3_," and payment_voucher.User_Id =",Login_User_Id_);
SET SearchbyUser4_ =concat(SearchbyUser4_," and waste_management.User_Id =",Login_User_Id_);
SET SearchbyUser5_ =concat(SearchbyUser5_," and stock_add_master.User_Id =",Login_User_Id_);
end if;
 

 
    SET @query = Concat(
    " select 1 as tp, count(purchase_master.Purchase_Master_Id) as Data_Count from purchase_master where purchase_master.DeleteStatus=0 ",Search_Date_, SearchbyName_Value,SearchbyUser_,"
  

    union

    select  2 as tp,count(petty_cash.Petty_Cash_Id) as Data_Count from petty_cash where     Type_Id=1   and  petty_cash.DeleteStatus=0 ",SearchbyName_Value1 ,Search_Date1_,SearchbyUser2_,"

    union

    select  3 as tp,count(petty_cash.Petty_Cash_Id) as Data_Count from petty_cash where     Type_Id=2  and  petty_cash.DeleteStatus=0 ",SearchbyName_Value1, Search_Date2_,SearchbyUser2_,"
    union

    select  4 as tp,count(payment_voucher.Payment_Voucher_Id) as Data_Count from payment_voucher where      payment_voucher.DeleteStatus=0 ",Search_Date3_, SearchbyName_Value3,SearchbyUser3_," 
    union 

    select  5 as tp,count(waste_management.Waste_Management_Id) as Data_Count from waste_management where   waste_management.DeleteStatus=0    ",SearchbyName_Value4 ,Search_Date4_,SearchbyUser4_,"
  

    union

    select  6 as tp,count(stock_add_master.Stock_Add_Master_Id) as Data_Count from stock_add_master where       stock_add_master.DeleteStatus=0  ",SearchbyName_Value5, Search_Date5_,SearchbyUser5_,"
  ");

  PREPARE QUERY FROM @query;
  EXECUTE QUERY;
#select @Query;
end
$$
