CREATE PROCEDURE `Search_Daybook`
Begin
 
	DECLARE Search_Date_ VARCHAR(500);
	DECLARE SearchbyName_Value VARCHAR(2000);
    DECLARE Search_User VARCHAR(500);
    
	SET Search_Date_="";
	SET SearchbyName_Value="";
    SET Search_User="";
	 
	IF Is_Date_Check_= true THEN
		SET Search_Date_=concat( " AND DATE(db.Entry_Date) >= '", From_Date_ ,"' AND  DATE(db.Entry_Date) <= '", To_Date_,"'");
	END IF;
	/*
	if Login_User_>0 then
	SET Search_User =concat(Search_User," and waste_management.User_Id =",Login_User_);
	end if;*/
    
	IF Branch_>0 then
		SET SearchbyName_Value =concat(SearchbyName_Value," AND db.Client_Accounts_Id =",Branch_);
	END IF;
    
	IF Item_>0 then
		SET SearchbyName_Value =concat(SearchbyName_Value," AND db.Master_Category_Id =",Item_);
	END IF;

	SET @query = Concat("
	 SELECT 
		Daybook_Id,
		Client_Accounts_Id,
		Client_Accounts_Name,
		Item_Id,
		Item_Name,
		Item_Group_Id,
		Item_Group_Name,
		Master_Category_Id,
		Master_Category_Name,
		Quantity,
		(Date_Format(db.Entry_Date,'%Y-%m-%d')) As Date, 
		(Date_Format(db.Entry_Date,'%d-%m-%Y')) As Search_Date,
		Item_Code,
		IFNULL(File_Name,'') AS File_Name,
        IFNULL(File_Path,'') AS File_Path,
        Remarks,
        IFNULL(Amount,0) AS Amount
	 FROM 
		Daybook db 
	 WHERE 
		db.DeleteStatus=0
	 ",Search_Date_,"
	 ",SearchbyName_Value,"
	 ",Search_User,"
	 ");
     
	 delete from db_logs;
     insert into db_logs values (0,@query,'','Search_Daybook');
	PREPARE QUERY FROM @query;
	EXECUTE QUERY;
End
$$
DELIMITER ;

