DELIMITER $$
CREATE PROCEDURE `Search_debitnote_master`
Begin 
 declare Search_Date_ varchar(500);declare SearchbyName_Value varchar(2000);
     DECLARE Cleaned_Part_No VARCHAR(200);


	set Search_Date_="";set SearchbyName_Value="";
if Is_Date_Check_=true then
	set Search_Date_=concat( " and debitnote_master.EntryDate >= '", From_Date_ ,"' and  debitnote_master.EntryDate <= '", To_Date_,"'");
end if;
if Account_Party_Id_>0 then
	SET SearchbyName_Value =concat(SearchbyName_Value," and debitnote_master.Account_Party_Id =",Account_Party_Id_);
end if;
if Invoice_No_ != '' then
	SET SearchbyName_Value =concat(SearchbyName_Value," and Concat( debitnote_master.InvNo ,'')  =",Invoice_No_);
end if;
	IF Part_No_ != '' THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND debitnote_details.ItemCode = '", Part_No_, "'");
    END IF;
     IF Part_No_ IS NOT NULL AND Part_No_ != '' THEN
        SET Cleaned_Part_No = REPLACE(Part_No_, '%', '\%');
        SET Cleaned_Part_No = REPLACE(Cleaned_Part_No, '_', '\_'); 

        SET SearchbyName_Value = CONCAT(
            " AND debitnote_details.ItemCode LIKE ", 
            QUOTE(CONCAT('%', Cleaned_Part_No, '%')) 
        );
    END IF;

    IF Item_Group_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND debitnote_details.GroupId = ", Item_Group_Id_);
    END IF;

    IF CurrencyDetails_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND debitnote_master.CurrencyId = ", CurrencyDetails_Id_);
    END IF;
    
    IF AccountType_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND debitnote_master.TypeId = ", AccountType_Id_);
    END IF;

    IF User_Details_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND debitnote_master.AttendEmployee = ", User_Details_Id_);
    END IF;
    
	IF User_Type = 2 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND debitnote_master.User_Id = ", Login_User_Id);
    END IF;
    
SET @query = Concat(" SELECT DISTINCT debitnote_master.DebitNote_Master_Id,
debitnote_master.Account_Party_Id,
(Date_Format(debitnote_master.EntryDate,'%Y-%m-%d')) As EntryDate,
debitnote_master.InvNo,
debitnote_master.LPONo,
debitnote_master.DONo,
debitnote_master.PackingListNumber,
debitnote_master.CurrencyId,
debitnote_master.TypeId,
debitnote_master.PaymentTerms,
debitnote_master.TotalAmount,
debitnote_master.TotalDiscount,
debitnote_master.TaxableAmount,
debitnote_master.VatAmount,
debitnote_master.Total_Amount,
debitnote_master.Roundoff_Amt,
debitnote_master.NetTotal,
debitnote_master.Makes,
debitnote_master.PriceBasis,
debitnote_master.Description1,
debitnote_master.User_Id,
debitnote_master.Delivery_Address1,
debitnote_master.Delivery_Address2,
debitnote_master.Delivery_Address3,
debitnote_master.Delivery_Address4,
debitnote_master.DeleteStatus,
debitnote_master.KindAttend,
debitnote_master.Charge1,
debitnote_master.charge1_Amount,
debitnote_master.Charge2,
debitnote_master.charge2_Amount,
debitnote_master.Discount_Description,
debitnote_master.Additional_Discount,
debitnote_master.Description2,
debitnote_master.Employee,
debitnote_master.Basic_Discount,
debitnote_master.Amount_In_Words,
debitnote_master.Notes,
debitnote_master.Charge1per,
debitnote_master.Payment_Term_Description,
debitnote_master.VAT_Description,
debitnote_master.VAT_percentage,
debitnote_master.VAT_Amount,
debitnote_master.New_Entry,
debitnote_master.Customer_Reference,
(Date_Format(debitnote_master.SupplyDate,'%Y-%m-%d')) As SupplyDate,
(Date_Format(debitnote_master.DueDate,'%Y-%m-%d')) As DueDate,
debitnote_master.Debit_Node_Image,
debitnote_master.CurrecnyName,
debitnote_master.UserName,
debitnote_master.AttendEmployee,
debitnote_master.PaymentTermValue,
(Date_Format(debitnote_master.EntryDate,'%d-%m-%Y')) As FormattedEntryDate,
(Date_Format(debitnote_master.EntryDate,'%d-%m-%Y')) As printDate,
(Date_Format(debitnote_master.SupplyDate,'%d-%m-%Y')) As supplyPrintDate,
(Date_Format(debitnote_master.DueDate,'%d-%m-%Y')) As duePrintDate,
debitnote_master.InvNo,debitnote_master.LPONo, debitnote_master.NetTotal,
Client_Accounts.Client_Accounts_Name as Customer 
FROM debitnote_master 
INNER JOIN Client_Accounts ON debitnote_master.Account_Party_Id=Client_Accounts.Client_Accounts_Id 
INNER JOIN debitnote_details ON debitnote_master.debitnote_master_Id=debitnote_details.debitnote_master_Id
WHERE debitnote_master.DeleteStatus =false ", Search_Date_ ,SearchbyName_Value,"
GROUP BY 
        debitnote_master.debitnote_master_Id,
        debitnote_master.EntryDate,
        debitnote_master.InvNo,
        debitnote_master.NetTotal,
        client_accounts.Client_Accounts_Name
ORDER BY debitnote_master.DebitNote_Master_Id ASC");
PREPARE QUERY FROM @query;EXECUTE QUERY;
#select @query;
End
$$
DELIMITER ;

