CREATE PROCEDURE `Search_Delivery_Order`
BEGIN
    DECLARE Search_Date_ VARCHAR(500);
    DECLARE SearchbyName_Value VARCHAR(2000);
     DECLARE Cleaned_Part_No VARCHAR(200);
     
    SET Search_Date_ = '';
    SET SearchbyName_Value = '';

    IF Is_Date_Check_ = 1 THEN
        SET Search_Date_ = CONCAT(" AND deliveryordermaster.EntryDate >= '", From_Date_, "' AND deliveryordermaster.EntryDate <= '", To_Date_, "'");
    END IF;

    IF Account_Party_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND deliveryordermaster.Account_Party_Id = ", Account_Party_Id_);
    END IF;

    IF Quot_No_ != '' THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND deliveryordermaster.DONo like '%", Quot_No_, "%'");
    END IF;

   /* IF Part_No_ != '' THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND deliveryorderdetails.ItemCode like '%", Part_No_, "%'");
    END IF;*/
    
        IF Part_No_ IS NOT NULL AND Part_No_ != '' THEN
        SET Cleaned_Part_No = REPLACE(Part_No_, '%', '\%');
        SET Cleaned_Part_No = REPLACE(Cleaned_Part_No, '', '\'); 

        SET SearchbyName_Value = CONCAT(
            " AND  deliveryorderdetails.ItemCode LIKE ", 
            QUOTE(CONCAT('%', Cleaned_Part_No, '%')) 
        );
    END IF;
    

    IF Item_Group_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND deliveryorderdetails.GroupId = ", Item_Group_Id_);
    END IF;

    IF CurrencyDetails_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND deliveryordermaster.CurrencyId = ", CurrencyDetails_Id_);
    END IF;

    IF User_Details_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND deliveryordermaster.kind_attend = ", User_Details_Id_);
    END IF;
    
    IF Account_Type_Id_ > 0 THEN
		SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND deliveryordermaster.TypeId = ",Account_Type_Id_);
	END IF;
    
	IF User_Type_ = 2 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND deliveryordermaster.User_Id = ", Login_User_Id_);
    END IF;
    
   SET @query = CONCAT("
    SELECT DISTINCT deliveryordermaster.DeliveryOrderMaster_Id,deliveryordermaster.Account_Party_Id,DATE_FORMAT(deliveryordermaster.EntryDate,'%Y-%m-%d') as EntryDate,
deliveryordermaster.DONo,deliveryordermaster.LPONo,deliveryordermaster.CurrencyId,deliveryordermaster.TypeId,deliveryordermaster.PaymentTerms,
deliveryordermaster.TotalAmount,deliveryordermaster.TotalDiscount,deliveryordermaster.TaxableAmount,deliveryordermaster.VatAmount,deliveryordermaster.NetTotal,
deliveryordermaster.Makes,deliveryordermaster.PriceBasis,deliveryordermaster.Description1,deliveryordermaster.User_Id,deliveryordermaster.Delivery_Address1,
deliveryordermaster.Delivery_Address2,deliveryordermaster.Delivery_Address3,deliveryordermaster.Delivery_Address4,deliveryordermaster.Kind_Attend,
deliveryordermaster.Payment_Term_Description,deliveryordermaster.Deliver_Order_Image,deliveryordermaster.CurrecnyName,deliveryordermaster.UserName,
deliveryordermaster.Payment_Term_Value,deliveryordermaster.Received_By,deliveryordermaster.vat_percentage,deliveryordermaster.LPONo as LPONo1,
DATE_FORMAT(deliveryordermaster.EntryDate, '%d-%m-%Y') AS FormattedEntryDate,deliveryordermaster.DONo as QuotationNo,client_accounts.Client_Accounts_Name AS Customer,
currencydetails.currecnyName AS CurrencyName,accounttype.AccountType_Name AS AccountType_Name,deliveryordermaster.TypeId AS AccountType_Id,
deliveryordermaster.CurrencyId AS CurrencyDetails_Id,deliveryordermaster.Payment_Term_Value AS payment_Term_Value,
client_accounts.Address1,client_accounts.Address2,client_accounts.Address3,client_accounts.Address4,
IFNULL(qdo.SalesQuotationMaster_Id,0) SalesQuotationMaster_Id,DATE_FORMAT(deliveryordermaster.EntryDate, '%d-%m-%Y') AS PrintDate,
IFNULL(client_accounts.GSTNo,'') GSTNo
    FROM deliveryordermaster 
    INNER JOIN deliveryorderdetails ON deliveryordermaster.DeliveryOrderMaster_Id = deliveryorderdetails.DeliveryMaster_Id
    INNER JOIN client_accounts ON deliveryordermaster.Account_Party_Id = client_accounts.Client_Accounts_Id 
    LEFT JOIN currencydetails ON deliveryordermaster.CurrencyId = currencydetails.CurrencyDetails_Id
    LEFT JOIN accounttype ON deliveryordermaster.TypeId = accounttype.AccountType_Id
    LEFT JOIN quotation_delivery_order qdo ON qdo.DeliveryOrderMaster_Id = deliveryordermaster.DeliveryOrderMaster_Id
    WHERE deliveryordermaster.DeleteStatus = 0 ",
    Search_Date_, 
    SearchbyName_Value,
    " ORDER BY DeliveryOrderMaster_Id ASC; "
);
    PREPARE QUERY FROM @query;
    EXECUTE QUERY;
END
$$
DELIMITER ;

