CREATE PROCEDURE `Search_GRNVatReport`
BEGIN
    DECLARE Search_Date_ VARCHAR(500);
   # SET SearchbyName_Value = '';

	SET Search_Date_ = CONCAT(" AND purchase_master.Entry_Date >= '", From_Date_, "' AND purchase_master.Entry_Date <= '", To_Date_, "'");
	
   # IF User_Type = 2 then
     #   SET SearchbyName_Value = CONCAT(" AND purchase_master.User_Id = ",Login_User);
	#END IF;

   SET @query = CONCAT("
    select 1 as tp,(Date_Format(purchase_master.Entry_Date,'%d-%m-%Y')) As Entry_Date,purchase_master.InvoiceNo,
    client_accounts.Client_Accounts_Name as Supplier,client_accounts.GSTNo,currencydetails.CurrecnyName,  
    ifnull(purchase_master.TotalAmount,0)as NetTotal,ifnull(purchase_master.VAT_Percentage,0)as 'Vat %',
    ifnull(purchase_master.VAT_Amount,0)as VatAmount,ifnull(purchase_master.Roundoff,0)as Roundoff,
    ifnull(purchase_master.NetTotal,0)as GrandTotal
    from purchase_master
	inner join client_accounts on client_accounts.Client_Accounts_Id = purchase_master.Account_Party_Id
	left join currencydetails on currencydetails.CurrencyDetails_Id =  purchase_master.Currency_Id
	where purchase_master.VAT_Amount=5 and purchase_master.deletestatus=0 ",Search_Date_,"
	union 
	select 2 as tp,(Date_Format(purchase_master.Entry_Date,'%d-%m-%Y')) As Entry_Date,purchase_master.InvoiceNo,
    client_accounts.Client_Accounts_Name as Supplier,client_accounts.GSTNo,currencydetails.CurrecnyName,  
    ifnull(purchase_master.TotalAmount,0)as NetTotal,ifnull(purchase_master.VAT_Percentage,0)as 'Vat %',
    ifnull(purchase_master.VAT_Amount,0)as VatAmount,ifnull(purchase_master.Roundoff,0)as Roundoff,
    ifnull(purchase_master.NetTotal,0)as GrandTotal
	from purchase_master
	inner join client_accounts on client_accounts.Client_Accounts_Id = purchase_master.Account_Party_Id
	left join currencydetails on currencydetails.CurrencyDetails_Id =  purchase_master.Currency_Id
	where purchase_master.VAT_Amount<>5 and purchase_master.deletestatus=0 ",
Search_Date_, " 
	union
    select 2 as tp,'Total' As Entry_Date,'' as InvoiceNo,'' as Supplier,'' as GSTNo,'' as CurrecnyName,  
    ifnull(sum(purchase_master.TotalAmount),0)as NetTotal,'' as 'Vat %',ifnull(sum(purchase_master.VAT_Amount),0)as VatAmount,
    ifnull(sum(purchase_master.Roundoff),0)as Roundoff,ifnull(sum(purchase_master.NetTotal),0)as GrandTotal
	from purchase_master
	inner join client_accounts on client_accounts.Client_Accounts_Id = purchase_master.Account_Party_Id
	left join currencydetails on currencydetails.CurrencyDetails_Id =  purchase_master.Currency_Id
	where purchase_master.deletestatus=0 ",Search_Date_, " 
"
);
    PREPARE QUERY FROM @query;
    delete from db_logs;
insert into db_logs values(0,@query,'Search_Registration_Report',1);
    EXECUTE QUERY;
END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Search_GRN_Order`
BEGIN
    DECLARE Search_Date_ VARCHAR(500);
    DECLARE SearchbyName_Value VARCHAR(2000);
    
    SET Search_Date_ = '';
    SET SearchbyName_Value = '';

    IF Is_Date_Check_ = 1 THEN
        SET Search_Date_ = CONCAT(" AND purchase_master.Entry_Date >= '", From_Date_, "' AND purchase_master.Entry_Date <= '", To_Date_, "'");
    END IF;

    IF Account_Party_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND purchase_master.Account_Party_Id = ", Account_Party_Id_);
    END IF;

    IF Quot_No_ != '' THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND purchase_master.InvoiceNo like '%", Quot_No_, "%'");
    END IF;

    IF Part_No_ != '' THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND purchase_details.Item_Code like '%", Part_No_, "%'");
    END IF;

    IF Item_Group_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND purchase_details.GroupId = ", Item_Group_Id_);
    END IF;

    IF CurrencyDetails_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND purchase_master.Currency_Id = ", CurrencyDetails_Id_);
    END IF;

    IF User_Details_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND purchase_master.KindAttend = ", User_Details_Id_);
    END IF;
    
    IF Account_Type_Id_ > 0 THEN
		SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND purchase_master.TypeId = ",Account_Type_Id_);
	END IF;
    
   SET @query = CONCAT("
    SELECT DISTINCT
        purchase_master.*,
        DATE_FORMAT(purchase_master.Entry_Date, '%d-%m-%Y') AS FormattedEntryDate,
        purchase_master.InvoiceNo as QuotationNo,
        client_accounts.Client_Accounts_Name AS Customer,
        currencydetails.currecnyName AS CurrencyName,
        accounttype.AccountType_Name AS AccountType_Name,
        purchase_master.TypeId AS AccountType_Id,
        purchase_master.Currency_Id AS CurrencyDetails_Id,
        purchase_master.Payment_Term_Description AS payment_Term_Value,
        client_accounts.Address1,
        client_accounts.Address2,
        client_accounts.Address3,
        client_accounts.Address4
    FROM purchase_master 
    INNER JOIN purchase_details ON purchase_master.Purchase_Master_Id = purchase_details.Purchase_Master_Id
    INNER JOIN client_accounts ON purchase_master.Account_Party_Id = client_accounts.Client_Accounts_Id 
    LEFT JOIN currencydetails ON purchase_master.Currency_Id = currencydetails.CurrencyDetails_Id
    LEFT JOIN accounttype ON purchase_master.TypeId = accounttype.AccountType_Id
    WHERE purchase_master.DeleteStatus = FALSE",
    Search_Date_, 
    SearchbyName_Value,
    " GROUP BY 
        purchase_master.Purchase_Master_Id,
        purchase_master.Entry_Date,
        purchase_master.InvoiceNo,
        client_accounts.Client_Accounts_Name"
);

    PREPARE QUERY FROM @query;
    EXECUTE QUERY;
END
$$
DELIMITER ;

