CREATE PROCEDURE `Search_Invoice_By_VoucherType_Typeahead`
BEGIN
set InvoiceNo_ = Concat( '%',InvoiceNo_ ,'%');

if(Voucher_Type_Id_ = 1) then
SELECT InvoiceNo as Invoice,(Date_Format(Entry_Date,'%d-%m-%Y')) As Date,NetTotal as Amount 
From purchase_master where InvoiceNo like InvoiceNo_ and purchase_master.DeleteStatus=false 
	and purchase_master.Account_Party_Id = Client_Accounts_Id_ ORDER BY InvoiceNo Asc;
elseif(Voucher_Type_Id_ = 8) then
SELECT InvoiceNo as Invoice, (Date_Format(Entry_Date,'%d-%m-%Y')) As Date,NetTotal as Amount 
From purchase_return_master where InvoiceNo like InvoiceNo_ and purchase_return_master.DeleteStatus=false 
	and purchase_return_master.Account_Party_Id = Client_Accounts_Id_ ORDER BY InvoiceNo Asc;
elseif(Voucher_Type_Id_ = 2) then
SELECT InvNo as Invoice, (Date_Format(Date,'%d-%m-%Y')) As Date,Amount as Amount 
From journal_entry where InvNo like InvoiceNo_ and journal_entry.DeleteStatus=false 
	and journal_entry.To_Account_Id = Client_Accounts_Id_ ORDER BY InvNo Asc;
elseif(Voucher_Type_Id_ = 10) then
SELECT InvNo as Invoice, (Date_Format(EntryDate,'%d-%m-%Y')) As Date,NetTotal as Amount
 From creditnote_master where InvNo like InvoiceNo_ and creditnote_master.DeleteStatus=false 
	and creditnote_master.Account_Party_Id = Client_Accounts_Id_ ORDER BY InvNo Asc;
    
elseif(Voucher_Type_Id_ = 5) then
SELECT Invoice_No as Invoice, (Date_Format(EntryDate,'%d-%m-%Y')) As Date,NetTotal as Amount 
From sales_master where Invoice_No like InvoiceNo_ and sales_master.DeleteStatus=false 
	and sales_master.Account_Party_Id = Client_Accounts_Id_ ORDER BY Invoice_No Asc;
elseif(Voucher_Type_Id_ = 7) then
SELECT Invoice_No as Invoice, (Date_Format(EntryDate,'%d-%m-%Y')) As Date,NetTotal as Amount 
From sales_return_master where Invoice_No like InvoiceNo_ and sales_return_master.DeleteStatus=false 
	and sales_return_master.Account_Party_Id = Client_Accounts_Id_ ORDER BY Invoice_No Asc;
elseif(Voucher_Type_Id_ = 9) then
SELECT InvNo as Invoice, (Date_Format(EntryDate,'%d-%m-%Y')) As Date,NetTotal as Amount 
From debitnote_master where InvNo like InvoiceNo_ and debitnote_master.DeleteStatus=false 
	and debitnote_master.Account_Party_Id = Client_Accounts_Id_ ORDER BY InvNo Asc;
end if;
END
$$
DELIMITER ;

