CREATE PROCEDURE `Search_Multi_Price_Quotation`
BEGIN
        SELECT 
            ca.Client_Accounts_Name AS SupplierName,
            prm.EntryDate AS Date,
            prd.ItemName,
            prd.Brand,
            prd.Quantity AS Qty,
            prd.UnitPrice AS Price,
            prd.TaxAmount AS Tax,
            prd.Amount AS Total,
            'Supplier' AS SourceType
        FROM Price_Request_Details prd
        INNER JOIN Price_Request_Master prm ON prd.Price_Request_Master_Id = prm.Price_Request_Master_Id
        LEFT JOIN Client_Accounts ca ON prm.Customer_Id = ca.Client_Accounts_Id
        WHERE (prd.ItemName LIKE CONCAT('%', p_Item_Name, '%') OR prd.ItemId = p_Item_Name)
          AND prd.DeleteStatus = 0 AND prm.DeleteStatus = 0
          
        UNION ALL
        
        SELECT 
            'In-House Stock' AS SupplierName,
            sd.EntryDate AS Date,
            sd.ItemName,
            sd.Brand,
            sd.Stock AS Qty,
            sd.SalesRate AS Price,
            sd.Tax AS Tax,
            (sd.SalesRate * sd.Stock) AS Total,
            'Stock' AS SourceType
        FROM Stock_Details sd
        INNER JOIN Stock s ON sd.Stock_Id = s.Stock_Id
        WHERE (sd.ItemName LIKE CONCAT('%', p_Item_Name, '%') OR sd.ItemId = p_Item_Name)
          AND sd.DeleteStatus = 0 AND s.DeleteStatus = 0
        ORDER BY Date DESC;
    END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Search_OutstandingReport`
BEGIN
    DECLARE group_flag TINYINT(1) DEFAULT 0;
    DECLARE groupslist INT DEFAULT 0;
    DECLARE subgroupslist INT DEFAULT 0;

    -- Drop existing temporary tables if they exist
    DROP TEMPORARY TABLE IF EXISTS group_table;
    DROP TEMPORARY TABLE IF EXISTS subgroup;
    DROP TEMPORARY TABLE IF EXISTS temp_accounts;
    DROP TEMPORARY TABLE IF EXISTS accountdisplay;

    -- Create temporary tables
    CREATE TEMPORARY TABLE group_table (groupid DECIMAL(18, 0));
    CREATE TEMPORARY TABLE subgroup (groupid DECIMAL(18, 0));
    CREATE TEMPORARY TABLE temp_accounts (
        acid DECIMAL(18, 0),
        name VARCHAR(250),
        Opening DECIMAL(18, 2)
    );
    CREATE TEMPORARY TABLE accountdisplay (
        SlNo DECIMAL(18, 0),
        Particulars VARCHAR(250),
        Opening DECIMAL(18, 2),
        OpenType VARCHAR(10),
        Debit DECIMAL(18, 2),
        Credit DECIMAL(18, 2),
        Closing DECIMAL(18, 2),
        CloseType VARCHAR(10)
    );
    
    -- Insert the initial GroupId
    INSERT INTO subgroup VALUES (GroupId);
    SET group_flag = 0;

    -- Loop through groups and subgroups
    WHILE (group_flag = 0) DO
        DELETE FROM group_table;
        INSERT INTO group_table 
        SELECT account_group_Id 
        FROM account_group 
        WHERE DeleteStatus = 0 
        AND Under_Group IN (SELECT groupid FROM subgroup);

        DELETE FROM subgroup;
        INSERT INTO subgroup 
        SELECT account_group_Id 
        FROM account_group 
        WHERE DeleteStatus = 0 
        AND Under_Group IN (SELECT groupid FROM group_table);

        SELECT COUNT(groupid) INTO groupslist FROM group_table;
        SELECT COUNT(groupid) INTO subgroupslist FROM subgroup;

        IF subgroupslist = groupslist OR subgroupslist = 0 THEN
            SET group_flag = 1;
        END IF;
    END WHILE;

    IF groupslist = 0 THEN
        INSERT INTO group_table VALUES (GroupId);
    END IF;

    IF NOT EXISTS (SELECT * FROM group_table WHERE groupid = GroupId) THEN
        INSERT INTO group_table VALUES (GroupId);
    END IF;

    -- Insert into temp_accounts table
    INSERT INTO temp_accounts
    SELECT 
        ca.client_accounts_Id AS acid,
        ca.Client_Accounts_Name AS name,
        IFNULL(ca.Opening_Balance, 0) + IFNULL(
            (SELECT SUM(IFNULL(A.Dr, 0) - IFNULL(A.Cr, 0))
             FROM Accounts A
             WHERE A.Client_Id = ca.client_accounts_Id
             AND A.Entry_Date < FromDate), 0) AS Opening
    FROM client_accounts ca
    WHERE ca.Account_Group_Id IN (SELECT groupid FROM group_table)
    AND ca.LedgerInclude = 'Y';

    -- Insert into accountdisplay
    INSERT INTO accountdisplay
    SELECT 
        ta.acid AS SlNo,
        ta.name AS Particulars,
        CASE WHEN ta.Opening < 0 THEN ABS(ta.Opening) ELSE ta.Opening END AS Opening,
        CASE WHEN ta.Opening < 0 THEN 'Cr' ELSE 'Dr' END AS OpenType,
        IFNULL((SELECT SUM(IFNULL(A.Dr, 0)) 
                FROM Accounts A 
                WHERE A.Client_Id = ta.acid 
                AND A.Entry_Date BETWEEN FromDate AND ToDate), 0) AS Debit,
        IFNULL((SELECT SUM(IFNULL(A.Cr, 0)) 
                FROM Accounts A 
                WHERE A.Client_Id = ta.acid 
                AND A.Entry_Date BETWEEN FromDate AND ToDate), 0) AS Credit,
        0 AS Closing,
        '' AS CloseType
    FROM temp_accounts ta;

    -- Update Closing balance and CloseType
    UPDATE accountdisplay
    SET Closing = ABS(Opening + Debit - Credit),
        CloseType = CASE 
            WHEN (Opening + Debit - Credit) < 0 THEN 'Cr'
            ELSE 'Dr'
        END;

    -- Select from accountdisplay with non-zero values
    SELECT * 
    FROM accountdisplay 
    WHERE Opening > 0 
        OR Debit > 0 
        OR Credit > 0 
        OR Closing > 0;

    -- Clean up temporary tables
    DROP TEMPORARY TABLE IF EXISTS group_table;
    DROP TEMPORARY TABLE IF EXISTS subgroup;
    DROP TEMPORARY TABLE IF EXISTS temp_accounts;
    DROP TEMPORARY TABLE IF EXISTS accountdisplay;

END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Search_outstanding_Report`
BEGIN
    DECLARE open DECIMAL(18, 2);
    DECLARE opendr DECIMAL(18, 2);
    DECLARE opencr DECIMAL(18, 2);
    DECLARE closebal DECIMAL(18, 2);
    DECLARE closbaldr DECIMAL(18, 2);
    DECLARE closbalcr DECIMAL(18, 2);
    DECLARE curdate DATE;

    SET curdate = CURRENT_DATE;

    IF (Voucher = 'Purchase') THEN
        SET open = COALESCE(oppurcr, 0) + COALESCE(OpBal, 0);
        SET opencr = COALESCE(open, 0);
        SET opendr = 0;
        SET closebal = (COALESCE(curpurcr, 0) + COALESCE(oppurcr, 0));
        SET closbaldr = 0;
        SET closbalcr = COALESCE(closebal, 0);

        SELECT * FROM (
            SELECT 1 AS SlNo, DATE_FORMAT(FromDate, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Opening Balance' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, opendr AS Dr, opencr AS Cr
            UNION
            SELECT 2 AS SlNo, DATE_FORMAT(PurchaseMaster.PurchaseDate, '%d/%m/%Y') AS E_Date, DATE_FORMAT(PurchaseDate + INTERVAL PaymentTerms DAY, '%d/%m/%Y') AS Terms,
                   DATEDIFF(curdate, DATE_ADD(EntryDate, INTERVAL PaymentTerms DAY)) AS Date_Dif, Acc_Name AS Particular, InvoiceNo AS VoucherNo, 'Purchase' AS Voucher, PurchaseMaster.Description1 AS Narration,
                   CurrecnyName AS TransactionCurrency, AccountType_Name AS EntryMode, 0 AS Dr, NetTotal - COALESCE(SUM(Payment_Reference.Amount), 0) AS Cr
            FROM PurchaseMaster
            INNER JOIN AccountType ON AccountType.AccountType_Id = PurchaseMaster.TypeId
            INNER JOIN CurrencyDetails ON CurrencyDetails.CurrencyDetails_Id = PurchaseMaster.CurrencyId
            INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = PurchaseMaster.Account_Party_Id AND ClientAccounts_Id = Client_Id
            LEFT JOIN Payment_Reference ON Payment_Reference.PurchaseMaster_Id = PurchaseMaster.PurchaseMaster_Id
            WHERE PurchaseMaster.DeleteStatus = FALSE
            AND PurchaseMaster.PurchaseDate BETWEEN FromDate AND ToDate
            AND (TypeId = 0 OR PurchaseMaster.TypeId = TypeId)
            AND (CurrencyId = 0 OR PurchaseMaster.CurrencyId = CurrencyId)
            GROUP BY PurchaseMaster.PurchaseMaster_Id, PurchaseDate, PaymentTerms, Acc_Name, InvoiceNo, PurchaseMaster.NetTotal, PurchaseMaster.Description1, CurrecnyName, AccountType_Name, EntryDate
            HAVING NetTotal - COALESCE(SUM(Payment_Reference.Amount), 0) > 0
            UNION
            SELECT 3 AS SlNo, DATE_FORMAT(ToDate, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Total' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, 0 AS Dr, curpurcr AS Cr
            UNION
            SELECT 4 AS SlNo, DATE_FORMAT(ToDate, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Balance Payment' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, closbaldr AS Dr, closbalcr AS Cr
        ) x
        ORDER BY SlNo, STR_TO_DATE(E_Date, '%d/%m/%Y') ASC;

    ELSEIF (Voucher = 'Payment') THEN
        SET open = COALESCE(oppaydr, 0) + COALESCE(OpBal, 0);
        SET opendr = COALESCE(open, 0);
        SET opencr = 0;
        SET closebal = (COALESCE(curpaydr, 0) + COALESCE(opendr, 0));
        SET closbaldr = COALESCE(closebal, 0);
        SET closbalcr = 0;

        SELECT * FROM (
            SELECT 1 AS SlNo, DATE_FORMAT(FromDate, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Opening Balance' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, opendr AS Dr, opencr AS Cr
            UNION
            SELECT 2 AS SlNo, DATE_FORMAT(PaymentVoucher.Date, '%d/%m/%Y') AS E_Date, Mode AS Terms, '' AS Date_Dif, Acc_Name AS Particular, Voucher_No AS VoucherNo, 'Payment' AS Voucher, PaymentVoucher.Description1 AS Narration, '' AS TransactionCurrency, '' AS EntryMode, Amount AS Dr, 0 AS Cr
            FROM PaymentVoucher
            INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = PaymentVoucher.To_Party_Id
            WHERE ClientAccounts_Id = Client_Id
            AND PaymentVoucher.Date BETWEEN FromDate AND ToDate
            AND PaymentVoucher.PaymentVoucher_Id NOT IN (SELECT Payment_Id FROM Payment_Reference)
            AND PaymentVoucher.DeleteStatus = FALSE
            AND (CurrencyId = 0 OR PaymentVoucher.CurrencyId = CurrencyId)
            UNION
            SELECT 3 AS SlNo, DATE_FORMAT(ToDate, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Total' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, curpaydr AS Dr, 0 AS Cr
            UNION
            SELECT 4 AS SlNo, DATE_FORMAT(ToDate, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Balance Payment' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, closbaldr AS Dr, closbalcr AS Cr
        ) x
        ORDER BY SlNo, STR_TO_DATE(E_Date, '%d/%m/%Y') ASC;

    ELSEIF (Voucher = 'Receipt') THEN
        SET open = COALESCE(opreccr, 0) + COALESCE(OpBal, 0);
        SET opencr = COALESCE(open, 0);
        SET opendr = 0;
        SET closebal = (COALESCE(curreccr, 0) + COALESCE(oppurcr, 0));
        SET closbaldr = 0;
        SET closbalcr = COALESCE(closebal, 0);

        SELECT * FROM (
            SELECT 1 AS SlNo, DATE_FORMAT(FromDate, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Opening Balance' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, opendr AS Dr, opencr AS Cr
            UNION
            SELECT 2 AS SlNo, DATE_FORMAT(RecieptVoucher.Date, '%d/%m/%Y') AS E_Date, Mode AS Terms, '' AS Date_Dif, Acc_Name AS Particular, Receipt_No AS VoucherNo, 'Receipt' AS Voucher, RecieptVoucher.Description1 AS Narration, '' AS TransactionCurrency, '' AS EntryMode, 0 AS Dr, Amount AS Cr
            FROM RecieptVoucher
            INNER JOIN ClientAccounts ON ClientAccounts.ClientAccounts_Id = RecieptVoucher.Frm_Party_Id
            WHERE ClientAccounts_Id = Client_Id
            AND RecieptVoucher.Date BETWEEN FromDate AND ToDate
            AND RecieptVoucher.RecieptVoucher_Id NOT IN (SELECT Receipt_Id FROM Receipt_Reference)
            AND RecieptVoucher.DeleteStatus = FALSE
            AND (CurrencyId = 0 OR RecieptVoucher.CurrencyId = CurrencyId)
            UNION
            SELECT 3 AS SlNo, DATE_FORMAT(ToDate, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Total' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, 0 AS Dr, curreccr AS Cr
            UNION
            SELECT 4 AS SlNo, DATE_FORMAT(ToDate, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Balance Payment' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, closbaldr AS Dr, closbalcr AS Cr
        ) x
        ORDER BY SlNo, STR_TO_DATE(E_Date, '%d/%m/%Y') ASC;

    ELSEIF (Voucher = 'Journal') THEN
        SET open = COALESCE(opjurdr, 0) + COALESCE(OpBal, 0);
        SET opendr = COALESCE(open, 0);
        SET opencr = 0;
        SET closebal = (COALESCE(curjurdr, 0) + COALESCE(opendr, 0));
        SET closbaldr = COALESCE(closebal, 0);
        SET closbalcr = 0;

        SELECT * FROM (
            SELECT 1 AS SlNo, DATE_FORMAT(FromDate, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Opening Balance' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, opendr AS Dr, opencr AS Cr
            UNION
            SELECT 2 AS SlNo, DATE_FORMAT(JournalMaster.Date, '%d/%m/%Y') AS E_Date, Mode AS Terms, '' AS Date_Dif, Acc_Name AS Particular, Voucher_No AS VoucherNo, 'Journal' AS Voucher, JournalMaster.Description1 AS Narration, '' AS TransactionCurrency, '' AS EntryMode, Amount AS Dr, 0 AS Cr
            FROM JournalMaster
            WHERE JournalMaster.Date BETWEEN FromDate AND ToDate
            AND JournalMaster.DeleteStatus = FALSE
            AND Client_Id = Client_Id
            AND (CurrencyId = 0 OR JournalMaster.CurrencyId = CurrencyId)
            UNION
            SELECT 3 AS SlNo, DATE_FORMAT(ToDate, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Total' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, closbaldr AS Dr, 0 AS Cr
            UNION
            SELECT 4 AS SlNo, DATE_FORMAT(ToDate, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Balance Payment' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, closbaldr AS Dr, closbalcr AS Cr
        ) x
        ORDER BY SlNo, STR_TO_DATE(E_Date, '%d/%m/%Y') ASC;

    ELSEIF (Voucher = 'Contra') THEN
        SET open = COALESCE(opcondr, 0) + COALESCE(OpBal, 0);
        SET opendr = COALESCE(open, 0);
        SET opencr = 0;
        SET closebal = (COALESCE(curcondr, 0) + COALESCE(opendr, 0));
        SET closbaldr = COALESCE(closebal, 0);
        SET closbalcr = 0;

        SELECT * FROM (
            SELECT 1 AS SlNo, DATE_FORMAT(FromDate, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Opening Balance' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, opendr AS Dr, opencr AS Cr
            UNION
            SELECT 2 AS SlNo, DATE_FORMAT(ContraMaster.Date, '%d/%m/%Y') AS E_Date, Mode AS Terms, '' AS Date_Dif, Acc_Name AS Particular, Voucher_No AS VoucherNo, 'Contra' AS Voucher, ContraMaster.Description1 AS Narration, '' AS TransactionCurrency, '' AS EntryMode, Amount AS Dr, 0 AS Cr
            FROM ContraMaster
            WHERE ContraMaster.Date BETWEEN FromDate AND ToDate
            AND ContraMaster.DeleteStatus = FALSE
            AND (CurrencyId = 0 OR ContraMaster.CurrencyId = CurrencyId)
            UNION
            SELECT 3 AS SlNo, DATE_FORMAT(ToDate, '%d/%m/%Y') AS E_Date, '' AS Terms, '' AS Date_Dif, '' AS Particular, '' AS VoucherNo, 'Total' AS Voucher, '' AS Narration, '' AS TransactionCurrency, '' AS EntryMode, closbaldr AS Dr, closbalcr AS Cr
        ) x
        ORDER BY SlNo, STR_TO_DATE(E_Date, '%d/%m/%Y') ASC;

    END IF;

END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Search_PackingDEtail`
BEGIN
    DECLARE Search_Date_ VARCHAR(500);
    DECLARE SearchbyName_Value LONGTEXT;
         DECLARE Cleaned_Part_No VARCHAR(200);

    
    SET Search_Date_ = '';
    SET SearchbyName_Value = '';

   if(Quot_No_ ='undefined') then
    set Quot_No_ = '';
    end if;
    
     if(Part_No_ ='undefined') then
    set Part_No_ = '';
    end if;

    IF Is_Date_Check_ = 1 THEN
        SET Search_Date_ = CONCAT(" AND packinglist_master.EntryDate >= '", From_Date_, "' AND packinglist_master.EntryDate <= '", To_Date_, "'");
    END IF;

    IF Account_Party_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND packinglist_master.Account_Party_Id = ", Account_Party_Id_);
    END IF;

    IF Quot_No_ != '' THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND packinglist_master.Packing_List_No = '", Quot_No_, "'");
    END IF;

   /* IF Part_No_ != '' THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND packinglist_details.ItemCode = '", Part_No_, "'");
    END IF;*/


    IF Part_No_ IS NOT NULL AND Part_No_ != '' THEN
        SET Cleaned_Part_No = REPLACE(Part_No_, '%', '\%');
        SET Cleaned_Part_No = REPLACE(Cleaned_Part_No, '', '\'); 

        SET SearchbyName_Value = CONCAT(
            " AND  packinglist_details.ItemCode LIKE ", 
            QUOTE(CONCAT('%', Cleaned_Part_No, '%')) 
        );
    END IF;
    IF Item_Group_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND packinglist_details.GroupId = ", Item_Group_Id_);
    END IF;

    IF CurrencyDetails_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND packinglist_master.CurrencyId = ", CurrencyDetails_Id_);
    END IF;

    IF User_Details_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND packinglist_master.AttendEmployee = ", User_Details_Id_);
    END IF;
    
        insert into db_logs values(0,SearchbyName_Value,'','');

	IF User_Type_ = 2 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND packinglist_master.User_Id = ", Login_User_Id_);
    END IF;
    

   SET @query = CONCAT("
    SELECT DISTINCT
         packinglist_master.PackingList_Master_Id ,
     packinglist_master.Account_Party_Id ,
      DATE_FORMAT(packinglist_master.EntryDate, '%Y-%m-%d') EntryDate ,
     packinglist_master.CurrencyId ,
     packinglist_master.Packing_List_No ,
     packinglist_master.PaymentTerms ,
	 packinglist_master.POnumber,
	packinglist_master.Invoice_No,
     packinglist_master.AttendEmployee ,
     packinglist_master.Brand ,
     packinglist_master.PriceBasis ,
     packinglist_master.Delivery ,
     packinglist_master.Validity ,
     packinglist_master.Description1 ,
     packinglist_master.User_Id ,
     packinglist_master.DeleteStatus ,
     packinglist_master.Delivery_Address1 ,
     packinglist_master.Delivery_Address2 ,
     packinglist_master.Delivery_Address3 ,
     packinglist_master.Delivery_Address4 ,
     packinglist_master.KindAttend ,
     packinglist_master.Payment_Term_Description ,
     packinglist_master.CurrecnyName ,
     packinglist_master.Reference ,
     packinglist_master.UserName ,
     packinglist_master.PaymentTermValue ,
     packinglist_master.AttendEmployeeId ,
     packinglist_master.KindAttendId ,
     packinglist_master.Total_No_Of_Boxes ,
     packinglist_master.Box_Details ,
     packinglist_master.Total_Weight ,
     packinglist_master.Consignee_Address ,
     packinglist_master.TotalAmount ,
     packinglist_master.TotalDiscount ,
     packinglist_master.TaxableAmount ,
     packinglist_master.VatAmount ,
     packinglist_master.NetTotal ,
     packinglist_master.vat_percentage ,
        DATE_FORMAT(packinglist_master.EntryDate, '%d-%m-%Y') AS Formatted_EntryDate,      
        client_accounts.Client_Accounts_Name AS Customer,
        Reference as Description2, 
        Packing_List_No as PackingList_No ,
		DATE_FORMAT(packinglist_master.EntryDate, '%d-%m-%Y') AS PrintDate,
        IFNULL(qdo.SalesQuotationMaster_Id,0) SalesQuotationMaster_Id
    FROM packinglist_master 
    INNER JOIN packinglist_details ON packinglist_master.PackingList_Master_Id = packinglist_details.PackingList_Master_Id
        INNER JOIN client_accounts ON packinglist_master.Account_Party_Id = client_accounts.Client_Accounts_Id 
            LEFT JOIN quotation_packinglist qdo ON qdo.PackingList_Master_Id = packinglist_master.PackingList_Master_Id
    WHERE packinglist_master.DeleteStatus = FALSE ",
    Search_Date_, 
    SearchbyName_Value,
    " ORDER BY PackingList_Master_Id asc;"    
);
    PREPARE QUERY FROM @query;

    EXECUTE QUERY;
END
$$
DELIMITER ;

DELIMITER $$
