DELIMITER $$
CREATE PROCEDURE `Search_payment_term`
Begin 
 #set search_payment_term_ = Concat( '%',search_payment_term_ ,'%');
  SET search_payment_term_ = REPLACE(search_payment_term_, '\', '\\'); -- Escape backslash
    SET search_payment_term_ = REPLACE(search_payment_term_, '%', '\%');  -- Escape percentage
    SET search_payment_term_ = REPLACE(search_payment_term_, '', '\');  -- Escape underscore
    SET search_payment_term_ = CONCAT('%', search_payment_term_, '%');
    
 SELECT payment_Term_ID,Payment_Term_Description
 From payment_term 
 where Payment_Term_Description like search_payment_term_ and DeleteStatus=false ;
 End
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Search_Payment_Voucher`
Begin 
 declare Search_Date_ varchar(500);
declare SearchbyName_Value varchar(2000); declare Search_User varchar(500);
set Search_Date_="";
set SearchbyName_Value="";set Search_User="";
 if Is_Date_Check_=true then
set Search_Date_=concat( " and Payment_Voucher.Date >= '", From_Date_ ,"' and  Payment_Voucher.Date <= '", To_Date_,"'");
end if;
if To_Account_Id_>0 then
SET SearchbyName_Value =concat(SearchbyName_Value," and Payment_Voucher.To_Party_Id =",To_Account_Id_);
end if;
if Voucher_No_>0 then
SET SearchbyName_Value =concat(SearchbyName_Value," and Concat( Payment_Voucher.Voucher_No ,'')  =",Voucher_No_);
end if;

if User_Type = 2 then
SET SearchbyName_Value =concat(SearchbyName_Value," and payment_voucher.User_Id =",Login_User);
end if;
if CurrencyId_>0 then
SET Search_User =concat(Search_User," and payment_voucher.CurrencyId =",CurrencyId_);
end if;
SET @query = Concat("
 SELECT Payment_Voucher_Id,Payment_Voucher.From_Account_Id,FromAcc.Client_Accounts_Name as FromAccount_Name,
(Date_Format(Payment_Voucher.Date,'%Y-%m-%d')) As Date , (Date_Format(Payment_Voucher.Date,'%d-%m-%Y')) As Search_Date, 
Amount,Payment_Voucher.To_Party_Id,ToAcc.Client_Accounts_Name as ToAccount_Name,ToAcc.Address1,
ToAcc.Address2,ToAcc.Address3,ToAcc.Address4,ToAcc.PinCode,ToAcc.GSTNo,ToAcc.Phone,ToAcc.Mobile,ToAcc.Email,ToAcc.GSTNo,
Concat( Payment_Voucher.Voucher_No ,'') Voucher_No,Payment_Voucher.User_Id,Payment_Voucher.Payment_Mode_Name as Mode,
Payment_Voucher.Description,Payment_Voucher.CurrencyId
 From Payment_Voucher 
inner join Client_Accounts as FromAcc on FromAcc.Client_Accounts_Id=Payment_Voucher.From_Account_Id
inner join Client_Accounts as ToAcc on ToAcc.Client_Accounts_Id=Payment_Voucher.To_Party_Id
 where Payment_Voucher.DeleteStatus=false", Search_Date_ ,SearchbyName_Value, Search_User,"");
PREPARE QUERY FROM @query;
EXECUTE QUERY;
End
$$
DELIMITER ;

