    price_request_master.Description2,price_request_master.Basic_Discount,price_request_master.Amount_In_Words,price_request_master.PreparedBy,price_request_master.Charge1per,price_request_master.Payment_Term_Description,price_request_master.VAT_Description,price_request_master.VAT_Percentage,price_request_master.VAT_Amount,price_request_master.SalesQuotation_Image,
    price_request_master.Acknolodgement_Image,price_request_master.CurrecnyName,price_request_master.UserName,price_request_master.PaymentTermValue,price_request_master.AttendEmployeeId,price_request_master.KindAttendId,
    DATE_FORMAT(price_request_master.EntryDate, '%d-%m-%Y') AS FormattedEntryDate,
