DELIMITER $$
CREATE PROCEDURE `Search_ProfitAndLoss`
BEGIN
    DECLARE StockValue DECIMAL(18,2) DEFAULT 0;
    DECLARE PurchaseValue DECIMAL(18,2) DEFAULT 0;
    DECLARE SalesValue DECIMAL(18,2) DEFAULT 0;
    DECLARE SalesValue_PurchaseRate DECIMAL(18,2) DEFAULT 0;
    DECLARE OpenStock DECIMAL(18,2) DEFAULT 0;
    DECLARE Profit DECIMAL(18,2) DEFAULT 0;
    DECLARE Loss DECIMAL(18,2) DEFAULT 0;

    -- Calculate StockValue
    SELECT IFNULL(SUM(Quantity * IFNULL(PurchaseRate, 0)), 0)
    INTO StockValue
    FROM Stock
    WHERE DeleteStatus = 'False';

    -- Calculate PurchaseValue
    SELECT IFNULL(SUM(NetValue), 0)
    INTO PurchaseValue
    FROM purchase_details 
    INNER JOIN purchase_master ON purchase_details.Purchase_Master_Id = purchase_master.Purchase_Master_Id
    WHERE purchase_details.DeleteStatus = 'False'
      AND DATE(purchase_master.PurchaseDate) BETWEEN DATE(FromDate) AND DATE(ToDate);

    -- Calculate SalesValue
    SELECT IFNULL(SUM(sales_details.Quantity * sales_details.UnitPrice) - IFNULL(SUM(sales_details.Item_Discount_Amount), 0), 0)
    INTO SalesValue
    FROM sales_details
    INNER JOIN sales_master ON sales_details.Sales_Master_Id = sales_master.Sales_Master_Id
    WHERE sales_details.DeleteStatus = 'False'
      AND DATE(sales_master.EntryDate) BETWEEN DATE(FromDate) AND DATE(ToDate);

    -- Calculate SalesValue_PurchaseRate
    SELECT IFNULL(SUM(sales_details.Quantity * sales_details.PurchaseRate) - IFNULL(SUM(sales_details.Item_Discount_Amount), 0), 0)
    INTO SalesValue_PurchaseRate
    FROM sales_details
    INNER JOIN sales_master ON sales_details.Sales_Master_Id = sales_master.Sales_Master_Id
    WHERE sales_details.DeleteStatus = 'False'
      AND DATE(sales_master.EntryDate) BETWEEN DATE(FromDate) AND DATE(ToDate);

    -- Calculate OpenStock
    SET OpenStock = (IFNULL(StockValue, 0) + IFNULL(SalesValue_PurchaseRate, 0)) - IFNULL(PurchaseValue, 0);

    -- Calculate Profit and Loss
    SET Profit = OpenStock + PurchaseValue;
    SET Loss = SalesValue + StockValue;
    SET Profit = Profit - Loss;

    IF Profit > 0 THEN
        SET Loss = 0;
    ELSE
        SET Loss = -Profit;
        SET Profit = 0;
    END IF;

    -- Return the result
    SELECT 1 AS tp, 'Opening Stock' AS Caption1, OpenStock AS Data1, 'Sales' AS Caption2, SalesValue AS Data2
    UNION
    SELECT 2 AS tp, 'Purchase' AS Caption1, PurchaseValue AS Data1, 'Closing Stock' AS Caption2, StockValue AS Data2
    UNION
    SELECT 3 AS tp, 'Profit' AS Caption1, Profit AS Data1, 'Loss' AS Caption2, Loss AS Data2
    ORDER BY tp;
    
END
$$
DELIMITER ;

