 DATE_FORMAT(purchaseordermaster.EntryDate, '%Y-%m-%d') EntryDate,DATE_FORMAT(purchaseordermaster.PurchaseDate, '%Y-%m-%d') PurchaseDate,
 DATE_FORMAT(purchaseordermaster.DeliveryDate, '%Y-%m-%d') DeliveryDate,
purchaseordermaster.InvoiceNo,purchaseordermaster.CurrencyId,purchaseordermaster.TypeId,purchaseordermaster.PaymentTerms,purchaseordermaster.AttendEmployee,
purchaseordermaster.TotalAmount,purchaseordermaster.TotalDiscount,purchaseordermaster.TaxableAmount,purchaseordermaster.VatAmount,purchaseordermaster.NetTotal,
purchaseordermaster.Total_Amount,purchaseordermaster.Brand,purchaseordermaster.PriceBasis,purchaseordermaster.Delivery,purchaseordermaster.Validity,purchaseordermaster.Description1,
purchaseordermaster.User_Id,purchaseordermaster.DeleteStatus,purchaseordermaster.Delivery_Address1,purchaseordermaster.Delivery_Address2,purchaseordermaster.Delivery_Address3,
purchaseordermaster.Delivery_Address4,purchaseordermaster.KindAttend,purchaseordermaster.Charge1,purchaseordermaster.charge1_Amount,purchaseordermaster.Charge2,
purchaseordermaster.charge2_Amount,purchaseordermaster.Discount_Description,purchaseordermaster.Additional_Discount,purchaseordermaster.Description2,
purchaseordermaster.Basic_Discount,purchaseordermaster.Amount_In_Words,purchaseordermaster.PreparedBy,purchaseordermaster.Charge1per,purchaseordermaster.Payment_Term_Description,
purchaseordermaster.VAT_Description,purchaseordermaster.VAT_Percentage,purchaseordermaster.VAT_Amount,purchaseordermaster.Customer_Reference,purchaseordermaster.Roundoff_Amt,
purchaseordermaster.Purchase_Order_Image,purchaseordermaster.UserName,purchaseordermaster.CurrecnyName,purchaseordermaster.PaymentTermValue,
 purchaseordermaster.PurchaseOrderMaster_Id as Purchase_OrderMaster_Id,DATE_FORMAT(purchaseordermaster.EntryDate, '%d-%m-%Y') AS FormattedEntryDate,
 purchaseordermaster.InvoiceNo as OrderNumber,purchaseordermaster.NetTotal,currencydetails.CurrecnyName,client_accounts.Client_Accounts_Name AS Customer,
purchaseordermaster.TypeId AS AccountType_Id,DATE_FORMAT(purchaseordermaster.EntryDate, '%d-%m-%Y') AS PrintDate,
IFNULL(qpe.SalesQuotationMaster_Id,0) SalesQuotationMaster_Id,
purchaseordermaster.Supplier_Ref_No
    FROM purchaseordermaster 
    INNER JOIN purchaseorderdetails ON purchaseordermaster.PurchaseOrderMaster_Id = purchaseorderdetails.PurchaseOrderId
    INNER JOIN client_accounts ON purchaseordermaster.Account_Party_Id = client_accounts.Client_Accounts_Id 
    LEFT JOIN currencydetails ON purchaseordermaster.CurrencyId = currencydetails.CurrencyDetails_Id
    	LEFT JOIN quotation_purchaseordermaster qpe ON qpe.PurchaseOrderMaster_Id = purchaseordermaster.PurchaseOrderMaster_Id

    WHERE purchaseordermaster.DeleteStatus = 0 ",
    Search_Date_, 
    SearchbyName_Value,
    " ORDER BY PurchaseOrderMaster_Id ASC; "
);

    PREPARE QUERY FROM @query;
    EXECUTE QUERY;
END
$$
DELIMITER ;

