CREATE PROCEDURE `Search_PurchaseOrderNumber_DeliveryOrderMaster_Typeahead`
BEGIN 

SET InvoiceNo_ = Concat( '%',InvoiceNo_ ,'%');

IF DeliveryOrderMaster_Id_ = 0 THEN
	 SELECT DISTINCT *,0 AS Is_Checked FROM purchaseordermaster 
     WHERE InvoiceNo LIKE InvoiceNo_ 
     AND DeleteStatus=false ;
ELSE 
	SELECT DISTINCT 
			po.*,
			CASE WHEN dopo.Is_Checked>0 THEN 1 ELSE 0 END AS Is_Checked
	 FROM purchaseordermaster po 
	LEFT JOIN deliveryordermaster_purchaseordermaster dopo ON po.PurchaseOrderMaster_Id = dopo.PurchaseOrderMaster_Id
			AND dopo.DeleteStatus = 0 
			AND dopo.DeliveryOrderMaster_Id = DeliveryOrderMaster_Id_
	WHERE
		po.InvoiceNo LIKE InvoiceNo_ 
		AND po.DeleteStatus=false ;
 END IF;
 
 END
$$
DELIMITER ;

