CREATE PROCEDURE `Search_Receipt_Voucher`
Begin 
 declare Search_Date_ varchar(500);
declare SearchbyName_Value varchar(2000); declare Search_User varchar(500);
set Search_Date_="";
set SearchbyName_Value="";set Search_User="";
 if Is_Date_Check_=true then
set Search_Date_=concat( " and receipt_voucher.Date >= '", From_Date_ ,"' and  receipt_voucher.Date <= '", To_Date_,"'");
end if;
if To_Account_Id_>0 then
SET SearchbyName_Value =concat(SearchbyName_Value," and receipt_voucher.Frm_Party_Id =",To_Account_Id_);
end if;
if Voucher_No_>0 then
SET SearchbyName_Value =concat(SearchbyName_Value," and Concat( receipt_voucher.Receipt_No ,'')  =",Voucher_No_);
end if;
if CurrencyId_>0 then
SET SearchbyName_Value =concat(SearchbyName_Value," and receipt_voucher.CurrencyId  =",CurrencyId_);
end if;
/*if User_Type = 2 then
SET SearchbyName_Value =concat(SearchbyName_Value," and receipt_voucher.User_Id  =",Login_User);
end if;*/


SET @query = Concat("
 SELECT Receipt_Voucher_Id,receipt_voucher.Frm_Party_Id,FromAcc.Client_Accounts_Name as FromAccount_Name,
(Date_Format(receipt_voucher.Date,'%Y-%m-%d')) As Date , (Date_Format(receipt_voucher.Date,'%d-%m-%Y')) As Search_Date, 
Amount,receipt_voucher.To_Party_Id,ToAcc.Client_Accounts_Name as ToAccount_Name,FromAcc.Address1,
FromAcc.Address2,FromAcc.Address3,FromAcc.Address4,FromAcc.PinCode,FromAcc.GSTNo,FromAcc.Phone,FromAcc.Mobile,FromAcc.Email,FromAcc.GSTNo,
receipt_voucher.Print_Caption_Id,receipt_voucher.Receipt_No,
receipt_voucher.User_Id,receipt_voucher.Payment_Mode_Name as Mode,
receipt_voucher.Description,receipt_voucher.CurrencyId,
receipt_voucher.Frm_Party_Id as From_Account_Id,receipt_voucher.To_Party_Id as To_Account_Id
 From receipt_voucher 
inner join Client_Accounts as FromAcc on FromAcc.Client_Accounts_Id=receipt_voucher.Frm_Party_Id
inner join Client_Accounts as ToAcc on ToAcc.Client_Accounts_Id=receipt_voucher.To_Party_Id
 where receipt_voucher.DeleteStatus=false", Search_Date_ ,SearchbyName_Value,Search_User,"");
PREPARE QUERY FROM @query;
insert into db_logs values(0,@query,'','');
EXECUTE QUERY;

End
$$
