CREATE PROCEDURE `Search_Requirement`
BEGIN
    DECLARE Search_Date_ VARCHAR(500);
    DECLARE SearchbyName_Value VARCHAR(2000);    DECLARE Cleaned_Part_No VARCHAR(200);

    delete from db_logs;
    SET Search_Date_ = '';
    SET SearchbyName_Value = '';
    
    if(RequirementNo_ ='undefined') then
    set RequirementNo_ = '';
    end if;
    
     if(Part_No_ ='undefined') then
    set Part_No_ = '';
    end if;

    IF Is_Date_Check_ = 1 THEN
        SET Search_Date_ = CONCAT(" AND requirementmaster.EntryDate >= '", From_Date_, "' AND requirementmaster.EntryDate <= '", To_Date_, "'");
    END IF;

    IF Account_Party_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND requirementmaster.Account_Party_Id = ", Account_Party_Id_);
    END IF;

    IF RequirementNo_ !='' THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND requirementmaster.RequirementNo = '", RequirementNo_, "'");
    END IF;

   /* IF Part_No_ != '' THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND salesquotationdetails.ItemCode = '", Part_No_, "'");
    END IF;*/
     IF Part_No_ IS NOT NULL AND Part_No_ != '' THEN
        SET Cleaned_Part_No = REPLACE(Part_No_, '%', '\%');
        SET Cleaned_Part_No = REPLACE(Cleaned_Part_No, '_', '\_'); 

        SET SearchbyName_Value = CONCAT(
            " AND  requirementdetails.ItemCode LIKE ", 
            QUOTE(CONCAT('%', Cleaned_Part_No, '%')) 
        );
    END IF;

    IF Item_Group_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND requirementdetails.GroupId = ", Item_Group_Id_);
    END IF;

    IF CurrencyDetails_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND requirementmaster.CurrencyId = ", CurrencyDetails_Id_);
    END IF;

    IF User_Details_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND requirementmaster.AttendEmployee = ", User_Details_Id_);
    END IF;
    
	IF User_Type_ = 2 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND requirementmaster.User_Id = ", Login_User_Id_);
    END IF;

   SET @query = CONCAT("  
    SELECT distinct requirementmaster.RequirementMaster_Id,requirementmaster.Account_Party_Id,requirementmaster.SONo,requirementmaster.RequirementNo,
    requirementmaster.POnumber,requirementmaster.CurrencyId,requirementmaster.TypeId,requirementmaster.PaymentTerms,requirementmaster.AttendEmployee,
    requirementmaster.TotalAmount,requirementmaster.TotalDiscount,requirementmaster.TaxableAmount,requirementmaster.VatAmount,requirementmaster.Roundoff_Amt,
    requirementmaster.Total_Amount,requirementmaster.NetTotal,requirementmaster.Brand,requirementmaster.PriceBasis,requirementmaster.Delivery,
    requirementmaster.Validity,requirementmaster.Description1,requirementmaster.User_Id,requirementmaster.Delivery_Address1,requirementmaster.Delivery_Address2,
    requirementmaster.Delivery_Address3,requirementmaster.Delivery_Address4,requirementmaster.KindAttend,requirementmaster.Charge1,requirementmaster.charge1_Amount,
    requirementmaster.Charge2,requirementmaster.charge2_Amount,requirementmaster.Discount_Description,requirementmaster.Additional_Discount,
    requirementmaster.Description2,requirementmaster.Basic_Discount,requirementmaster.Amount_In_Words,requirementmaster.PreparedBy,requirementmaster.Charge1per,
    requirementmaster.Payment_Term_Description,requirementmaster.VAT_Description,requirementmaster.VAT_Percentage,requirementmaster.VAT_Amount,
    requirementmaster.SalesQuotation_Image,requirementmaster.Acknolodgement_Image,requirementmaster.CurrecnyName,requirementmaster.UserName,requirementmaster.PaymentTermValue,
    requirementmaster.AttendEmployeeId,requirementmaster.KindAttendId,DATE_FORMAT(requirementmaster.EntryDate, '%d-%m-%Y') AS FormattedEntryDate,
    DATE_FORMAT(requirementmaster.EntryDate, '%Y-%m-%d') AS EntryDate,requirementmaster.Supplier_Ref_No,requirementmaster.RequirementNo,requirementmaster.NetTotal,
        client_accounts.Client_Accounts_Name AS Customer_Name,
        DATE_FORMAT(requirementmaster.EntryDate, '%d-%m-%Y') AS PrintDate
    FROM requirementmaster 
    INNER JOIN requirementdetails ON requirementmaster.RequirementMaster_Id = requirementdetails.RequirementMaster_Id
    INNER JOIN client_accounts ON requirementmaster.Account_Party_Id = client_accounts.Client_Accounts_Id 
    WHERE requirementmaster.DeleteStatus = 0", Search_Date_, SearchbyName_Value,"
     ORDER BY RequirementMaster_Id ASC; " 
);
    PREPARE QUERY FROM @query;
    insert into db_logs values(0,@query,'','');
    EXECUTE QUERY;
END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Search_requirementdetails`
BEGIN
    SELECT *, ItemCode AS Item_Code FROM requirementdetails 
    WHERE ItemName LIKE CONCAT('%', requirementdetails_Name_, '%') AND DeleteStatus = 0;
END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `Search_requirementmaster`
BEGIN
    SELECT DISTINCT rm.*, ca.Client_Accounts_Name AS Customer_Name 
    FROM requirementmaster rm
    LEFT JOIN Client_Accounts ca ON rm.Account_Party_Id = ca.Client_Accounts_Id
    LEFT JOIN requirementdetails rd ON rm.RequirementMaster_Id = rd.RequirementMaster_Id
    WHERE rm.DeleteStatus = 0
    AND (Is_Date_Check_ = 0 OR (rm.EntryDate >= From_Date_ AND rm.EntryDate <= To_Date_))
    AND (Customer_ = 0 OR rm.Account_Party_Id = Customer_)
    AND (RequirementNo_ = '' OR rm.RequirementNo LIKE CONCAT('%', RequirementNo_, '%'))
    AND (Item_Group_Id_ = 0 OR rd.GroupId = Item_Group_Id_)
    AND (CurrencyDetails_Id_ = 0 OR rm.CurrencyId = CurrencyDetails_Id_)
    AND (User_Details_Id_ = 0 OR rm.User_Id = User_Details_Id_)
    AND (User_Type_ = 1 OR rm.User_Id = Login_User_Id_)
    AND (partNo_ = '' OR rd.ItemCode LIKE CONCAT('%', partNo_, '%') OR rd.ItemName LIKE CONCAT('%', partNo_, '%'))
    ORDER BY rm.RequirementMaster_Id DESC;
END
$$
DELIMITER ;

