    END IF;*/
     IF Part_No_ IS NOT NULL AND Part_No_ != '' THEN
        SET Cleaned_Part_No = REPLACE(Part_No_, '%', '\%');
        SET Cleaned_Part_No = REPLACE(Cleaned_Part_No, '', '\'); 

        SET SearchbyName_Value = CONCAT(SearchbyName_Value,
            " AND  sales_details.ItemCode LIKE ", 
