        );
    END IF;
    IF Item_Group_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND sales_details.GroupId = ", Item_Group_Id_);
    END IF;
    IF CurrencyDetails_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND sales_master.CurrencyId = ", CurrencyDetails_Id_);
    END IF;    
    IF AccountType_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND sales_master.TypeId = ", AccountType_Id_);
    END IF;
    IF User_Details_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND sales_master.User_Id = ", User_Details_Id_);
    END IF;  
    
	IF User_Type = 2 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value, " AND sales_master.User_Id = ", Login_User_Id);
    END IF;
    
SET @query = Concat(" SELECT DISTINCT sales_master.Sales_Master_Id,sales_master.Account_Party_Id,(Date_Format(sales_master.EntryDate,'%Y-%m-%d'))as EntryDate,
sales_master.Invoice_No,sales_master.LPONo,sales_master.DONo,sales_master.PackingListNumber,sales_master.CurrencyId,sales_master.TypeId,
sales_master.PaymentTerms,sales_master.TotalAmount,sales_master.TotalDiscount,sales_master.TaxableAmount,sales_master.VatAmount,sales_master.Total_Amount,
sales_master.Roundoff_Amt,sales_master.NetTotal,sales_master.Makes,sales_master.PriceBasis,sales_master.Description1,sales_master.User_Id,
sales_master.Delivery_Address1,sales_master.Delivery_Address2,sales_master.Delivery_Address3,sales_master.Delivery_Address4,sales_master.KindAttend,
sales_master.Charge1,sales_master.charge1_Amount,sales_master.Charge2,sales_master.charge2_Amount,sales_master.Discount_Description,
sales_master.Additional_Discount,sales_master.Description2,sales_master.Employee,sales_master.Basic_Discount,sales_master.Amount_In_Words,sales_master.Notes,
sales_master.Charge1per,sales_master.Payment_Term_Description,sales_master.VAT_Description,sales_master.VAT_percentage,sales_master.VAT_Amount,
sales_master.New_Entry,sales_master.Customer_Reference,(Date_Format(sales_master.SupplyDate,'%Y-%m-%d')) SupplyDate,
(Date_Format(sales_master.SupplyDate,'%d-%m-%Y')) SupplyPrintDate,(Date_Format(sales_master.DueDate,'%d-%m-%Y')) DuePrintDate,
(Date_Format(sales_master.DueDate,'%Y-%m-%d')) DueDate,sales_master.PaymentTermValue,(Date_Format(sales_master.EntryDate,'%d-%m-%Y')) As FormattedEntryDate,
sales_master.Invoice_No,sales_master.LPONo,Sales_Master.NetTotal,Client_Accounts.Client_Accounts_Name as Customer,
DATE_FORMAT(sales_master.EntryDate, '%d-%m-%Y') AS PrintDate,currencydetails.CurrecnyName,accounttype.AccountType_Name,
IFNULL(qsm.SalesQuotationMaster_Id,0) SalesQuotationMaster_Id
FROM sales_master 
INNER JOIN Client_Accounts ON sales_master.Account_Party_Id=Client_Accounts.Client_Accounts_Id 
INNER JOIN sales_details ON Sales_Master.Sales_Master_Id=sales_details.Sales_Master_Id
INNER JOIN accounttype on Sales_Master.TypeId=accounttype.AccountType_Id
INNER JOIN currencydetails ON Sales_Master.CurrencyId=currencydetails.CurrencyDetails_Id
LEFT JOIN quotation_salesmaster qsm ON qsm.SalesMaster_Id = sales_master.Sales_Master_Id
