CREATE PROCEDURE `Search_Sales_Order_Master`
BEGIN 

    DECLARE Search_Date_ VARCHAR(500);
    DECLARE SearchbyName_Value VARCHAR(2000);
    DECLARE Cleaned_Part_No VARCHAR(200);

    SET Search_Date_ = "";
    SET SearchbyName_Value = "";

    IF Is_Date_Check_ = TRUE THEN
        SET Search_Date_ = CONCAT(
            " AND sales_order_master.EntryDate >= '", From_Date_,
            "' AND sales_order_master.EntryDate <= '", To_Date_, "'"
        );
    END IF;

    IF Account_Party_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value,
            " AND sales_order_master.Account_Party_Id = ", Account_Party_Id_);
    END IF;

    IF Invoice_No_ != '' THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value,
            " AND CONCAT(sales_order_master.Invoice_No,'') = ", Invoice_No_);
    END IF;

    IF Part_No_ IS NOT NULL AND Part_No_ != '' THEN
        SET Cleaned_Part_No = REPLACE(Part_No_, '%', '\%');
        SET Cleaned_Part_No = REPLACE(Cleaned_Part_No, '_', '\_');

        SET SearchbyName_Value = CONCAT(SearchbyName_Value,
            " AND sales_order_details.ItemCode LIKE ",
            QUOTE(CONCAT('%', Cleaned_Part_No, '%'))
        );
    END IF;

    IF Item_Group_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value,
            " AND sales_order_details.GroupId = ", Item_Group_Id_);
    END IF;

    IF CurrencyDetails_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value,
            " AND sales_order_master.CurrencyId = ", CurrencyDetails_Id_);
    END IF;

    IF AccountType_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value,
            " AND sales_order_master.TypeId = ", AccountType_Id_);
    END IF;

    IF User_Details_Id_ > 0 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value,
            " AND sales_order_master.User_Id = ", User_Details_Id_);
    END IF;

    IF User_Type = 2 THEN
        SET SearchbyName_Value = CONCAT(SearchbyName_Value,
            " AND sales_order_master.User_Id = ", Login_User_Id);
    END IF;

    SET @query = CONCAT("
        SELECT DISTINCT
            sales_order_master.Sales_Order_Master_Id,
            sales_order_master.Account_Party_Id,
            DATE_FORMAT(sales_order_master.EntryDate,'%Y-%m-%d') AS EntryDate,
            sales_order_master.Invoice_No,
            sales_order_master.LPONo,
            sales_order_master.DONo,
            sales_order_master.PackingListNumber,
            sales_order_master.CurrencyId,
            sales_order_master.TypeId,
            sales_order_master.PaymentTerms,
            sales_order_master.TotalAmount,
            sales_order_master.TotalDiscount,
            sales_order_master.TaxableAmount,
            sales_order_master.VatAmount,
            sales_order_master.Total_Amount,
            sales_order_master.Roundoff_Amt,
            sales_order_master.NetTotal,
            sales_order_master.Makes,
            sales_order_master.PriceBasis,
            sales_order_master.Description1,
            sales_order_master.User_Id,
            sales_order_master.Delivery_Address1,
            sales_order_master.Delivery_Address2,
            sales_order_master.Delivery_Address3,
            sales_order_master.Delivery_Address4,
            sales_order_master.KindAttend,
            sales_order_master.Charge1,
            sales_order_master.charge1_Amount,
            sales_order_master.Charge2,
            sales_order_master.charge2_Amount,
            sales_order_master.Discount_Description,
            sales_order_master.Additional_Discount,
            sales_order_master.Description2,
            sales_order_master.Employee,
            sales_order_master.Basic_Discount,
            sales_order_master.Amount_In_Words,
            sales_order_master.Notes,
            sales_order_master.Charge1per,
            sales_order_master.Payment_Term_Description,
            sales_order_master.VAT_Description,
            sales_order_master.VAT_percentage,
            sales_order_master.VAT_Amount,
            sales_order_master.New_Entry,
            sales_order_master.Customer_Reference,
            DATE_FORMAT(sales_order_master.SupplyDate,'%Y-%m-%d') SupplyDate,
            DATE_FORMAT(sales_order_master.SupplyDate,'%d-%m-%Y') SupplyPrintDate,
            DATE_FORMAT(sales_order_master.DueDate,'%d-%m-%Y') DuePrintDate,
            DATE_FORMAT(sales_order_master.DueDate,'%Y-%m-%d') DueDate,
            sales_order_master.PaymentTermValue,
            DATE_FORMAT(sales_order_master.EntryDate,'%d-%m-%Y') AS FormattedEntryDate,
            Client_Accounts.Client_Accounts_Name AS Customer,
            DATE_FORMAT(sales_order_master.EntryDate,'%d-%m-%Y') AS PrintDate,
            currencydetails.CurrecnyName,
            accounttype.AccountType_Name,
            IFNULL(qsm.SalesQuotationMaster_Id,0) SalesQuotationMaster_Id
        FROM sales_order_master
        INNER JOIN Client_Accounts
            ON sales_order_master.Account_Party_Id = Client_Accounts.Client_Accounts_Id
        INNER JOIN sales_order_details
            ON sales_order_master.Sales_Order_Master_Id = sales_order_details.Sales_Order_Master_Id
        INNER JOIN accounttype
            ON sales_order_master.TypeId = accounttype.AccountType_Id
        INNER JOIN currencydetails
            ON sales_order_master.CurrencyId = currencydetails.CurrencyDetails_Id
        LEFT JOIN quotation_salesorder_master qsm
            ON qsm.Sales_Order_Master_Id = sales_order_master.Sales_Order_Master_Id
        WHERE sales_order_master.DeleteStatus = FALSE ",
        Search_Date_,
        SearchbyName_Value,
        " ORDER BY Sales_Order_Master_Id ASC"
    );

    PREPARE QUERY FROM @query;
    EXECUTE QUERY;
    DEALLOCATE PREPARE QUERY;

END
$$
