 if Is_Date_Check_=true then
	set Search_Date_=concat( " and Sales_Return_Master.Bill_Date >= '", FromDate_ ,"' and  Sales_Return_Master.Bill_Date <= '", ToDate_,"'");
end if;
if Client_Id_>0 then
	SET SearchbyName_Value =concat(SearchbyName_Value," and Sales_Return_Master.Account_Party_Id =",Client_Id_);
end if;
if VoucherType_>0 then
	SET SearchbyName_Value =concat(SearchbyName_Value," and Concat( Sales_Return_Master.Invoice_No ,'')  =",VoucherType_);
end if;
if ItemId_>0 then
	SET SearchbyName_Value =concat(SearchbyName_Value," and Sales_Return_Details.ItemId =",ItemId_);
end if;
    
SET @query = Concat("SELECT Sales_Return_Details.Sales_Return_Master_Id,(Date_Format(Bill_Date,'%Y-%m-%d')) As Bill_Date,
Invoice_No,Account_Party_Id,Client_Accounts.Client_Accounts_Name as Customer,
UnitName,ItemId,ItemName,Barcode,
GroupId,GroupName,PurchaseRate,SaleRate,MRP,Sales_Return_Details.HSNCODE,Sales_Return_Details.SaleTax,
Sales_Return_Details.CGST,Sales_Return_Details.IGST,Sales_Return_Details.SGST,Sales_Return_Details.Cesspers,
Sales_Return_Details.Quantity,Sales_Return_Details.GrossValue,Sales_Return_Details.Discount,Sales_Return_Details.NetValue,
Sales_Return_Details.CGSTAMT,Sales_Return_Details.SGSTAMT,Sales_Return_Details.IGSTAMT,Sales_Return_Details.CessAMT,
Sales_Return_Details.TotalAmount 

FROM Sales_Return_Details
	 INNER JOIN Sales_Return_Master ON Sales_Return_Details.Sales_Return_Master_Id=Sales_Return_Master.Sales_Return_Master_Id 
	 INNER JOIN Client_Accounts ON Sales_Return_Master.Account_Party_Id=Client_Accounts.Client_Accounts_Id 
