CREATE PROCEDURE `Search_VatReport`
BEGIN
    DECLARE Search_Date_ VARCHAR(500);
   # DECLARE SearchbyName_Value VARCHAR(2000);
    
    SET Search_Date_ = '';
    #SET SearchbyName_Value = '';
        SET Search_Date_ = CONCAT(" AND sales_master.EntryDate >= '", From_Date_, "' AND sales_master.EntryDate <= '", To_Date_, "'");
   # IF User_Type = 2 then
    #    SET SearchbyName_Value = CONCAT(" AND sales_master.User_Id = ",Login_User);
	#END IF;
   SET @query = CONCAT("
   select 1 as tp,(Date_Format(sales_master.EntryDate,'%d-%m-%Y')) As EntryDate,sales_master.Invoice_No as 'InvoiceNo',
   client_accounts.Client_Accounts_Name as Customer,client_accounts.GSTNo,ifnull(sales_master.VAT_percentage,0)as 'Vat %',
   (ifnull(sales_master.Total_Amount,0)-ifnull(sales_master.VAT_Amount,0))as NetTotal,
   ifnull(sales_master.VAT_Amount,0)as VATAmount,ifnull(sales_master.Total_Amount,0)as Total,ifnull(Roundoff_Amt,0)as Discount,
   ifnull(sales_master.NetTotal,0)as GrandTotal 
	from sales_master
	inner join client_accounts on client_accounts.Client_Accounts_Id = sales_master.Account_Party_Id
	where sales_master.VAT_percentage=5 and sales_master.deletestatus=0 ",Search_Date_,"
	union 
	select 2 as tp,(Date_Format(sales_master.EntryDate,'%d-%m-%Y')) As EntryDate,sales_master.Invoice_No as 'InvoiceNo',
   client_accounts.Client_Accounts_Name as Customer,client_accounts.GSTNo,ifnull(sales_master.VAT_percentage,0)as 'Vat %',
   (ifnull(sales_master.Total_Amount,0)-ifnull(sales_master.VAT_Amount,0))as NetTotal,
   ifnull(sales_master.VAT_Amount,0)as VATAmount,ifnull(sales_master.Total_Amount,0)as Total,ifnull(Roundoff_Amt,0)as Discount,
   ifnull(sales_master.NetTotal,0)as GrandTotal 
    from sales_master
	inner join client_accounts on client_accounts.Client_Accounts_Id = sales_master.Account_Party_Id
	where sales_master.VAT_percentage<>5 and sales_master.deletestatus=0 ",
    Search_Date_, "
    union
    select 3 as tp,'Total' As EntryDate,'' as InvoiceNo,'' as Customer,'' as GSTNo,'' as 'Vat %',
       (ifnull(sum(sales_master.Total_Amount),0)-ifnull(sum(sales_master.VAT_Amount),0)) as NetTotal,
       ifnull(sum(sales_master.VAT_Amount),0)as VATAmount,ifnull(sum(sales_master.Total_Amount),0)as Total,
       ifnull(sum(Roundoff_Amt),0)as Discount,ifnull(sum(sales_master.NetTotal),0)as GrandTotal  
         from sales_master
	inner join client_accounts on client_accounts.Client_Accounts_Id = sales_master.Account_Party_Id
	where sales_master.deletestatus=0 ",
    Search_Date_, 
    " " );
    PREPARE QUERY FROM @query;
delete from db_logs;
insert into db_logs values(0,@query,'Search_Registration_Report',1);
    EXECUTE QUERY;
END
$$
DELIMITER ;

