CREATE PROCEDURE `Search_Waste_Management_Report`
Begin 
 declare Search_Date_ varchar(500);
declare SearchbyName_Value varchar(2000);
set Search_Date_="";
set SearchbyName_Value="";
 if Is_Date_Check_=true then
set Search_Date_=concat( " and waste_management.Date >= '", From_Date_ ,"' and  waste_management.Date <= '", To_Date_,"'");
end if;


if Branch_>0 then
SET SearchbyName_Value =concat(SearchbyName_Value," and waste_management.Branch_Id =",Branch_);
end if;
if Item_>0 then
SET SearchbyName_Value =concat(SearchbyName_Value," and waste_management.Item_Id =",Item_);
end if;

SET @query = Concat("
 SELECT Waste_Management_Id,Branch_Id,Branch_Name,Item_Id,Item_Name,Item_Quantity,Particular,Description,
(Date_Format(waste_management.Date,'%Y-%m-%d')) As Date , (Date_Format(waste_management.Date,'%d-%m-%Y')) As Search_Date
 From waste_management 
 where waste_management.DeleteStatus=false", Search_Date_ ,SearchbyName_Value,"");
PREPARE QUERY FROM @query;

EXECUTE QUERY;

End
$$
