DELIMITER $$
CREATE PROCEDURE `SelectSettledBills`
Begin
Select distinct 1 as Voucher_Type_Id,'Purchase' as Voucher_Type_Name,purchase_master.Purchase_Master_Id,
purchase_master.InvoiceNo,(Date_Format(purchase_master.PurchaseDate,'%d-%m-%Y')) As PurchaseDate,
purchase_master.NetTotal as Amount,0 as Paying_Amount,
(purchase_master.NetTotal-ifnull(purchase_master.PaidAmount,0))BalAmt,purchase_master.Account_Party_Id
from purchase_master 
#left join payment_reference on purchase_master.Purchase_Master_Id=payment_reference.Master_Id and Voucher_Type_Id=1 
where purchase_master.DeleteStatus=0 AND purchase_master.Account_Party_Id=Account_Party_Id_
-- group by purchase_master.Purchase_Master_Id,purchase_master.InvoiceNo,purchase_master.PurchaseDate,
-- purchase_master.NetTotal,purchase_master.Account_Party_Id
and (COALESCE(purchase_master.NetTotal,0)-ifnull(purchase_master.PaidAmount,0))>0
union
select 2 as Voucher_Type_Id,'Expense' as Voucher_Type_Name,journal_entry.Journal_Entry_Id as Purchase_Master_Id,
Voucher_No as InvoiceNo,(Date_Format(journal_entry.Date,'%d-%m-%Y')) As PurchaseDate,
journal_entry.Amount,0 as Paying_Amount, 
(journal_entry.Amount-ifnull(journal_entry.PaidAmount,0))BalAmt,journal_entry.To_Account_Id as Account_Party_Id
from journal_entry 
#left join payment_reference on journal_entry.Journal_Entry_Id=payment_reference.Master_Id and Voucher_Type_Id=2 and payment_reference.DeleteStatus=0
where journal_entry.DeleteStatus=0 AND journal_entry.To_Account_Id=Account_Party_Id_ 
-- group by journal_entry.Journal_Entry_Id,Voucher_No,journal_entry.Date,journal_entry.Amount,journal_entry.To_Account_Id
and (COALESCE(journal_entry.Amount,0)-(ifnull(journal_entry.PaidAmount,0)))>0;
End
$$
DELIMITER ;

