CREATE PROCEDURE `Update_Stock_FromST`
BEGIN
declare StockId_ decimal(18,0);
declare Stock_From_Id_ decimal(18,0);
declare Quantity_ decimal(18,2);
declare New_Stock_Id_ decimal(18,0);
declare Stock_To_Id_ decimal(18,0);

declare fetch_status decimal(18,0);
Declare Cur Cursor for select  Stock_Transfer_Details.Stock_Id,Stock_From_Id,Quantity,New_Stock_Id,Stock_To_Id
from Stock_Transfer_Details 
where Stock_Transfer_Master_Id=Stock_Transfer_Master_Id_;
set fetch_status=(select Count(Stock_Transfer_Details_Id) from Stock_Transfer_Details where 
Stock_Transfer_Master_Id=Stock_Transfer_Master_Id_);
Open Cur;
FETCH Cur INTO StockId_,Stock_From_Id_,Quantity_,New_Stock_Id_,Stock_To_Id_;  
While(fetch_status != 0)do
update Stock_Details set Quantity=Quantity+Quantity_ 
where Stock_Details.Stock_Id=StockId_ and To_Employee_Id=Stock_From_Id_;

update Stock_Details set Quantity=Quantity-Quantity_ 
where Stock_Details.Stock_Id=New_Stock_Id_ and To_Employee_Id=Stock_To_Id_;

set fetch_status=fetch_status-1;
 if(fetch_status != 0)
			then
				FETCH Cur INTO StockId_,Stock_From_Id_,Quantity_,New_Stock_Id_,Stock_To_Id_;  
			end if;
END WHILE;
Close Cur;
End
$$
