DELIMITER $$
CREATE PROCEDURE `Update_Sub_Tables`
BEGIN
declare fetch_status decimal(18,0);declare Master_Id_ int;declare Voucher_Type_Id_ int;declare Paying_Amount_ DECIMAL(18,2);
declare Cur Cursor for select Master_Id,Paying_Amount,Voucher_Type_Id 
from payment_reference where Payment_Voucher_Id = Payment_Voucher_Id_ ;
set fetch_status = (select count(Payment_Reference_Id) from payment_reference where Payment_Voucher_Id = Payment_Voucher_Id_) ;
if fetch_status>0 then
	 Open cur;
	 Fetch Cur Into Master_Id_,Paying_Amount_,Voucher_Type_Id_;
		While(fetch_status!=0) do
		if Voucher_Type_Id_=1 then
		update purchase_master set PaidAmount = ifnull(PaidAmount,0) - Paying_Amount_
        where Purchase_Master_Id = Master_Id_ ;
		end if;
		if Voucher_Type_Id_=2 then
		  update journal_entry set PaidAmount = ifnull(PaidAmount,0) - Paying_Amount_ where Journal_Entry_Id = Master_Id_  ;
		end if;
			set fetch_status=fetch_status-1;
			if(fetch_status != 0)
			then
				FETCH Cur INTO Master_Id_,Paying_Amount_,Voucher_Type_Id_;  
			end if;
		End While;
end if;
END
$$
DELIMITER ;

DELIMITER $$
CREATE PROCEDURE `User_Employee`
BEGIN
select
User_Details_Id,
Employee_Id,
Client_Accounts_Name as Employee_Name
from User_Details
inner join Client_Accounts on Client_Accounts.Client_Accounts_Id=User_Details.Employee_Id
where User_Details_Id=User_Details_Id_ and Client_Accounts.DeleteStatus=false;
END
$$
